    def t_notebook_chained_cte():
        # Notebook cell-chaining composes a WITH clause on the front end and
        # runs it as an ordinary query. Verify the engine executes the shape
        # compose produces: nested CTEs where a later one reads an earlier one.
        s = _loaded_session()
        try:
            sql = (
                "WITH cell1 AS (\n"
                "  SELECT category, COUNT(*) AS n FROM data GROUP BY category\n"
                "),\n"
                "cell2 AS (\n"
                "  SELECT category, n FROM cell1 WHERE n > 0\n"
                ")\n"
                "SELECT category, n FROM cell2 ORDER BY n DESC"
            )
            r = s.run_query(sql, target="__local__")
            need(not r.get("error"), f"chained CTE query errored: {r.get('error')}")
            eq(r["columns"], ["category", "n"], "chained CTE columns")
            need(r["total_rows"] >= 1, "chained CTE returned rows")
            need(r["result_id"], "chained CTE has a result_id (pageable)")
            # totals across the rolled-up buckets equal the base row count
            tot = sum(int(row[1]) for row in s.page(
                r["result_id"], offset=0, limit=100)["rows"])
            eq(tot, ROWS, "chained CTE bucket counts sum to base rows")
        finally:
            s.shutdown()

