    def t_profile_cache_clears_on_write_epoch_bump():
        # Latest-data wins: INSERT (write that returns columns) bumps epoch via
        # _invalidate_counts and must drop _profile_cache — not only DDL paths
        # that call _invalidate_profiles explicitly.
        from samql_core.session import LOCAL_TARGET
        s = _loaded_session()
        try:
            a = s.profile("data")
            b = s.profile("data")
            need(a is b, "profile cached before write")
            ep = s._data_epoch
            w = s.run_query(
                "INSERT INTO data (id, name, score, category, dt) "
                "VALUES (9999, 'x', 1.0, 'A', '2024-06-01')",
                target=LOCAL_TARGET)
            need(not w.get("error"), "insert ok: %s" % w.get("error"))
            need(s._data_epoch > ep, "insert bumps data_epoch")
            c = s.profile("data")
            need(c is not a,
                 "profile cache must miss after write epoch bump")
            need(c.get("columns"), "fresh profile has columns")
        finally:
            s.shutdown()

    def t_profile_field():
        s = _loaded_session()
        try:
            # table field (SQL aggregation path)
            pf = s.profile_field(
                {"table": "data", "engine": "sqlite", "column": "score"})
            need("columns" in pf and len(pf["columns"]) == 1,
                 "profile_field should return exactly one column")
            col = pf["columns"][0]
            eq(col["column"], "score", "field name")
            eq(col["raw_type"], "NUMERIC", "score field type")
            eq(float(col["min"]), 0.0, "score field min")
            eq(float(col["max"]), 88.5, "score field max")
            eq(col["nulls"], 0, "score field nulls")
            eq(pf["field"], "score", "field marker")
            # result field (small in-memory Python path)
            r = s.run_query("SELECT * FROM data", target="__local__")
            need(r.get("result_id"), "no result_id")
            pc = s.profile_field(
                {"result_id": r["result_id"], "column": "category"})
            c2 = pc["columns"][0]
            eq(c2["distinct"], 3, "category field distinct (result)")
            need(len(c2["top_values"]) == 3,
                 "expected 3 distinct category top values")
            need(abs(sum(t["pct"] for t in c2["top_values"]) - 100.0) < 0.6,
                 "category top-value pcts should cover ~100%")
        finally:
            s.shutdown()

