    def t_pivot_node_crosstab():
        # The NodeFlow pivot NODE's crosstab SQL: multiple column dims, multiple
        # measures, and subtotals/grand-totals (exercised on SQLite, whose
        # ROLLUP is emulated with UNION ALL).
        from samql_core import nodeflow as _nf
        s = _fresh_session()
        try:
            db = s.db
            db.execute("CREATE TABLE pt (region TEXT, quarter TEXT, "
                       "channel TEXT, sales REAL, margin REAL)")
            for r in [("North", "Q1", "Web", 100, 0.2),
                      ("North", "Q1", "Store", 50, 0.1),
                      ("North", "Q2", "Web", 80, 0.3),
                      ("South", "Q1", "Web", 60, 0.25),
                      ("South", "Q2", "Store", 40, 0.15)]:
                db.execute("INSERT INTO pt VALUES ('%s','%s','%s',%r,%r)" % r)

            # multi-col + multi-measure + subtotals
            cfg = {"rows": ["region"], "cols": ["quarter", "channel"],
                   "values": [{"field": "sales", "agg": "sum"},
                              {"field": "margin", "agg": "avg"}],
                   "subtotals": True}
            cols, rows = db.execute(s._pivot_crosstab_sql(db, '"pt"', cfg, "sqlite"))
            need("region" in cols, "row-dim column present")
            need(any(c.startswith("Q1 / Web / sum(sales)") for c in cols),
                 "nested column-combination header present")
            need(sum(1 for c in cols if c.startswith("Total")) == 2,
                 "one grand-total column per measure")
            gt = [r for r in rows if r[0] == "Total"]
            eq(len(gt), 1, "exactly one grand-total row")
            eq(gt[0][cols.index("Total / sum(sales)")], 330.0,
               "grand total of sales = 330")

            # back-compat: a legacy single-col/single-value config is unchanged
            cfg2 = {"rows": ["region"], "col": "quarter",
                    "value": "sales", "agg": "sum"}
            cols2, _r2 = db.execute(
                s._pivot_crosstab_sql(db, '"pt"', cfg2, "sqlite"))
            eq(cols2, ["region", "Q1", "Q2"],
               "legacy single-column crosstab columns unchanged")

            # two row dims -> a subtotal row per outer group + grand total
            cfg3 = {"rows": ["region", "quarter"], "cols": ["channel"],
                    "values": [{"field": "sales", "agg": "sum"}],
                    "subtotals": True}
            _c3, rows3 = db.execute(
                s._pivot_crosstab_sql(db, '"pt"', cfg3, "sqlite"))
            labels = [(r[0], r[1]) for r in rows3]
            need(("North", "Total") in labels and ("South", "Total") in labels,
                 "a subtotal row per region group")
            need(("Total", "") in labels, "a grand-total row at the end")

            # outline (Tableau-style nested sub-rows): one indented label
            # column; parents above children. Without subtotals the parent rows
            # are headers (blank measures) and there's no grand total.
            cfg4 = {"rows": ["region", "quarter"], "cols": ["channel"],
                    "values": [{"field": "sales", "agg": "sum"}],
                    "outline": True}
            c4, r4 = db.execute(s._pivot_crosstab_sql(db, '"pt"', cfg4, "sqlite"))
            need(c4[0] == "Row Labels",
                 "outline collapses row dims into one 'Row Labels' column")
            need(not any(str(c).startswith("Total") for c in c4),
                 "no Total column without subtotals")
            labels4 = [r[0] for r in r4]
            need(any(str(x).strip("\u00a0") == "North" for x in labels4),
                 "outline shows the parent (region) as its own row")
            need(any("\u00a0" in str(x) for x in labels4),
                 "outline indents child rows")
            need(not any(str(x) == "Grand Total" for x in labels4),
                 "no grand-total row without subtotals")
            # the North parent row precedes its quarter children
            iN = next(i for i, x in enumerate(labels4)
                      if str(x).strip("\u00a0") == "North")
            iNQ = next(i for i, x in enumerate(labels4)
                       if "\u00a0" in str(x) and i > iN)
            need(iN < iNQ, "parent row comes above its indented children")
            # outline + subtotals keeps a Grand Total row + a Total column
            cfg5 = dict(cfg4); cfg5["subtotals"] = True
            c5, r5 = db.execute(s._pivot_crosstab_sql(db, '"pt"', cfg5, "sqlite"))
            need(any(str(c).startswith("Total") for c in c5),
                 "outline + subtotals keeps a Total column")
            need(any(str(r[0]) == "Grand Total" for r in r5),
                 "outline + subtotals keeps a grand-total row")

            # no column field -> a friendly error, not a crash
            try:
                s._pivot_crosstab_sql(db, '"pt"', {"rows": ["region"]}, "sqlite")
                need(False, "expected an error when no column field is set")
            except _nf.NodeflowError:
                pass
        finally:
            s.shutdown()

    def t_rename():
        s = _loaded_session()
        try:
            s.rename_table("sqlite", "data", "renamed")
            names = [t["name"] for t in s.tables_tree()]
            need("renamed" in names and "data" not in names,
                 f"rename failed: {names}")
        finally:
            s.shutdown()

    def t_table_ui_reorder():
        # Loaded-tables drag order is session-scoped: empty = alphabetical
        # catalog default; set_table_ui_order reshapes /api/tables; rename
        # keeps the key; drop/clear prune it. New tables not in the order
        # list still append after ranked ones (flatten registration friendly).
        s = _fresh_session()
        try:
            s.db.add_table_streaming(
                "alpha", ["id"], iter([(1,), (2,)]))
            s.db.add_table_streaming(
                "bravo", ["id"], iter([(3,), (4,)]))
            s.db.add_table_streaming(
                "charlie", ["id"], iter([(5,), (6,)]))
            s.db.sync_catalog()
            names0 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names0, ["alpha", "bravo", "charlie"],
               "default catalog order is alphabetical")
            r = s.set_table_ui_order([
                {"engine": "sqlite", "name": "charlie"},
                {"engine": "sqlite", "name": "alpha"},
                {"engine": "sqlite", "name": "bravo"},
            ])
            eq(r.get("ok"), True, "set_table_ui_order ok")
            names1 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names1, ["charlie", "alpha", "bravo"],
               "tables_tree honors session UI order")
            s.rename_table("sqlite", "charlie", "delta")
            names2 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names2, ["delta", "alpha", "bravo"],
               "rename updates UI-order key")
            s.drop_table("sqlite", "alpha")
            names3 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names3, ["delta", "bravo"],
               "drop removes UI-order key")
            s.db.add_table_streaming(
                "echo", ["id"], iter([(7,)]))
            s.db.sync_catalog()
            names4 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names4, ["delta", "bravo", "echo"],
               "new unranked table appends after ranked")
            # clear_all wipes order so the next session starts alphabetical
            s.clear_all(clear_manifest=True)
            s.db.add_table_streaming(
                "zulu", ["id"], iter([(1,)]))
            s.db.add_table_streaming(
                "able", ["id"], iter([(2,)]))
            s.db.sync_catalog()
            names5 = [t["name"] for t in s.tables_tree()
                      if t["engine"] == "sqlite"]
            eq(names5, ["able", "zulu"],
               "after clear, order is alphabetical again")
        finally:
            s.shutdown()

    def t_change_type():
        s = _loaded_session()
        try:
            s.change_column_type("sqlite", "data", "id", "TEXT")
            prof = {c["column"]: c for c in s.profile("data")["columns"]}
            eq(prof["id"]["type"], "TEXT", "changed type")
        finally:
            s.shutdown()

    def t_duckdb_change_column_type():
        # DuckDBManager.change_column_type was missing entirely (AttributeError
        # on the real DuckDB path). Verify it retypes a column and keeps rows.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        try:
            s.load_file(CSV, destination="duckdb", base_name="d")
            ok = s.change_column_type("duckdb", "d", "id", "VARCHAR")
            eq(ok.get("ok"), True, "duckdb change_column_type returned ok")
            prof = {c["column"]: c
                    for c in s.profile("d", engine="duckdb")["columns"]}
            # the profiler reports the DATA-inferred type, not the schema type;
            # a now-VARCHAR id column comes back as strings -> "TEXT". (That it
            # is no longer "NUMERIC" is the proof the retype took effect.)
            eq(prof["id"]["type"], "TEXT", "duckdb column retyped to string")
            n = s.run_query('SELECT COUNT(*) FROM d',
                            target="__duckdb__")["rows"][0][0]
            eq(n, ROWS, "row count preserved after retype")
        finally:
            s.shutdown()

    def t_table_count_cache():
        # /api/tables used to re-run COUNT(*) on every refresh (slow column
        # expansion). Counts are now cached and invalidated on writes.
        s = _loaded_session()
        try:
            tree = {t["name"]: t for t in s.tables_tree()}
            eq(tree["data"]["row_count"], ROWS, "row count correct")
            need(("sqlite", "data") in s._count_cache,
                 "count cached after tables_tree")
            s.run_query("DELETE FROM data WHERE name = 'name_0'",
                        target="__local__")
            need(("sqlite", "data") not in s._count_cache,
                 "write invalidated the count cache")
            tree2 = {t["name"]: t for t in s.tables_tree()}
            eq(tree2["data"]["row_count"], ROWS - 1, "recount after delete")
        finally:
            s.shutdown()

    def t_table_count_cache_scoped_drop():
        # CODE was wrong: every mutation cleared ALL sidebar counts. Dropping
        # one table must only forget that table's key; unrelated counts stay.
        s = _fresh_session()
        try:
            import csv as _csv
            dd = tempfile.mkdtemp()
            for name, n in (("keep_me", 7), ("drop_me", 3)):
                pp = os.path.join(dd, name + ".csv")
                with open(pp, "w", newline="") as f:
                    w = _csv.writer(f)
                    w.writerow(["x"])
                    for i in range(n):
                        w.writerow([i])
                s.load_file(pp, destination="sqlite", base_name=name)
            tree = {t["name"]: t for t in s.tables_tree()}
            eq(tree["keep_me"]["row_count"], 7, "keep_me counted")
            eq(tree["drop_me"]["row_count"], 3, "drop_me counted")
            need(("sqlite", "keep_me") in s._count_cache
                 and ("sqlite", "drop_me") in s._count_cache,
                 "both counts cached")
            ep = s._data_epoch
            s.drop_table("sqlite", "drop_me")
            need(("sqlite", "drop_me") not in s._count_cache,
                 "dropped table count cleared")
            need(("sqlite", "keep_me") in s._count_cache,
                 "unrelated table count preserved after scoped invalidate")
            eq(s._count_cache[("sqlite", "keep_me")], 7,
               "preserved count value intact")
            # Latest-data wins: any content-touching drop advances data_epoch
            # so IDE/Journal refuse retained snapshots. Flow cache clears on
            # the same epoch bump (covered by t_flow_cache_clears_on_unrelated…).
            need(s._data_epoch > ep,
                 "content-touching drop must advance data_epoch")
        finally:
            s.shutdown()

    def t_flow_cache_clears_on_unrelated_table_drop():
        # CODE was incomplete: scoped flow clear + epoch-salted fingerprints
        # left orphaned entries that could never hit. Unrelated drops must
        # still advance data_epoch AND clear volatile flow cache.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.flow_cache = True
            s.run_query("CREATE TABLE flow_src AS SELECT 1 AS g, 10 AS v",
                        target=LOCAL_TARGET)
            s.run_query("CREATE TABLE other_tbl AS SELECT 1 AS x",
                        target=LOCAL_TARGET)
            g = {"nodes": [
                {"id": "n1", "type": "input", "config": {"table": "flow_src"}},
                {"id": "n2", "type": "output", "config": {"label": "out"}}],
                 "edges": [{"from": {"node": "n1", "port": "out"},
                            "to": {"node": "n2", "port": "in"}}]}
            r1 = s.run_nodeflow(g, "n2", "out")
            need(not r1.get("error"), "flow runs: %s" % r1.get("error"))
            need("flow_src" in (s._flow_source_tables or set()),
                 "flow input table recorded for scoped invalidation")
            ep = s._data_epoch
            size = s.flow_cache_info()["size"]
            need(size >= 1, "flow cache populated before unrelated drop")
            s.drop_table("sqlite", "other_tbl")
            need(s._data_epoch > ep,
                 "unrelated drop still advances data_epoch")
            eq(s.flow_cache_info()["size"], 0,
               "unrelated drop clears flow cache (no epoch-orphan entries)")
            # Rematerialize after clear still works and sees live inputs.
            r2 = s.run_nodeflow(g, "n2", "out")
            need(not r2.get("error"), "flow re-run after clear: %s"
                 % r2.get("error"))
            need(s.flow_cache_info()["size"] >= 1,
                 "flow cache repopulates after rematerialize")
            ep2 = s._data_epoch
            s.drop_table("sqlite", "flow_src")
            need(s._data_epoch > ep2, "drop of flow input still bumps epoch")
            eq(s.flow_cache_info()["size"], 0,
               "drop of flow input clears flow cache")
        finally:
            s.shutdown()

    def t_flow_cache_notes_nested_and_plural_tables():
        # CODE was wrong: _note_flow_source_tables only scanned top-level
        # singular table/err/left/right keys. Nested group/iterator children,
        # created-node graphs, and plural config.tables were invisible, so
        # dropping those inputs left stale flow-cache entries.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.flow_cache = True
            s._flow_source_tables = set()
            s._note_flow_source_tables({
                "nodes": [
                    {"id": "g", "type": "group", "config": {"children": [
                        {"id": "gi", "type": "input",
                         "config": {"table": "nested_grp"}}]}},
                    {"id": "it", "type": "iterator", "config": {
                        "table": "iter_accum",
                        "children": [
                            {"id": "ii", "type": "input",
                             "config": {"table": "nested_iter"}}]}},
                    {"id": "u", "type": "usernode", "config": {
                        "graph": {"nodes": [
                            {"id": "ui", "type": "input",
                             "config": {"table": "nested_user"}}]}}},
                    {"id": "ins", "type": "inputs", "config": {
                        "tables": ["plural_a",
                                   {"name": "plural_b"},
                                   {"table": "plural_c"}]}},
                    {"id": "api", "type": "apinode",
                     "config": {"table": "api_ok", "err_table": "api_err"}},
                ],
            })
            deps = s._flow_source_tables or set()
            for name in ("nested_grp", "nested_iter", "nested_user",
                         "iter_accum", "plural_a", "plural_b", "plural_c",
                         "api_ok", "api_err"):
                need(name in deps, "records %s as a flow source" % name)

            # Live nested group input: any content drop clears cache (epoch);
            # drop of the nested input still clears.
            s.run_query(
                "CREATE TABLE flow_nested AS SELECT 1 AS g, 10 AS v",
                target=LOCAL_TARGET)
            s.run_query("CREATE TABLE other_nested AS SELECT 1 AS x",
                        target=LOCAL_TARGET)
            g = {"nodes": [
                {"id": "g", "type": "group", "config": {"children": [
                    {"id": "n1", "type": "input",
                     "config": {"table": "flow_nested"}}]}},
                {"id": "n2", "type": "output", "config": {"label": "out"}}],
                 "edges": [{"from": {"node": "g", "port": "out"},
                            "to": {"node": "n2", "port": "in"}}]}
            r1 = s.run_nodeflow(g, "n2", "out")
            need(not r1.get("error"), "nested group flow runs: %s"
                 % r1.get("error"))
            need("flow_nested" in (s._flow_source_tables or set()),
                 "nested group input recorded after run")
            ep = s._data_epoch
            size = s.flow_cache_info()["size"]
            need(size >= 1, "flow cache populated after nested run")
            s.drop_table("sqlite", "other_nested")
            need(s._data_epoch > ep,
                 "unrelated drop advances data_epoch with nested deps")
            eq(s.flow_cache_info()["size"], 0,
               "unrelated drop clears nested flow cache (no orphans)")
            # Repopulate, then drop the nested input.
            r2 = s.run_nodeflow(g, "n2", "out")
            need(not r2.get("error"), "nested re-run: %s" % r2.get("error"))
            ep2 = s._data_epoch
            s.drop_table("sqlite", "flow_nested")
            need(s._data_epoch > ep2,
                 "drop of nested group input bumps flow epoch")
            eq(s.flow_cache_info()["size"], 0,
               "drop of nested group input clears flow cache")

            # SQL-node tables must be recorded too (audit high #1).
            s._flow_source_tables = set()
            s._note_flow_source_tables({
                "nodes": [
                    {"id": "sq", "type": "sql",
                     "config": {"sql": "SELECT * FROM sql_dep_tbl"}},
                    {"id": "out", "type": "output", "config": {}}],
            })
            need("sql_dep_tbl" in (s._flow_source_tables or set()),
                 "SQL node FROM table is a flow source dep")
        finally:
            s.shutdown()

    def t_create_or_replace_refreshes_same_shape_types():
        # CODE was wrong after incremental sync: CREATE OR REPLACE that kept
        # the same column names skipped DESCRIBE, so types stayed stale.
        from samql_core.engines import HAS_DUCKDB
        if not HAS_DUCKDB:
            skip("duckdb is not installed")
        from samql_core.session import DUCKDB_TARGET
        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            s.run_query(
                "CREATE OR REPLACE TABLE shape_t AS "
                "SELECT 1 AS id, 'x' AS val",
                target=DUCKDB_TARGET)
            types1 = duck.types_cached("shape_t")
            need(types1.get("val"), "val typed after create")
            t0 = str(types1.get("val") or "").upper()
            need("VARCHAR" in t0 or "STRING" in t0 or "TEXT" in t0,
                 "val starts as text-ish: %r" % types1.get("val"))
            # Same column names, different type for val.
            s.run_query(
                "CREATE OR REPLACE TABLE shape_t AS "
                "SELECT 1 AS id, 42 AS val",
                target=DUCKDB_TARGET)
            types2 = duck.types_cached("shape_t")
            t1 = str(types2.get("val") or "").upper()
            need(("INT" in t1) and ("VARCHAR" not in t1) and ("STRING" not in t1)
                 and ("TEXT" not in t1),
                 "val type refreshed after same-shape REPLACE: %r"
                 % types2.get("val"))
            need(t0 != t1, "type string actually changed")
        finally:
            s.shutdown()

    def t_change_type_persists():
        # a column that loads as TEXT (identifier name) -> change to INTEGER;
        # the change must show in the profile and persist (numeric ordering).
        import csv as _csv
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        pp = os.path.join(dd, "ct.csv")
        with open(pp, "w", newline="") as f:
            w = _csv.writer(f)
            w.writerow(["code"])
            for i in range(20):
                w.writerow([i])
        try:
            s.load_file(pp, destination="sqlite", base_name="ct")
            before = {c["column"]: c["type"] for c in s.profile("ct")["columns"]}
            eq(before["code"], "TEXT", "code should load as TEXT")
            r = s.change_column_type("sqlite", "ct", "code", "INTEGER")
            need(r.get("ok"), "change_column_type not ok")
            after = {c["column"]: c["type"] for c in s.profile("ct")["columns"]}
            eq(after["code"], "NUMERIC", "profile not updated after change")
            res = s.run_query("SELECT code FROM ct ORDER BY code DESC",
                              target="__local__")
            eq([r0[0] for r0 in res["rows"][:3]], [19, 18, 17],
               "ordering not numeric after change (did not persist)")
        finally:
            s.shutdown()

