    def t_excel_sheet_and_header_row():
        # Build .199 — Excel import can pick one sheet and start the header on a
        # chosen row (skipping a banner/preamble above it). Functional: build a
        # two-sheet workbook with a banner row, then load specific sheets.
        if not feats["openpyxl"]:
            skip("openpyxl not installed")
        import openpyxl as _xl
        import shutil as _sh
        from samql_core.loaders import excel_sheet_names
        d = tempfile.mkdtemp(prefix="samql_xl_")
        path = os.path.join(d, "book.xlsx")
        wb = _xl.Workbook()
        a = wb.active
        a.title = "Alpha"
        a.append(["Quarterly report", None])     # row 1: a banner, not the header
        a.append(["id", "name"])                  # row 2: the real header
        a.append([1, "ada"])
        a.append([2, "bob"])
        b = wb.create_sheet("Beta")
        b.append(["x", "y"])                      # row 1 header
        b.append([10, 20])
        wb.save(path)
        wb.close()

        def colnames(t):
            return [c["name"] if isinstance(c, dict) else c
                    for c in t["columns"]]

        eq(excel_sheet_names(path), ["Alpha", "Beta"],
           "sheet names listed in order")
        s = _fresh_session()
        try:
            out = s.load_file(path, destination="sqlite", base_name="book",
                              sheet="Alpha", header_row=2)
            eq(len(out), 1, "one chosen sheet -> one table")
            eq(out[0]["name"], "book",
               "a single chosen sheet is named after the file (no _sheet)")
            eq(colnames(out[0]), ["id", "name"],
               "header taken from the chosen start row (2), banner skipped")
            eq(out[0]["rows"], 2, "two data rows below the header")
            out2 = s.load_file(path, destination="sqlite", base_name="beta",
                               sheet="Beta", header_row=1)
            eq(colnames(out2[0]), ["x", "y"], "second sheet, header on row 1")
            raised = False
            try:
                s.load_file(path, destination="sqlite", base_name="z",
                            sheet="Nope", header_row=1)
            except Exception as e:
                raised = "found" in str(e).lower()
            need(raised, "a missing sheet name raises a clear error")
        finally:
            s.shutdown()
            _sh.rmtree(d, ignore_errors=True)

    def t_export_tableau_powerbi_removed():
        # Build .204 — the dedicated Tableau / Power BI export targets were
        # removed: Parquet (typed, columnar) opens directly in both, so the
        # separate options were redundant. The backend now rejects those format
        # strings outright in the results export and the output node; Parquet
        # stays a first-class format.
        s = _loaded_session()
        try:
            r = s.run_query("SELECT id, name FROM data ORDER BY id LIMIT 2",
                            target="__local__")
            rid = r["result_id"]
            for fmt in ("tableau", "powerbi"):
                res = s.export(rid, fmt)
                need(not res.get("ok")
                     and "nsupported" in (res.get("error") or ""),
                     "results export rejects %s now: %s" % (fmt, res))
            import tempfile
            ct = {"id": "ct", "type": "createtable", "config": {
                "label": "t", "columns": ["a"], "rows": [["x"]],
                "dest": "sqlite"}}
            out = {"id": "o", "type": "output", "config": {"label": "o"}}
            g = {"nodes": [ct, out], "edges": [
                {"from": {"node": "ct", "port": "out"},
                 "to": {"node": "o", "port": "in"}}]}
            d = tempfile.mkdtemp(prefix="samql_export_")
            for fmt in ("tableau", "powerbi"):
                res = s.export_nodeflow(g, "o", d, fmt=fmt, base_name="o")
                need(not res.get("ok"),
                     "output node rejects %s now: %s" % (fmt, res))
            # Parquet is still an accepted format string -- the writer needs
            # pyarrow (may be absent in CI), so just assert it is NOT rejected
            # as an unknown format.
            res = s.export_nodeflow(g, "o", d, fmt="parquet", base_name="o")
            need("Output format must be" not in (res.get("error") or ""),
                 "parquet is still an accepted output format: %s" % res)
        finally:
            s.shutdown()

