    def t_suite_temp_hygiene():
        # The runner's temp canary + teardown: every temp path the suite
        # creates is registered and reclaimed at the end, with the tally
        # printed -- leaky tests can never litter the box again.
        import tempfile as _tf
        # the canary is live in THIS process (main installed it)
        need(getattr(_tf, "_samql_canary", False),
             "the canary wraps tempfile for this run")
        d = _tf.mkdtemp(prefix="hyg_")
        f = _tf.NamedTemporaryFile(prefix="hyg_", delete=False)
        f.write(b"x" * 10)
        f.close()
        import __main__ as M
        need(d in M._TEMP_REGISTRY and f.name in M._TEMP_REGISTRY,
             "created paths are registered")
        n, freed = M._sweep_registered({d, f.name, d + "_ghost"})
        need(n == 2 and freed >= 10
             and not os.path.exists(d) and not os.path.exists(f.name),
             "the sweeper removes what exists and counts the bytes "
             "(n=%d freed=%d)" % (n, freed))
        src = open(os.path.abspath(M.__file__), encoding="utf-8").read()
        need("_install_temp_canary()" in src.split("def main(")[1]
             and "_sweep_registered(_TEMP_REGISTRY)" in src
             and "tmputil.sweep_stale()" in src.split("finally:", 1)[1]
             and "temp cleanup:" in src,
             "the runner installs the canary, sweeps, and prints the tally")

    def t_run_surface_meta():
        # .381: every run registers WHERE it came from (ide/journal/node) and
        # a human label; the stat modal groups running queries by these.
        from samql_core import progress as P
        P.begin("query", op_id="qq1", engine="duckdb",
                surface="ide", label="Tab 3")
        try:
            row = [o for o in P.snapshot() if o["id"] == "qq1"][0]
            need(row["surface"] == "ide" and row["label"] == "Tab 3",
                 "opreg snapshot carries surface + label: %r" % row)
        finally:
            P.end(op_id="qq1")
        # through the session's register path
        s = _fresh_session()
        try:
            s._register_run("qq2", s.db, surface="journal", label="cell7")
            row = [o for o in P.snapshot() if o["id"] == "qq2"][0]
            need(row["surface"] == "journal" and row["label"] == "cell7",
                 "_register_run threads the meta through")
            s._unregister_run("qq2")
            # .516: a finished op lingers observable; it must be FINISHED
            # and no longer active
            _q2 = [o for o in P.snapshot() if o["id"] == "qq2"]
            need(all(o["finished"] for o in _q2) and P.count() == 0,
                 "unregister finishes it (linger-visible, not active)")
            # flow label helper: label > type > id
            g = {"nodes": [{"id": "n9", "type": "filter",
                            "config": {"label": "keep big"}}]}
            eq(s._flow_node_label(g, "n9"), "keep big", "cfg label wins")
            eq(s._flow_node_label({"nodes": [{"id": "n9",
                                              "type": "filter"}]}, "n9"),
               "filter", "type is the fallback")
            eq(s._flow_node_label({}, "zz"), "zz", "id is the last resort")
        finally:
            s.shutdown()
        # run_query accepts and forwards the meta (signature-level)
        import inspect
        ps = set(inspect.signature(
            __import__("samql_core.session",
                       fromlist=["Session"]).Session.run_query
        ).parameters)
        need({"surface", "label"} <= ps,
             "run_query carries surface/label")
        srv = open(os.path.join(BACKEND, "server.py"),
                   encoding="utf-8").read()
        need('surface=b.get("surface")' in srv
             and 'label=b.get("label")' in srv,
             "the query handler passes both through")
        sess = open(os.path.join(BACKEND, "samql_core", "session.py"),
                    encoding="utf-8").read()
        need(sess.count('surface="node"') >= 5
             and "_flow_node_label(graph, node_id)" in sess,
             "flow runs register as node-surface with the node's label")

