    def t_icon_and_sniff_chain_526():
        # .526: two on-box reports. (A) "Identifier scan failed. Request
        # timed out after 20s": sniffing the file path directly made
        # DuckDB parse the WHOLE file when the top level is one giant
        # wrapper object -- the path mode now samples a 2MB PREFIX like
        # drag-drop, and the repair learned to close a truncated wrapper
        # ({"json": [ ... ]}), so any file size sniffs in milliseconds.
        # (B) The Edge mark kept returning because the launcher stamped
        # whatever /favicon.ico served -- which a stale
        # frontend_dist/favicon.ico shadows. Now: an AUTHORITATIVE
        # /samql.ico route (bundle/exe/repo icon, never the dist file),
        # the launcher prefers it and LOGS the art's sha, the build
        # propagates the repo icon into public/favicon.ico, and the
        # restamps run out to 60s.
        import json as _json
        import urllib.request as _ur
        import threading as _th
        import time as _tm
        from samql_core.session import Session

        # (A1) wrapper repair
        R = Session._repair_json_prefix
        full = _json.dumps({"json": [
            {"code": 1, "legs": [{"r": 1}]},
            {"code": 2, "legs": []},
            {"code": 3, "legs": [{"r": 9}]}]})
        cut = full[:full.rfind('"legs"')]
        d = _json.loads(R(cut.encode()))
        need(list(d.keys()) == ["json"]
             and [r["code"] for r in d["json"]] == [1, 2],
             "truncated WRAPPER repaired to whole records: %r" % d)
        d2 = _json.loads(R(b'{"a":{"json":[{"c":1},{"c":2},{"c":'))
        need(d2 == {"a": {"json": [{"c": 1}, {"c": 2}]}},
             "nested wrapper closes every brace")
        need(R(b'{"only": "sca') == b"[]", "wrapper with no array -> []")

        # (A2) the server path mode reads a PREFIX, not the whole file
        srv = open(os.path.join(BACKEND, "server.py"),
                   encoding="utf-8").read()
        _ls = srv.split("def load_sniff(", 1)[1][:2400]
        need('fh.read(2 * 1024 * 1024)' in _ls
             and "sniff_root_sample(raw, os.path.basename(" in _ls,
             "path-mode sniff samples a prefix")
        need("sniff_root_candidates(path.strip())" not in _ls,
             "no direct whole-file DuckDB sniff remains")

        # (B1) the authoritative icon route serves the resolver's file
        need('def _authoritative_ico():' in srv
             and '"X-SamQL-Brand": "authoritative"' in srv,
             "authoritative resolver + header present")
        import server as _sv
        ap = _sv._authoritative_ico()
        httpd, _p = _sv.make_server("127.0.0.1", 0)
        port = httpd.server_address[1]
        _th.Thread(target=httpd.serve_forever, daemon=True).start()
        _tm.sleep(0.2)
        try:
            try:
                with _ur.urlopen("http://127.0.0.1:%d/samql.ico" % port,
                                 timeout=10) as r:
                    body = r.read()
                    code = r.status
            except _ur.HTTPError as e:
                body = e.read()
                code = e.code
            if ap:
                with open(ap, "rb") as fh:
                    need(code == 200 and body == fh.read(),
                         "/samql.ico serves the authoritative bytes")
            else:
                need(code == 404,
                     "no authoritative icon -> honest 404 (launcher "
                     "falls back to /favicon.ico)")
        finally:
            httpd.shutdown()

        # (B2) launcher: prefers /samql.ico, fingerprints the art, and
        # restamps out to 60s
        la = open(os.path.join(BACKEND, "launcher_app.py"),
                  encoding="utf-8").read()
        for frag, why in (
            ('for route in ("/samql.ico", "/favicon.ico"):',
             "authoritative route preferred"),
            ("icon art source=%s path=%s sha=%s",
             "the stamped art is fingerprinted in the log"),
            ("def _ico_fingerprint(path):", "fingerprint helper"),
            ("(2.0, 3.0, 5.0, 8.0, 15.0, 30.0, 60.0)",
             "restamps run out to 60s"),
        ):
            need(frag in la, "launcher: %s" % why)
        need(la.count("icon art source=") >= 2,
             "BOTH stamp sites log the art source")

        # (B3) the build propagates the repo icon into public/favicon.ico
        bp = _root_script("build.ps1")
        need(os.path.isfile(bp), "build.ps1 present on disk")
        bs = open(bp, encoding="utf-8").read()
        need('Copy-Item $ico "frontend\\public\\favicon.ico" -Force' in bs
             and "SamQL.ico" in bs,
             "build copies the repo icon over the web favicon")

    
    def t_onbox_fixes_525():
        # .525: the four on-box breakages from the 2026-07-08 test pass.
        # (1) The sniff quoted no path -- C:\... parsed as C then ':'
        #     ("syntax error at or near ':'"); and it read self.duckdb
        #     directly, which is LAZY (None on a fresh launch -> "DuckDB
        #     is not available"). Now: get_duckdb() + a quoted literal.
        # (2) A cancel Event left SET by an earlier Stop is sticky on the
        #     manager and _BeatScope interrupts every statement while set
        #     -- a fresh flatten died on arrival ("flatten cancelled
        #     (tables so far kept)"). flatten_table now clears it at
        #     entry, like the loaders' fresh-load clears.
        # (3) The Load modal's real path is SHRED (flatten:false,
        #     shred:true) -> _shred_after_load -- which never received
        #     root_id, so the .521 feature was dead on-box. Now threaded,
        #     stats surfaced on the item.
        # (4) The taskbar/Alt-Tab sample the WinForms CLASS icon -- the
        #     Edge mark leaked from there; the launcher stamps GCLP too.
        import contextlib
        from samql_core.session import Session
        from samql_core import sqlutil as _squ

        CAPT = []

        class _Cur:
            description = [("ok",)]

            def execute(self, q, *a):
                return self

            def fetchall(self):
                return [(0,)]

            def fetchone(self):
                return (0,)

        class _Mgr:
            def __init__(s2):
                s2.table_columns = {"t": ["json"]}
                s2.table_sources = {}
                s2.write_lock = threading.RLock()
                s2._cancel = threading.Event()
                s2.conn = _Cur()

            def _column_types_raw(s2, t2):
                # sophis-shaped: the element CARRIES a nested list --
                # the promote-deep path (a flat element takes a shallow
                # route; that planner edge is out of scope here)
                return {"json": "STRUCT(code BIGINT, identifier "
                                "MAP(VARCHAR, JSON), "
                                "legs STRUCT(r DOUBLE)[])[]"}

            def execute(s2, q):
                CAPT.append(q)
                if q.startswith("DESCRIBE"):
                    return ([], [("json",
                                  "STRUCT(code BIGINT, identifier "
                                  "MAP(VARCHAR, JSON), "
                                  "legs STRUCT(r DOUBLE)[])[]")])
                if "map_keys(" in q:
                    return ([], [("sophis",)])
                if "COUNT(" in q:
                    return ([], [(3, 3, 3)])
                return ([], [])

            def sync_catalog(s2):
                pass

            def native_op_cursor(s2):
                @contextlib.contextmanager
                def cm():
                    yield _Cur(), threading.RLock()
                return cm()

        def _fresh():
            # each stage gets an ISOLATED session: reserved/family state
            # from one flatten legitimately changes naming on the next,
            # which is not what these stages are probing
            s2 = Session()
            s2.duckdb = _Mgr()
            return s2

        # (1) sniff: quoted Windows path with ':' + live map keys
        ses = _fresh()
        try:
            pth = "C:\\data\\sophis trades.json"
            r = ses.sniff_root_candidates(pth)
            need(r.get("ok"), "sniff succeeds on a fake engine: %r" % r)
            fp = _squ.sql_path(pth)
            dq = next((q for q in CAPT if q.startswith("DESCRIBE")), None)
            need(dq is not None,
                 "stage1: no DESCRIBE captured; CAPT=%r" % CAPT[:4])
            need("read_json_auto('%s'" % fp in dq,
                 "the sniff QUOTES the path (was: syntax error at ':')")
            mp = next((c for c in r["candidates"] if c["map"]), None)
            need(mp is not None and mp.get("keys") == ["sophis"],
                 "map keys filled from the sample: %r" % mp)
        finally:
            ses.duckdb = None
            ses.shutdown()

        # (2) a stale sticky cancel must NOT abort a fresh flatten
        CAPT.clear()
        ses = _fresh()
        try:
            ses.duckdb._cancel.set()
            fr = ses.flatten_table("t", base="t")
            need(not fr.get("cancelled") and not fr.get("error"),
                 "fresh flatten survives a stale cancel flag: %r" % fr)
            need(not ses.duckdb._cancel.is_set(),
                 "the stale flag was cleared at entry")
        finally:
            ses.duckdb = None
            ses.shutdown()

        # (3) the SHRED path (the Load modal's real path) carries
        # root_id end-to-end and surfaces the stats on the item
        CAPT.clear()
        ses = _fresh()
        try:
            item = {"engine": "duckdb", "name": "t"}
            out = ses._shred_after_load(
                [item], root_id={"steps": ["identifier"], "map": True,
                                 "map_key": "sophis"})
            need(out and out[0].get("shredded"),
                 "shred path flattened: %r" % out)
            st = out[0].get("root_id_stats")
            need(st and st["master_table"].startswith("Master_Keys"),
                 "uniqueness stats surfaced on the item: %r" % st)
            hubq = next((q for q in CAPT if q.startswith("CREATE")
                         and "_flattened" in q), None)
            need(hubq is not None,
                 "stage3: no hub CREATE; out=%r CAPT=%r"
                 % (out, [q[:70] for q in CAPT][:8]))
            need("map_extract(" in hubq and 'AS "root_id"' in hubq,
                 "the shred-path hub carries root_id")
        finally:
            ses.duckdb = None
            ses.shutdown()

        # frags: the plumbing + the launcher class-icon stamp
        ss = open(os.path.join(BACKEND, "samql_core", "session.py"),
                  encoding="utf-8").read()
        for frag, why in (
            ("mgr = self.get_duckdb()", "sniff uses the lazy getter"),
            ("read_json_auto('%s', sample_size = 2048)",
             "sniff path is quoted"),
            ("_shred_after_load(loaded, root_id=root_id)",
             "load_file threads root_id into the shred path"),
            ("flatten_table(table, base=table, root_id=root_id)",
             "the shred hook forwards it"),
            ('item["root_id_stats"] = r["root_id"]',
             "the item surfaces the uniqueness verdict"),
        ):
            need(frag in ss, "session: %s" % why)
        la = open(os.path.join(BACKEND, "launcher_app.py"),
                  encoding="utf-8").read()
        need("GCLP_HICON, GCLP_HICONSM = -14, -34" in la
             and '"SetClassLongPtrW"' in la
             and "class icon set (GCLP)" in la,
             "launcher stamps the WinForms CLASS icon too")

    
    def t_nuclear_reset_523():
        # .523: the Activity-modal Reset server button is a KILL SWITCH.
        # Backend: every query/load/op interrupted, both engines orphaned
        # (fresh empty SQLite now, DuckDB rebuilt lazily like startup),
        # results + temps + family + restore manifest all destroyed --
        # launch-empty state. Frontend: hard page reload, fired even if
        # the request hangs. Nothing survives on either side.
        import tempfile as _tf
        from samql_core.session import Session
        CALLS = []

        class _Duck:
            def __init__(s2):
                s2._cancel = threading.Event()

            def interrupt(s2):
                CALLS.append("duck.interrupt")

            def recycle(s2):
                CALLS.append("duck.recycle")

        class _Store:
            def close(s2):
                CALLS.append("store.close")

        class _CR:
            store = _Store()

        class _Man:
            def __init__(s2):
                s2.entries = [1, 2, 3]

            def all(s2):
                return list(s2.entries)

            def clear(s2):
                CALLS.append("manifest.clear")
                s2.entries = []

        ses = Session()
        try:
            old_db = ses.db
            ses.duckdb = _Duck()
            ses.manifest = _Man()
            ses._results["r1"] = _CR()
            tf = _tf.mktemp(suffix=".tmp")
            open(tf, "w").write("x")
            ses.temp_files.append(tf)
            ses._table_family["a"] = "b"
            ses._running["q1"] = object()
            ses.cancel_query = lambda qid: CALLS.append("cancel:" + qid)
            ses._restore_started = True
            r = ses.nuclear_reset()
            need(r.get("ok") and r["nuked"]["queries"] == 1
                 and r["nuked"]["results"] == 1
                 and r["nuked"]["temps"] == 1
                 and r["nuked"]["tables_forgotten"] == 3,
                 "nuke stats: %r" % r)
            need(ses.duckdb is None,
                 "DuckDB left None: the first-use block builds a fresh "
                 "engine exactly like startup")
            need(ses.db is not old_db, "SQLite replaced with a fresh one")
            need(not ses._results and not ses._table_family
                 and not ses._running, "runtime dicts empty")
            need(not os.path.exists(tf) and not ses.temp_files,
                 "session temps destroyed")
            need(ses._restore_started is False, "restore flag reset")
            for c in ("cancel:q1", "duck.interrupt", "duck.recycle",
                      "store.close", "manifest.clear"):
                need(c in CALLS, "kill step ran: %s (%r)" % (c, CALLS))
            need(CALLS.index("cancel:q1")
                 < CALLS.index("duck.recycle"),
                 "queries cancelled before the engine is orphaned")
        finally:
            ses.duckdb = None
            ses.shutdown()

        # manifest.clear persists launch-empty (real store, temp home)
        from samql_core.stores import LoadManifestStore
        need(hasattr(LoadManifestStore, "clear"),
             "manifest store has the nuclear clear()")

        # server: the endpoint kills + forgets every job, empties the
        # error dashboard, and delegates to nuclear_reset
        srv = open(os.path.join(BACKEND, "server.py"),
                   encoding="utf-8").read()
        need('r"^/api/nuke$"' in srv, "server: route registered")
        need("def nuke(s, m, body, ctx):" in srv,
             "server: handler present")
        _h = srv.split("def nuke(s, m, body, ctx):", 1)[1][:1600]
        for frag, why in (
            ('j["cancel"] = True', "every load job flagged"),
            ("JOBS.clear()", "jobs forgotten"),
            ("_ERROR_LOG.clear()", "error dashboard emptied"),
            ("s.nuclear_reset()", "session teardown delegated"),
        ):
            need(frag in _h, "server: %s" % why)

        # frontend: the shared hook nukes then HARD-RELOADS -- even on a
        # hung request -- and the modal button says so
        sh = open(os.path.join(FRONTEND, "src", "components",
                               "ActivityShared.tsx"),
                  encoding="utf-8").read()
        for frag, why in (
            ("NUCLEAR RESET — nothing survives.", "confirm says it plain"),
            ("api.nuke().then(boom, boom)", "reload on success AND error"),
            ("window.setTimeout(boom, 4000)", "reload even if it hangs"),
            ("window.location.reload()", "hard reload = frontend restart"),
            ("abortInflight()", "in-flight requests aborted"),
            ("cancelAllBgOps()", "background ops cancelled"),
        ):
            need(frag in sh, "hook: %s" % why)
        # .524: the confirmation is IN-APP (two-step arm; no native
        # dialog dependency), and the nuke wipes the JOURNAL + NODEFLOW
        # working state (including legacy Nodebook keys) before the reload.
        hook = sh.split("export function useEngineReset", 1)[1]
        need("window.confirm(" not in hook,
             "no native confirm CALL -- the button arms in-app instead")
        need("const [armed, setArmed] = useState(false)" in hook
             and "window.setTimeout(disarm, 6000)" in hook
             and "Click the button again to confirm." in hook
             and "softResetEngines" in hook
             and ".engineReset()" in hook
             and "resetMode" in hook,
             "two-step arm + soft engineReset path")
        need('const NUKE_PREFIXES = ["samql.nb.", "samql.notebook.", '
             '"samql.nodebook.", "samql.nodeflow."];' in sh,
             "journal + NodeFlow + legacy working-state prefixes die")
        need("window.sessionStorage.clear()" in sh,
             "sessionStorage cleared wholesale")
        _boom = hook.split("const boom = () => {", 1)[1]
        need(_boom.index("purgeWorkingState()")
             < _boom.index("window.location.reload()"),
             "working state purged BEFORE the reload")
        need('"Click again to confirm"' in sh,
             "the dashboard button shows the armed step")
        am2 = open(os.path.join(FRONTEND, "src", "components",
                                "ActivityModal.tsx"),
                   encoding="utf-8").read()
        need('"Reset server"' in am2 and '"Nuking…"' in am2
             and '"Click again to confirm"' in am2
             and '"Reset engines"' in am2
             and "softResetEngines" in am2,
             "modal buttons: Reset engines + Reset server / armed / Nuking…")
        at = open(os.path.join(FRONTEND, "src", "lib", "api.ts"),
                  encoding="utf-8").read()
        need('"/api/nuke"' in at, "api.nuke wired")
        need('"/api/engine/reset"' in at and "engineReset:" in at,
             "api.engineReset wired for soft recovery")

    
    def t_root_id_audit_522():
        # .522: correctness audit of the .521 unique-identifier feature.
        # (1) ZIP-SAFE u0: the e0-flavoured expression is rendered against
        # the unnest EXPRESSION, not the same-SELECT alias (lateral column
        # aliases are version-fragile; multiple unnests of one list zip
        # positionally by contract). (2) Every candidate shape renders and
        # validates: map-in-list, first-element lists, deep collisions in
        # CHILD tables. (3) Non-promoted deep subtrees get the t0 flavour.
        # (4) The picker shows a spinner while the schema sniff runs.
        import contextlib
        from samql_core.shred import (
            root_id_candidates, render_root_expr, validate_root_choice,
            plan_shred, build_table_sql)
        from samql_core.diagnostics import parse_duckdb_type as P

        cols = [("json", P(
            'STRUCT(code BIGINT, identifier MAP(VARCHAR, JSON), '
            'legs STRUCT(rate DOUBLE, m MAP(VARCHAR, VARCHAR))[], '
            'qty DOUBLE[])[]'))]
        pl = plan_shred("json", cols[0][1], base="f", root_ord="json_ord",
                        children_use_base=False)

        # zip-safe substitution -- scalar and map flavours; t0 untouched
        rex = render_root_expr({"steps": ["code"], "map": False}, "e0")
        q = build_table_sql(dict(next(t for t in pl["tables"]
                                      if t["name"] == "legs_flattened"),
                                 root_expr=rex), "json", "C:/c.pq")
        u0 = q.split("n0 AS")[0]
        need('unnest(t0.json)."code" AS "root_id"' in u0
             and 'e0."code"' not in u0, "u0 substitutes the unnest expr")
        need(q.count('"root_id"') >= 3, "still carried + emitted")
        mrex = render_root_expr({"steps": ["identifier"], "map": True},
                                "e0", map_key="sophis")
        qh = build_table_sql(dict(next(t for t in pl["tables"]
                                       if t["name"] == "f_flattened"),
                                  root_expr=mrex), "json", "C:/c.pq")
        need('map_extract(unnest(t0.json)."identifier"' in qh,
             "map flavour substitutes too")
        trex = render_root_expr({"steps": ["code"], "map": False}, "t0")
        qt = build_table_sql(dict(next(t for t in pl["tables"]
                                       if t["name"] == "legs_flattened"),
                                  root_expr=trex), "json", "C:/c.pq")
        need('t0."code" AS "root_id"' in qt.split("n0 AS")[0],
             "t0 flavour passes through untouched")

        # every candidate shape: map-in-list offered, rendered, validated
        cands = root_id_candidates(cols, promote_col="json")
        mil = next(c for c in cands if c["map"] and c["in_list"] == ["legs"])
        need(mil["steps"] == ["m"], "map-in-list candidate offered")
        need(render_root_expr(mil, "t0", map_key="k")
             == "CAST(map_extract(t0.\"legs\"[1].\"m\", 'k')[1] "
                "AS VARCHAR)", "map-in-list renders through the [1] hop")
        vc = validate_root_choice(cols, "json",
                                  {"steps": ["m"], "in_list": ["legs"],
                                   "map": True, "map_key": "k"})
        need(bool(vc) and vc["map_key"] == "k",
             "validator round-trips map-in-list")

        # a list of SCALARS still carries the identifier next to value
        qs = build_table_sql(dict(next(t for t in pl["tables"]
                                       if t["name"] == "qty_flattened"),
                                  root_expr=rex), "json", "C:/c.pq")
        need('"root_id"' in qs and 'AS "value"' in qs,
             "elem-scalar child carries root_id")

        # a CHILD element field named root_id: ours wins, theirs _1
        cols2 = [("json", P('STRUCT(code VARCHAR, '
                            'legs STRUCT(root_id BIGINT, r DOUBLE)[])[]'))]
        pl2 = plan_shred("json", cols2[0][1], base="f",
                         root_ord="json_ord", children_use_base=False)
        ql = build_table_sql(dict(next(t for t in pl2["tables"]
                                       if t["name"] == "legs_flattened"),
                                  root_expr=render_root_expr(
                                      {"steps": ["code"], "map": False},
                                      "e0")), "json", "C:/c.pq")
        need("AS root_id_1" in ql and ql.count('AS "root_id"') == 1,
             "deep CHILD collision renamed root_id_1")

        # non-promoted deep subtree gets the t0 flavour (session level)
        from samql_core.session import Session
        CAPT = []

        class _Cur:
            description = [("ok",)]

            def execute(self, q2, *a):
                return self

            def fetchall(self):
                return [(0,)]

            def fetchone(self):
                return (0,)

        class _Mgr:
            def __init__(s2):
                s2.table_columns = {"t": ["id", "deep"]}
                s2.table_sources = {}
                s2.write_lock = threading.RLock()
                s2._cancel = threading.Event()
                s2.conn = _Cur()

            def _column_types_raw(s2, t2):
                return {"id": "BIGINT",
                        "deep": "STRUCT(a BIGINT, "
                                "kids STRUCT(b BIGINT)[])[]"}

            def execute(s2, q2):
                CAPT.append(q2)
                if "COUNT(" in q2:
                    return ([], [(10, 10, 10)])
                return ([], [])

            def sync_catalog(s2):
                pass

            def native_op_cursor(s2):
                @contextlib.contextmanager
                def cm():
                    yield _Cur(), threading.RLock()
                return cm()

        ses = Session()
        ses.duckdb = _Mgr()
        try:
            r = ses.flatten_table("t", base="t",
                                  root_id={"steps": ["id"], "map": False})
            need(not r.get("error"), "non-promote flatten ok: %r" % r)
            deepc = [q2 for q2 in CAPT if q2.startswith("CREATE")
                     and "u0 AS" in q2]
            need(deepc and all('t0."id" AS "root_id"' in q2
                               for q2 in deepc),
                 "non-promoted deep subtrees use the t0 flavour")
            need(any("Master_Keys" in q2 for q2 in CAPT
                     if q2.startswith("CREATE")), "Master_Keys created")
            need(any("Join_Keys" in q2 for q2 in CAPT
                     if q2.startswith("CREATE")), "Join_Keys created")
            need(r["root_id"].get("join_table") == "Join_Keys",
                 "stats name Join_Keys on first flatten")
            # re-flatten: the family sweep frees Master_Keys + Join_Keys;
            # the second run succeeds and recreates them under the same names
            CAPT.clear()
            r2 = ses.flatten_table("t", base="t",
                                   root_id={"steps": ["id"],
                                            "map": False})
            need(not r2.get("error")
                 and r2["root_id"]["master_table"] == "Master_Keys"
                 and r2["root_id"].get("join_table") == "Join_Keys",
                 "re-flatten frees + recreates Master_Keys + Join_Keys")
        finally:
            ses.duckdb = None
            ses.shutdown()

        # sniff plumbing: the key-fill wraps in_list maps too; the picker
        # spins while the sniff runs
        ss = open(os.path.join(BACKEND, "samql_core", "session.py"),
                  encoding="utf-8").read()
        for frag in ("def _frm_and_alias", "AS eL", "map_keys(",
                     "LIMIT 40"):
            need(frag in ss, "key-fill frag: %s" % frag)
        pk = open(os.path.join(FRONTEND, "src", "components", "load",
                               "RootIdPicker.tsx"),
                  encoding="utf-8").read()
        need('className="spinner-sm"' in pk
             and "Scanning the schema" in pk,
             "picker shows a spinner during the sniff")

    def t_export_formats_522():
        # .522: the OUTPUT matrix, unified. Every surface (IDE result tabs,
        # journal cells, NodeFlow file-output nodes) offers csv / tsv /
        # json / ndjson (+ xlsx / parquet where the optional libs exist),
        # and both backend exporters implement all of them. The nodeflow
        # xlsx path gains the .451 formula-injection guard the result
        # exporter already had.
        import csv as _csv
        import json as _json
        import tempfile as _tf
        from samql_core.session import Session

        # writers: tsv delimiter + None handling
        tmp = _tf.mktemp(suffix=".tsv")
        Session._export_csv(tmp, ["a", "b c"],
                            [[1, None], ["x\ty", "q"]], delim="\t")
        rows = list(_csv.reader(open(tmp, encoding="utf-8"),
                                delimiter="\t"))
        need(rows[0] == ["a", "b c"] and rows[1] == ["1", ""]
             and rows[2] == ["x\ty", "q"], "tsv writer: %r" % rows)
        os.remove(tmp)

        # result export falls back to the streaming writers for tsv
        class _V:
            def __iter__(s2):
                return iter([[1, "a"], [2, None]])

        class _CR:
            cols = ["id", "name"]
            total = 2

            class store:
                pass

            def view(s2, sc, d):
                return _V()

        ses = Session.__new__(Session)
        ses._results = {"r1": _CR()}
        out = ses.export("r1", "tsv")
        need(out.get("ok"), "result tsv export: %r" % out)
        body = open(out["path"], encoding="utf-8").read()
        need("id\tname" in body and "2\t" in body, "tsv body")
        os.remove(out["path"])

        # nodeflow streamer, DuckDB fast path: ONE COPY per format
        CAP = []

        class _Conn:
            def execute(s2, q):
                CAP.append(q)
                return s2

            def fetchone(s2):
                return (7,)

        class _Duck:
            ENGINE_KIND = "duckdb"
            write_lock = threading.RLock()
            conn = _Conn()

        for fmt, frag in (("csv", "FORMAT CSV, HEADER"),
                          ("tsv", "DELIMITER '\t'"),
                          ("json", "FORMAT JSON, ARRAY true"),
                          ("ndjson", "FORMAT JSON")):
            CAP.clear()
            n = ses._stream_relation_to_file(
                _Duck(), 'SELECT * FROM "t"', "/tmp/o." + fmt, fmt)
            need(n == 7 and CAP and CAP[0].startswith("COPY (")
                 and frag in CAP[0],
                 "duck fast path %s: %r" % (fmt, CAP))
            if fmt == "ndjson":
                need("ARRAY" not in CAP[0], "ndjson is line-delimited")

        # generic-engine fallback: csv / ndjson / json write real files
        class _Cur2:
            def __init__(s2):
                s2.done = False

            def fetchmany(s2, b):
                if s2.done:
                    return []
                s2.done = True
                return [[2, "y"]]

            def close(s2):
                pass

        class _Gen:
            ENGINE_KIND = "sqlite"

            def execute_cursor(s2, sql, batch=10000):
                return (["a", "b"], [[1, "x"]], _Cur2())

        for fmt in ("csv", "ndjson", "json"):
            pth = _tf.mktemp(suffix="." + fmt)
            n = ses._stream_relation_to_file(_Gen(), "S", pth, fmt)
            t = open(pth, encoding="utf-8-sig").read()
            if fmt == "ndjson":
                lines = [_json.loads(l) for l in t.strip().splitlines()]
                need(n == 2 and lines == [{"a": 1, "b": "x"},
                                          {"a": 2, "b": "y"}],
                     "ndjson fallback: %r" % lines)
            elif fmt == "json":
                need(_json.loads(t) == [{"a": 1, "b": "x"},
                                        {"a": 2, "b": "y"}],
                     "json fallback")
            else:
                need(t.splitlines()[0] == "a,b", "csv fallback header")
            os.remove(pth)

        # xlsx: with openpyxl present the formula-injection guard holds on
        # BOTH exporters; absent, the error is clear. parquet mirrors it.
        try:
            import openpyxl
            _oxl = True
        except Exception:
            _oxl = False
        if _oxl:
            class _GenF:
                ENGINE_KIND = "sqlite"

                def execute_cursor(s2, sql, batch=10000):
                    return (["f"], [["=2+2"]], _Cur2())

            pth = _tf.mktemp(suffix=".xlsx")
            ses._stream_relation_to_file(_GenF(), "S", pth, "xlsx")
            ws = openpyxl.load_workbook(pth)["data"]
            c = ws.cell(row=2, column=1)
            need(c.value == "=2+2" and c.data_type == "s",
                 "nodeflow xlsx keeps '=' TEXT (injection guard): %r"
                 % ((c.value, c.data_type),))
            os.remove(pth)

            class _V2:
                def __iter__(s2):
                    return iter([["=2+2", None]])

            pth2 = _tf.mktemp(suffix=".xlsx")
            Session._export_xlsx(pth2, ["f", "g"], _V2())
            c2 = openpyxl.load_workbook(pth2)["results"].cell(
                row=2, column=1)
            need(c2.value == "=2+2" and c2.data_type == "s",
                 "result xlsx guard intact")
            os.remove(pth2)
        else:
            try:
                ses._stream_relation_to_file(_Gen(), "S", "/tmp/o.xlsx",
                                             "xlsx")
                need(False, "xlsx without openpyxl must raise")
            except RuntimeError as e:
                need("openpyxl" in str(e), "clear xlsx error")
        try:
            import pyarrow  # noqa: F401
        except Exception:
            try:
                ses._stream_relation_to_file(_Gen(), "S",
                                             "/tmp/o.parquet", "parquet")
                need(False, "parquet without pyarrow must raise")
            except RuntimeError as e:
                need("pyarrow" in str(e), "clear parquet error")

        # nodeflow validation: ndjson is accepted; the rejection message
        # names the full list; the folder gate still comes first
        r = ses.export_nodeflow({}, "n1", "/definitely/missing",
                                fmt="ndjson")
        need(r.get("error") == "Pick an output folder.",
             "folder gate first (ndjson passed the format gate)")
        r = ses.export_nodeflow({}, "n1", _tf.gettempdir(), fmt="bmp")
        need("NDJSON" in (r.get("error") or ""),
             "format message names NDJSON: %r" % r)

        # frags: server ctypes + all three surface menus + both source
        # format lists
        ss = open(os.path.join(BACKEND, "samql_core", "session.py"),
                  encoding="utf-8").read()
        need(ss.count('"ndjson", "xlsx"') >= 1
             and '"tsv": "FORMAT CSV, HEADER, DELIMITER' in ss,
             "session format lists include ndjson + tsv COPY opts")
        srv = open(os.path.join(BACKEND, "server.py"),
                   encoding="utf-8").read()
        need('"tsv": "text/tab-separated-values"' in srv,
             "server ctypes: tsv")
        app = open(os.path.join(FRONTEND, "src", "App.tsx"),
                   encoding="utf-8").read()
        ref = open(os.path.join(FRONTEND, "src", "lib",
                                "resultExportFormats.ts"),
                   encoding="utf-8").read()
        need('["tsv", "TSV"]' in ref and '["ndjson", "NDJSON"]' in ref,
             "shared export formats: tsv + ndjson")
        need('"parquet"' in ref and "features?.pyarrow" in ref
             and "features?.openpyxl" in ref,
             "shared export formats: parquet/xlsx gated on features")
        need("exportFormatsForResultTab" in app
             and "ExportResultsMenuItems" in app,
             "IDE Output menu consumes shared export formats")
        nc = open(os.path.join(FRONTEND, "src", "components",
                               "notebook", "SqlNotebookCell.tsx"),
                  encoding="utf-8").read()
        need("backendResultExportFormats" in nc
             and "backendResultExportFormats(props.features)" in nc,
             "journal menu uses shared export formats + feature gates")
        nb = _nodeflow_source()
        need('"csv", "tsv", "json", "ndjson", "xlsx", "parquet"' in nb,
             "NodeFlow DATA_FORMATS unified")

    
    def t_shred_audit_520():
        # .520: full shredder audit. Six findings, all fixed and pinned:
        #  S1 the deep hub carried only the FIRST FIVE non-JSON scalars --
        #     under .518 (no base table) every other record column was
        #     silently LOST from the family. The hub now carries EVERY
        #     depth-1 scalar the root would have.
        #  S2 planner uniqueness was case-sensitive; DuckDB's catalog is
        #     not, so a live "LEGS" collided with a planned "legs".
        #  S3 the hub SQL had no output-collision renaming -- a record
        #     field literally named "_sk"/"json_ord" collided with the
        #     key columns.
        #  S4 a wrapper table's _parent_sk dropped the ordinal (keys[:-1]),
        #     so the one-line surrogate join to the hub matched NOTHING.
        #  S5 the shallow planner's hub was keys-only, one PER list, and
        #     skipped entirely for a slim base -- so a scalars+list file
        #     had NO hub (children parented to a ghost) and lost every
        #     scalar. It is now ONE records hub, always, carrying the old
        #     base payload with _sk = the record's _rid.
        #  S6 a jsonside 1:1 table had no _parent_sk, breaking the shared
        #     join rule for blob side tables.
        from samql_core.shred import (plan_shred as _ps0,
                                      build_table_sql as _bt0,
                                      plan_flatten_table as _pf0,
                                      build_flatten_sql as _bf0)
        from samql_core.diagnostics import parse_duckdb_type as _P0
        # S1
        n1 = _P0("STRUCT(code BIGINT, currency VARCHAR, name VARCHAR, "
                 "settlement VARCHAR, isin VARCHAR, ric VARCHAR, "
                 "notional DOUBLE, meta JSON, legs STRUCT(r DOUBLE)[])[]")
        p1 = _ps0("json", n1, base="f", root_ord="json_ord",
                  children_use_base=False)
        hub1 = next(t for t in p1["tables"] if t["name"] == "f_flattened")
        eq(hub1["fields"], p1["tables"][0]["fields"],
           "the hub carries EVERY record scalar (no 5-cap, JSON kept)")
        # S2
        n2 = _P0("STRUCT(code BIGINT, legs STRUCT(r DOUBLE)[])[]")
        p2 = _ps0("json", n2, base="f", root_ord="json_ord",
                  children_use_base=False, reserved={"LEGS_FLATTENED"})
        need(any(t["name"] == "legs_flattened_2" for t in p2["tables"]),
             "a live LEGS_FLATTENED blocks planned legs_flattened")
        # S3
        n3 = _P0('STRUCT("_sk" VARCHAR, "json_ord" BIGINT, code BIGINT, '
                 "legs STRUCT(r DOUBLE)[])[]")
        p3 = _ps0("json", n3, base="f", root_ord="json_ord",
                  children_use_base=False)
        hub3 = next(t for t in p3["tables"] if t["name"] == "f_flattened")
        s3 = _bt0(hub3, "json", "C:/c.pq")
        need(" AS _sk_1" in s3 and " AS json_ord_1" in s3,
             "record fields colliding with key columns get _1 suffixes "
             "in the hub SQL")
        # S4
        n4 = _P0("STRUCT(code BIGINT, identifier STRUCT(sophis VARCHAR, "
                 "opt VARCHAR), legs STRUCT(r DOUBLE)[])[]")
        p4 = _ps0("json", n4, base="f", root_ord="json_ord",
                  children_use_base=False)
        w4 = next(t for t in p4["tables"]
                  if t.get("wrapper_field") == "identifier")
        s4 = _bt0(w4, "json", "C:/c.pq")
        l4 = [l for l in s4.splitlines() if "_parent_sk" in l][0]
        need("json_ord" in l4,
             "a wrapper's _parent_sk is the FULL-key concat (== hub._sk)")
        # S5
        cols = [("id", _P0("BIGINT")), ("name", _P0("VARCHAR")),
                ("fees", _P0("STRUCT(amt DOUBLE)[]")),
                ("tags", _P0("VARCHAR[]"))]
        pf = _pf0(cols, base="t")
        hubs = [t for t in pf["tables"] if t["kind"] == "joinkeys"]
        need(len(hubs) == 1 and hubs[0]["name"] == "t_flattened"
             and hubs[0]["scalars"] == ["id", "name"]
             and pf["tables"][1]["kind"] == "joinkeys",
             "ONE records hub, always, right after the base spec")
        hs = _bf0(hubs[0], '"t"', "t0.rowid")
        need('t0."id"' in hs and 't0."name"' in hs and '"_rid"' in hs,
             "the shallow hub SQL carries the record payload")
        cols3 = [("id", _P0("BIGINT")),
                 ("fees", _P0("STRUCT(amt DOUBLE)[]")),
                 ("legs", _P0("STRUCT(r DOUBLE)[]"))]
        pf3 = _pf0(cols3, base="t")
        need(len([t for t in pf3["tables"]
                  if t["kind"] == "joinkeys"]) == 1,
             "multi-list files get ONE hub too (no per-list key tables)")
        ls = _bf0(next(t for t in pf3["tables"] if t["kind"] == "list"),
                  '"t"', "t0.rowid")
        need("concat_ws('/', CAST(t0.rowid AS VARCHAR)) AS \"_parent_sk\""
             in ls,
             "child._parent_sk is the rid-concat -- exactly the hub's _sk")
        # S6
        cols2 = [("id", _P0("BIGINT")), ("blob", _P0("JSON")),
                 ("fees", _P0("STRUCT(amt DOUBLE)[]"))]
        pf2 = _pf0(cols2, base="t")
        js = next(t for t in pf2["tables"] if t["kind"] == "jsonside")
        need("_parent_sk" in _bf0(js, '"t"', "t0.rowid"),
             "a jsonside 1:1 table joins one-line too")
        # session-level: a slim shallow family (scalars + list) anchors at
        # the hub -- the exact shape that had NO anchor before
        import threading as _tS, contextlib as _cS

        class _CurS:
            description = [("ok",)]
            def execute(self, q, *a): return self
            def fetchall(self): return [(0,)]
            def fetchone(self): return (0,)

        class _MgrS:
            def __init__(self):
                self.table_columns = {"t": ["id", "name", "fees"]}
                self.table_sources = {}
                self.write_lock = _tS.RLock()
                self._cancel = _tS.Event()
                self.conn = _CurS()
                self.dropped = []
            def _column_types_raw(self, t):
                return {"id": "BIGINT", "name": "VARCHAR",
                        "fees": "STRUCT(amt DOUBLE)[]"}
            def execute(self, q): return ([], [])
            def sync_catalog(self): pass
            def native_op_cursor(self):
                @_cS.contextmanager
                def cm(): yield _CurS(), _tS.RLock()
                return cm()
        from samql_core.session import Session as _SS
        _orig = _SS._drop_named
        def _spy(self, mgr, names):
            getattr(mgr, "dropped", []).extend(names)
            return _orig(self, mgr, names)
        _SS._drop_named = _spy
        _sS = _SS(); _sS.duckdb = _MgrS()
        try:
            r = _sS.flatten_table("t", base="t")
            names = [c["name"] for c in r.get("created", [])]
            need(not r.get("error") and names
                 and names[0] == "t_flattened" and "t" not in names,
                 "slim shallow family: hub anchors, no base: %r" % names)
            need(_sS._table_family.get("fees_flattened") == "t_flattened"
                 and "t" in _sS.duckdb.dropped,
                 "children parent to the REAL hub; the source is dropped")
        finally:
            _SS._drop_named = _orig
            _sS.duckdb = None
            _sS.shutdown()

    def t_shredder_audit_520():
        # .520 AUDIT: an adversarial battery over the shredder -- hostile
        # names, system-column collisions, wrapper-hidden lists, map value
        # shapes -- with the two real findings FIXED: (1) the sanitizer was
        # ASCII-only, so a non-latin table name collapsed to "x" (order-
        # dependent collisions); (2) a MAP with all-scalar STRUCT values
        # dumped whole structs into one "value" cell -- nested json again.
        from samql_core.shred import (plan_shred as _psA,
                                      build_table_sql as _btA,
                                      _sanitize as _saA)
        from samql_core.diagnostics import parse_duckdb_type as _PA2

        def _plan(typ):
            return _psA("json", _PA2(typ), base="f", root_ord="json_ord",
                        children_use_base=False)
        # 1) unicode survives as a real table name
        pl = _plan('STRUCT(code BIGINT, "税率" STRUCT(r DOUBLE)[])[]')
        tz = next((t for t in pl["tables"] if t["name"] == "税率_flattened"), None)
        need(tz is not None, "a non-latin list keeps its name: %r"
             % [t["name"] for t in pl["tables"]])
        need(tz["keys"][-1] == "税率_ord", "and its ordinal follows it")
        # 2) pure-symbol names: deterministic, distinct, stable
        a, b = _saA("§±"), _saA("%%")
        eq((a, _saA("§±")), (a, a), "symbol-name fallback is stable")
        need(a != b and a.startswith("c_") and b.startswith("c_"),
             "two symbol columns never collide: %r %r" % (a, b))
        # 3) a record field literally named _sk: the SYSTEM column wins
        pl = _plan("STRUCT(_sk BIGINT, code VARCHAR, "
                   "legs STRUCT(r DOUBLE)[])[]")
        hub = next(t for t in pl["tables"] if t["name"] == "f_flattened")
        q = _btA(hub, "json", "C:/c.pq")
        need("e0._sk AS _sk_1" in q,
             "the user's _sk field is alias-suffixed")
        eq(q.count('AS "_sk"'), 1, "exactly one system _sk is emitted")
        # 4) a field named after a sibling's ordinal: no duplicate aliases
        pl = _plan("STRUCT(code BIGINT, legs_ord VARCHAR, "
                   "legs STRUCT(r DOUBLE)[])[]")
        hub = next(t for t in pl["tables"] if t["name"] == "f_flattened")
        q = _btA(hub, "json", "C:/c.pq")
        import re as _reA
        cols = [c for c in
                _reA.findall(r"AS ((?:\"[^\"]+\")|(?:[A-Za-z_][\w]*))",
                             q.rsplit("SELECT", 1)[1])
                if c != "VARCHAR"]
        eq(len(cols), len(set(cols)),
           "hub output aliases are unique: %r" % cols)
        # 5+6) a wrapper hiding a LIST is planned and chained; a wrapper's
        # _parent_sk is the FULL element key (== hub._sk)
        pl = _plan("STRUCT(code BIGINT, pricing STRUCT(ctx VARCHAR, "
                   "curves STRUCT(x DOUBLE)[]))[]")
        pc = next(t for t in pl["tables"]
                  if t["name"] == "pricing_curves_flattened")
        eq(pc["keys"], ["_rid", "json_ord", "pricing_curves_ord"],
           "the hidden list gets the full compound key")
        q = _btA(pc, "json", "C:/c.pq")
        need("e0.pricing.curves AS _l1" in q
             and "WHERE e0.pricing.curves IS NOT NULL" in q,
             "the chain guards NULL wrappers before unnesting")
        wr = next(t for t in pl["tables"]
                  if t.get("wrapper_field") == "pricing")
        wq = _btA(wr, "json", "C:/c.pq")
        _psk = wq.split('AS "_parent_sk"', 1)[0].rsplit("concat_ws", 1)[1]
        need("json_ord" in _psk,
             "a wrapper's _parent_sk carries the FULL key (joins to the "
             "hub row 1:1)")
        # 7) MAP of an all-scalar STRUCT explodes into real columns
        pl = _plan("STRUCT(code BIGINT, identifier MAP(VARCHAR, "
                   "STRUCT(v VARCHAR, src VARCHAR)))[]")
        mi = next(t for t in pl["tables"]
                  if t["name"] == "identifier_flattened")
        eq(mi["fields"], ["key", "v", "src"],
           "map values become (key, v, src) columns")
        q = _btA(mi, "json", "C:/c.pq")
        need("_mv[identifier_ord].v AS v" in q
             and "_mv[identifier_ord].src AS src" in q,
             "the value struct's leaves are selected relatively")
        # 8) any non-scalar member: the plain (key, value) shape is kept
        pl = _plan("STRUCT(code BIGINT, m MAP(VARCHAR, "
                   "STRUCT(v VARCHAR, deep STRUCT(a INT))))[]")
        eq(next(t for t in pl["tables"]
                if t["name"] == "m_flattened")["fields"], ["key", "value"],
           "a deep map value stays (key, value)")
        # 9) JSON-valued maps unchanged
        pl = _plan("STRUCT(code BIGINT, i MAP(VARCHAR, JSON))[]")
        eq(next(t for t in pl["tables"]
                if t["name"] == "i_flattened")["fields"], ["key", "value"],
           "a JSON map value stays (key, value)")
        # 10) list-of-list: pinned current shape (value holds the inner
        # list) so any future change is deliberate
        pl = _plan("STRUCT(code BIGINT, mat DOUBLE[][])[]")
        eq(next(t for t in pl["tables"]
                if t["name"] == "mat_flattened")["fields"], ["value"],
           "list-of-list keeps the inner list in value (documented)")
        # 11) embedded quotes are doubled on emission
        pl = _plan('STRUCT("we""ird" BIGINT, legs STRUCT(r DOUBLE)[])[]')
        hub = next(t for t in pl["tables"] if t["name"] == "f_flattened")
        need('e0."we""ird"' in _btA(hub, "json", "C:/c.pq"),
             "quoted-quote field names emit safely")

    def t_cancel_deep_audit_520():
        # .520 DEEP AUDIT of cancel: beyond the run response, a cancel now
        # reaches PAGE sends (grids scrolling a monster result), the Node
        # surface registers its runs, and the Run-all/load paths are pinned.
        rc = open(os.path.join(ROOT, "frontend", "src", "lib",
                               "runController.ts"), encoding="utf-8").read()
        need("Map<string, Set<AbortController>>" in rc,
             "the registry holds SETS (a run + its page fetches coexist)")
        need("ctrl?: AbortController,\n): void {" in rc
             and "if (ctrl) set.delete(ctrl);" in rc,
             "unregister removes one controller or all")
        need("for (const c of set) {" in rc,
             "cancelById aborts every registered controller")
        ap_ = open(os.path.join(ROOT, "frontend", "src", "lib", "api.ts"),
                   encoding="utf-8").read()
        need("query_id?: string; // .520" in ap_
             and ap_.count("signal?: AbortSignal,") >= 2,
             "api.page and nodeflowRun accept a query id / signal")
        sv = open(os.path.join(BACKEND, "server.py"),
                  encoding="utf-8").read()
        need('_q = b.get("query_id")\n        if _q:\n'
             '            _REQ_LOCAL.qid = _q' in sv,
             "a page request tags its sender thread -- the .514 chunk "
             "poller can abort a giant page's SEND")
        nb = open(os.path.join(ROOT, "frontend", "src", "components",
                               "Notebook.tsx"), encoding="utf-8").read()
        paging = open(os.path.join(ROOT, "frontend", "src", "lib",
                                   "usePagedResult.ts"),
                      encoding="utf-8").read()
        need("queryId, // .520" in nb
             and "query_id: item.queryId" in paging
             and "usePagedResult<RunCell>" in nb,
             "Journal cells remember their run id and page with it")
        need("if (cancelAllRef.current) return null;" in nb
             and "if (cancelAllRef.current) break;" in nb
             and "cancelAllRef.current = true;" in nb,
             "a Run-all Stop halts both dependency work and the sweep")
        app = open(os.path.join(ROOT, "frontend", "src", "App.tsx"),
                   encoding="utf-8").read()
        result_ctl = open(os.path.join(ROOT, "frontend", "src", "controllers",
                                       "useResultController.ts"),
                          encoding="utf-8").read()
        need("useResultController" in app
             and "usePagedResult<ResultTab>" in result_ctl
             and "query_id: item.queryId" in paging,
             "IDE grid pages (sort/lazy/filter) carry the run id")
        ndb = _nodeflow_source()
        need(ndb.count("registerRun(id, ctrl)") >= 2
             and ndb.count("ctrl.signal") >= 2
             and ndb.count("isCancelledError(e, id)") >= 2,
             "Node runs register, pass a signal, and classify by id")
        need("Scoped interrupt" in sv and 'job["cancel"] = True' in sv,
             "load cancel: flag + engine interrupt only for the slot "
             "owner (pinned)")

    def t_cancel_pipeline_audit_519():
        # .519 AUDIT: the Activity-modal Cancel must stop a run END TO END
        # -- frontend fetch AND every backend stage -- and the aftermath
        # must read as Cancelled, never as a red "Failed to fetch".
        rc = open(os.path.join(ROOT, "frontend", "src", "lib",
                               "runController.ts"), encoding="utf-8").read()
        for frag, why in (
            ("export function registerRun(", "surfaces register their run"),
            ("export function cancelById(", "one call cancels end to end"),
            ("export function wasCancelled(", "cancel intent is remembered"),
            ("isCancelledError(e: any, queryId?: string | null)",
             "the classifier is query-id aware"),
        ):
            need(frag in rc, "runController: " + why)
        need("markCancelled(queryId)" in rc
             and "abortRegistered(queryId)" in rc
             and "api.cancelQuery(queryId)" in rc,
             "cancelOne records intent, aborts every registered fetch, "
             "and interrupts the backend")
        ap = open(os.path.join(ROOT, "frontend", "src", "App.tsx"),
                  encoding="utf-8").read()
        need("registerRun(queryId, ctrl);" in ap
             and "unregisterRun(queryId);" in ap,
             "the IDE run is registered for modal cancel")
        need("isCancelledError(e, queryId)" in ap,
             "an IDE fetch failure after a cancel reads as cancelled")
        need("if (network && !_retry && !wasCancelled(queryId))" in ap,
             "a cancelled run is NEVER auto-retried")
        nb = open(os.path.join(ROOT, "frontend", "src", "components",
                               "Notebook.tsx"), encoding="utf-8").read()
        need("registerRun(queryId, ctrl);" in nb
             and "unregisterRun(queryId);" in nb
             and "isCancelledError(e, queryId)" in nb,
             "Journal cells register + classify by query id too")
        am = open(os.path.join(ROOT, "frontend", "src", "components",
                               "ActivityModal.tsx"), encoding="utf-8").read()
        need("cancelById(id);" in am,
             "the modal Cancel goes through the registry (frontend + "
             "backend in one call)")
        # backend: every stage a run passes through is cancellable
        sv = open(os.path.join(BACKEND, "server.py"),
                  encoding="utf-8").read()
        ss = open(os.path.join(BACKEND, "samql_core", "session.py"),
                  encoding="utf-8").read()
        eg = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                  encoding="utf-8").read()
        ld = open(os.path.join(BACKEND, "samql_core", "loaders.py"),
                  encoding="utf-8").read()
        for frag, where, why in (
            ("def cancel_query(self, query_id", ss,
             "stage 0: the cancel entry point exists"),
            ("class _ReadCursorHandle", ss,
             "stage 1: own-cursor reads are interrupt targets"),
            ("cancel=self._cancel)", eg,
             "stage 2: the row FETCH polls the cancel flag"),
            ("raw, cell_capped = _cap_page_rows(raw)", ss,
             "stage 3: page conversion is bounded (cap before convert)"),
            ("def _send_cancelled():", sv,
             "stage 4: the response SEND aborts on cancel"),
            ('return {"error": "cancelled", "cancelled": True}', ss,
             "a caught cancel returns a CLEAN envelope"),
            ('r"^/api/load/cancel/', sv,
             "loads: the cancel route exists"),
            ("LoadCancelled", ld,
             "loads: the loaders honor the cancel"),
        ):
            need(frag in where, why)

    def t_appwindow_pywebview_main_519():
        # .519 AUDIT: SamQL-AppWindow's MAIN flow, end to end with a fake
        # pywebview -- reuses the running server, opens the native window,
        # never consults a browser, and the log names the renderer. Plus:
        # the bundled-icon resolver honors the frozen (_MEIPASS) layout, the
        # SERVER exe carries the icon + the same window branding, and the
        # spec ships the art into BOTH exes.
        import types as _tyB, threading as _tB, tempfile as _tfB
        import time as _tmB
        saved = {m: sys.modules.get(m) for m in
                 ("webview", "webview.platforms",
                  "webview.platforms.edgechromium",
                  "webview.platforms.winforms",
                  "clr", "System", "System.Drawing")}
        wv = _tyB.ModuleType("webview"); wv.__path__ = []
        wv.gui = None
        created = {}

        class _NB:
            Handle = "424242"

        class _WB:
            def __init__(self):
                self.events = _tyB.SimpleNamespace(shown=_tB.Event())
                self.events.shown.set()
                self.native = _NB()

        wv.create_window = lambda t, u, **k: created.setdefault(
            "win", (created.__setitem__("title", t), _WB())[1])

        def _startB(func=None, *a, **kw):
            wv.gui = "edgechromium"
            if func:
                func()
        wv.start = _startB
        sys.modules["webview"] = wv
        for m in ("webview.platforms", "webview.platforms.edgechromium",
                  "webview.platforms.winforms"):
            sys.modules[m] = _tyB.ModuleType(m)
        sys.modules["clr"] = _tyB.ModuleType("clr")
        sdB = _tyB.ModuleType("System.Drawing")
        sdB.Icon = lambda p: ("ICO", p)
        smB = _tyB.ModuleType("System"); smB.Drawing = sdB
        sys.modules["System"] = smB
        sys.modules["System.Drawing"] = sdB
        import launcher_app as _LA
        keep = {n: getattr(_LA, n) for n in
                ("write_log", "_bundled_asset", "set_app_user_model_id",
                 "apply_app_icon", "set_relaunch_icon",
                 "wait_for_app_window", "port_open", "_is_samql",
                 "stop_server", "find_browser", "make_splash")}
        logs = []
        browser_asks = []
        ico = _tfB.mktemp(suffix=".ico")
        open(ico, "wb").write(b"\x00\x00\x01\x00")
        try:
            _LA.write_log = lambda m: logs.append(m)
            _LA._bundled_asset = lambda name: ico
            _LA.set_app_user_model_id = lambda h, aumid="x": None
            _LA.apply_app_icon = lambda h, p: None
            _LA.set_relaunch_icon = lambda h, p: None
            _LA.wait_for_app_window = lambda *a, **k: None
            _LA.port_open = lambda p, **k: True
            _LA._is_samql = lambda p: True
            _LA.stop_server = lambda p: browser_asks.append("STOP?!")
            _LA.find_browser = lambda w: browser_asks.append(w) or None
            _LA.make_splash = lambda: _tyB.SimpleNamespace(
                set_text=lambda t: None, close=lambda: None,
                pump=lambda s=0: None)
            rc = _LA.main(["--port", "8765"])
            _tmB.sleep(0.3)
            eq(rc, 0, "the launcher exits clean via the native path")
            eq(created.get("title"), "SamQL",
               "a SamQL-titled pywebview window was created")
            eq(created["win"].native.Icon, ("ICO", ico),
               "the non-standard logo lands on the Form")
            need(browser_asks == [],
                 "a reused server + native window: no browser, no "
                 "stop_server: %r" % browser_asks)
            need(any("reusing the SamQL server already on port 8765" in l
                     for l in logs),
                 "reuse is identified and logged")
            need(any("native window closed (renderer=edgechromium)" in l
                     for l in logs),
                 "the renderer is logged by name")
        finally:
            for n, v in keep.items():
                setattr(_LA, n, v)
            for m, v in saved.items():
                if v is None:
                    sys.modules.pop(m, None)
                else:
                    sys.modules[m] = v
            try:
                os.remove(ico)
            except OSError:
                pass
        # the frozen-layout resolver: _MEIPASS wins when the art is there
        import tempfile as _tf2
        d = _tf2.mkdtemp()
        open(os.path.join(d, "samql.ico"), "wb").write(b"i")
        had = hasattr(sys, "_MEIPASS")
        old = getattr(sys, "_MEIPASS", None)
        try:
            sys._MEIPASS = d
            eq(keep["_bundled_asset"]("samql.ico"),
               os.path.join(d, "samql.ico"),
               "_bundled_asset resolves from the frozen _MEIPASS root")
        finally:
            if had:
                sys._MEIPASS = old
            else:
                del sys._MEIPASS
        # server-exe parity + the spec ships the art into BOTH exes
        sv = open(os.path.join(BACKEND, "server.py"),
                  encoding="utf-8").read()
        need("SetCurrentProcessExplicitAppUserModelID" in sv
             and sv.count("_set_srv_icon") >= 3
             and "def _srv_ico():" in sv,
             "SamQL.exe --window sets the process AUMID and lands the "
             "Form icon like the launcher")
        spec = open(os.path.join(BACKEND, "samql.spec"),
                    encoding="utf-8").read()
        need('datas.append((_ic, "."))' in spec,
             "the SERVER exe bundles samql.ico")
        need('la_datas.append((_cand, "."))' in spec
             or "la_datas.append((_ic" in spec
             or ("samql.ico" in spec
                 and spec.count("la_datas") >= 2),
             "the LAUNCHER exe bundles samql.ico")

    def t_no_root_family_contract_518():
        # .518 (on-box, repeatedly: SELECT * on the file name STILL served
        # nested json). The contract is now structural: the base data table
        # is NEVER created, the nested source under the base name is DROPPED,
        # and the family = <base>_flattened (record keys + record scalars,
        # same "_sk") plus the element-path children. Nothing answers to the
        # bare file name -- the whole failure class cannot exist.
        import threading as _t8, contextlib as _c8

        class _Cur8:
            description = [("ok",)]
            def execute(self, q, *a): return self
            def fetchall(self): return [(0,)]
            def fetchone(self): return (0,)

        class _Mgr8:
            def __init__(self):
                self.table_columns = {"t": ["json"]}
                self.table_sources = {}
                self.write_lock = _t8.RLock()
                self._cancel = _t8.Event()
                self.conn = _Cur8()
                self.dropped = []
            def _column_types_raw(self, t):
                return {"json": "STRUCT(code BIGINT, "
                                "identifier STRUCT(sophis VARCHAR), "
                                "legs STRUCT(r DOUBLE)[])[]"}
            def execute(self, q): return ([], [])
            def sync_catalog(self): pass
            def native_op_cursor(self):
                @_c8.contextmanager
                def cm(): yield _Cur8(), _t8.RLock()
                return cm()
        from samql_core.session import Session as _S8
        _orig = _S8._drop_named
        def _spy(self, mgr, names):
            getattr(mgr, "dropped", []).extend(names)
            return _orig(self, mgr, names)
        _S8._drop_named = _spy
        _s8 = _S8(); _s8.duckdb = _Mgr8()
        try:
            r = _s8.flatten_table("t", base="t")
            need(not r.get("error"), "flatten runs: %r" % r.get("error"))
            names = [c["name"] for c in r.get("created", [])]
            need("t" not in names,
                 "NO table is created under the file name: %r" % names)
            need(names[0].startswith("Master_Keys") or names[0] == "t_flattened",
                 "Master_Keys or hub first: %r" % names)
            eq(r.get("base"), "t_flattened",
               "the reported family base IS the hub")
            need("t" in _s8.duckdb.dropped,
                 "the nested SOURCE under the base name is dropped: %r"
                 % _s8.duckdb.dropped)
            need(_s8._table_family.get("identifier_flattened") == "t_flattened"
                 and _s8._table_family.get("legs_flattened") == "t_flattened",
                 "children parent to the hub")
        finally:
            _S8._drop_named = _orig
            _s8.duckdb = None
            _s8.shutdown()
        # the hub plan carries the record scalars + the SAME "_sk" recipe
        from samql_core.shred import plan_shred as _ps8
        from samql_core.diagnostics import parse_duckdb_type as _P8
        pl = _ps8("json", _P8("STRUCT(code BIGINT, ccy VARCHAR, "
                              "legs STRUCT(r DOUBLE)[])[]"),
                  base="f", root_ord="json_ord", children_use_base=False)
        hub = next(t for t in pl["tables"] if t["name"] == "f_flattened")
        root = pl["tables"][0]
        eq(hub["fields"], root["fields"],
           "the hub carries the record's scalar fields")
        eq(hub["keys"], root["keys"],
           "the hub shares the record keys (identical _sk)")

    def t_pywebview_window_logo_518():
        # .518: the WINDOW flow is now under test. A fake pywebview drives
        # open_native_window end to end: the SamQL-titled window is created,
        # start() runs the icon callback inside the GUI loop, the Form gets
        # the bundled logo (Icon + ShowIcon), and the Form's OWN handle is
        # branded (AUMID + window icon + relaunch icon) -- the taskbar
        # identity, no title search, no stamping race.
        import types as _ty, threading as _t9, tempfile as _tf
        import time as _tm9
        saved = {m: sys.modules.get(m) for m in
                 ("webview", "webview.platforms",
                  "webview.platforms.edgechromium",
                  "webview.platforms.winforms",
                  "clr", "System", "System.Drawing")}
        wv = _ty.ModuleType("webview"); wv.__path__ = []
        wv.gui = None
        created = {}

        class _Native:
            Handle = "987654"

        class _Win:
            def __init__(self):
                self.events = _ty.SimpleNamespace(shown=_t9.Event())
                self.events.shown.set()
                self.native = _Native()

        def _cw(title, url, width=None, height=None, min_size=None,
                background_color=None, **kw):
            created.update(title=title, win=_Win(),
                           background_color=background_color)
            return created["win"]

        def _start(func=None, *a, **kw):
            wv.gui = "edgechromium"
            if func:
                func()
        wv.create_window = _cw
        wv.start = _start
        sys.modules["webview"] = wv
        for m in ("webview.platforms", "webview.platforms.edgechromium",
                  "webview.platforms.winforms"):
            sys.modules[m] = _ty.ModuleType(m)
        sys.modules["clr"] = _ty.ModuleType("clr")
        sd = _ty.ModuleType("System.Drawing")
        sd.Icon = lambda p: ("ICO", p)
        sm = _ty.ModuleType("System"); sm.Drawing = sd
        sys.modules["System"] = sm
        sys.modules["System.Drawing"] = sd
        import launcher_app as _LA
        keep = {n: getattr(_LA, n) for n in
                ("write_log", "_bundled_asset", "set_app_user_model_id",
                 "apply_app_icon", "set_relaunch_icon",
                 "wait_for_app_window")}
        logs = []
        calls = {"aumid": [], "icon": [], "relaunch": []}
        ico = _tf.mktemp(suffix=".ico")
        open(ico, "wb").write(b"\x00\x00\x01\x00")
        try:
            _LA.write_log = lambda m: logs.append(m)
            _LA._bundled_asset = lambda name: ico
            _LA.set_app_user_model_id = \
                lambda h, aumid="SamQL.SamQL": calls["aumid"].append(h)
            _LA.apply_app_icon = lambda h, p: calls["icon"].append((h, p))
            _LA.set_relaunch_icon = \
                lambda h, p: calls["relaunch"].append((h, p))
            _LA.wait_for_app_window = lambda *a, **k: None
            args = _ty.SimpleNamespace(window_size="1400,900",
                                       port=8765, browser="auto")
            splash = _ty.SimpleNamespace(set_text=lambda t: None,
                                         close=lambda: None,
                                         pump=lambda s=0: None)
            ok = _LA.open_native_window("http://127.0.0.1:8765/",
                                        args, splash)
            _tm9.sleep(0.3)
            need(ok is True, "the pywebview window path drove the window")
            eq(created["title"], "SamQL", "the window is SamQL-titled")
            eq(created.get("background_color"), _LA.CHROME_BG,
               "WebView2 starts dark, not the default white")
            win = created["win"]
            eq(win.native.Icon, ("ICO", ico),
               "the Form carries the bundled logo")
            need(getattr(win.native, "ShowIcon", None) is True,
                 "ShowIcon is on")
            eq(calls["aumid"], [987654],
               "the Form's own handle gets the AppUserModelID")
            need(calls["icon"] and calls["icon"][0][0] == 987654
                 and calls["relaunch"]
                 and calls["relaunch"][0][0] == 987654,
                 "window + relaunch icons land on the SAME handle")
            need(any("native WinForms icon set (hwnd=987654)" in l
                     for l in logs),
                 "the log records the landed icon")
            need(any("renderer=edgechromium" in l for l in logs),
                 "the renderer is logged as a clean name")
        finally:
            for n, v in keep.items():
                setattr(_LA, n, v)
            for m, v in saved.items():
                if v is None:
                    sys.modules.pop(m, None)
                else:
                    sys.modules[m] = v
            try:
                os.remove(ico)
            except OSError:
                pass

    def t_fetch_cancel_beats_518():
        # .518 (on-box: Cancel "still didn't fix the stall"). Cancel always
        # interrupted DuckDB -- but the stall lived in the FETCH, which never
        # looked at the cancel flag and never beat the op (the watchdog saw
        # "idle"). The fetch now polls cancel per batch (raising an
        # interrupt-shaped error) and heartbeats rows-so-far.
        import types as _tyA, threading as _tA
        from samql_core import engines as _E
        from samql_core import progress as _PA

        class _B:
            def __init__(self, n): self.num_rows = n

        class _CurA:
            def __init__(self, cancel): self._c = cancel
            def fetch_record_batch(self, n):
                def gen():
                    yield _B(100)
                    self._c.set()
                    yield _B(100)
                return gen()
        old_pa = _E.HAS_PYARROW
        old_tup = _E._arrow_batch_tuples
        had_pa = "pyarrow" in sys.modules
        try:
            _E.HAS_PYARROW = True
            _E._arrow_batch_tuples = lambda b: [()] * b.num_rows
            sys.modules.setdefault("pyarrow",
                                   _tyA.ModuleType("pyarrow"))
            _PA.reset_for_tests()
            _PA.begin("query", op_id="f518")
            cancel = _tA.Event()
            try:
                _E._fetch_rows_arrow_or_spill(_CurA(cancel), 3,
                                              cancel=cancel)
                need(False, "a cancelled fetch must raise")
            except InterruptedError as e:
                need(_E._is_interrupt(e),
                     "the raise is interrupt-shaped (cancel plumbing "
                     "recognizes it)")
            sn = [o for o in _PA.snapshot() if o["id"] == "f518"][0]
            eq(sn["rows"], 100,
               "the fetch heartbeats rows-so-far (watchdog sees progress)")
            eng = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                       encoding="utf-8").read()
            need("cancel=self._cancel)" in eng,
                 "the engine's execute passes its cancel flag to the fetch")
            need("if isinstance(_e, InterruptedError) or _is_interrupt(_e):"
                 in eng,
                 "a cancel PROPAGATES instead of degrading to the spill "
                 "fallback")
        finally:
            _E.HAS_PYARROW = old_pa
            _E._arrow_batch_tuples = old_tup
            if not had_pa:
                sys.modules.pop("pyarrow", None)
            _PA.reset_for_tests()

    def t_native_icon_shown_wait_517():
        # .517 (on-box: "native icon skipped (AttributeError)" -- the .513
        # Form.Icon ran before window.native existed, so the ONE mechanism
        # that owns the frame + taskbar icon never fired and the taskbar
        # kept Edge's mark). The GUI callback now waits for the shown event
        # and for .native, brands through the Form's own Handle (AUMID +
        # relaunch icon on the RIGHT hwnd, no title search), and logs reprs.
        la = open(os.path.join(BACKEND, "launcher_app.py"),
                  encoding="utf-8").read()
        need('ev = getattr(getattr(_w, "events", None), "shown", None)' in la
             and "ev.wait(10)" in la,
             "the icon callback waits for the window's shown event")
        need('native = getattr(_w, "native", None)' in la
             and "time.sleep(0.2)" in la,
             "it polls for window.native instead of assuming it")
        # Must not wait/sleep on the pywebview GUI thread (Not Responding).
        need('name="samql-native-icon"' in la
             and "BeginInvoke" in la
             and la.index("def _set_native_icon")
             < la.index("ev.wait(10)")
             < la.index('name="samql-native-icon"'),
             "shown/native wait runs on a daemon thread, not the GUI callback")
        need('hwnd = int(str(native.Handle))' in la
             and la.index("native.Icon = _Icon(ip)")
             < la.index('hwnd = int(str(native.Handle))'),
             "the Form icon is set and the Form's own handle is branded")
        need('"INFO native icon skipped (%r); stamper will cover"' in la,
             "failures log the repr, not just the exception class")
        need("GetClassNameW" in la and "GetWindowThreadProcessId" in la
             and "stamp target hwnd=" in la,
             "the stamper names its target (class + our-process check)")
        need('(process AppUserModelID=%s)" % APP_AUMID' in la
             and "_AUMID_SET" in la,
             "the process-level AUMID is visible in the log")
        need('rsplit(".", 1)[-1]' in la,
             "the renderer logs as a clean name, not a module repr")

    def t_progress_finish_linger_516():
        # .516 (on-box .469b failure: the live recon's milestone poller saw
        # [25, 50, 75] -- never 100). end() used to POP the op in the same
        # instant it completed, so observing the terminal state required a
        # poll landing inside a sub-millisecond window; the .510/.514
        # speedups shrank it below the 20ms poll. A finished op now LINGERS
        # briefly (finished=True, percent pinned terminal), while count()/
        # active_kinds()/the stall watchdog see only ACTIVE ops.
        import time as _tm
        from samql_core import progress as _P
        _P.reset_for_tests()
        _P.begin("recon", op_id="q516", total=4, unit="pass")
        _P.advance(done=3, total=4, op_id="q516")
        _P.end("q516")
        sn = [o for o in _P.snapshot() if o["id"] == "q516"]
        need(sn and sn[0]["finished"] and sn[0]["percent"] == 100.0,
             "a finished op stays observable at 100%%: %r" % sn)
        eq(_P.count(), 0, "count() reflects ACTIVE ops only")
        need(_P.stale(0.0) == [],
             "the stall watchdog never flags a finished op")
        need("recon" not in _P.active_kinds(),
             "active_kinds() excludes finished ops")
        old = _P._LINGER_S
        try:
            _P._LINGER_S = 0.05
            _tm.sleep(0.12)
            need(not [o for o in _P.snapshot() if o["id"] == "q516"],
                 "the linger sweeps on the next registry read")
        finally:
            _P._LINGER_S = old
            _P.reset_for_tests()

