    def t_more_motion():
        # .435: the second motion pass. (a) DELETING a journal cell now
        # glides the survivors up to close the gap -- the same FLIP rail
        # as the .434 move (shared snapshotTops; lifted is null so
        # nothing raises, everything glides), guarded by the same
        # motion-reduced check BEFORE any measurement. (b) NEW cells
        # arrive with a one-shot mount animation. (c) EVERY modal exits
        # as smoothly as it enters: a closing phase plays the reverse
        # pop on the card AND fades the backdrop, then the real onClose
        # fires 140 ms later -- Escape, the X, and a backdrop click all
        # route through it, and Reduce motion closes immediately. (d)
        # Sidebar carets rotate instead of snapping; buttons compress on
        # press. All CSS rides the existing global kill.
        def _fe(*parts):
            return open(os.path.join(ROOT, "frontend", *parts),
                        encoding="utf-8").read()
        nb = _fe("src", "components", "Notebook.tsx")
        dseg = nb.split("const deleteCell")[1].split("const moveCell")[0] \
            if nb.index("const deleteCell") < nb.index("const moveCell") \
            else nb.split("const deleteCell")[1][:1400]
        checks = [
            ("delete snapshots the SURVIVORS before the filter",
             "snapshotTops(ids)" in dseg
             and '"motion-reduced"' in dseg
             and dseg.index("snapshotTops") < dseg.index(
                 "setCells((cs) => cs.filter")),
            ("nothing lifts on delete (pure glide)",
             "lifted: null" in dseg),
            ("one shared snapshot helper feeds move AND delete",
             nb.count("const snapshotTops") == 1
             and nb.count("snapshotTops(") == 2),  # exactly 2 call sites
        ]
        md = _fe("src", "components", "Modal.tsx")
        # Wave 2 made Modal accessible and timer-safe. Validate the behavior,
        # not the obsolete one-line formatting used before focus trapping.
        close_timer = re.search(
            r"window\.setTimeout\(\(\) => \{.*?onClose\(\);.*?\},\s*160\)",
            md, re.S)
        escape_branch = re.search(
            r'if \(e\.key === "Escape"\) \{.*?beginClose\(\);.*?\}',
            md, re.S)
        checks += [
            ("modals exit through one closing phase",
             "const beginClose = useCallback" in md
             and close_timer is not None
             and md.count("beginClose") >= 4),
            ("Reduce motion closes immediately",
             'classList.contains("motion-reduced")' in md),
            ("Escape, X, and backdrop all route through it",
             escape_branch is not None
             and "onMouseDown={beginClose}" in md
             and "onClick={beginClose}" in md),
            ("the accessible close rail clears its timer on unmount",
             "window.clearTimeout(closeTimer.current)" in md
             and 'role="dialog"' in md
             and 'aria-modal="true"' in md),
        ]
        css = _fe("src", "styles.css")
        checks += [
            ("cells arrive; modals leave; backdrop fades",
             "@keyframes cell-in" in css
             and ".nb-cell { animation: cell-in" in css
             and "@keyframes modal-out" in css
             and ".modal.closing" in css
             and "animation: modal-out" in css
             and ".modal-backdrop.closing" in css
             and "opacity: 0;" in css),
            ("carets turn; buttons press",
             ".tree-row .twist { transition: transform" in css
             and "button:not(:disabled):active { transform: scale(0.97)"
             in css),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "motion pass 2: " + "; ".join(missing))

    def t_cell_move_flip():
        # .434: pressing up/down teleported the cell -- easy to miss.
        # The swap is now a FLIP: the two positions are snapshotted
        # BEFORE the reorder, the layout effect applies the inverted
        # transform and releases it, the stylesheet transition glides
        # both into place, and the pressed cell carries .cell-lift (a
        # raised shadow above its neighbour) for the ride. Fully
        # skipped when Reduce motion is on -- the JS checks
        # body.motion-reduced BEFORE snapshotting, and the global kill
        # rule already zeroes the CSS. Plus quiet, event-driven
        # entrances: the Settings menu, Activity task cards, and
        # sidebar table rows fade in on mount.
        def _fe(*parts):
            return open(os.path.join(ROOT, "frontend", *parts),
                        encoding="utf-8").read()
        nb = _fe("src", "components", "Notebook.tsx")
        cell = _fe("src", "components", "NotebookCell.tsx")
        css = _fe("src", "styles.css")
        checks = [
            ("positions snapshot BEFORE the reorder",
             "pendingFlip" in nb
             and "snapshotTops(" in
             nb.split("const moveCell")[1].split("setCells((cs)")[0]),
            ("the JS honors Reduce motion",
             'classList.contains("motion-reduced")' in nb),
            ("inverted transform applied then released in a layout "
             "effect",
             "useLayoutEffect" in nb
             and "translateY(${d}px)" in nb
             and 'el.style.transform = ""' in nb),
            ("the pressed cell is the one that lifts",
             'classList.add("cell-lift")' in nb
             and "cid === flip.lifted" in nb),
            ("cells are addressable for the snapshot",
             "data-cellid={cell.id}" in cell
             and "[data-cellid=" in nb),
            ("the stylesheet does the glide + the raise",
             "transition: transform 0.22s" in css
             and ".nb-cell.cell-lift" in css
             and "box-shadow" in css.split(".nb-cell.cell-lift")[1][:220]),
            ("quiet entrances: menu, task cards, table rows",
             "@keyframes menu-in" in css and "@keyframes card-in" in css
             and "@keyframes row-in" in css
             and ".settings-menu { animation: menu-in" in css
             and ".task-card { animation: card-in" in css
             and ".tree-row { animation: row-in" in css),
            ("everything rides the existing global kill",
             "body.motion-reduced *" in css),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "flip: " + "; ".join(missing))

    def t_docs_modal():
        # .433: "Join guide" grew into "Documentation" -- tabs for
        # Joins (the live-templated .432 content, intact), Journal,
        # JSON querying, NodeFlow, and SQL functions. The NodeFlow tab
        # must document EVERY node in the palette (the test extracts
        # the palette from NodeFlow.tsx and diffs it against the doc
        # dictionary), and the functions tab is LIVE: /api/docs/
        # functions returns PRAGMA function_list (SQLite -- including
        # SamQL's registered regexp helpers) and duckdb_functions()
        # (DuckDB), cached per session, degrading to a note when the
        # engine is absent. Route executed against a real session.
        import re as _re
        sess = _fresh_session()
        try:
            out = sess.list_functions()
            names = {f["name"] for f in out["sqlite"]}
            need(out["counts"]["sqlite"] > 100
                 and "regexp_matches" in names,
                 "live SQLite list incl. SamQL UDFs: %d"
                 % out["counts"]["sqlite"])
            # DuckDB may or may not be installed. Absent (sandbox): an
            # empty list + honest note, deliberately NOT cached so it
            # re-computes. Present (on-box): a populated list that DOES
            # cache. The contract is "never cache an INCOMPLETE answer".
            from samql_core.engines import HAS_DUCKDB as _HAS_DUCK
            if _HAS_DUCK:
                need(out["duckdb"] and "note" not in out
                     and sess.__dict__.get("_fn_docs_cache") is not None,
                     "with DuckDB present, a complete list caches")
            else:
                need(out["duckdb"] == [] and "note" in out
                     and sess.__dict__.get("_fn_docs_cache") is None,
                     "no DuckDB -> empty list + honest note, not cached")
        finally:
            sess.shutdown()
        srv = open(os.path.join(BACKEND, "server.py"),
                   encoding="utf-8").read()
        need('r"^/api/docs/functions$"' in srv
             and "def docs_functions" in srv,
             "the route is registered")
        apisrc = open(os.path.join(ROOT, "frontend", "src", "lib",
                                   "api.ts"), encoding="utf-8").read()
        need("docsFunctions:" in apisrc
             and '"/api/docs/functions"' in apisrc,
             "api.docsFunctions hits the route")

        def _fe(*parts):
            return open(os.path.join(ROOT, "frontend", *parts),
                        encoding="utf-8").read()
        dm = _fe("src", "components", "DocsModal.tsx")
        nb = _nodeflow_source()
        palette = set(_re.findall(r'\{ type: "([a-z]+)"', nb))
        documented = set(_re.findall(r"^  ([a-z]+):", dm, _re.M))
        missing = sorted(palette - documented)
        need(not missing,
             "every palette node is documented; missing: %r" % missing)
        checks = [
            ("five tabs", all(x in dm for x in (
                'label: "Joins"', 'label: "Journal"',
                'label: "JSON querying"', 'label: "NodeFlow"',
                'label: "SQL functions"'))
             and "<DocsTabs active={tab} onSelect={setTab} />" in dm),
            ("joins content intact (live templating + rule + trap)",
             'endsWith("_flattened")' in dm
             or '/_flattened$/' in dm
             or "_flattened" in dm
             and "_parent_sk" in dm and "cartesian" in dm),
            ("journal doc teaches cell chaining",
             "FROM Cell1" in dm and "USES" in dm and "FEEDS" in dm),
            ("json doc covers dots, unnest, recursive, ->>",
             "recursive := true" in dm and "UNNEST(" in dm
             and "->>" in dm and "json_each" in dm),
            ("functions tab fetches live + filters",
             ".docsFunctions()" in dm  # formatter may line-break api.
             and "Filter functions" in dm),
        ]
        appsrc = _fe("src", "App.tsx")
        checks += [
            ("the menu says Documentation and opens the modal",
             "Documentation…" in appsrc and "<DocsModal" in appsrc
             and "Join guide (how shred tables link)" not in appsrc),
        ]
        miss2 = [n for n, ok in checks if not ok]
        need(not miss2, "docs modal: " + "; ".join(miss2))

    def t_rowgroup_cap_and_thread_throttle():
        # .431: two remaining structural memory levers, both executed.
        # (1) ROW GROUPS: 925 jumbo rows land far below the ~122k-row
        # parquet default, i.e. the whole 1.7 GB cache was effectively
        # ONE row group -- every downstream statement decoded the whole
        # column chunk as a single unit before any pipeline could
        # stream. Cache writes now cap row groups by BYTES (64MB), with
        # an automatic retry on plain options when the local DuckDB
        # predates ROW_GROUP_SIZE_BYTES -- and any OTHER copy error
        # re-raises untouched. (2) THREADS: DuckDB parallelizes a
        # pipeline and each thread holds fat-struct batches, so peak
        # memory multiplies by thread count; shred_run now throttles to
        # 2 (SAMQL_SHRED_THREADS tunes/disables) and restores on every
        # exit path.
        from samql_core import engines as E
        need("ROW_GROUP_SIZE_BYTES '64MB'" in E.copy_parquet_options(),
             "jumbo cache writes cap row groups by bytes")

        class _RetryCur:
            def __init__(self, fail_kind):
                self.fail_kind, self.calls = fail_kind, []

            def execute(self, sql):
                self.calls.append(sql)
                if len(self.calls) == 1 and self.fail_kind == "opt":
                    raise RuntimeError(
                        'Unrecognized option "ROW_GROUP_SIZE_BYTES"')
                if self.fail_kind == "other" and len(self.calls) == 1:
                    raise RuntimeError("disk full")
        c = _RetryCur("opt")
        ran = E.exec_copy_parquet(c, "SELECT 1", "x.parquet")
        need(len(c.calls) == 2
             and "ROW_GROUP_SIZE_BYTES" in c.calls[0]
             and "ROW_GROUP_SIZE_BYTES" not in c.calls[1]
             and ran == c.calls[1],
             "old-DuckDB option error -> plain retry: %r" % c.calls)
        c2 = _RetryCur("other")
        try:
            E.exec_copy_parquet(c2, "SELECT 1", "x.parquet")
            need(False, "a non-option copy error must re-raise")
        except RuntimeError as e:
            need("disk full" in str(e), "the original error surfaces")
        src = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                   encoding="utf-8").read()
        need(src.count("exec_copy_parquet(") >= 3,
             "def + both cache writers route through the retrying copy "
             "(got %d refs)" % src.count("exec_copy_parquet("))

        class _ThrConn:
            def __init__(self, threads):
                self.threads, self.log = threads, []

            def execute(self, sql):
                self.log.append(sql)
                return self

            def fetchone(self):
                return (self.threads,)
        conn = _ThrConn(8)
        restore = E.shred_thread_throttle(conn)
        need(any(x == "SET threads TO 2" for x in conn.log),
             "8 threads -> capped to 2: %r" % conn.log)
        restore()
        need(conn.log[-1] == "SET threads TO 8",
             "restore puts the original count back: %r" % conn.log)
        conn2 = _ThrConn(2)
        E.shred_thread_throttle(conn2)()
        need(all("SET threads TO" not in x or "TO 2" not in x
                 for x in conn2.log[1:]) and len(conn2.log) == 1,
             "already at/below the cap -> untouched: %r" % conn2.log)
        os.environ["SAMQL_SHRED_THREADS"] = "0"
        try:
            conn3 = _ThrConn(8)
            E.shred_thread_throttle(conn3)()
            eq(conn3.log, [], "env 0 disables the throttle entirely")
        finally:
            os.environ.pop("SAMQL_SHRED_THREADS", None)
        ses = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        need("_unthrottle = shred_thread_throttle(" in ses
             and ses.count("_unthrottle()") == 2,
             "shred_run AND the deep flatten path (.494) both throttle and "
             "restore in their finally")
        fc = open(os.path.join(BACKEND, "samql_core", "filecache.py"),
                  encoding="utf-8").read()
        need("byte-capped row groups" in fc,
             ".431: CACHE_VERSION bumped so existing single-group "
             "caches rebuild under the new writer")

    def t_shred_oom_batch_fallback():
        # .430: batching as the DEFAULT would tax every healthy run with
        # N repeated parquet decodes -- but as an OOM-triggered FALLBACK
        # it costs zero on the good path and guarantees completion on
        # the bad one. shred_run tries the single statement; on an
        # OutOfMemoryException (and ONLY that -- interrupts and other
        # errors re-raise untouched) it rebuilds THAT table in
        # file_row_number ranges: CREATE for the first range, INSERT for
        # the rest, halving the batch size on a repeat OOM down to a
        # 50-row floor, beating progress between batches, and a cancel
        # between batches keeps the ranges already landed.
        from samql_core import shred as SH
        base = SH.build_table_sql(
            {"name": "t", "keys": ["_rid", "o"], "path": "json",
             "parent": None, "depth": 1, "fields": ["a"], "leaves": [],
             "child_arrays": [], "elem_scalar": False, "hop_path": []},
            "json", "x.parquet", row_range=(11, 20), insert=True)
        need(base.startswith("INSERT INTO t\n")
             and "BETWEEN 11 AND 20" in base
             and "CREATE" not in base,
             "insert mode + row range render: %s" % base[:120])
        sess = _fresh_session()
        try:
            seen = []

            class _Cur:
                def execute(self, sql):
                    if sql.startswith("SELECT count(*)"):
                        seen.append(("count", ""))
                        return
                    if sql.startswith("CREATE OR REPLACE TABLE") \
                            and "BETWEEN" not in sql:
                        seen.append(("full", ""))
                        raise RuntimeError(
                            "OutOfMemoryException: Out of Memory Error")
                    frag = sql.split("BETWEEN ")[1].split("\n")[0] \
                        if "BETWEEN" in sql else "?"
                    seen.append(("batch",
                                 sql.split("\n")[0][:6] + " " + frag))

                def fetchone(self):
                    return (100,)

                def close(self):
                    pass

            class _Lk:
                def __enter__(self):
                    return self

                def __exit__(self, *a):
                    return False

            class _Mgr:
                view_backing = {}
                table_columns = {}
                _cancel = {}

                def native_op_cursor(self):
                    class _C:
                        def __enter__(_s):
                            return (_Cur(), _Lk())

                        def __exit__(_s, *a):
                            return False
                    return _C()

                def sync_catalog(self):
                    pass
            sess.duckdb = _Mgr()
            sess.shred_plan = lambda e, t, c, base=None: {
                "tables": [{"name": "soph",
                            "keys": ["_rid", "soph_ord"],
                            "path": "json", "parent": None, "depth": 1,
                            "fields": ["a"], "leaves": [],
                            "child_arrays": [], "elem_scalar": False,
                            "hop_path": []}],
                "notes": [], "source": "x.parquet"}
            r = sess.shred_run("duckdb", "soph", "json", base="soph")
            kinds = [k for k, _ in seen]
            need(kinds[0] == "full" and "count" in kinds
                 and kinds.count("batch") == 8,
                 "full OOM -> rowcount -> 8 ranges of 13: %r" % seen)
            batches = [v for k, v in seen if k == "batch"]
            need(batches[0].startswith("CREATE")
                 and all(b.startswith("INSERT") for b in batches[1:]),
                 "CREATE first, INSERT after: %r" % batches)
            need("1 AND 13" in batches[0]
                 and "92 AND 100" in batches[-1],
                 "the ranges tile 1..100: %r" % batches)
            need(r.get("created")
                 and r["created"][0].get("batched") == 8,
                 "the created record says it was batched: %r" % r)
        finally:
            sess.duckdb = None
            sess.shutdown()

    def t_shred_lean_projection():
        # .428: the on-box run cleared EXCLUDE (.425) and the catalog
        # (.427) and hit the 13 GiB DuckDB memory ceiling on the ROOT
        # CTAS -- OutOfMemoryException with the spill directory already
        # configured, because giant struct vectors in a projection are
        # not spillable mid-pipeline. Root cause: e0.* materialized the
        # WHOLE element -- every wrapper blob, with every nested array
        # duplicated inline (once in the parent's blob, again in its
        # child table). Projections are now EXPLICIT AND LEAN: depth-1
        # scalars by name, wrapper leaves as dotted aliased columns,
        # arrays never selected in a parent at all. Executed on a
        # sophis-mini with a wrapper leaf on the root AND one inside a
        # child element.
        from samql_core import shred as SH
        sc = lambda ty="VARCHAR": {"t": "scalar", "type": ty}
        node = {"t": "list", "of": {"t": "struct", "fields": [
            ("code", sc("BIGINT")),
            ("SwapHistory", {"t": "struct", "fields": [
                ("SwapHistory", {"t": "struct", "fields": [
                    ("resetDates", {"t": "list", "of": {
                        "t": "struct",
                        "fields": [("d", sc("DATE"))]}}),
                    ("dayType", sc())]})]}),
            ("cashflows", {"t": "list", "of": {"t": "struct", "fields": [
                ("amt", sc("DOUBLE")),
                ("wrap", {"t": "struct",
                          "fields": [("note", sc())]}),
                ("subflows", {"t": "list", "of": sc()})]}}),
        ]}}
        plan = SH.plan_shred("json", node, base="soph")
        # .507: the SwapHistory wrapper is its own 1:1 table now, carrying
        # the dotted leaf RELATIVELY, with a row only where the object exists
        _wsp = next(t for t in plan["tables"]
                    if t.get("wrapper_field") == "SwapHistory")
        _wsql = SH.build_table_sql(_wsp, "json", "x.parquet")
        need("swaphistory_daytype" in _wsql.lower()
             and "IS NOT NULL" in _wsql,
             "the wrapper table carries the leaf; absent object -> no row")
        root = SH.build_table_sql(plan["tables"][0], "json", "x.parquet")
        rp = root.rsplit("SELECT", 1)[1].rsplit("FROM", 1)[0]
        checks = [
            ("no star, no EXCLUDE on the root",
             ".*" not in root and "EXCLUDE" not in root),
            ("depth-1 scalar by name", "e0.code" in rp),
            (".507: wrapper leaves are NOT on the root anymore",
             "swaphistory" not in rp.lower()),
            ("array data never selected in the parent",
             "cashflows" not in rp and "resetDates" not in rp),
        ]
        kid = SH.build_table_sql(
            next(t for t in plan["tables"]
                 if t["name"] == "soph_cashflows_flattened"),
            "json", "x.parquet")
        kp = kid.rsplit("SELECT", 1)[1].rsplit("FROM", 1)[0]
        checks += [
            ("child element: same lean rules",
             ".*" not in kid and "e1.amt" in kp
             and "wrap_note" in kp and "subflows" not in kp),
            ("the deep grandchild still exists",
             any("subflows" in t["name"] for t in plan["tables"])),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "lean projection: " + "; ".join(missing))

    def t_shred_predrops_view():
        # .427: the .425 fix carried the shred past EXCLUDE and into the
        # NEXT wall -- CatalogException: "<table> is not a table". A
        # query-in-place load is a VIEW, and the root spec deliberately
        # takes the source's name (root REPLACES source, the established
        # shred semantic on materialized loads) -- but CREATE OR REPLACE
        # TABLE cannot replace a VIEW. shred_run now pre-drops a view
        # squatting on any target name before its CTAS; safe because
        # every shred statement reads read_parquet() directly and never
        # touches the view. Behavioral: a stub engine records the drop
        # arriving BEFORE the create, and the created list still names
        # the root.
        import types as _t
        sess = _fresh_session()
        try:
            seen = []

            class _Cur:
                def execute(self, sql):
                    seen.append(("exec", sql.split("\n")[0][:60]))

                def close(self):
                    pass

            class _Lk:
                def __enter__(self):
                    return self

                def __exit__(self, *a):
                    return False

                def acquire(self, *a, **k):
                    return True

                def release(self):
                    pass

            class _Mgr:
                view_backing = {"soph": "fc_x.parquet"}
                table_columns = {"soph": ["json"]}
                _cancel = {}

                def native_op_cursor(self):
                    class _C:
                        def __enter__(_s):
                            return (_Cur(), _Lk())

                        def __exit__(_s, *a):
                            return False
                    return _C()

                def sync_catalog(self):
                    seen.append(("sync", ""))
            mgr = _Mgr()
            sess.duckdb = mgr
            sess._drop_named = (lambda m, names:
                                seen.append(("drop", list(names))))
            # shred_run gets its plan via self.shred_plan -- stub THAT
            sess.shred_plan = lambda eng, tbl, col, base=None: {
                "tables": [{"name": "soph",
                            "keys": ["_rid", "soph_ord"],
                            "path": "json", "parent": None, "depth": 1,
                            "fields": [], "child_arrays": [],
                            "elem_scalar": False, "hop_path": []}],
                "notes": [], "source": "x.parquet"}
            r = sess.shred_run("duckdb", "soph", "json", base="soph")
            kinds = [k for k, _v in seen]
            need("drop" in kinds and "exec" in kinds
                 and kinds.index("drop") < kinds.index("exec"),
                 "the view drop lands BEFORE the create: %r" % seen)
            need(any(v == ["soph"] for k, v in seen if k == "drop"),
                 "the squatting name is what gets dropped")
            need(r.get("created")
                 and r["created"][0]["name"] == "soph",
                 "the root still reports created under the source name")
        finally:
            sess.duckdb = None
            sess.shutdown()

    def t_async_reads_always_on():
        # .426: the product leans on concurrent reads everywhere (grid
        # pages, catalog peeks, counts), so the toggle is retired --
        # always ON: the setter clamps, a persisted opt-out from an
        # older build cannot resurrect on engine rebuild, the engines
        # default stays True, and the Settings menu loses both the
        # toggle and the orphaned "Loading" header (its one item moved
        # into the Load modal builds ago). ENHANCEMENT, executed: slot
        # acquisition is lock-aware -- saturated pool + IDLE write lock
        # degrades instantly (the locked path is cheap), but saturated
        # pool + HELD write lock waits briefly for a slot instead of
        # queueing behind the very build async reads exist to dodge.
        sess = _fresh_session()
        try:
            got = sess.set_concurrent_reads(False)
            need(got is True and sess._concurrent_reads_pref is True,
                 "the opt-out clamps to True")
        finally:
            sess.shutdown()
        import threading as _th, time as _tm
        from samql_core.session import _acquire_read_slot as acq

        class _Eng:
            def __init__(self, locked):
                self.lock = _th.Lock()
                if locked:
                    self.lock.acquire()
        free = _th.BoundedSemaphore(1)
        eq(acq(free, _Eng(False)), True, "free slot: instant")
        sat = _th.BoundedSemaphore(1); sat.acquire()
        t0 = _tm.monotonic()
        eq(acq(sat, _Eng(False)), False,
           "saturated + idle lock: degrade immediately")
        need(_tm.monotonic() - t0 < 0.2, "no wait when the lock is idle")
        sat2 = _th.BoundedSemaphore(1); sat2.acquire()
        eng2 = _Eng(True)
        _th.Timer(0.05, sat2.release).start()
        t1 = _tm.monotonic()
        eq(acq(sat2, eng2), True,
           "saturated + held lock: waits and wins the freed slot")
        need(0.03 < _tm.monotonic() - t1 < 0.34,
             "the wait is brief and bounded")
        sat3 = _th.BoundedSemaphore(1); sat3.acquire()
        t2 = _tm.monotonic()
        eq(acq(sat3, _Eng(True), timeout=0.08), False,
           "held lock but no slot arrives: bounded surrender")
        need(_tm.monotonic() - t2 >= 0.07, "the bound was honored")
        eng = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                   encoding="utf-8").read()
        need("_env_truthy(CONCURRENT_READS_ENV, True)" in eng,
             "the engines default is ON (env can still A/B it off)")
        app = open(os.path.join(ROOT, "frontend", "src", "App.tsx"),
                   encoding="utf-8").read()
        need("async reads" not in app
             and '<div className="label">Loading</div>' not in app,
             "the menu lost the toggle and the orphaned header")
        ses = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        need('_acquire_read_slot(slots, engine)' in ses,
             "the read path routes through the lock-aware acquire")

    def t_shred_exclude_direct_and_dashboard():
        # .425: the .423 card note delivered its first real on-box
        # diagnostic -- BinderException: Column "SwapHistory.SwapHistory"
        # in EXCLUDE list not found in e0. child_arrays carries DOTTED
        # hop paths for lists found behind struct wrappers (.393 deep
        # scan), but EXCLUDE against the element alias accepts DIRECT
        # field names only; a dotted kid lives INSIDE a wrapper column
        # the parent keeps whole (so its scalar siblings ride along) and
        # must not be excluded at all -- while its own child table still
        # builds from the dotted hop. Executed on the sophis shape that
        # failed. Plus: a flatten failure now lands in the Error
        # Dashboard, not just the load card.
        from samql_core import shred as SH
        sc = lambda ty="VARCHAR": {"t": "scalar", "type": ty}
        node = {"t": "list", "of": {"t": "struct", "fields": [
            ("code", sc("BIGINT")),
            ("SwapHistory", {"t": "struct", "fields": [
                ("SwapHistory", {"t": "struct", "fields": [
                    ("resetDates", {"t": "list", "of": {
                        "t": "struct",
                        "fields": [("d", sc("DATE"))]}}),
                    ("dayType", sc())]})]}),
            ("cashflows", {"t": "list", "of": {
                "t": "struct", "fields": [("amt", sc("DOUBLE"))]}}),
        ]}}
        plan = SH.plan_shred("json", node, base="soph")
        root_sql = SH.build_table_sql(plan["tables"][0], "json",
                                      "x.parquet")
        # .428 repoint: the projection is now EXPLICIT (no element star,
        # no EXCLUDE, no wrapper blobs) -- the dotted-kid-in-EXCLUDE
        # class of error cannot occur by construction.
        proj = root_sql.split("SELECT")[1].split("FROM")[0]
        need("EXCLUDE" not in root_sql and ".*" not in root_sql,
             "no EXCLUDE and no element star anywhere")
        need("cashflows" not in proj,
             "the direct array is simply not selected")
        need("SwapHistory.SwapHistory" not in proj.replace('"', "")
             or "daytype" in proj,
             "no dotted path leaks except as an aliased leaf")
        deep = next(t for t in plan["tables"]
                    if "resetdates" in t["name"])  # names sanitize lower
        dsql = SH.build_table_sql(deep, "json", "x.parquet")
        need("SwapHistory.SwapHistory.resetDates" in dsql.replace('"', ""),
             "the deep child still hops the dotted path: %s" % dsql)
        wrapper_only = {"t": "list", "of": {"t": "struct", "fields": [
            ("w", {"t": "struct", "fields": [
                ("inner", {"t": "list", "of": sc()})]})]}}
        p2 = SH.plan_shred("json", wrapper_only, base="w2")
        s2 = SH.build_table_sql(p2["tables"][0], "json", "x.parquet")
        need("EXCLUDE" not in s2 and ".*" not in s2,
             ".428: an all-array element projects keys only: %s" % s2)
        import server as _srv
        seen = []
        _orig = _srv.log_server_error
        _srv.log_server_error = (lambda *a, **k:
                                 seen.append((a, k)))
        try:
            job = {"shred": True}
            _srv._shred_note(job, [{"name": "soph",
                                    "shred_error": "kapow"}])
        finally:
            _srv.log_server_error = _orig
        need(seen and seen[0][0][3] == "flatten"
             and seen[0][0][4] == "kapow"
             and "soph" in seen[0][1].get("detail", ""),
             "a flatten failure reaches the Error Dashboard store: %r"
             % seen)
        eq(job["note"], "flatten failed: kapow",
           "the card note still carries it")

    def t_launcher_frozen_child_hygiene():
        # .421: two on-box exe-launcher bugs. (1) The spawned frozen
        # server inherited the launcher's PyInstaller runtime env
        # (_MEIPASS2/_PYI_*) and could latch onto the launcher's temp
        # extraction -- the "Failed to remove temporary directory:
        # _MEIxxxxxx" dialog; children now get a SCRUBBED env (executed
        # here) and fully detached creation flags. (2) The server's own
        # auto-open plus the launcher's app window gave TWO windows;
        # both launchers (exe twin AND the PowerShell script) now pass
        # --no-browser at every server-start site.
        import importlib
        sys.path.insert(0, BACKEND)
        import launcher_app as L
        importlib.reload(L)
        fake = {"_MEIPASS2": "/tmp/_MEI1", "_PYI_ARCHIVE_FILE": "/x",
                "_PYI_APPLICATION_HOME_DIR": "/y",
                "PATH": os.pathsep.join(["/keep/bin", "/mei/dir"]),
                "HOME": "/h"}
        old_mei = getattr(sys, "_MEIPASS", None)
        sys._MEIPASS = "/mei/dir"
        try:
            env = L.clean_child_env(fake)
        finally:
            if old_mei is None:
                del sys._MEIPASS
            else:
                sys._MEIPASS = old_mei
        need("_MEIPASS2" not in env
             and not any(k.startswith("_PYI_") for k in env)
             and env["PATH"] == "/keep/bin" and env["HOME"] == "/h",
             "the child env is scrubbed of the launcher's PyInstaller "
             "runtime: %r" % env)
        src = open(os.path.join(BACKEND, "launcher_app.py"),
                   encoding="utf-8").read()
        need(src.count('"--no-browser"') == 3
             and "0x00000008" not in src
             and src.count("0x08000000") == 1
             and "clean_child_env()" in src,
             "server starts suppress auto-open (exe, py, .535 self-serve); "
             "spawns are detached with the clean env")
        ps = open(_root_script("Start-SamQL-AppWindow.ps1"),
                  encoding="utf-8").read()
        need(ps.count("--no-browser") == 3,
             "the PowerShell launcher suppresses auto-open at all "
             "three server-start sites")

    def t_ps1_pure_ascii():
        # .420: PowerShell 5.1 reads BOM-less scripts as ANSI. A UTF-8
        # em-dash decodes via CP1252 into bytes ending in 0x94 -- a
        # CURLY DOUBLE QUOTE, which PS 5.1 accepts as a string
        # delimiter. One stray dash in Run-SamQLTests unbalanced every
        # string after it ("missing terminator", phantom missing brace
        # -- the on-box 2026-07-03 parser explosion). Every checked-in
        # script must therefore be pure 7-bit ASCII, forever.
        bad = []
        for base, _dirs, files in os.walk(ROOT):
            if "node_modules" in base or "__pycache__" in base:
                continue
            for fn in files:
                if not fn.endswith(".ps1"):
                    continue
                fp = os.path.join(base, fn)
                data = open(fp, "rb").read()
                hits = [(i, b) for i, b in enumerate(data) if b > 0x7F]
                if hits:
                    i, b = hits[0]
                    ln = data[:i].count(b"\n") + 1
                    bad.append("%s line %d byte 0x%02X (+%d more)"
                               % (os.path.relpath(fp, ROOT), ln, b,
                                  len(hits) - 1))
        need(not bad,
             "non-ASCII in PowerShell sources (PS 5.1 reads these as "
             "ANSI; CP1252 0x94 is a quote): " + "; ".join(bad))

    def t_launcher_exe_twin():
        # .418: backend/launcher_app.py is the stdlib-only Python twin
        # of the PowerShell launcher, and backend/samql.spec now builds
        # it as a second, CONSOLE-LESS executable from the same
        # one-command build. Behavior parity executed here: the port
        # probe, the 200-line launcher-log trim into the SAME file the
        # Error-log viewer reads, and the py -> exe -> dist server
        # search order. Splash and window-wait degrade gracefully (no
        # tkinter / non-Windows), and importing the module never opens
        # a window.
        import importlib, tempfile as _tf
        old_tmp = os.environ.get("SAMQL_TMP")
        tdir = _tf.mkdtemp(prefix="samql_l_")
        os.environ["SAMQL_TMP"] = tdir
        try:
            sys.path.insert(0, BACKEND)
            import launcher_app as L
            importlib.reload(L)
            need(not L.port_open(59998), "a closed port probes False")
            for i in range(230):
                L.write_log("INFO line %d" % i)
            lines = open(L.launcher_log_path(),
                         encoding="utf-8").readlines()
            need(len(lines) == 200 and "line 229" in lines[-1],
                 "the log trims to the last 200 lines")
            need(L.launcher_log_path()
                 == os.path.join(tdir, "launcher.log"),
                 "the log is the SAME file Settings -> Error log reads")
            cands = L.server_candidates(base="/x")
            need([k for k, _ in cands]
                 == ["py", "exe", "exe", "exe", "exe"]
                 and cands[0][1].endswith(
                     os.path.join("backend", "server.py"))
                 and "dist" in cands[3][1],
                 "search order: source py -> exe beside -> dist")
            need(L.find_browser(
                "auto", env={"ProgramFiles": "/nope",
                             "ProgramFiles(x86)": "/nope",
                             "LocalAppData": ""}) is None,
                 "browser lookup honors the env it is given")
            src = open(os.path.join(BACKEND, "launcher_app.py"),
                       encoding="utf-8").read()
            need("EnumWindows" in src and '"SamQL"' in src
                 and "class _NoSplash" in src
                 and "def make_splash" in src,
                 "window-titled wait + splash degradation are wired")
            spec = open(os.path.join(BACKEND, "samql.spec"),
                        encoding="utf-8").read()
            need('name="SamQL-AppWindow"' in spec
                 and spec.count("EXE(") >= 2
                 and 'excludes=["samql_core"]' not in spec
                 and spec.index('name="SamQL-AppWindow"')
                 < spec.index("console=False"),
                 "the spec builds the console-less AppWindow exe "
                 "(.535: backend bundled; .549: +onedir EXE/COLLECT)")

            # .485: the launcher opens a NATIVE pywebview window (its own
            # process -> its own taskbar icon, no Edge logo), mirroring the
            # server's --window path, and only falls back to the Edge --app
            # window + icon-stamping when pywebview isn't bundled. With no
            # pywebview in this harness open_native_window returns False.
            need("def open_native_window" in src
                 and 'webview.create_window("SamQL"' in src
                 and "webview.start()" in src,
                 "the launcher drives a native pywebview window")
            need(src.index("open_native_window(url, args, splash)")
                 < src.index("find_browser(args.browser)"),
                 "pywebview is tried FIRST; the browser window is the "
                 "fallback")
            # .488: only exercise the fallback path when pywebview is NOT
            # importable. On a box where pywebview IS installed (Sam's build),
            # open_native_window would actually create + start a real GUI
            # window (webview.start() blocks), so we must not call it here --
            # branch on availability exactly like the HAS_DUCKDB pattern.
            import importlib.util as _ilu485
            if _ilu485.find_spec("webview") is None:
                eq(L.open_native_window(
                    "http://127.0.0.1:1/",
                    type("A", (), {"window_size": "1400,900"})(),
                    L._NoSplash()), False,
                   "without pywebview the launcher falls back to a browser")
            # the launcher exe bundles pywebview (+ its Windows WebView2/.NET
            # backend, incl. clr_loader) when built -- SAME shared collect
            # that SamQL.exe --window receives (payload parity).
            need('_WINDOW_PKGS = ("webview", "clr", "clr_loader", "pythonnet"'
                 in spec
                 and "bundling native-window package for BOTH exes" in spec
                 and "la_binaries = list(binaries)" in spec
                 and "la_datas = list(datas)" in spec,
                 "the spec bundles pywebview + WebView2 into BOTH exes "
                 "from one shared collect")
            reqs = open(os.path.join(ROOT, "requirements-optional.txt"),
                        encoding="utf-8").read()
            need(any(ln.strip() == "pywebview"
                     for ln in reqs.splitlines()),
                 "pywebview is an active (installed) optional dependency")
        finally:
            if old_tmp is None:
                os.environ.pop("SAMQL_TMP", None)
            else:
                os.environ["SAMQL_TMP"] = old_tmp
            import shutil as _sh
            _sh.rmtree(tdir, ignore_errors=True)

    def t_tsc_deep_audit():
        # .417: the on-box gate was failing on TWO real type errors
        # that survived .415 -- api.errors() lacked the .409
        # file/launcher fields (TS2339 x2 in ErrorLogModal) and
        # api.reconcile() lacked the .413 query_id (TS2353 in
        # ReconcileModal). They stayed invisible because (a) the
        # Failures summary printed only LINE ONE of each message, and
        # (b) the sandbox shim's empty JSX Element interface is `{}`,
        # which every object satisfies. All four layers fixed + pinned:
        # the api types carry the fields; the summary prints full
        # messages; the guard shim BRANDS Element and types children
        # strictly; the guard filter includes the local-type codes.
        api = open(os.path.join(ROOT, "frontend", "src", "lib",
                                "api.ts"), encoding="utf-8").read()
        need("file?: { path: string; size: number; text: string }"
             in api and "launcher?: { path: string" in api,
             "api.errors() declares the on-disk tails")
        i = api.index("reconcile: (spec: {")
        need("query_id?: string;" in api[i:i + 500],
             "api.reconcile() accepts the run name")
        me = read_test_sources(ROOT)
        need('__jsx_brand: "element"' in me
             and "2339|2353" in me
             and '"error TS2322" in ln and "__Node" in ln' in me,
             "the guard shim is branded and the filter covers the "
             "local-type codes")
        need('lines = (d or "").splitlines() or [""]' in me
             and 'print("        " + extra)' in me,
             "the failure summary prints the WHOLE message")

    def t_tsc_gate_not_mute():
        # .416: BOTH on-box "type errors:"-with-nothing-after failures
        # (2026-07-03) were `tsc -b` incremental replay: after a cached
        # failure, an unchanged re-run exits 1 and prints NOTHING (the
        # errors sit in tsbuildinfo). Two fixes, both pinned: the
        # typecheck script is a full non-incremental --noEmit run with
        # --pretty false (always lists every error), and the gate
        # itself detects the exit-nonzero/empty-output state, deletes
        # stale tsbuildinfo, and re-runs tsc directly so the assertion
        # can never again raise without the actual error lines.
        import json as _json
        pkg = _json.load(open(os.path.join(ROOT, "frontend",
                                           "package.json")))
        # .607: the script invokes the local tsc via node (bare `tsc` was not
        # resolvable behind the corporate npm setup); still non-incremental
        # (--noEmit, no -b) and verbose (--pretty false) so it can never mute.
        eq(pkg["scripts"]["typecheck"],
           "node ./node_modules/typescript/bin/tsc --noEmit "
           "-p tsconfig.json --pretty false",
           "the typecheck script is non-incremental and verbose")
        src = read_test_sources(ROOT)
        need("if p.returncode != 0 and not out:" in src
             and 'os.unlink(os.path.join(FRONTEND, bi))' in src
             and '"--pretty", "false"' in src
             and '(no output -- see ' in src,
             "the gate retries a mute failure with a direct, "
             "full listing")

    def t_recon_single_pass():
        # .414: the reconcile summary -- a_only, b_only, matched, every
        # per-field tally with balances, and the row-level mismatch --
        # is computed in ONE null-safe FULL OUTER JOIN aggregate over
        # the deduped sides (one scan of each input) instead of five
        # statements. Executed here on a fixture that exercises the
        # semantics corners: duplicate keys (deduped, no fan-out), a
        # NULL key present on BOTH sides (EXCEPT treats NULLs equal ->
        # in NO bucket, exactly like before), dollar/comma balance
        # strings, and a case-differing field mismatch. Hand-computed
        # totals asserted, then the SAME spec re-run down the legacy
        # path (toggle off) must produce a deep-equal report.
        import samql_core.session as S
        sess = _fresh_session()
        try:
            eng = sess.db
            eng.execute("CREATE TABLE ra (k INTEGER, v TEXT, bal TEXT)")
            eng.execute(
                "INSERT INTO ra VALUES (1,'x','$100'),(1,'x','100'),"
                "(2,'y','200'),(NULL,'n','5'),(4,'w','1,000')")
            eng.execute("CREATE TABLE rb (k INTEGER, v TEXT, bal TEXT)")
            eng.execute(
                "INSERT INTO rb VALUES (1,'x','100'),(2,'Y','200'),"
                "(NULL,'n','5'),(5,'z','50')")
            eng.table_columns["ra"] = ["k", "v", "bal"]
            eng.table_columns["rb"] = ["k", "v", "bal"]
            spec = {"left": "ra", "right": "rb", "keys": ["k"],
                    "compare": ["v"], "balance": "bal"}
            need(S.RECON_SINGLE_PASS is True
                 and S.RECON_SINGLE_PASS_SQLITE is False,
                 "one-pass defaults: on for DuckDB, off for SQLite "
                 "(SQLite nested-loops a null-safe join)")
            S.RECON_SINGLE_PASS_SQLITE = True   # tiny fixture: safe
            one = sess.reconcile(dict(spec))
            need("error" not in one, "one-pass report: %r" % one)
            eq(one["totals"],
               {"a_only": 1, "b_only": 1,
                "null_keys": {"a": 1, "b": 1}, "matching": 1,
                "non_matching": 1, "total": 4},
               "hand-computed totals (dup keys deduped; the "
               "NULL-key-on-both-sides row lands in NO bucket -- "
               ".452: and is counted under null_keys)")
            f0 = one["fields"][0]
            need(f0["matching"] == 1 and f0["non_matching"] == 1
                 and abs(f0["sum_matching_balance"] - 100.0) < 1e-9
                 and abs(f0["sum_non_matching_balance"] - 200.0) < 1e-9,
                 "per-field tallies + cleaned balance sums: %r" % f0)
            S.RECON_SINGLE_PASS = False
            try:
                legacy = sess.reconcile(dict(spec))
            finally:
                S.RECON_SINGLE_PASS = True
                S.RECON_SINGLE_PASS_SQLITE = False
            eq(one, legacy, "one-pass report deep-equals the legacy "
               "five-statement report")
        finally:
            sess.shutdown()
        src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        need("FULL OUTER JOIN" in src
             and "IS NOT DISTINCT FROM" in src
             and "sqlite3.sqlite_version_info >= (3, 39)" in src
             and "RECON_SINGLE_PASS_SQLITE" in src
             and "got = None   # any surprise -> the legacy statements"
             in src,
             "version guard + silent legacy fallback are wired")
        i = src.index("def _legacy_counts")
        j = src.index("def _one_pass_counts")
        need('_c, rows = _rd(' in src[i:j],
             "the legacy per-field aggregate rides the read cursor "
             "(the .413 miss, fixed)")

    def t_consolidation_and_reconcile():
        # .413: (a) ONE drag implementation (useWinDrag) -- Activity
        # window, value inspector, and field-explorer window all ride
        # it; (b) ONE sql_path() for the path-literal escaping a dozen
        # sites hand-rolled (adopted at the hot sites, raw pattern
        # budget enforced); (c) the reconcile audit: summary and
        # drilldown REGISTER on the dashboard (surface "reconcile",
        # labeled, unregistered in a finally) so they are visible and
        # per-run cancellable; summary counts ride execute_read when
        # both inputs are real tables (temp-staged inputs keep the
        # locked path); drilldown already shares _recon_bucket_sql and
        # the _exec_target rail (pruned paging).
        comp = os.path.join(ROOT, "frontend", "src", "components")
        shared = open(os.path.join(comp, "ActivityShared.tsx"),
                      encoding="utf-8").read()
        eq(shared.count("dx: e.clientX"), 1,
           "the ONE drag implementation lives in the shared hook")
        for f in ("ActivityModal.tsx", "DataGrid.tsx",
                  "FieldExplorer.tsx"):
            src = open(os.path.join(comp, f), encoding="utf-8").read()
            need("useWinDrag" in src and "dx: e.clientX" not in src,
                 f + " rides the shared hook")
        from samql_core.sqlutil import sql_path
        eq(sql_path("C:\\a\\b's.parquet"), "C:/a/b''s.parquet",
           "sql_path: forward slashes + doubled quotes")
        sess = open(os.path.join(BACKEND, "samql_core", "session.py"),
                    encoding="utf-8").read()
        engs = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                    encoding="utf-8").read()
        need(sess.count("sqlutil.sql_path(") >= 4
             and engs.count("sqlutil.sql_path(") >= 3,
             "the hot sites adopted the helper")
        raw = (sess + engs).count(
            'replace("\\\\", "/").replace("\'", "\'\'")')
        need(raw <= 6, "raw path-escape budget holds (%d left)" % raw)
        # reconcile registration + cursor reads
        need('self._register_run(qid, eng0, kind="reconcile"' in sess
             and sess.count('surface="reconcile"') >= 3
             and "def _reconcile_inner(self, spec):" in sess
             and "def _reconcile_drilldown_inner(self, spec):" in sess
             and ("_end_run_keep_cancel(qid)" in sess
                  or "_unregister_run(qid)" in sess),
             "summary + drilldown register (and tear down) on the "
             "dashboard")
        need("_both_real = (left in getattr(eng" in sess
             and "eng.execute_read" in sess
             and "_rd(sql)" in sess,
             "summary counts ride the read cursor when safe")
        recon = open(os.path.join(comp, "ReconcileModal.tsx"),
                     encoding="utf-8").read()
        # .469 repoint: the id moved to a const so the modal's
        # progress poller can watch the SAME run it launched.
        need('const qid = "recon-"' in recon
             and "query_id: qid" in recon,
             "the frontend names the run so cancel + the progress "
             "poller target it")

