    def t_precise_cancel_everywhere():
        # .411 cancel audit across IDE / journal / node / loads /
        # flattens: every Stop hits EXACTLY its own run. Registrations
        # carry the executing thread; _interrupt_entry resolves the most
        # precise interruptible (per-run cursor handle -> that thread's
        # native-op cursor -> the engine); load jobs record their tid
        # and their per-card cancel interrupts just that statement; the
        # qid route defaults to scope=run. Node flows register with
        # surface="node" so they show on the stat dashboard.
        import types as _t
        import threading as _th
        import samql_core.session as S
        from samql_core import progress as P
        hits = []

        class _H:
            def __init__(self, tag):
                self.tag = tag

            def interrupt(self):
                hits.append(self.tag)

        class _Eng:
            ENGINE_KIND = "duckdb"
            _native_ops_lock = _th.Lock()

            def __init__(self):
                self._native_ops = {}

            def interrupt(self):
                hits.append("engine")
        eng = _Eng()
        eng._native_ops[111] = _H("op-111")
        eng._native_ops[222] = _H("op-222")
        # a dict registration interrupts ITS thread's native op only
        S.Session._interrupt_entry({"engine": eng, "tid": 111})
        eq(hits, ["op-111"], "one run's cancel hits one run's cursor")
        # a per-run handle is even more precise
        S.Session._interrupt_entry({"engine": eng, "tid": 999,
                                    "handle": _H("read-cursor")})
        eq(hits[-1], "read-cursor", "a read handle wins outright")
        # no native op for the tid -> the engine, never someone else's op
        S.Session._interrupt_entry({"engine": eng, "tid": 999})
        eq(hits[-1], "engine", "missing tid falls back to the engine")
        need("op-222" not in hits, "the OTHER run was never touched")
        # registrations carry the thread + node flows carry the surface
        P.reset_for_tests()
        sess = _fresh_session()
        try:
            sess._register_run("q-node", eng, surface="node",
                               label="my flow")
            with sess._running_lock:
                entry = sess._running["q-node"]
            need(isinstance(entry, dict)
                 and entry["tid"] == _th.get_ident()
                 and entry["engine"] is eng,
                 "registration records the executing thread")
            snap = P.snapshot()
            need(any(o.get("surface") == "node"
                     and o.get("label") == "my flow" for o in snap),
                 "a node flow shows on the dashboard: %r" % snap)
        finally:
            sess._unregister_run("q-node")
            P.reset_for_tests()
            sess.shutdown()
        srv = open(os.path.join(ROOT, "backend", "server.py"),
                   encoding="utf-8").read()
        need(srv.count('job["tid"] = threading.get_ident()') == 5,
             "every job thread records its tid")
        need("duck._native_ops.get(tid)" in srv
             and srv.index("duck._native_ops.get(tid)")
             < srv.index("s.interrupt_loads()"),
             "per-card load cancel tries the job's own statement first")
        need('scope = (body or {}).get("scope") or "run"' in srv,
             "the qid route is per-run by default")

    def t_journal_node_audit():
        # .410 audit of the Journal and the Node flow. Fixed: every
        # per-node CREATE now pulses the run's heartbeat, so a long
        # multi-node flow is never a silent op (blank Activity card +
        # spurious stall flags). Pinned as design contracts: the journal
        # chain's reuse pins are refcounted and released in cleanup
        # (deferred discards flushed); chained cells run prefer_locked
        # because TEMP views are connection-local; the flow builder
        # cancels between nodes and attributes per-node failures; temps
        # are dropped on success AND on both failure paths; Run-all's
        # dependency gate awaits a cell's own prior run exactly once.
        src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        i = src.index("def _materialize_flows")
        flows = src[i:src.index("def _flow_cleanup")]
        checks = [
            ("every node CREATE pulses the heartbeat",
             "opreg.beat()" in flows
             and flows.index("opreg.beat()")
             < flows.index("DROP TABLE IF EXISTS")),
            ("cancel + per-node failure attribution",
             "NodeRunError" in flows and "_is_interrupt(e)" in flows),
            ("journal reuse pins are refcounted and released",
             "pins[rid] = pins.get(rid, 0) + 1" in src
             and "n = pins.get(rid, 0) - 1" in src
             and "self.discard_result(rid)" in src),
            ("chained cells run locked because TEMP views are "
             "connection-local",
             "prefer_locked=reuse_cleanup is not None" in src),
            ("flow temps drop on success and on both failure paths",
             src.count("self._flow_cleanup(query_id, et, created)") >= 2
             and "_drop_flow_temps(et, created)" in src),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "journal/node audit: " + "; ".join(missing))
        nb = open(os.path.join(ROOT, "frontend", "src", "components",
                               "Notebook.tsx"), encoding="utf-8").read()
        need("const hadGate = inflightRef.current.get(id);" in nb
             and "if (hadGate) await hadGate;" in nb,
             "the Run-all gate awaits a prior run exactly once")

    def t_errorlog_temp_and_app_wait():
        # .409: (a) server errors now ALSO append to an on-disk log in
        # the samql temp tree (bounded ~512KB, trimmed on a line
        # boundary) so they survive restarts; the existing Error-log
        # viewer (already reachable from Settings) shows its tail plus
        # the launcher's log; clearing clears the file too. (b) The
        # launcher writes its failures to temp\launcher.log and holds
        # the splash until a browser window titled SamQL exists.
        import importlib
        import server as _srv
        importlib.reload(_srv) if False else None
        import tempfile, types as _t
        # behavioral: append + bound + tail through a redirected path
        tdir = tempfile.mkdtemp(prefix="samql_errlog_")
        real = _srv._error_file_path
        try:
            _srv._error_file_path = lambda: os.path.join(tdir, "error.log")
            _srv._append_error_file("GET", "/x", 500, "ServerError",
                                    "boom", tb="Trace\n  line")
            t = _srv._tail_text(_srv._error_file_path())
            need("boom" in t["text"] and "| Trace" in t["text"]
                 and t["size"] > 0,
                 "an error lands on disk with its traceback: %r"
                 % t["text"][:80])
            big = "x" * 1000
            for i in range(700):
                _srv._append_error_file("GET", "/big%d" % i, 500,
                                        "ServerError", big)
            sz = os.path.getsize(_srv._error_file_path())
            need(sz <= 512 * 1024,
                 "the on-disk log is bounded (size=%d)" % sz)
            first = open(_srv._error_file_path(),
                         encoding="utf-8").read(40)
            need(first.startswith("20") or first.startswith("19"),
                 "trim lands on a line boundary: %r" % first)
        finally:
            _srv._error_file_path = real
            import shutil
            shutil.rmtree(tdir, ignore_errors=True)
        srv = open(os.path.join(ROOT, "backend", "server.py"),
                   encoding="utf-8").read()
        need('"file": _tail_text(_error_file_path())' in srv
             and '"launcher": _tail_text(_launcher_log_path())' in srv
             and srv.index("def errors_clear")
             < srv.index("os.unlink(_error_file_path())"),
             "the viewer payload carries both tails; clear clears disk")
        ps = open(_root_script("Start-SamQL-AppWindow.ps1"),
                  encoding="utf-8").read()
        need("Write-LauncherLog" in ps
             and 'Join-Path $env:TEMP "samql"' in ps
             and 'Write-LauncherLog "ERROR' in ps
             and 'MainWindowTitle -like "*SamQL*"' in ps
             and ps.index('MainWindowTitle -like "*SamQL*"')
             < ps.rindex("Close-Splash"),
             "launcher logs to temp and holds the splash for the window")
        mod = open(os.path.join(ROOT, "frontend", "src", "components",
                                "ErrorLogModal.tsx"),
                   encoding="utf-8").read()
        need("On-disk log (survives restarts)" in mod
             and "App-window launcher log" in mod,
             "the modal renders both on-disk sections")

    def t_native_window_persist_490():
        # .490, two on-box reports about the native (pywebview) window:
        #   (2) it didn't PERSIST like the browser tab -- pywebview defaults
        #       to private_mode (a throwaway session), so localStorage / saved
        #       UI state never survived a restart. Both entry points now pass
        #       private_mode=False + a STABLE storage_path.
        #   (1) after the window closed, an installer _MEI wouldn't clear
        #       ("in use") -- because the launcher-started server kept running,
        #       holding its onefile extraction. The launcher now gracefully
        #       stops the server IT started when the window closes, so the
        #       frozen server exits cleanly and PyInstaller releases the _MEI.
        def rd(*parts):
            return open(os.path.join(ROOT, *parts), encoding="utf-8").read()
        la = rd("backend", "launcher_app.py")
        srv = rd("backend", "server.py")
        checks = [
            # (2) persistence -- BOTH the launcher and the server's --window
            ("launcher persists the native window's storage",
             "private_mode=False" in la
             and "storage_path=_webview_storage_path()" in la),
            ("the server's --window persists too",
             "private_mode=False" in srv
             and "storage_path=_webview_storage_path()" in srv),
            ("both derive a STABLE per-user path (LOCALAPPDATA/SamQL/webview)",
             "def _webview_storage_path" in la
             and "def _webview_storage_path" in srv
             and 'os.path.join(base, "SamQL", "webview")' in la
             and 'os.path.join(base, "SamQL", "webview")' in srv),
            # (1) window close stops the server the launcher started so
            # SamQL.exe / llama-server do not linger in Task Manager
            ("the launcher has a graceful stop_server via /api/shutdown",
             "def stop_server" in la and "/api/shutdown" in la),
            ("closing the window stops the server the launcher started",
             "we_started_server = True" in la
             and "if we_started_server:" in la
             and "stop_server(args.port)" in la
             and "stopped the server on port" in la),
            ("the server honours that request with a graceful shutdown route",
             "_graceful_shutdown()" in srv and "^/api/shutdown$" in srv),
            ("graceful shutdown stops the llama-server sidecar",
             "_asst.stop_server(SESSION)" in srv),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing,
             "native-window persist/_MEI wiring broken: "
             + "; ".join(missing))
        # functional: the storage path is the per-user SamQL/webview folder
        # and gets created (same folder the real WebView2 data lands in).
        import launcher_app as _LA
        p = _LA._webview_storage_path()
        need(p.replace("\\", "/").endswith("SamQL/webview"),
             "the storage path is the per-user SamQL/webview folder: %s" % p)
        need(os.path.isdir(p), "the storage path is created on demand")

