    def t_launcher_splash_and_hidden():
        # .408: the personal launcher relaunches itself HIDDEN on its
        # first pass (console gone in a blink; a console it was CALLED
        # from is never touched -- the relaunch spawns a separate hidden
        # powershell and returns), shows a WinForms splash with live
        # status while it works, pumps the message loop during the port
        # wait, surfaces failures ON the splash in red (no console to
        # read), and closes the splash once the app window is up.
        # -KeepConsole opts out for debugging; -NoSplash stays hidden
        # and quiet. Also fixed here: the x86 Edge path used
        # "$env:ProgramFiles(x86)" which PS parses as ProgramFiles +
        # literal "(x86)" -- now ${env:ProgramFiles(x86)}.
        ps = open(_root_script("Start-SamQL-AppWindow.ps1"),
                  encoding="utf-8").read()
        checks = [
            ("first pass relaunches hidden and forwards every option",
             '-WindowStyle Hidden' in ps and "-HiddenRelaunch" in ps
             and '"-Port", "$Port"' in ps
             and 'if ($NoServer) { $fwd += "-NoServer" }' in ps),
            ("splash: borderless topmost WinForms with a marquee",
             'FormBorderStyle = "None"' in ps and "$f.TopMost" in ps
             and '"Marquee"' in ps),
            ("live status + red failure ON the splash",
             "Set-SplashText" in ps and "Fail-Visibly" in ps
             and "IsError" in ps),
            ("the message loop is pumped during the wait",
             ps.index("DoEvents()")
             < ps.index("Start-Sleep -Milliseconds 300")),
            ("WinForms is loaded before any DoEvents (KeepConsole/NoSplash safe)",
             ps.index("Add-Type -AssemblyName System.Windows.Forms")
             < ps.index("DoEvents()")
             and ps.index("Add-Type -AssemblyName System.Windows.Forms")
             < ps.index("function Show-Splash")),
            ("the splash closes after the app window opens",
             ps.index("--app=$url") < ps.rindex("Close-Splash")),
            ("escape hatches",
             "-KeepConsole" in ps and "$NoSplash" in ps),
            ("the x86 Edge path is actually expandable",
             "${env:ProgramFiles(x86)}" in ps
             and '"$env:ProgramFiles(x86)' not in ps),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "launcher v2 contract: " + "; ".join(missing))

