    def t_result_row_cap():
        # A runaway explode must terminate at a safety ceiling instead of
        # materializing forever (which pins the engine lock and wedges the app).
        # Verify the cap helper, that the COPY carries the LIMIT, and that an
        # over-cap result is flagged + reported at the ceiling.
        import types as _t
        import threading as _th
        import os as _os
        from samql_core import session as S

        class C:
            _result_row_cap = S.Session._result_row_cap
            low_memory = False

            def _zero_copy_source(self, e, q):
                return None
        c = C()
        _os.environ.pop("SAMQL_MAX_RESULT_ROWS", None)
        need(c._result_row_cap() == 10_000_000, "default safety cap is 10M rows")
        _os.environ["SAMQL_MAX_RESULT_ROWS"] = "0"
        need(c._result_row_cap() is None, "cap disabled with 0")
        _os.environ["SAMQL_MAX_RESULT_ROWS"] = "5"
        # NOTE: everything below runs under try/finally so a failure can't
        # leak a 5-row cap into later tests.

        try:
            seen = []

            class FakeCur:
                def __init__(self, desc=None, one=None):
                    self.description = desc
                    self._one = one

                def fetchone(self):
                    return self._one

            class FakeConn:
                def __init__(self, cnt):
                    self.cnt = cnt

                def execute(self, sql):
                    seen.append(sql)
                    if sql.startswith("COPY"):
                        return FakeCur()
                    if "LIMIT 0" in sql:
                        return FakeCur(desc=[("a",), ("b",)])
                    if "count(*)" in sql:
                        return FakeCur(one=(self.cnt,))
                    return FakeCur()

            exec_pq = S.Session._exec_duckdb_parquet.__get__(c, S.Session)
            # over the cap: 6 > 5
            eng = _t.SimpleNamespace(conn=FakeConn(6), write_lock=_th.Lock())
            cols, store, total, kind = exec_pq(eng, "SELECT * FROM big")
            copy_sql = next(s for s in seen if s.startswith("COPY"))
            need("LIMIT 6" in copy_sql,
                 "COPY carries the safety LIMIT (cap+1): " + copy_sql)
            need("row_number()" not in copy_sql,
                 "the COPY pays NO global window; __rn is synthesized at read "
                 "time: " + copy_sql)
            need(cols == ["a", "b"],
                 "store columns are the data columns (no __rn to strip)")
            from samql_core.rows import ParquetResultStore
            src = ParquetResultStore(eng, "/tmp/x.parquet", ["a"])._src()
            need("file_row_number = true" in src and '"__rn"' in src
                 and "EXCLUDE (file_row_number)" in src,
                 "the store synthesizes a 1-based __rn from file_row_number: "
                 + src)
            need(total == 5 and getattr(store, "capped", False) is True
                 and store.cap == 5,
                 "over-cap result is flagged capped and total reports the ceiling")
            # under the cap: 3 < 5 -> not capped, real total
            seen.clear()
            eng2 = _t.SimpleNamespace(conn=FakeConn(3), write_lock=_th.Lock())
            _cols, store2, total2, _k = exec_pq(eng2, "SELECT * FROM small")
            need(total2 == 3 and getattr(store2, "capped", False) is False,
                 "under-cap result is not flagged and keeps its real total")
        finally:
            _os.environ.pop("SAMQL_MAX_RESULT_ROWS", None)
        # the cached result carries the flag, and page() surfaces it
        cr = S._CachedResult("rid", ["a"], _t.SimpleNamespace(capped=True, cap=5),
                             5, "sql", "t", "duckdb")
        need(cr.capped is True and cr.cap == 5,
             "_CachedResult inherits capped/cap from the store")
        # a REAL page() call proves the flag flows to the wire (was a grep)
        class _CR2:
            cols = ["a"]
            total = 1
            sql = "SELECT 1"
            engine = "duckdb"
            capped = True
            cap = 5

            def view(self, sort_col, descending):
                return [(1,)]
        sess2 = _t.SimpleNamespace(_results={"rid2": _CR2()})
        pg = S.Session.page.__get__(sess2, S.Session)("rid2")
        need(pg.get("result_capped") is True and pg.get("result_cap") == 5,
             "page() surfaces result_capped/result_cap on the wire: "
             + repr({k: pg.get(k) for k in ("result_capped", "result_cap")}))

