    def t_temp_cleanup_on_restart():
        # Every session's temp data must be gone on exit AND on the next start.
        # reset_instance() (startup) wipes our dir to a clean slate even if a
        # dead same-PID instance left junk; cleanup_instance() (exit) removes it.
        #
        # Isolate onto a THROWAWAY dir instead of the real shared instance dir:
        # when DuckDB is installed the suite's live engine holds open handles to
        # its db file + spill dir inside the real instance dir, and Windows
        # refuses to rmtree a directory that still has open handles -- so testing
        # cleanup against the live dir mid-suite is not a valid check. (At real
        # shutdown the engines are recycled first, releasing those handles.)
        import tempfile as _tf
        from samql_core import tmputil as T
        saved_inst, saved_made = T._INSTANCE, T._made
        tmp = _tf.mkdtemp(prefix="samql_cleanup_test_")
        try:
            T._INSTANCE, T._made = tmp, True
            # reset_instance() wipes leftovers and recreates the dir empty.
            stale = os.path.join(tmp, "stale_qr_test.parquet")
            with open(stale, "w") as fh:
                fh.write("x")
            T.reset_instance()
            need(not os.path.exists(stale) and os.path.isdir(T._INSTANCE),
                 "reset_instance wipes leftovers and recreates the dir empty")
            # cleanup_instance() removes the whole dir. Files are written via a
            # closed context manager so no handle lingers to defeat rmtree.
            with open(os.path.join(T._INSTANCE, "live.tmp"), "w") as fh:
                fh.write("y")
            T.cleanup_instance()
            need(not os.path.exists(T._INSTANCE),
                 "cleanup_instance removes the whole instance dir on shutdown")
        finally:
            T._INSTANCE, T._made = saved_inst, saved_made
            try:
                import shutil as _sh
                _sh.rmtree(tmp, ignore_errors=True)
            except Exception:
                pass

    def t_temp_cleanup_wiring():
        # Structural: startup wipes+sweeps, exit cleans, and every temp artifact
        # lives under the per-instance dir so those two hooks actually catch it.
        def rd(*p):
            return open(os.path.join(ROOT, *p), encoding="utf-8").read()
        srv = rd("backend", "server.py")
        tmp = rd("backend", "samql_core", "tmputil.py")
        eng = rd("backend", "samql_core", "engines.py")
        sess = rd("backend", "samql_core", "session.py")
        checks = [
            ("startup wipes our instance dir, then sweeps dead ones",
             "tmputil.reset_instance()" in srv
             and "tmputil.sweep_stale()" in srv),
            ("clean exit removes this instance's temp dir",
             "tmputil.cleanup_instance()" in srv),
            ("exit handlers cover atexit + termination signals",
             "atexit.register(_graceful_shutdown)" in srv
             and "SIGTERM" in srv and "SIGINT" in srv),
            ("reset_instance wipes then recreates the dir",
             "def reset_instance" in tmp
             and "_rmtree(_INSTANCE" in tmp),
            ("cleanup is hardened against Windows read-only leftovers",
             "def _rmtree" in tmp and "S_IWRITE" in tmp),
            ("DuckDB spill + db file live under the instance dir",
             'instance_path("duckdb_spill")' in eng
             and "tmputil.instance_path(" in eng
             and '/duckdb_spill")' not in eng
             and '+ "/duckdb_spill"' not in eng),
            ("parquet result store + large-file cache use instance temp",
             'new_tempfile("qr_"' in sess and 'new_tempfile("cache_"' in eng),
            ("the on-disk SQLite db lives under the instance dir",
             "dir=tmputil.instance_dir()" in eng),
            ("session shutdown closes remote connections then recycles engines",
             "interrupt_loads()" in sess
             and "for name, conn in list((self.connections" in sess
             and "sync_restore_manifest()" in sess
             and "self.clear_all(clear_manifest=False)" in sess
             and sess.index("interrupt_loads()")
             < sess.index("self.clear_all(clear_manifest=False)")
             and sess.index("self.connections.clear()")
             < sess.index("self.clear_all(clear_manifest=False)")),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "temp-cleanup wiring broken: " + "; ".join(missing))

    def t_session_shutdown_closes_connections():
        # A clean Exit→stop / Ctrl+C must close ODBC/SQL Server connections
        # before engines recycle, so the next start never inherits hung
        # driver sessions or locked spill files from a half-closed exit.
        s = _fresh_session()
        closed = []

        class _Conn:
            def close(self):
                closed.append(True)

        try:
            s.connections["mssql_prod"] = _Conn()
            s.shutdown()
            need(closed == [True], "remote connection.close() ran on shutdown")
            need(not s.connections, "connections map cleared on shutdown")
            need(getattr(s, "_closed", False), "session marked closed")
        finally:
            try:
                s.shutdown()
            except Exception:
                pass

    def t_json_streaming_parser():
        from samql_core.flatten import stream_json_records
        dd = tempfile.mkdtemp()

        def w(name, text):
            p = os.path.join(dd, name)
            with open(p, "w", encoding="utf-8") as f:
                f.write(text)
            return p

        eq(len(list(stream_json_records(
            w("a.json", '[{"x":1},{"x":2},{"x":3}]')))), 3, "array of objects")
        eq(len(list(stream_json_records(
            w("p.json", '[\n {"x":1},\n {"x":2}\n]\n')))), 2, "pretty array")
        eq(len(list(stream_json_records(
            w("n.jsonl", '{"x":1}\n{"x":2}\n\n{"x":3}\n')))), 3, "ndjson")
        eq(list(stream_json_records(w("o.json", '{"only":true}'))),
           [{"only": True}], "single object")
        eq(len(list(stream_json_records(
            w("c.json", '{"x":1} {"x":2}\n{"x":3}')))), 3, "concatenated")
        eq(list(stream_json_records(w("e.json", "[]"))), [], "empty array")
        # a value larger than one read chunk must still parse as one record
        big = '[{"id":1,"blob":"' + ("z" * 200000) + '"},{"id":2}]'
        recs = list(stream_json_records(w("big.json", big)))
        eq(len(recs), 2, "chunk-straddling element")
        eq(len(recs[0]["blob"]), 200000, "big value intact")

    def t_json_stream_spill_equiv():
        # streamed + spilled flatten must equal the whole-file flatten
        from samql_core.flatten import (stream_json_records, JSONFlattener,
                                        read_json_any_format)
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "equiv.json")
        data = [{"id": i, "user": {"name": f"n{i}"},
                 "tags": ["a", "b"][: 1 + (i % 2)]} for i in range(1500)]
        with open(p, "w", encoding="utf-8") as f:
            json.dump(data, f)
        fa = JSONFlattener(root_name="data")
        fa.flatten(read_json_any_format(p))
        fb = JSONFlattener(root_name="data", spill_threshold=100)
        try:
            for rec in stream_json_records(p):
                fb.add_record(rec)
            ta = {t: fa.row_count(t) for t in fa.table_names()}
            tb = {t: fb.row_count(t) for t in fb.table_names()}
            eq(tb, ta, "streamed+spill row counts differ from whole-file")
            eq(fb.columns("data"), fa.columns("data"), "column order differs")
        finally:
            fa.close()
            fb.close()

    def t_json_load_ndjson():
        # end-to-end NDJSON load through a Session, with spill forced low
        import samql_core.loaders as L
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "people.jsonl")
        with open(p, "w", encoding="utf-8") as f:
            for i in range(300):
                f.write(json.dumps({"id": i, "tags": ["a", "b"]}) + "\n")
        try:
            out = L.load_json(s.db, p, base_name="ppl", spill_threshold=50)
            counts = {o["name"]: o["rows"] for o in out}
            eq(counts.get("ppl"), 300, "ndjson root rows")
            eq(counts.get("ppl_tags"), 600, "ndjson child rows")
            n = s.run_query("SELECT COUNT(*) FROM ppl_tags",
                            target="__local__")["rows"][0][0]
            eq(n, 600, "child table not queryable")
        finally:
            s.shutdown()

    def t_duckdb_json_readers():
        # The DuckDB JSON reader list is NDJSON-aware. For .ndjson/.jsonl the
        # first reader pins format='newline_delimited' so DuckDB skips the
        # format-sniffing scan on huge files; for plain .json it auto-detects.
        # Both keep a tolerant retry and cap the per-object size. Pure string
        # builder, so this runs even without duckdb installed.
        from samql_core import engines as E
        fwd = "C:/data/huge.ndjson"
        eq(E._is_ndjson_path("a/b.ndjson"), True, ".ndjson is ndjson")
        eq(E._is_ndjson_path("a/b.JSONL"), True, ".jsonl is ndjson (any case)")
        eq(E._is_ndjson_path("a/b.json"), False, "plain .json is not ndjson")

        nd = E._json_readers(fwd, ndjson=True)
        need("format='newline_delimited'" in nd[0],
             "ndjson reads newline-delimited explicitly (no sniff)")
        need("read_json_auto" not in nd[0],
             "the fast ndjson reader does not auto-detect")
        need(any("ignore_errors=true" in r and "newline_delimited" in r
                 for r in nd),
             "a tolerant newline-delimited retry skips bad lines")
        need(any("read_json_auto" in r for r in nd),
             "a final auto-detect fallback covers a mislabelled extension")
        need(any("read_ndjson_objects" in r for r in nd),
             "typed JSON falls back to JSON-objects (VARCHAR-safe) reader")
        need(all("maximum_object_size=268435456" in r
                 for r in nd if "read_ndjson_objects" not in r),
             "every typed ndjson reader uses the bounded 256 MiB default")
        # Adaptive engines can sit at the 512 MiB floor; without a clamp the
        # default 256 MiB object size alone requests a ~512 MiB parser buffer
        # and nested JSON loads OOM before any rows are read.
        tight = E._json_readers(fwd, ndjson=True, memory_limit_mb=512)
        need(all("maximum_object_size=134217728" in r
                 for r in tight if "read_ndjson_objects" not in r),
             "object cap clamps to ~1/4 of a tight engine budget")
        eq(E._json_object_cap_bytes(512), 134217728,
           "_json_object_cap_bytes honors memory_limit_mb")
        eq(E._json_object_cap_bytes(None), 268435456,
           "no memory hint keeps the 256 MiB default")
        shallow = E._json_readers(fwd, ndjson=True, maximum_depth=2)
        need(all("maximum_depth=2" in r for r in shallow
                 if "read_ndjson_objects" not in r
                 and "read_json_objects" not in r),
             "flatten-off readers can pin maximum_depth")
        as_json = E._json_readers(fwd, ndjson=True, maximum_depth=0)
        need(all("read_ndjson_objects" in r or "read_json_objects" in r
                 for r in as_json),
             "depth 0 uses the JSON-objects readers")
        eq(E._json_shallow_depth_default(), 2,
           "default flatten-off depth is 2")
        old_depth = os.environ.get("SAMQL_JSON_MAX_DEPTH")
        try:
            os.environ["SAMQL_JSON_MAX_DEPTH"] = "0"
            eq(E._json_shallow_depth_default(), 0,
               "SAMQL_JSON_MAX_DEPTH=0 selects JSON-column mode")
            os.environ["SAMQL_JSON_MAX_DEPTH"] = "3"
            eq(E._json_shallow_depth_default(), 3,
               "SAMQL_JSON_MAX_DEPTH overrides shallow depth")
        finally:
            if old_depth is None:
                os.environ.pop("SAMQL_JSON_MAX_DEPTH", None)
            else:
                os.environ["SAMQL_JSON_MAX_DEPTH"] = old_depth
        need("_json_oom_hint" in dir(E) and callable(E._json_oom_hint),
             "OOM hint helper is exported for nested JSON failures")
        hint = E._json_oom_hint("C:/x.json", 512)
        need("out of memory" in hint.lower() and "512" in hint,
             "OOM hint mentions budget and nested JSON")
        old_cap = os.environ.get("SAMQL_JSON_OBJECT_MB")
        try:
            os.environ["SAMQL_JSON_OBJECT_MB"] = "64"
            need(all("maximum_object_size=67108864" in r
                     for r in E._json_readers(fwd, ndjson=True)
                     if "read_ndjson_objects" not in r),
                 "SAMQL_JSON_OBJECT_MB overrides the parser ceiling")
        finally:
            if old_cap is None:
                os.environ.pop("SAMQL_JSON_OBJECT_MB", None)
            else:
                os.environ["SAMQL_JSON_OBJECT_MB"] = old_cap

        js = E._json_readers(fwd, ndjson=False)
        need("read_json_auto" in js[0] and "newline_delimited" not in js[0],
             "plain json auto-detects array/object/ndjson")
        need(any("auto_detect=true" in r and "ignore_errors=true" in r
                 for r in js),
             "plain json keeps a tolerant retry")
        need(any("read_json_objects" in r for r in js),
             "plain json falls back to objects reader on type failures")
        old_j = os.environ.get("SAMQL_JSON_ONDISK_MB")
        try:
            os.environ.pop("SAMQL_JSON_ONDISK_MB", None)
            eq(E._json_ondisk_min_bytes(), 64 * 1024 * 1024,
               "nested JSON prefers on-disk Parquet from 64 MiB")
            os.environ["SAMQL_JSON_ONDISK_MB"] = "0"
            eq(E._json_ondisk_min_bytes(), None,
               "SAMQL_JSON_ONDISK_MB=0 disables the JSON floor")
        finally:
            if old_j is None:
                os.environ.pop("SAMQL_JSON_ONDISK_MB", None)
            else:
                os.environ["SAMQL_JSON_ONDISK_MB"] = old_j

    def t_duckdb_loads_ndjson():
        # End-to-end: a .ndjson file loaded with destination='duckdb' goes
        # through Session.load_file -- the same loader the drag-drop and
        # Load-files flows both call -- and lands a DuckDB table with the
        # expected columns/rows via the newline-delimited reader. Skips when
        # duckdb is absent.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "events.ndjson")
        with open(p, "w", encoding="utf-8") as f:
            for i in range(200):
                f.write(json.dumps({"id": i, "kind": "click"}) + "\n")
        try:
            out = s.load_file(p, destination="duckdb", base_name="ev")
            o = out[0]
            eq(o["engine"], "duckdb", "ndjson landed in duckdb")
            need("id" in o["columns"] and "kind" in o["columns"],
                 "ndjson columns parsed: %s" % o["columns"])
            n = s.run_query("SELECT COUNT(*) FROM ev",
                            target="__duckdb__")["rows"][0][0]
            eq(n, 200, "all ndjson rows loaded")
        finally:
            s.shutdown()

    def t_duckdb_struct_expand():
        # The decision for expanding a one-column JSON load into real columns.
        # A list-of-struct (the [{...}]-per-line NDJSON shape) is unnested
        # recursively; a bare struct is star-expanded; scalars / lists of
        # scalars / opaque JSON are left alone. Pure, so it runs without duckdb.
        from samql_core import engines as E
        eq(E._struct_expand_select("json", "STRUCT(a BIGINT, b VARCHAR)[]"),
           'UNNEST("json", recursive := true)',
           "list-of-struct is unnested recursively")
        eq(E._struct_expand_select("j", "STRUCT(x INTEGER)"), '"j".*',
           "a bare struct is star-expanded")
        eq(E._struct_expand_select("c", "struct(a int)[]"),
           'UNNEST("c", recursive := true)', "type match is case-insensitive")
        for typ in ("BIGINT[]", "VARCHAR", "JSON", "INTEGER", ""):
            eq(E._struct_expand_select("c", typ), None,
               "non-struct column left alone: %r" % typ)
        eq(E._struct_expand_select('we"ird', "STRUCT(a INT)"), '"we""ird".*',
           "the column name is quote-escaped")

    def t_duckdb_ndjson_array_wrapped():
        # End-to-end: NDJSON whose every line is a single-element array wrapping
        # an object ([{...}]) used to load as one opaque STRUCT[] column. With
        # flatten/shred ON, keys become real columns. Skips when duckdb is absent.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "wrapped.ndjson")
        with open(p, "w", encoding="utf-8") as f:
            for i in range(120):
                f.write(json.dumps([{"id": i, "name": f"r{i}"}]) + "\n")
        try:
            out = s.load_file(p, destination="duckdb", base_name="wrap",
                              flatten=False, shred=True)
            need(out and (out[0].get("table") or out[0].get("name")),
                 "array-wrapped load returned a table: %r" % out)
            # Prefer a shredded child/expanded table that exposes id+name.
            candidates = []
            for t in out:
                nm = t.get("table") or t.get("name")
                if nm:
                    candidates.append(nm)
                for child in (t.get("shredded") or []):
                    candidates.append(child)
            found = None
            cols = []
            for tbl in candidates:
                c = [x.lower() for x in (
                    getattr(s, "duckdb", None)
                    and getattr(s.duckdb, "table_columns", {}).get(tbl)
                    or [])]
                if not c:
                    try:
                        c = [x.lower() for x in s.run_query(
                            'SELECT * FROM "%s" LIMIT 0' % tbl,
                            target="__duckdb__")["columns"]]
                    except Exception:
                        c = []
                if "id" in c and "name" in c:
                    found, cols = tbl, c
                    break
            need(found and "id" in cols and "name" in cols,
                 "array-wrapped ndjson keys became columns: %s (tables=%r)"
                 % (cols, candidates))
            need(len(cols) >= 2, "expanded to multiple columns, not one struct")
            n = s.run_query('SELECT COUNT(*) FROM "%s"' % found,
                            target="__duckdb__")["rows"][0][0]
            eq(n, 120, "one row per wrapped object")
        finally:
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_json_stream_to_ndjson():
        # The large-array pre-pass now reuses the shared streaming reader
        # (flatten.stream_json_records) and is cancellable. Pure stdlib (no
        # duckdb): the array detector, the NDJSON writer round-trip, and that a
        # cancel callback aborts the read promptly instead of finishing it.
        from samql_core import engines as E
        dd = tempfile.mkdtemp()

        def write(name, text):
            p = os.path.join(dd, name)
            with open(p, "w", encoding="utf-8") as f:
                f.write(text)
            return p

        need(E._file_starts_with_array(write("a.json", '  \n [ {"a":1} ]')),
             "a top-level array is detected (after whitespace)")
        need(E._file_starts_with_array(write("b.json", '\ufeff[1,2]')),
             "a BOM before the array is handled")
        for nm, t in (("o.json", '{"a":1}'), ("nd.json", '{"a":1}\n{"a":2}'),
                      ("s.json", "42"), ("e.json", "   ")):
            need(not E._file_starts_with_array(write(nm, t)),
                 "non-array first-char check: %r" % t)

        eq(E._sniff_json_format(write("sa.json", '[{"a":1},{"a":2}]')),
           "array", "array sniff")
        eq(E._sniff_json_format(write("so.json", '{"a":1}')),
           "object", "single object sniff")
        eq(E._sniff_json_format(write("snd.json", '{"a":1}\n{"a":2}\n')),
           "ndjson", "ndjson sniff (.json extension)")
        eq(E._sniff_json_format(write("sc.json", '{"a":1}{"a":2}')),
           "concat", "concatenated objects sniff")
        eq(E._sniff_json_format(write("sca.json", '[{"a":1}][{"a":2}]')),
           "concat", "concatenated arrays sniff")
        eq(E._sniff_json_format(write("x.ndjson", '{"a":1}\n{"a":2}\n')),
           "ndjson", "ndjson extension short-circuits sniff")

        arr = '[{"a":1,"s":"has ] , } in it"},{"b":[1,2,{"c":3}]},"bare",7]'
        want = json.loads(arr)
        dst = os.path.join(dd, "out.ndjson")
        n = E._write_ndjson_from_stream(write("arr.json", arr), dst)
        eq(n, len(want), "one NDJSON line per array element")
        got = [json.loads(x) for x in open(dst, encoding="utf-8") if x.strip()]
        eq(got, want, "array round-trips through the streamed NDJSON")

        # Concatenated objects also rewrite to one NDJSON line per value.
        concat = '{"a":1}{"a":2}{"a":3}'
        dstc = os.path.join(dd, "concat.ndjson")
        nc = E._write_ndjson_from_stream(write("concat.json", concat), dstc)
        eq(nc, 3, "concat objects become three NDJSON lines")
        gotc = [json.loads(x) for x in open(dstc, encoding="utf-8") if x.strip()]
        eq(gotc, [{"a": 1}, {"a": 2}, {"a": 3}], "concat round-trip")

        dst2 = os.path.join(dd, "obj.ndjson")
        eq(E._write_ndjson_from_stream(write("obj.json", '{"x":9}'), dst2), 1,
           "a single object becomes one NDJSON line")

        raised = []
        try:
            E._write_ndjson_from_stream(
                write("big.json", arr), os.path.join(dd, "c.ndjson"),
                should_cancel=lambda: True)
        except InterruptedError:
            raised.append(True)
        need(raised,
             "should_cancel() True aborts the read with InterruptedError")

        # ijson yajl yields decimal.Decimal for numbers. Rewrite must serialize
        # them (orjson default / use_float) — otherwise the first record raises
        # and flatten-off falls into a multi-GB stream-flatten stall.
        from decimal import Decimal as _Dec
        need(E._json_dumps_default(_Dec("42")) == 42,
             "Decimal integers dump as int")
        need(isinstance(E._json_dumps_default(_Dec("1.5")), float),
             "Decimal fractions dump as float")
        deep = [{"id": i, "qty": i + 0.5,
                 "nest": {"a": i, "b": {"c": [i, i + 1]}}}
                for i in range(80)]
        deep_path = write("deep_arr.json", json.dumps(deep))
        deep_dst = os.path.join(dd, "deep.ndjson")
        nd = E._write_ndjson_from_stream(deep_path, deep_dst)
        eq(nd, 80, "deep array rewrite survives ijson Decimals")
        got_d = [json.loads(x) for x in open(deep_dst, encoding="utf-8")
                 if x.strip()]
        eq(len(got_d), 80, "deep NDJSON line count")
        eq(got_d[7]["id"], 7, "deep rewrite preserves ids")

        # _json_source_for_read rewrites every non-NDJSON shape to NDJSON;
        # true NDJSON is read in place.
        try:
            mgr = E.DuckDBManager() if feats.get("duckdb") else None
            if mgr is not None:
                try:
                    for label, text, expect_cleanup in (
                        ("arr.json", '[{"id":1},{"id":2}]', True),
                        ("concat.json", '{"id":1}{"id":2}', True),
                        ("obj.json", '{"id":1,"nest":{"a":2}}', True),
                        ("lines.json", '{"id":1}\n{"id":2}\n', False),
                    ):
                        p = write(label, text)
                        rp, is_nd, cleanup = mgr._json_source_for_read(p)
                        need(is_nd, "%s reads as ndjson" % label)
                        if expect_cleanup:
                            need(cleanup, "%s is rewritten to a temp NDJSON" % label)
                            try:
                                os.unlink(cleanup)
                            except Exception:
                                pass
                        else:
                            need(cleanup is None,
                                 "%s (already NDJSON) is read in place" % label)
                finally:
                    try:
                        mgr._conn.close()
                    except Exception:
                        pass
        except Exception:
            pass

    def t_duckdb_json_all_formats_convert():
        # Matrix: every JSON shape × flatten on/off goes through NDJSON→Parquet
        # conversion. Flatten-off keeps shallow nested JSON; flatten-on shreds
        # into relational tables. Covers array, NDJSON (.json + .ndjson),
        # concatenated objects, and a single nested object.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        dd = tempfile.mkdtemp()
        rows = [{"id": i, "name": "n%d" % i,
                 "nest": {"a": i, "tags": ["x", "y"]}}
                for i in range(200)]
        paths = {}
        # array
        paths["array"] = os.path.join(dd, "array.json")
        with open(paths["array"], "w", encoding="utf-8") as f:
            json.dump(rows, f)
        # NDJSON mislabelled as .json
        paths["ndjson_json"] = os.path.join(dd, "lines.json")
        with open(paths["ndjson_json"], "w", encoding="utf-8") as f:
            for r in rows:
                f.write(json.dumps(r) + "\n")
        # .ndjson extension
        paths["ndjson_ext"] = os.path.join(dd, "lines.ndjson")
        with open(paths["ndjson_ext"], "w", encoding="utf-8") as f:
            for r in rows:
                f.write(json.dumps(r) + "\n")
        # concatenated objects (no newlines)
        paths["concat"] = os.path.join(dd, "concat.json")
        with open(paths["concat"], "w", encoding="utf-8") as f:
            for r in rows:
                f.write(json.dumps(r))
        # single nested object with an array child
        paths["object"] = os.path.join(dd, "one.json")
        with open(paths["object"], "w", encoding="utf-8") as f:
            json.dump({"id": 1, "name": "root",
                       "items": [{"i": i, "s": "v%d" % i} for i in range(50)]},
                      f)

        for fmt, path in paths.items():
            for flatten in (False, True):
                s = _fresh_session()
                base = ("f" if flatten else "n") + "_" + fmt
                try:
                    out = s.load_file(path, destination="duckdb",
                                      base_name=base, flatten=flatten)
                    need(out and all(t.get("engine") == "duckdb" for t in out),
                         "%s flatten=%s landed in duckdb: %s" % (fmt, flatten, out))
                    names = {(t.get("name") or t.get("table")) for t in out}
                    if not flatten:
                        root = out[0]
                        root_name = root.get("name") or root.get("table")
                        eq(root.get("json_depth"), 2,
                           "%s flatten-off uses depth=2" % fmt)
                        # Small fixtures materialize in-engine (CTAS + expand).
                        # Parquet cache is reserved for files at/above the
                        # JSON on-disk threshold (see large-load tests).
                        need(root.get("storage") in (None, "parquet-cache",
                                                     "duckdb", "table"),
                             "%s flatten-off storage ok: %s" % (fmt, root))
                        if fmt == "object":
                            n = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % root_name,
                                target="__duckdb__")["rows"][0][0]
                            eq(n, 1, "%s flatten-off: one root row" % fmt)
                            need("items" in [c.lower() for c in root["columns"]],
                                 "%s flatten-off keeps items column: %s"
                                 % (fmt, root["columns"]))
                        else:
                            n = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % root_name,
                                target="__duckdb__")["rows"][0][0]
                            eq(n, len(rows),
                               "%s flatten-off row count" % fmt)
                            got = s.run_query(
                                'SELECT id, nest->>\'a\' FROM "%s" '
                                "WHERE id = 7" % root_name,
                                target="__duckdb__")["rows"]
                            eq(got, [[7, "7"]],
                               "%s flatten-off nested JSON queryable: %r"
                               % (fmt, got))
                    else:
                        # Flatten-on shreds into {base}_flattened + child tables.
                        need(all(t.get("method") == "flatten-table" for t in out),
                             "%s flatten-on uses flatten-table: %s" % (fmt, out))
                        if fmt == "object":
                            child = next(
                                (n for n in names
                                 if n and "item" in n.lower()), None)
                            need(child,
                                 "%s flatten-on created items child: %s"
                                 % (fmt, names))
                            n = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % child,
                                target="__duckdb__")["rows"][0][0]
                            eq(n, 50, "%s flatten-on child rows" % fmt)
                            hub = next(
                                (n for n in names
                                 if n == base + "_flattened"), None)
                            need(hub, "%s flatten-on hub table: %s" % (fmt, names))
                            hn = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % hub,
                                target="__duckdb__")["rows"][0][0]
                            eq(hn, 1, "%s flatten-on hub rows" % fmt)
                        else:
                            hub = next(
                                (n for n in names
                                 if n == base + "_flattened"),
                                None)
                            need(hub,
                                 "%s flatten-on hub ({base}_flattened): %s"
                                 % (fmt, names))
                            n = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % hub,
                                target="__duckdb__")["rows"][0][0]
                            eq(n, len(rows),
                               "%s flatten-on hub row count" % fmt)
                            child = next(
                                (n for n in names
                                 if n and n != hub
                                 and ("tag" in n.lower() or "nest" in n.lower())),
                                None)
                            need(child,
                                 "%s flatten-on tags child: %s" % (fmt, names))
                            cn = s.run_query(
                                'SELECT COUNT(*) FROM "%s"' % child,
                                target="__duckdb__")["rows"][0][0]
                            eq(cn, len(rows) * 2,
                               "%s flatten-on tags rows (2 per record)" % fmt)
                            got = s.run_query(
                                'SELECT id, nest_a FROM "%s" WHERE id = 7'
                                % hub,
                                target="__duckdb__")["rows"]
                            eq(got, [[7, 7]],
                               "%s flatten-on nested field shredded: %r"
                               % (fmt, got))
                finally:
                    s.shutdown()

    def t_duckdb_json_depth0_parquet_column():
        # Flatten-off with SAMQL_JSON_MAX_DEPTH=0 lands one JSON column per row
        # (the safest nested-off shape for multi-GB files). Small fixtures stay
        # in-engine CTAS; Parquet is used once size hits the on-disk threshold.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "rows.json")
        rows = [{"id": i, "nest": {"a": i}} for i in range(100)]
        with open(p, "w", encoding="utf-8") as f:
            json.dump(rows, f)
        old = os.environ.get("SAMQL_JSON_MAX_DEPTH")
        os.environ["SAMQL_JSON_MAX_DEPTH"] = "0"
        try:
            out = s.load_file(p, destination="duckdb", base_name="j0",
                              flatten=False)
            eq(out[0].get("json_depth"), 0, "depth 0 recorded on load")
            need(out[0].get("storage") in (None, "parquet-cache",
                                           "duckdb", "table"),
                 "depth 0 storage ok: %s" % out[0])
            cols = [c.lower() for c in out[0]["columns"]]
            need(cols == ["json"] or "json" in cols,
                 "depth 0 exposes a json column: %s" % cols)
            n = s.run_query("SELECT COUNT(*) FROM j0",
                            target="__duckdb__")["rows"][0][0]
            eq(n, 100, "depth 0 keeps every row")
            got = s.run_query(
                "SELECT json->>'id' FROM j0 WHERE cast(json->>'id' as integer) = 7",
                target="__duckdb__")["rows"]
            eq(got, [["7"]], "depth 0 JSON column is queryable: %r" % got)
        finally:
            if old is None:
                os.environ.pop("SAMQL_JSON_MAX_DEPTH", None)
            else:
                os.environ["SAMQL_JSON_MAX_DEPTH"] = old
            s.shutdown()

    def t_duckdb_json_flatten_on_flat_still_parquet():
        # Flatten-on always converts through Parquet first. Flat scalar rows
        # have nothing to shred, so the Parquet nested table stands.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "flat.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"id": i, "sym": "X", "qty": i} for i in range(150)], f)
        try:
            out = s.load_file(p, destination="duckdb", base_name="flat",
                              flatten=True)
            need(out[0].get("storage") == "parquet-cache"
                 or out[0].get("method") == "flatten-table",
                 "flatten-on flat JSON converted (parquet or shred): %s"
                 % out[0])
            n = s.run_query("SELECT COUNT(*) FROM flat",
                            target="__duckdb__")["rows"][0][0]
            eq(n, 150, "flat flatten-on keeps every row")
            cols = [c.lower() for c in out[0].get("columns") or []]
            if cols:
                need("id" in cols and "sym" in cols and "qty" in cols,
                     "flat columns present: %s" % cols)
        finally:
            s.shutdown()

    def t_duckdb_big_json_array_streams():
        # End-to-end: a single top-level JSON array loads via NDJSON→Parquet
        # then shreds (flatten on). Skips without duckdb.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "trades.json")
        rows = [{"id": i, "sym": "X%d" % (i % 7), "qty": i * 10}
                for i in range(30000)]
        with open(p, "w", encoding="utf-8") as f:
            json.dump(rows, f)
        try:
            out = s.load_file(p, destination="duckdb", base_name="trades",
                              flatten=True)
            cols = [c.lower() for c in out[0]["columns"]]
            need("id" in cols and "sym" in cols and "qty" in cols,
                 "array-of-objects keys became columns: %s" % cols)
            n = s.run_query("SELECT COUNT(*) FROM trades",
                            target="__duckdb__")["rows"][0][0]
            eq(n, 30000, "every array element became a row")
        finally:
            s.shutdown()

    def t_duckdb_large_object_stream_flattens():
        # A single nested object above SAMQL_JSON_STREAM_FLATTEN_MB must not try
        # to materialise as one DuckDB STRUCT -- it uses the Python streamer
        # with spill into DuckDB tables (the multi-GB nested-object path).
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        # ~1.2 MB single object with a nested array -- over a 1 MB flatten floor.
        blob = {
            "code": 1,
            "meta": {"a": 1, "b": {"c": 2}},
            "items": [{"i": i, "s": "x" * 80} for i in range(12000)],
        }
        p = os.path.join(dd, "one.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump(blob, f)
        old = os.environ.get("SAMQL_JSON_STREAM_FLATTEN_MB")
        os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = "1"
        try:
            out = s.load_file(p, destination="duckdb", base_name="one",
                              flatten=True)
            names = {t.get("name") or t.get("table") for t in out}
            need(any(n == "one" or (n and n.startswith("one")) for n in names),
                 "streamer produced a root table: %s" % names)
            need(all(t.get("engine") == "duckdb" for t in out),
                 "all streamer tables landed in duckdb")
            # Nested array becomes a child table with one row per item.
            child = next((n for n in names if n and "item" in n.lower()), None)
            need(child, "nested items array became a child table: %s" % names)
            n = s.run_query('SELECT COUNT(*) FROM "%s"' % child,
                            target="__duckdb__")["rows"][0][0]
            eq(n, 12000, "every nested item row survived the stream flatten")
        finally:
            if old is None:
                os.environ.pop("SAMQL_JSON_STREAM_FLATTEN_MB", None)
            else:
                os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = old
            s.shutdown()

    def t_flatten_off_array_stays_nested_not_stream_flatten():
        # Regression: array→NDJSON rewrite used to TypeError on ijson Decimals,
        # then flatten-off silently stream-flattened into many relational
        # tables (looked like a stall on multi-GB files). Flatten-off must
        # keep a single nested / Parquet-backed table.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        rows = [{"id": i, "sym": "X%d" % i,
                 "legs": [{"n": i, "cf": [{"a": i}, {"a": i + 1}]}],
                 "nest": {"lvl": {"deep": {"v": i}}}}
                for i in range(120)]
        p = os.path.join(dd, "arr.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump(rows, f)
        old = {k: os.environ.get(k) for k in (
            "SAMQL_JSON_ONDISK_MB", "SAMQL_JSON_STREAM_MB",
            "SAMQL_ONDISK_MB", "SAMQL_ONDISK_HARD_MB", "SAMQL_FILECACHE")}
        os.environ["SAMQL_JSON_ONDISK_MB"] = "0.000001"
        os.environ["SAMQL_JSON_STREAM_MB"] = "0.000001"
        os.environ["SAMQL_ONDISK_MB"] = "0.000001"
        os.environ["SAMQL_ONDISK_HARD_MB"] = "0"
        os.environ["SAMQL_FILECACHE"] = "0"
        try:
            out = s.load_file(p, destination="duckdb", base_name="nestarr",
                              flatten=False, shred=False)
            eq(len(out), 1, "flatten-off keeps one table, not stream-flatten: %r"
               % out)
            need(not any(t.get("shredded") or t.get("method") == "stream-flatten"
                         for t in out),
                 "no shred/stream-flatten on flatten-off: %r" % out)
            need(out[0].get("storage") in (None, "parquet-cache", "duckdb",
                                           "table"),
                 "flatten-off storage ok: %r" % out[0])
            n = s.run_query('SELECT COUNT(*) FROM "nestarr"',
                            target="__duckdb__")["rows"][0][0]
            eq(n, 120, "every array element loaded")
            cols = [c.lower() for c in (out[0].get("columns") or [])]
            need("id" in cols or "json" in cols,
                 "nested columns present (not shredded soup): %s" % cols)
        finally:
            for k, v in old.items():
                if v is None:
                    os.environ.pop(k, None)
                else:
                    os.environ[k] = v
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_flatten_off_native_fail_does_not_stream_flatten():
        # Flatten-off must not recover via stream-flatten (relational shred).
        from samql_core import loaders as L
        calls = {"stream": 0}

        def _fake_stream(*_a, **_k):
            calls["stream"] += 1
            return [{"name": "t", "engine": "duckdb",
                     "method": "stream-flatten"}]

        def _fake_native(*_a, **_k):
            raise RuntimeError("simulated nested load failure")

        o_sf, o_n = L._stream_flatten_into_duckdb, L._load_into_duckdb
        L._stream_flatten_into_duckdb = _fake_stream
        L._load_into_duckdb = _fake_native
        dd = tempfile.mkdtemp()
        try:
            p = os.path.join(dd, "arr.json")
            with open(p, "w", encoding="utf-8") as f:
                f.write('[{"a":1}]')

            class _Sess:
                def get_duckdb(self):
                    raise AssertionError("should not open duckdb here")

            raised = None
            try:
                L._load_json_duckdb(_Sess(), p, "arr", flatten=False)
            except RuntimeError as e:
                raised = e
            need(raised is not None, "flatten-off surfaces the error")
            need("Flatten off" in str(raised),
                 "error mentions Flatten off: %s" % raised)
            eq(calls["stream"], 0,
               "stream-flatten must not run on flatten-off failure")
        finally:
            L._stream_flatten_into_duckdb = o_sf
            L._load_into_duckdb = o_n
            shutil.rmtree(dd, ignore_errors=True)

    def t_flatten_off_parquet_nested_field_tree_and_page():
        # Flatten-off Parquet cache: DESCRIBE shows opaque JSON / JSON[] so the
        # sidebar used to say "no nested fields". Sample live values for a real
        # field tree. Also: SELECT * via zero-copy ParquetResultStore must page
        # non-empty rows (count matching a non-empty first page).
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core.diagnostics import profile_json_load, _resolve_path
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        rows = [{"id": i,
                 "legs": [{"n": i, "cf": [{"amt": i, "ccy": "USD"}]}],
                 "nest": {"deep": {"v": i, "tag": "t%d" % i}}}
                for i in range(40)]
        p = os.path.join(dd, "nested.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump(rows, f)
        old = {k: os.environ.get(k) for k in (
            "SAMQL_JSON_ONDISK_MB", "SAMQL_ONDISK_MB",
            "SAMQL_ONDISK_HARD_MB", "SAMQL_FILECACHE")}
        os.environ["SAMQL_ONDISK_MB"] = "0.000001"
        os.environ["SAMQL_ONDISK_HARD_MB"] = "0"
        os.environ["SAMQL_FILECACHE"] = "0"
        try:
            out = s.load_file(p, destination="duckdb", base_name="nested_ft",
                              flatten=False)
            need(out and out[0].get("storage") == "parquet-cache",
                 "forced Parquet-cache load: %r" % out)
            name = out[0]["name"]
            src = s.duckdb.table_sources.get(name)
            need(str(src).lower().endswith(".parquet"),
                 "table_sources is the Parquet cache: %r" % src)
            origin = (getattr(s.duckdb, "table_origins", {}) or {}).get(name)
            need(origin and os.path.samefile(origin, p),
                 "table_origins keeps the original JSON: %r" % origin)
            resolved = _resolve_path(s, name, None)
            need(resolved and os.path.samefile(resolved, p),
                 "_resolve_path prefers origin over cache: %r" % resolved)

            types = s.duckdb._column_types_raw(name)
            # Opaque JSON column (depth=0 style) via a dedicated load
            opaque = s.duckdb.load_file_to_parquet_view(
                "opaque_ft", p, "json", json_depth=0)
            otypes = s.duckdb._column_types_raw(opaque)
            ocol = next(iter(otypes))
            ot = s.column_field_tree("duckdb", opaque, ocol)
            onames = [f["name"] for f in ot.get("fields") or []]
            need("legs" in onames and "nest" in onames and "id" in onames,
                 "sampled field tree lists real JSON keys: %r" % onames[:12])
            need(ot.get("source") == "sampled-values",
                 "opaque JSON tree marks sampled-values source")

            # Depth-2 columns: JSON[] / STRUCT(... JSON) also need sampling
            for col in types:
                if "JSON" not in (types[col] or "").upper():
                    continue
                tree = s.column_field_tree("duckdb", name, col)
                names = [f["name"] for f in tree.get("fields") or []]
                need(names and names != ["(element)"],
                     "%s field tree not empty/opaque: type=%s names=%r"
                     % (col, types[col], names[:10]))
                if col == "legs":
                    need("n" in names or "cf" in names or "amt" in names,
                         "legs samples nested keys: %r" % names[:12])
                if col == "nest":
                    need("deep" in names or "v" in names or "tag" in names,
                         "nest samples nested keys: %r" % names[:12])

            q = s.run_query('SELECT * FROM "%s"' % name, target="__duckdb__")
            eq(q.get("total_rows"), len(rows), "query total_rows")
            need(len(q.get("rows") or []) > 0,
                 "inline first page is non-empty")
            store = s._results[q["result_id"]].store
            need(type(store).__name__ == "ParquetResultStore",
                 "zero-copy ParquetResultStore path: %s"
                 % type(store).__name__)
            page = s.page(q["result_id"], 0, 10)
            eq(page.get("total_rows"), len(rows), "page total_rows")
            need(len(page.get("rows") or []) == 10,
                 "page returns 10 rows, not empty: %r"
                 % (page.get("rows") or [])[:1])
            need(page["rows"][0][0] is not None
                 or any(c is not None for c in page["rows"][0]),
                 "first page row has cell data: %r" % page["rows"][0])

            # Profiler includes the flatten-off Parquet path timing
            pr = profile_json_load(p, max_records=15, session=s)
            need(isinstance(pr.get("flatten_off_parquet"), dict),
                 "profiler reports flatten_off_parquet: %r"
                 % list(pr.keys())[:20])
            fop = pr["flatten_off_parquet"]
            need(not fop.get("skipped") or fop.get("reason"),
                 "parquet profile ran or explained skip: %r" % fop)
            if not fop.get("skipped") and not fop.get("error"):
                need(fop.get("maximum_depth") == 2,
                     "profiler uses depth=2: %r" % fop)
                need("native_parquet_s" in fop,
                     "profiler times native Parquet COPY: %r" % fop)
            need("sampling" in (pr.get("nested_discovery") or "").lower()
                 and "live cell" in (pr.get("nested_discovery") or "").lower(),
                 "profiler notes live-cell nested discovery: %r"
                 % pr.get("nested_discovery"))
        finally:
            for k, v in old.items():
                if v is None:
                    os.environ.pop(k, None)
                else:
                    os.environ[k] = v
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_json_array_element_field_tree_double_encoded():
        # Flatten-off / opaque JSON often stores arrays as JSON / JSON[] whose
        # elements are *stringified* objects (double-encoded). Field discovery
        # must expand those under "(element)" so the sidebar shows real keys
        # (id, version, cashflow, ...) — not a dead-end "(element)" leaf.
        from samql_core.diagnostics import (json_values_to_field_tree,
                                            _coerce_json_sample)
        objs = [
            {"id": 1, "version": 5,
             "cashflow": [{"type": "FIXED", "amt": 1.0, "ccy": "USD"}]},
            {"id": 2, "version": 6,
             "cashflow": [{"type": "FLOAT", "amt": 2.0, "ccy": "EUR"}]},
        ]
        # Cell is a JSON array of stringified objects (user-reported shape).
        cell = json.dumps([json.dumps(o) for o in objs])
        coerced = _coerce_json_sample(cell)
        need(isinstance(coerced, list) and isinstance(coerced[0], dict),
             "coerce peels double-encoded array elements: %r"
             % (type(coerced[0]).__name__ if coerced else None,))
        need(coerced[0].get("id") == 1 and "cashflow" in coerced[0],
             "coerced element has object keys: %r" % (coerced[0] if coerced else None,))
        ft = json_values_to_field_tree([cell], colname="data")
        names = [n["name"] for n in ft.get("nodes") or []]
        need("(element)" in names, "array wrapper present: %r" % names[:12])
        for key in ("id", "version", "cashflow"):
            need(key in names,
                 "nested key %r under (element): %r" % (key, names[:16]))
        need("type" in names or "amt" in names or "ccy" in names,
             "cashflow element fields visible: %r" % names[:20])

        # JSON[] cell: Python list of stringified objects (DuckDB read shape).
        listed = [json.dumps(o) for o in objs]
        ft2 = json_values_to_field_tree([listed], colname="data")
        names2 = [n["name"] for n in ft2.get("nodes") or []]
        need("id" in names2 and "cashflow" in names2,
             "JSON[] of stringified objects expands: %r" % names2[:16])

        if not feats["duckdb"]:
            return
        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            # Live DuckDB JSON cell matching the double-encoded array shape.
            duck.conn.execute(
                "CREATE OR REPLACE TABLE dbl_el AS SELECT ?::JSON AS data",
                [cell])
            tree = s.column_field_tree("duckdb", "dbl_el", "data")
            tnames = [f["name"] for f in tree.get("fields") or []]
            need(tree.get("source") == "sampled-values",
                 "sampled-values source for opaque JSON array")
            need(tnames != ["(element)"],
                 "not a dead-end (element) leaf: %r" % tnames[:12])
            for key in ("id", "version", "cashflow"):
                need(key in tnames,
                     "column_field_tree lists %r under (element): %r"
                     % (key, tnames[:16]))
            by = {f["name"] + ":" + str(f["depth"]): f for f in tree["fields"]}
            el = by.get("(element):1") or {}
            need(el.get("kind") in ("struct", "array"),
                 "(element) is expandable, not opaque scalar: %r" % el)
            # Opaque JSON array cells use JSONPath ([0]), not STRUCT list [1].
            # (Older assertion required "[1]" from STRUCT-style recipes that
            # returned NULL / failed UNNEST on JSON arrays — that was wrong.)
            id_acc = (by.get("id:2") or {}).get("access") or {}
            need(id_acc.get("first") and (
                    "[0]" in id_acc["first"] or "[1]" in id_acc["first"]),
                 "id recipe hops the array: %r" % id_acc)
            need("->>" in (id_acc.get("first") or ""),
                 "opaque JSON array recipe uses ->>: %r" % id_acc.get("first"))
            id_sql = "SELECT %s FROM dbl_el" % id_acc["first"]
            eq(duck.conn.execute(id_sql).fetchall(), [("1",)],
               "id first-record recipe executes: %s" % id_sql)
            cf = by.get("cashflow:2") or {}
            need((cf.get("access") or {}).get("recursive")
                 or (cf.get("kind") == "array"),
                 "cashflow keeps array access recipe: %r" % cf.get("access"))

            # JSON[] column of stringified records (flatten-off nested array).
            duck.conn.execute("""
                CREATE OR REPLACE TABLE jarr_el AS
                SELECT CAST([
                  '{"id":1,"version":5,"cashflow":[{"type":"FIXED","amt":1.0}]}',
                  '{"id":2,"version":6,"cashflow":[{"type":"FLOAT","amt":2.0}]}'
                ] AS JSON[]) AS data
            """)
            jt = s.column_field_tree("duckdb", "jarr_el", "data")
            jnames = [f["name"] for f in jt.get("fields") or []]
            need("id" in jnames and "version" in jnames and "cashflow" in jnames,
                 "JSON[] field tree nests object keys under (element): %r"
                 % jnames[:16])
        finally:
            s.shutdown()

    def t_json_field_tree_deep_nested_and_heterogeneous():
        # Cashflow-style depth (col→array→object→array→object→array→scalars)
        # plus ragged array elements whose unique keys appear late (past the
        # old 8-element merge cap) and mixed STRUCT+JSON DESCRIBE shells that
        # used to skip live-cell sampling.
        from samql_core import session as S
        from samql_core.diagnostics import json_values_to_field_tree
        deep = {
            "code": "X",
            "trades": [{
                "tid": 1,
                "legs": [{
                    "side": "PAY",
                    "cashflows": [{
                        "cf_type": "FIXED",
                        "schedule": [
                            {"pay_date": "2024-01-01", "amt": 1.0,
                             "ccy": "USD"},
                        ],
                    }],
                }],
            }],
        }
        ft = json_values_to_field_tree([deep], colname="json")
        names = [n["name"] for n in ft.get("nodes") or []]
        depths = {n["name"]: n["depth"] for n in ft.get("nodes") or []}
        for key in ("trades", "legs", "cashflows", "schedule",
                    "pay_date", "amt", "ccy", "cf_type", "side", "tid"):
            need(key in names,
                 "deep cashflow tree lists %r: %r" % (key, names))
        need(depths.get("pay_date", 0) >= 5,
             "pay_date is at depth 5+: %r" % depths.get("pay_date"))
        need(max(n["depth"] for n in ft["nodes"]) >= 6,
             "tree walks past depth 5: max=%d" % max(
                 n["depth"] for n in ft["nodes"]))

        # Heterogeneous array: unique keys only after element 8, plus a nested
        # array-of-arrays shape under a late element.
        ragged = {
            "items": ([{"k": i} for i in range(10)]
                      + [{"late_key": 99,
                          "matrix": [[{"deep_z": 1, "only_late": True}]]}]),
        }
        ft2 = json_values_to_field_tree([ragged], colname="json")
        names2 = [n["name"] for n in ft2.get("nodes") or []]
        need("late_key" in names2,
             "union keys across array elements (late_key): %r" % names2)
        need("deep_z" in names2 and "only_late" in names2,
             "nested array-of-array under late element: %r" % names2)
        need("k" in names2,
             "early element keys still merged: %r" % names2)

        # Different keys on different top-level array elements must union.
        hetero = [
            {"a": 1, "shared": True},
            {"b": 2, "shared": True},
            {"c": {"inner_only": 3}},
        ]
        ft3 = json_values_to_field_tree(hetero, colname="json")
        names3 = [n["name"] for n in ft3.get("nodes") or []]
        for key in ("a", "b", "c", "shared", "inner_only"):
            need(key in names3,
                 "heterogeneous records union key %r: %r" % (key, names3))

        # Mixed STRUCT+JSON DESCRIBE leaf used to return needs_sample=False.
        from samql_core.diagnostics import (parse_duckdb_type,
                                            flatten_type_tree)
        raw = "STRUCT(id INTEGER, nest JSON)"
        node = parse_duckdb_type(raw)
        rows = flatten_type_tree("col", node)
        fields = rows[1:] if rows and rows[0].get("depth") == 0 else rows
        need(S.Session._field_tree_needs_json_sample(raw, fields),
             "mixed STRUCT+JSON leaf must trigger live-cell sampling")
        raw2 = ("STRUCT(trades STRUCT(id INTEGER, "
                "legs STRUCT(n INTEGER, cf JSON)[])[])")
        node2 = parse_duckdb_type(raw2)
        rows2 = flatten_type_tree("col", node2)
        fields2 = rows2[1:] if rows2 and rows2[0].get("depth") == 0 else rows2
        need(S.Session._field_tree_needs_json_sample(raw2, fields2),
             "deep STRUCT shell with JSON leaf samples: %r"
             % [f.get("name") for f in fields2])

        if not feats["duckdb"]:
            return
        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            # Live flatten-off-style cell: typed shell + opaque JSON nest.
            duck.conn.execute(
                "CREATE OR REPLACE TABLE mixed_ft AS "
                "SELECT 7 AS id, ?::JSON AS nest",
                [json.dumps({"trades": [{
                    "legs": [{"cashflows": [{"schedule": [
                        {"pay_date": "2025-06-01", "amt": 9.5}]}]}]}]})])
            # Probe the JSON column directly (opaque leaf case).
            tree = s.column_field_tree("duckdb", "mixed_ft", "nest")
            tnames = [f["name"] for f in tree.get("fields") or []]
            need(tree.get("source") == "sampled-values",
                 "JSON nest column uses sampled-values: %r" % tree)
            for key in ("trades", "legs", "cashflows", "schedule",
                        "pay_date", "amt"):
                need(key in tnames,
                     "live nest expands deep key %r: %r" % (key, tnames))
            # Also: a true STRUCT column with a JSON leaf (maximum_depth style).
            duck.conn.execute("""
                CREATE OR REPLACE TABLE struct_json_leaf AS
                SELECT {
                    'id': 1,
                    'nest': '{"deep":{"v":42,"tag":"z"}}'::JSON
                } AS payload
            """)
            st = s.column_field_tree("duckdb", "struct_json_leaf", "payload")
            snames = [f["name"] for f in st.get("fields") or []]
            # DESCRIBE alone would stop at nest:JSON; sampling must expand it.
            need(st.get("source") == "sampled-values"
                 or ("deep" in snames or "v" in snames or "tag" in snames),
                 "STRUCT+JSON leaf expands nested keys: source=%r names=%r"
                 % (st.get("source"), snames[:20]))
            need("deep" in snames or "v" in snames or "tag" in snames,
                 "nested keys under JSON leaf visible: %r" % snames[:20])
        finally:
            s.shutdown()

    def t_cashflows_receiving_leg_field_tree():
        # Exact user shape: object → nested array of objects → scalar
        # CashFlows.receivingLeg[].fixingdate — must appear under the column
        # in column_field_tree / field explorer (incl. opaque JSON leaf,
        # JSON[] elements, double-encoded strings, and original key casing).
        from samql_core.diagnostics import json_values_to_field_tree

        shape = {"CashFlows": {"receivingLeg": [{"fixingdate": "test"}]}}
        ft = json_values_to_field_tree([shape], colname="payload")
        names = [n["name"] for n in ft.get("nodes") or []]
        for key in ("CashFlows", "receivingLeg", "(element)", "fixingdate"):
            need(key in names,
                 "CashFlows shape lists %r: %r" % (key, names))
        need("fixingDate" not in names,
             "key casing preserved (fixingdate, not fixingDate): %r" % names)

        # Opaque JSON string leaf under a STRUCT-like shell.
        opaque = {"CashFlows": json.dumps(
            {"receivingLeg": [{"fixingdate": "test"}]})}
        ft2 = json_values_to_field_tree([opaque], colname="payload")
        names2 = [n["name"] for n in ft2.get("nodes") or []]
        need("receivingLeg" in names2 and "fixingdate" in names2,
             "opaque CashFlows JSON leaf expands: %r" % names2)

        # receivingLeg as array of stringified objects (JSON[]-style cells).
        jarr = {"CashFlows": {"receivingLeg": [
            json.dumps({"fixingdate": "test"})]}}
        ft3 = json_values_to_field_tree([jarr], colname="payload")
        names3 = [n["name"] for n in ft3.get("nodes") or []]
        need("fixingdate" in names3,
             "stringified receivingLeg elements expand: %r" % names3)

        # Whole cell double-encoded.
        ft4 = json_values_to_field_tree([json.dumps(shape)], colname="payload")
        names4 = [n["name"] for n in ft4.get("nodes") or []]
        need("CashFlows" in names4 and "fixingdate" in names4,
             "double-encoded cell expands CashFlows tree: %r" % names4)

        if not feats["duckdb"]:
            return
        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            duck.conn.execute(
                "CREATE OR REPLACE TABLE cf_leg AS SELECT ?::JSON AS payload",
                [json.dumps(shape)])
            tree = s.column_field_tree("duckdb", "cf_leg", "payload")
            tnames = [f["name"] for f in tree.get("fields") or []]
            need(tree.get("source") == "sampled-values",
                 "live CashFlows column uses sampled-values")
            for key in ("CashFlows", "receivingLeg", "(element)", "fixingdate"):
                need(key in tnames,
                     "column_field_tree lists %r: %r" % (key, tnames))

            duck.conn.execute("""
                CREATE OR REPLACE TABLE cf_struct_leaf AS
                SELECT {'id': 1, 'CashFlows': ?::JSON} AS payload
            """, [json.dumps({"receivingLeg": [{"fixingdate": "test"}]})])
            st = s.column_field_tree("duckdb", "cf_struct_leaf", "payload")
            snames = [f["name"] for f in st.get("fields") or []]
            need("receivingLeg" in snames and "fixingdate" in snames,
                 "STRUCT+JSON CashFlows leaf expands: %r" % snames[:20])
        finally:
            s.shutdown()

    def t_field_tree_skips_empty_array_prefix_rows():
        # Intermittent Field Explorer bug: early rows with empty nested arrays
        # (contacts: []) made live-cell sampling emit a dead-end "(element)"
        # and hide real keys that only appear later in the table. Discovery
        # must keep sampling past the hollow prefix (still discovery-only).
        from samql_core.diagnostics import (json_values_to_field_tree,
                                            _json_shape_has_hollow_array,
                                            _json_tree_new, _json_tree_merge,
                                            _coerce_json_sample)

        hollow = {"lei": "x", "name": "y", "contacts": []}
        full = {"lei": "x", "name": "y", "contacts": [
            {"role": "trader", "email": "t@x.com", "phones": ["1"]},
        ]}
        ft_h = json_values_to_field_tree([hollow], colname="counterparty")
        hnames = [n["name"] for n in ft_h.get("nodes") or []]
        need("contacts" in hnames,
             "empty contacts still listed as an array: %r" % hnames)
        need("role" not in hnames,
             "empty array has no element keys yet: %r" % hnames)
        # No dead-end "(element)" placeholder for a shape-less array.
        need("(element)" not in hnames,
             "hollow array must not emit dead-end (element): %r" % hnames)

        root = _json_tree_new()
        _json_tree_merge(root, _coerce_json_sample(hollow), 0)
        need(_json_shape_has_hollow_array(root),
             "empty nested array is detected as hollow for re-sample")
        _json_tree_merge(root, _coerce_json_sample(full), 0)
        need(not _json_shape_has_hollow_array(root),
             "populated contacts clears hollow flag")

        if not feats.get("duckdb"):
            skip("duckdb not available")

        rows = []
        for i in range(100):
            rows.append({
                "tradeId": "T-%d" % i,
                "counterparty": {
                    "lei": "LEI", "name": "EmptyCo", "contacts": [],
                },
            })
        rows.append({
            "tradeId": "T-FULL",
            "counterparty": {
                "lei": "LEI-FULL", "name": "FullCo",
                "contacts": [
                    {"role": "trader", "email": "t@x.com", "phones": ["1"]},
                ],
            },
        })
        path = os.path.join(tempfile.mkdtemp(prefix="samql_ft_hollow_"),
                            "empty_prefix.json")
        with open(path, "w", encoding="utf-8") as fh:
            json.dump(rows, fh)
        s = _fresh_session()
        try:
            loaded = s.load_file(path, destination="duckdb",
                                 flatten=False, shred=False)
            need(isinstance(loaded, list) and loaded,
                 "flatten-off load produced a table")
            name = loaded[0]["name"]
            # Single-pass LIMIT 80 would only see empty contacts.
            need(Session._FIELD_TREE_SAMPLE_ROWS < 100,
                 "test assumes default sample batch < empty prefix")
            tree = s.column_field_tree("duckdb", name, "counterparty")
            tnames = [f["name"] for f in tree.get("fields") or []]
            need(tree.get("source") == "sampled-values",
                 "uses live-cell sampling: %r" % tree.get("source"))
            need(tnames != ["lei", "name", "contacts", "(element)"],
                 "must not stop at dead-end (element): %r" % tnames)
            for key in ("role", "email", "phones"):
                need(key in tnames,
                     "keys after empty-array prefix listed %r: %r"
                     % (key, tnames))
            # Unified Field Explorer tree must show them too.
            ft = s.table_field_tree("duckdb", name)
            fnames = [f["name"] for f in (ft.get("fields") or [])]
            need("role" in fnames and "email" in fnames,
                 "table_field_tree lists contacts element keys: %r"
                 % fnames[:40])

            # Keys past the sequential MAX budget: mid/end window probes must
            # still find them (empty prefix longer than SAMPLE_MAX_ROWS).
            long_rows = []
            empty_n = int(Session._FIELD_TREE_SAMPLE_MAX_ROWS) + 50
            for i in range(empty_n):
                long_rows.append({
                    "tradeId": "L-%d" % i,
                    "counterparty": {
                        "lei": "LEI", "name": "EmptyCo", "contacts": [],
                    },
                })
            long_rows.append({
                "tradeId": "L-FULL",
                "counterparty": {
                    "lei": "LEI-FULL", "name": "FullCo",
                    "contacts": [
                        {"role": "ops", "email": "o@x.com", "phones": ["9"]},
                    ],
                },
            })
            long_path = os.path.join(os.path.dirname(path),
                                     "empty_prefix_long.json")
            with open(long_path, "w", encoding="utf-8") as fh:
                json.dump(long_rows, fh)
            loaded2 = s.load_file(long_path, destination="duckdb",
                                  flatten=False, shred=False)
            need(isinstance(loaded2, list) and loaded2,
                 "long empty-prefix load produced a table")
            name2 = loaded2[0]["name"]
            tree2 = s.column_field_tree("duckdb", name2, "counterparty")
            tnames2 = [f["name"] for f in tree2.get("fields") or []]
            need("role" in tnames2 and "email" in tnames2,
                 "mid/end probes find keys past SAMPLE_MAX: %r" % tnames2)

            # Optional empty sibling must not force max scan once contacts
            # already has element keys (resolved-array early exit).
            from samql_core.diagnostics import _json_shape_has_resolved_array
            mixed = {
                "contacts": [{"role": "t"}],
                "tags": [],
            }
            root_m = _json_tree_new()
            _json_tree_merge(root_m, _coerce_json_sample(mixed), 0)
            need(_json_shape_has_hollow_array(root_m),
                 "empty tags still counts as hollow")
            need(_json_shape_has_resolved_array(root_m),
                 "populated contacts counts as resolved")
        finally:
            s.shutdown()
            try:
                shutil.rmtree(os.path.dirname(path), ignore_errors=True)
            except Exception:
                pass

    def t_field_explorer_recipes_execute():
        # Field Explorer copies access.first / access.sel + unnests into SQL.
        # Those recipes must actually run against flatten-off opaque JSON,
        # JSON[], STRUCT+JSON, and still preserve native STRUCT recipes.
        # Assert by EXECUTING the generated SQL (not only that recipes exist).
        if not feats["duckdb"]:
            skip("duckdb not installed")

        def _recipe_sqls(table, acc):
            from samql_core.diagnostics import field_access_sql
            first = field_access_sql(table, acc, which="first")
            # Preview recipes include LIMIT 50; execute tests need the full
            # explode, so strip the trailing LIMIT for equivalence checks.
            all_sql = field_access_sql(table, acc, which="all")
            need(first and all_sql, "field_access_sql builds first/all")
            if all_sql.upper().rstrip().endswith("LIMIT 50"):
                all_sql = all_sql[: all_sql.upper().rfind("LIMIT 50")].rstrip()
            return first, all_sql

        def _fixing(fields):
            hits = [f for f in fields if f.get("name") == "fixingdate"]
            need(hits, "fixingdate node present for recipe execute test")
            acc = hits[-1].get("access") or {}
            need(acc.get("first") and acc.get("sel") is not None,
                 "fixingdate carries first/sel recipes: %r" % acc)
            return acc

        shape = {"CashFlows": {"receivingLeg": [
            {"fixingdate": "test", "amt": 1.5},
            {"fixingdate": "test2", "amt": 2.0},
        ]}}
        s = _fresh_session()
        try:
            duck = s.get_duckdb()

            # 1) Opaque JSON column (flatten-off style)
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fx_json AS SELECT ?::JSON AS payload",
                [json.dumps(shape)])
            tree = s.column_field_tree("duckdb", "fx_json", "payload")
            need(tree.get("source") == "sampled-values",
                 "opaque JSON uses sampled-values recipes")
            acc = _fixing(tree.get("fields") or [])
            need("->>" in (acc.get("first") or ""),
                 "opaque JSON first recipe uses ->>: %r" % acc.get("first"))
            need("[0]" in (acc.get("first") or ""),
                 "JSONPath uses 0-based array index: %r" % acc.get("first"))
            need("payload.CashFlows.receivingLeg[1]" not in (acc.get("first") or ""),
                 "must not emit STRUCT-style [1] path for opaque JSON")
            sql1, sql2 = _recipe_sqls("fx_json", acc)
            eq(duck.conn.execute(sql1).fetchall(), [("test",)],
               "opaque JSON first-record recipe returns fixingdate")
            rows = duck.conn.execute(sql2).fetchall()
            need(sorted(r[0] for r in rows) == ["test", "test2"],
                 "opaque JSON all-rows recipe unnests receivingLeg: %r" % rows)

            # 2) JSON[] column
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fx_jarr AS "
                "SELECT [?::JSON]::JSON[] AS data",
                [json.dumps(shape)])
            jt = s.column_field_tree("duckdb", "fx_jarr", "data")
            jacc = _fixing(jt.get("fields") or [])
            need("data[1]" in (jacc.get("first") or ""),
                 "JSON[] first hops the list with [1]: %r" % jacc.get("first"))
            need("->>" in (jacc.get("first") or ""),
                 "JSON[] nested path still uses ->>: %r" % jacc.get("first"))
            js1, js2 = _recipe_sqls("fx_jarr", jacc)
            eq(duck.conn.execute(js1).fetchall(), [("test",)],
               "JSON[] first-record recipe returns fixingdate")
            jrows = duck.conn.execute(js2).fetchall()
            need(sorted(r[0] for r in jrows) == ["test", "test2"],
                 "JSON[] all-rows recipe works: %r" % jrows)

            # 3) STRUCT shell + opaque JSON leaf (common flatten-off DESCRIBE)
            duck.conn.execute("""
                CREATE OR REPLACE TABLE fx_mixed AS
                SELECT {'id': 1, 'CashFlows': ?::JSON} AS payload
            """, [json.dumps({"receivingLeg": [
                {"fixingdate": "test"}, {"fixingdate": "test2"}]})])
            mt = s.column_field_tree("duckdb", "fx_mixed", "payload")
            need(mt.get("source") == "sampled-values",
                 "STRUCT+JSON leaf triggers sampling")
            macc = _fixing(mt.get("fields") or [])
            need("::JSON" in (macc.get("first") or "")
                 and "->>" in (macc.get("first") or ""),
                 "STRUCT+JSON recipes cast then ->>: %r" % macc.get("first"))
            ms1, ms2 = _recipe_sqls("fx_mixed", macc)
            eq(duck.conn.execute(ms1).fetchall(), [("test",)],
               "STRUCT+JSON first-record recipe returns fixingdate")
            mrows = duck.conn.execute(ms2).fetchall()
            need(sorted(r[0] for r in mrows) == ["test", "test2"],
                 "STRUCT+JSON all-rows recipe works: %r" % mrows)

            # 3b) Double-encoded JSON array (elements are stringified objects)
            dbl = json.dumps([json.dumps({"id": 1, "fixingdate": "test"}),
                              json.dumps({"id": 2, "fixingdate": "test2"})])
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fx_dbl AS SELECT ?::JSON AS data",
                [dbl])
            dt = s.column_field_tree("duckdb", "fx_dbl", "data")
            dacc = _fixing(dt.get("fields") or [])
            need("json(" in (dacc.get("first") or ""),
                 "double-encoded recipes decode elements: %r" % dacc.get("first"))
            ds1, ds2 = _recipe_sqls("fx_dbl", dacc)
            eq(duck.conn.execute(ds1).fetchall(), [("test",)],
               "double-encoded first-record recipe returns fixingdate")
            drows = duck.conn.execute(ds2).fetchall()
            need(sorted(r[0] for r in drows) == ["test", "test2"],
                 "double-encoded all-rows recipe works: %r" % drows)

            # 4) Native STRUCT (no sampling) — STRUCT recipes must still work
            duck.conn.execute("""
                CREATE OR REPLACE TABLE fx_native AS
                SELECT {'CashFlows': {'receivingLeg': [
                    {'fixingdate': 'test'}, {'fixingdate': 'test2'}
                ]}} AS payload
            """)
            nt = s.column_field_tree("duckdb", "fx_native", "payload")
            need(nt.get("source") in (None, ""),
                 "native STRUCT does not sample: %r" % nt.get("source"))
            nacc = _fixing(nt.get("fields") or [])
            need("->>" not in (nacc.get("first") or ""),
                 "native STRUCT keeps dotted recipes: %r" % nacc.get("first"))
            need("[1]" in (nacc.get("first") or ""),
                 "native STRUCT uses 1-based list index: %r" % nacc.get("first"))
            ns1, ns2 = _recipe_sqls("fx_native", nacc)
            eq(duck.conn.execute(ns1).fetchall(), [("test",)],
               "native STRUCT first-record recipe still works")
            nrows = duck.conn.execute(ns2).fetchall()
            need(sorted(r[0] for r in nrows) == ["test", "test2"],
                 "native STRUCT UNNEST recipe still works: %r" % nrows)

            # 5) Nested array-inside-array element (list under list element)
            nest = [{"oid": 1, "li": [{"sku": "a"}, {"sku": "b"}]},
                    {"oid": 2, "li": [{"sku": "c"}]}]
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fx_nest AS SELECT ?::JSON AS payload",
                [json.dumps(nest)])
            nt2 = s.column_field_tree("duckdb", "fx_nest", "payload")
            sku_hits = [f for f in (nt2.get("fields") or [])
                        if f.get("name") == "sku"]
            need(sku_hits, "nested sku under li appears in field tree")
            sacc = sku_hits[-1].get("access") or {}
            need(sacc.get("first") and "->>" in (sacc.get("first") or ""),
                 "nested-array sku has JSON recipe: %r" % sacc)
            ss1, ss2 = _recipe_sqls("fx_nest", sacc)
            eq(duck.conn.execute(ss1).fetchall(), [("a",)],
               "nested-array first recipe returns sku")
            srows = duck.conn.execute(ss2).fetchall()
            need(sorted(r[0] for r in srows) == ["a", "b", "c"],
                 "nested-array all-rows recipe retains every sku: %r" % srows)

            # 6) access-preview validates + falls back
            prev = s.preview_column_access(
                "duckdb", "fx_json", "payload", field_path="fixingdate")
            need(prev.get("ok"), "preview ok for opaque JSON: %r" % prev)
            need(prev.get("sample") == "test",
                 "preview sample is non-NULL: %r" % prev.get("sample"))
            need(prev.get("sql"), "preview returns validated SQL")
        finally:
            s.shutdown()

    def t_field_explorer_unnest_cte_pipeline():
        # CODE was wrong (slow): Field Explorer All-rows used comma-FROM
        # UNNEST hops. CTE pipelines return the SAME exact rows/counts and
        # are what field_access_sql emits now. Preserve shred/flatten paths.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core.diagnostics import (
            build_unnest_pipeline_sql, field_access_sql, parse_unnest_as_clause)

        hop = parse_unnest_as_clause(
            "UNNEST(from_json(json_extract(payload, '$.legs'), '[\"JSON\"]')) "
            "AS x1(e1)")
        need(hop and hop[1] == "x1" and hop[2] == "e1",
             "parse_unnest_as_clause handles nested from_json parens: %r" % (hop,))

        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            duck.conn.execute("""
                CREATE OR REPLACE TABLE fx_cte AS
                SELECT i AS id,
                  list_transform(range(0, 3), j -> {
                    'leg_id': j,
                    'cashflows': list_transform(range(0, 4), k -> {
                      'amt': (i * 100 + j * 10 + k)::DOUBLE
                    })
                  }) AS legs
                FROM range(0, 20) t(i)
            """)
            # Expected leaf count: 20 * 3 * 4 = 240
            unnests = [
                "UNNEST(legs) AS x1(e1)",
                "UNNEST(e1.cashflows) AS x2(e2)",
            ]
            legacy = (
                "SELECT e2.amt FROM fx_cte, UNNEST(legs) AS x1(e1), "
                "UNNEST(e1.cashflows) AS x2(e2)")
            pipeline = build_unnest_pipeline_sql(
                "fx_cte", "e2.amt", unnests, limit=None)
            need("WITH x1 AS" in pipeline and "x2 AS" in pipeline,
                 "pipeline emits CTE hops: " + pipeline)
            need("FROM fx_cte," not in pipeline and "FROM fx_cte ," not in pipeline,
                 "pipeline must not use comma-FROM UNNEST: " + pipeline)
            legacy_rows = sorted(
                r[0] for r in duck.conn.execute(legacy).fetchall())
            pipe_rows = sorted(
                r[0] for r in duck.conn.execute(pipeline).fetchall())
            eq(pipe_rows, legacy_rows,
               "CTE pipeline matches comma-FROM UNNEST row-for-row")
            eq(len(pipe_rows), 240, "full leaf count preserved")

            acc = {"sel": "e2.amt", "unnests": unnests}
            cnt_sql = field_access_sql("fx_cte", acc, which="count")
            need(cnt_sql and "count(*)" in cnt_sql.lower()
                 and "LIMIT" not in cnt_sql.upper(),
                 "count recipe is unlimited: %r" % cnt_sql)
            eq(int(duck.conn.execute(cnt_sql).fetchone()[0]), 240,
               "exact count matches full explode")

            # Opaque JSON multi-hop also stays exact under the CTE assembler.
            rows = []
            for i in range(5):
                rows.append(json.dumps({
                    "legs": [{"cashflows": [
                        {"fixingdate": "d%d_%d" % (i, k)} for k in range(2)
                    ]} for _ in range(2)]
                }))
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fx_cte_json AS "
                "SELECT unnest(?)::JSON AS payload", [rows])
            j_unnests = [
                "UNNEST(from_json(json_extract(payload, '$.legs'), "
                "'[\"JSON\"]')) AS x1(e1)",
                "UNNEST(from_json(json_extract(e1, '$.cashflows'), "
                "'[\"JSON\"]')) AS x2(e2)",
            ]
            j_legacy = (
                "SELECT e2 ->> '$.fixingdate' FROM fx_cte_json, %s, %s"
                % (j_unnests[0], j_unnests[1]))
            j_pipe = build_unnest_pipeline_sql(
                "fx_cte_json", "e2 ->> '$.fixingdate'", j_unnests)
            j_legacy_rows = sorted(
                r[0] for r in duck.conn.execute(j_legacy).fetchall())
            j_pipe_rows = sorted(
                r[0] for r in duck.conn.execute(j_pipe).fetchall())
            eq(j_pipe_rows, j_legacy_rows,
               "JSON CTE pipeline matches comma-FROM UNNEST")
            eq(len(j_pipe_rows), 20, "JSON full explode count 5*2*2")
            j_cnt = field_access_sql(
                "fx_cte_json",
                {"sel": "e2", "unnests": j_unnests},
                which="count")
            eq(int(duck.conn.execute(j_cnt).fetchone()[0]), 20,
               "JSON exact count recipe")
        finally:
            s.shutdown()

    def t_opaque_json_shred_and_nested_flatten():
        # Flatten-off opaque JSON must shred via sample-derived plan (no
        # DESCRIBE LIST), and flatten must keep list-inside-list-element
        # rows with compound keys.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core.diagnostics import json_samples_to_type_node
        shape = [
            {"id": 1, "legs": [{"cf": [{"amt": 1.0}, {"amt": 2.0}]}]},
            {"id": 2, "legs": [{"cf": [{"amt": 3.0}]}]},
        ]
        node = json_samples_to_type_node([shape])
        need(node and node.get("t") == "list",
             "samples infer a list root: %r" % node)
        elem = (node or {}).get("of") or {}
        kids = [fn for fn, n in (elem.get("fields") or [])
                if (n or {}).get("t") == "list"]
        need("legs" in kids, "inferred element has legs list")

        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            duck.conn.execute(
                "CREATE OR REPLACE TABLE opaque_trades AS "
                "SELECT ?::JSON AS json",
                [json.dumps(shape)])
            # Materialize a parquet cache like shred_run does for non-parquet
            # tables so CTAS can use file_row_number.
            plan = s.shred_plan("duckdb", "opaque_trades", "json",
                                base="opaque_trades")
            need(plan.get("json_access"),
                 "opaque JSON shred plan uses json_access: %r" % plan)
            need(any(t.get("child_arrays") for t in plan.get("tables") or []),
                 "sample plan sees nested arrays: %r" % plan.get("tables"))
            res = s.shred_run("duckdb", "opaque_trades", "json",
                              base="opaque_trades")
            need(res.get("ok"), "opaque shred succeeds: %r" % res)
            created = {c["name"] for c in (res.get("created") or [])}
            need(any("legs" in n for n in created),
                 "shred creates a legs child: %r" % created)
            need(any("cf" in n for n in created),
                 "shred creates nested cf child (not dropped): %r" % created)

            # Typed flatten: list-inside-list-element retention
            duck.conn.execute(
                "CREATE OR REPLACE TABLE nest_orders AS "
                "SELECT 1 AS id, "
                "[{'oid': 1, 'li': [{'sku': 'a'}, {'sku': 'b'}]}, "
                " {'oid': 2, 'li': [{'sku': 'c'}]}]::"
                "STRUCT(oid INTEGER, li STRUCT(sku VARCHAR)[])[] AS orders")
            fres = s.flatten_table("nest_orders", base="nest_orders")
            need(not fres.get("error"),
                 "flatten nested orders succeeds: %r" % fres)
            made = {c["name"] for c in (fres.get("created") or [])}
            need(any("orders_li" == n or n.endswith("_li") or "li" in n
                     for n in made),
                 "flatten creates orders/li child table: %r" % made)
            # Find the li table and count skus
            li_name = next((n for n in made
                            if n == "orders_li" or n.endswith("orders_li")
                            or (n.endswith("_li") and "order" in n)), None)
            if li_name is None:
                li_name = next((n for n in made if "li" in n), None)
            need(li_name, "li child table name found in %r" % made)
            _c, rows = duck.execute(
                'SELECT "sku" FROM %s ORDER BY 1'
                % s._rq(li_name))
            eq([r[0] for r in (rows or [])], ["a", "b", "c"],
               "nested li skus retained with compound-key flatten")
        finally:
            s.shutdown()

    def t_duckdb_load_cancel_aborts_read():
        # interrupt() trips the cooperative flag so the Python array pre-pass
        # aborts mid-read -- conn.interrupt() alone can't stop it, since no
        # DuckDB statement is running during the pre-pass. Skips without duckdb.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core import engines as E
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "big.json")
        # The fixture is rewritten to NDJSON on every JSON load now; size only
        # affects how long the pre-pass runs. 120k rows ~= 1.7 MB.
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"id": i} for i in range(120000)], f)
        mgr = E.DuckDBManager()
        old = os.environ.get("SAMQL_JSON_STREAM_MB")
        os.environ["SAMQL_JSON_STREAM_MB"] = "1"
        try:
            mgr._cancel.clear()
            mgr.interrupt()                 # a cancel arrives before/while reading
            raised = False
            try:
                mgr._json_source_for_read(p)
            except InterruptedError:
                raised = True
            need(raised, "a tripped cancel makes the array pre-pass abort")
        finally:
            if old is None:
                os.environ.pop("SAMQL_JSON_STREAM_MB", None)
            else:
                os.environ["SAMQL_JSON_STREAM_MB"] = old
            try:
                mgr._conn.close()
            except Exception:
                pass

    def t_csv_readers_sql():
        # The consolidated CSV reader builder must emit exactly the SQL the
        # three call sites (materialize table, view, Parquet cache) built inline
        # before -- pure, so it runs everywhere and proves the refactor changed
        # no behaviour.
        from samql_core import engines as E
        r = E._csv_readers("d/f.csv")
        eq(len(r), 2, "fast + tolerant reader")
        eq(r[0], "read_csv_auto('d/f.csv', sample_size=204800, nullstr='')",
           "fast typed reader treats blanks as NULL")
        eq(r[1], "read_csv_auto('d/f.csv', all_varchar=true, "
                 "ignore_errors=true, sample_size=204800)",
           "tolerant all-text reader")
        rt = E._csv_readers("d/f.tsv", "\t")
        need("delim='\\t'" in rt[0] and "nullstr=''" in rt[0],
             "tab delimiter pinned: %s" % rt[0])
        rp = E._csv_readers("d/f.psv", "|")
        need("delim='|'" in rp[0], "other delimiter pinned: %s" % rp[0])

    def t_json_prepass_cancel_poll():
        # The array->NDJSON pre-pass polls should_cancel and raises promptly,
        # rather than running the whole file. This is the mechanism the gated
        # DuckDB cancel test relies on -- exercised directly here so it runs
        # without duckdb and without depending on the 1 MB size floor.
        from samql_core.engines import _write_ndjson_from_stream
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "arr.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"id": i} for i in range(3000)], f)
        dst = os.path.join(dd, "out.ndjson")
        raised = False
        try:
            _write_ndjson_from_stream(p, dst, should_cancel=lambda: True)
        except InterruptedError:
            raised = True
        need(raised, "an already-tripped cancel aborts the pre-pass at once")
        n = _write_ndjson_from_stream(p, dst, should_cancel=lambda: False)
        eq(n, 3000, "no cancel -> every array element is written as NDJSON")

    def t_stream_json_cancel_midread():
        # The reported bug: a load of a FEW but HUGE records didn't cancel,
        # because the old poll fired only every 8192 records and never inside
        # one record. stream_json_records now polls should_cancel on every raw
        # chunk read, so an already-tripped cancel aborts a single enormous
        # element before it is even fully read -- not after the whole file.
        # Pure/stdlib -> runs in the sandbox (no ijson, no duckdb).
        from samql_core.flatten import stream_json_records
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "huge.json")
        big = "x" * (5 * 1024 * 1024)     # one 5 MB element -> many chunk reads
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"blob": big}], f)
        raised = seen = 0
        try:
            for _ in stream_json_records(p, should_cancel=lambda: True):
                seen += 1
        except InterruptedError:
            raised = 1
        need(raised, "a tripped cancel aborts mid-read of one huge record")
        eq(seen, 0, "the huge element is never yielded (aborted while reading)")

    def t_stream_json_read_heartbeat():
        # The false-positive "stalled" fix: while reading, the streaming reader
        # stamps a heartbeat (a bare beat() -> the load op on this thread), so a
        # slow read (esp. the pure-Python pre-pass) no longer trips the stall
        # watchdog. Spy on the registry beat to confirm it fires. This passes
        # should_cancel exactly as the real load's pre-pass does, so it covers
        # BOTH the stdlib reader and the ijson fast path (when ijson is
        # installed). Beating only on an actual read preserves real hang
        # detection (a blocked read stops beating).
        from samql_core import flatten as F
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "multi.json")
        # comfortably over the counting reader's 256 KB report interval, and
        # many stdlib 64 KB chunks
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"i": i, "pad": "z" * 3000} for i in range(400)], f)
        calls = [0]
        orig = F._opreg.beat
        F._opreg.beat = lambda *a, **k: calls.__setitem__(0, calls[0] + 1)
        try:
            got = sum(1 for _ in F.stream_json_records(
                p, should_cancel=lambda: False))
        finally:
            F._opreg.beat = orig
        eq(got, 400, "all records still stream through")
        need(calls[0] >= 1, "the read stamped at least one heartbeat")

    def t_counting_reader_heartbeat():
        # The ijson fast path wraps the file in _CountingReader. Verify directly
        # -- without needing ijson installed -- that it stamps a heartbeat as
        # data is pulled (first read, then every ~256 KB) and that a tripped
        # cancel raises on the next read. This is the exact mechanism that must
        # hold on a box WITH ijson.
        from samql_core import flatten as F
        import io
        data = b'[{"a":1}]' + b" " * (300 * 1024)   # > 256 KB
        calls = [0]
        orig = F._opreg.beat
        F._opreg.beat = lambda *a, **k: calls.__setitem__(0, calls[0] + 1)
        try:
            r = F._CountingReader(io.BytesIO(data), None, None, lambda: False)
            while r.read(65536):
                pass
        finally:
            F._opreg.beat = orig
        need(calls[0] >= 1,
             "counting reader stamps a heartbeat while ijson reads")
        r2 = F._CountingReader(io.BytesIO(data), None, None, lambda: True)
        raised = False
        try:
            r2.read(1024)
        except InterruptedError:
            raised = True
        need(raised, "counting reader aborts the ijson read on cancel")

    def t_beat_on_thread():
        # beat_on_thread lets one thread refresh the heartbeat of an op that is
        # registered on ANOTHER thread -- the mechanism the exec keepalive uses
        # to keep a blocking native call off the stall list. Pure -> runs
        # everywhere.
        from samql_core import progress as opreg
        import threading
        import time as _t
        tid = threading.get_ident()
        oid = opreg.begin("load", target="native")
        try:
            # age by the SAME clock idle_s uses: sleep() can wake a
            # Windows timer-tick early (the on-box 2026-07-03 flake:
            # aged 0.047 < the 0.05 margin), so spin on monotonic until
            # the elapsed time is REAL, not hoped-for.
            _t0 = _t.monotonic()
            while _t.monotonic() - _t0 < 0.06:
                _t.sleep(0.01)
            aged = next(o["idle_s"] for o in opreg.snapshot()
                        if o["id"] == oid)
            done = threading.Event()
            threading.Thread(
                target=lambda: (opreg.beat_on_thread(tid), done.set())).start()
            done.wait(5)
            fresh = next(o["idle_s"] for o in opreg.snapshot()
                         if o["id"] == oid)
            need(aged >= 0.05, "heartbeat aged before the cross-thread beat")
            need(fresh < aged,
                 "beat_on_thread from another thread refreshed the op")
        finally:
            opreg.end(oid)

    def t_exec_keepalive():
        # _ExecKeepalive beats the worker's op while a long native call runs (so
        # a big read doesn't trip the stall watchdog) and re-issues interrupt
        # once cancel is set (so a Stop is nudged through at the engine's next
        # checkpoint). Uses a fake connection; no DuckDB needed.
        from samql_core import engines as E
        from samql_core import progress as opreg
        import threading
        import time as _t
        interrupts = [0]

        class _FakeConn:
            def interrupt(self):
                interrupts[0] += 1

        cancel = threading.Event()
        tid = threading.get_ident()
        oid = opreg.begin("load", target="native")
        try:
            _t0 = _t.monotonic()
            while _t.monotonic() - _t0 < 0.06:
                _t.sleep(0.01)   # real elapsed on the idle_s clock
            aged = next(o["idle_s"] for o in opreg.snapshot()
                        if o["id"] == oid)
            with E._ExecKeepalive(_FakeConn(), cancel, tid, interval=0.02):
                _t.sleep(0.1)                  # keepalive beats our op here
                fresh = next(o["idle_s"] for o in opreg.snapshot()
                             if o["id"] == oid)
                need(interrupts[0] == 0, "no interrupt before cancel")
                cancel.set()                   # now it should nudge interrupt
                _t.sleep(0.1)
            need(aged >= 0.05, "op aged before the keepalive")
            need(fresh < aged, "keepalive beat the worker op (no false stall)")
            need(interrupts[0] >= 1,
                 "keepalive re-issued interrupt after cancel")
        finally:
            opreg.end(oid)

    def t_json_stream_threshold_default():
        # The array->NDJSON streaming pre-pass (the cancellable, heartbeating
        # read path) now kicks in at a modest 32 MB by default, so a mid-size
        # array a user might cancel doesn't take DuckDB's uninterruptible
        # raw-array read. Pure -> runs everywhere.
        from samql_core import engines as E
        old = os.environ.get("SAMQL_JSON_STREAM_MB")
        try:
            os.environ.pop("SAMQL_JSON_STREAM_MB", None)
            eq(E._json_stream_min_bytes(), 32 * 1024 * 1024,
               "default JSON streaming threshold is 32 MB")
            os.environ["SAMQL_JSON_STREAM_MB"] = "64"
            eq(E._json_stream_min_bytes(), 64 * 1024 * 1024,
               "SAMQL_JSON_STREAM_MB override honored")
        finally:
            if old is None:
                os.environ.pop("SAMQL_JSON_STREAM_MB", None)
            else:
                os.environ["SAMQL_JSON_STREAM_MB"] = old

    def t_native_load_statements_are_guarded():
        # Every long, file-streaming native statement -- a CREATE TABLE AS read
        # of a file, or a COPY (...) that streams a whole dataset to/from disk
        # (the Parquet cache on load, and the table->JSON dump that feeds a
        # flatten) -- must run inside an _ExecKeepalive so it heartbeats (no
        # false "stalled" card) and is nudged to cancel. These live in BOTH
        # engines.py (load paths) and session.py (the flatten dump), so both are
        # scanned. In-memory table->table statements are a separate concern and
        # not covered here. Pure (source inspection) -> runs everywhere.
        import ast
        import inspect
        from samql_core import engines as E
        from samql_core import session as S
        offenders = []
        for mod, markers in ((E, ('CREATE TABLE "{final}" AS SELECT',
                                   "COPY (SELECT * FROM")),
                             (S, ("COPY (SELECT * FROM",))):
            src = inspect.getsource(mod)
            tree = ast.parse(src)
            for node in ast.walk(tree):
                if isinstance(node, ast.FunctionDef):
                    body = ast.get_source_segment(src, node) or ""
                    if any(h in body for h in markers) \
                            and "_ExecKeepalive" not in body:
                        offenders.append("%s.%s" % (mod.__name__, node.name))
        need(not offenders,
             "file-streaming native statement(s) not guarded by "
             "_ExecKeepalive: %r" % (offenders,))

    def t_detect_key_column():
        # The SQL-UNNEST flatten auto-detects an id-like SCALAR column to link
        # child tables by (the record key whose NAME differs per file), and
        # returns None -> synthesize when none exists. Array/struct columns are
        # never chosen. Pure -> runs everywhere (no DuckDB).
        from samql_core import flatten as F
        eq(F.detect_key_column({"tradeId": "VARCHAR", "x": "DOUBLE"}),
           "tradeId", "camelCase tradeId detected")
        eq(F.detect_key_column({"trade_id": "BIGINT", "x": "DOUBLE"}),
           "trade_id", "snake_case trade_id detected")
        eq(F.detect_key_column({"name": "VARCHAR", "dealId": "VARCHAR"}),
           "dealId", "dealId detected over a non-id column")
        eq(F.detect_key_column({"id": "BIGINT", "tradeId": "VARCHAR"}),
           "tradeId", "the more specific trade id outscores a bare id")
        eq(F.detect_key_column({"name": "VARCHAR", "amount": "DOUBLE"}),
           None, "no id-like column -> None (caller synthesizes)")
        eq(F.detect_key_column({"ids": "BIGINT[]", "ref": "VARCHAR"}),
           "ref", "an array column is never a key; a scalar 'ref' is")
        eq(F.detect_key_column({"legs": "STRUCT(a INTEGER)[]"}),
           None, "a struct-array is not a key candidate")

    def t_duckdb_unnest_plan():
        # The schema-driven planner emits the DuckDB SQL to flatten a nested
        # table via UNNEST: root = all non-array cols (EXCLUDE arrays); one
        # child per array (struct arrays struct-expanded, scalar arrays -> a
        # value col); keyed by a detected column, or a synthesized row key that
        # needs a keyed staging copy. Pure string builder -> runs everywhere.
        from samql_core import flatten as F

        # (a) real key + mixed arrays -> no staging, children read the source
        ct = {"tradeId": "VARCHAR", "notional": "DOUBLE",
              "legs": "STRUCT(rate DOUBLE)[]", "tags": "VARCHAR[]"}
        p = F.duckdb_unnest_plan("src", ct, "trades")
        eq(p["synthesized"], False, "real key -> not synthesized")
        eq(p["key"], "tradeId", "detected key carried down")
        eq(p["fk"], "trades_id", "FK named <root>_id")
        eq(p["cleanup"], [], "no staging with a real key")
        eq(sorted(p["children"].keys()), ["trades_legs", "trades_tags"],
           "one child per array, named <root>_<col>")
        sqls = {s["kind"]: s["sql"] for s in p["statements"]}
        need('EXCLUDE ("legs", "tags")' in sqls["root"],
             "root excludes the array columns")
        need('FROM "src"' in sqls["root"], "root reads the source table")
        legs = [s["sql"] for s in p["statements"]
                if s["target"] == "trades_legs"][0]
        need('UNNEST("legs")' in legs and "_e.*" in legs and "WITH _x" in legs,
             "struct array is unnested + struct-expanded via a CTE")
        need('"tradeId" AS "trades_id"' in legs,
             "child carries the FK value from the key column")
        need('WHERE "legs" IS NOT NULL' in legs, "child skips null arrays")
        tags = [s["sql"] for s in p["statements"]
                if s["target"] == "trades_tags"][0]
        need('UNNEST("tags") AS "value"' in tags,
             "scalar array becomes a single value column")

        # (b) no id-like column -> synthesized key via a keyed staging copy
        ct2 = {"name": "VARCHAR", "legs": "STRUCT(a INTEGER)[]"}
        p2 = F.duckdb_unnest_plan("src", ct2, "recs")
        eq(p2["synthesized"], True, "no id -> synthesized")
        need(len(p2["cleanup"]) == 1, "one staging table to clean up")
        staging = p2["cleanup"][0]
        stg = [s["sql"] for s in p2["statements"]
               if s["kind"] == "staging"][0]
        need("row_number() OVER ()" in stg and "_rowkey" in stg,
             "staging materializes a stable synthesized row key")
        root2 = [s["sql"] for s in p2["statements"] if s["kind"] == "root"][0]
        need(('FROM "%s"' % staging) in root2,
             "root reads the keyed staging copy, not the raw source")
        # the synthesized key is the SAME column on root + children, so one
        # WHERE/join links them (the user filters on this uniqueid).
        eq(p2["fk"], "_rowkey", "synthesized FK uses the row-key name")
        child2 = [s["sql"] for s in p2["statements"]
                  if s["target"] in p2["children"]][0]
        need('AS "_rowkey"' in child2,
             "child carries _rowkey (same column name as the root key)")

        # (c) colliding child names are uniquified against existing tables
        p3 = F.duckdb_unnest_plan("src", ct, "trades",
                                  existing_names={"trades_legs"})
        need("trades_legs" not in p3["children"],
             "a colliding child name is not reused")
        need(any(k.startswith("trades_legs_") for k in p3["children"]),
             "collision resolved by suffixing")

        # (d) detect=False ALWAYS synthesizes, even when an id column exists
        # (deterministic; no name-based guessing) -- this is the flatten's mode.
        p4 = F.duckdb_unnest_plan("src", ct, "trades", detect=False)
        eq(p4["synthesized"], True, "detect=False forces a synthesized key")
        eq(p4["key"], "_rowkey", "synthesized key column")
        eq(p4["fk"], "_rowkey", "FK == synthesized key name on both sides")
        need(any(s["kind"] == "staging" for s in p4["statements"]),
             "forced-synth with arrays still stages a keyed copy")

        # (e) struct-only (no arrays) -> ONE keyed table, no children, no
        # staging; the struct column is kept nested (dot-accessible).
        ct5 = {"identifier": "STRUCT(sophis VARCHAR, mic VARCHAR)",
               "currency": "VARCHAR"}
        p5 = F.duckdb_unnest_plan("src", ct5, "inst", detect=False)
        eq(p5["children"], {}, "no arrays -> no child tables")
        eq(p5["cleanup"], [], "no arrays -> no staging copy")
        eq(len([s for s in p5["statements"] if s["kind"] == "root"]), 1,
           "exactly one root statement")
        root5 = [s["sql"] for s in p5["statements"] if s["kind"] == "root"][0]
        need("row_number() OVER () AS \"_rowkey\"" in root5,
             "the keyed root synthesizes _rowkey")
        # .422 repoint: the wrapper struct no longer rides along as a
        # nested blob -- its leaves come back as dotted, aliased root
        # columns (this WAS the on-box "partial JSON").
        need('EXCLUDE ("identifier")' in root5
             and '"identifier"."sophis" AS "identifier_sophis"' in root5
             and '"identifier"."mic" AS "identifier_mic"' in root5,
             "the wrapper is exploded into dotted root columns")

    def t_flatten_method_plumbing():
        # (1) The activity card still projects a finished job's method/key/loaded
        # fields for the UI. (2) flatten_json now DEEP-flattens (the shallow SQL
        # UNNEST is not used). (3) the DuckDB writer bulk-inserts each batch via
        # Arrow (pyarrow) when available, with a per-batch executemany fallback,
        # which is the acceleration that lets a deep flatten's millions of child
        # rows land in minutes instead of the row-at-a-time crawl.
        import inspect
        import server
        from samql_core import session as S
        from samql_core import engines as E
        job = {"id": "j1", "kind": "flatten", "state": "done",
               "name": "trades", "engine": "duckdb", "method": "python",
               "key": None,
               "loaded": [{"name": "trades", "rows": 10, "engine": "duckdb"}]}
        card = server._task_card(job)
        eq(card["method"], "python", "method projected onto the UI card")
        need("key" in card and "loaded" in card,
             "key + loaded fields exposed on the card")

        fj = inspect.getsource(S.Session.flatten_json)
        # .401 flipped this contract ON PURPOSE: the in-engine flatten is
        # the .371 DEEP engine (full normalized tree, every array at every
        # depth) and it is conversion-proof, so flatten_json tries it
        # FIRST; the dump + typed-re-parse path is the fallback.
        uf = inspect.getsource(S.Session._duckdb_unnest_flatten)
        need("_duckdb_unnest_flatten" in fj
             and "no Python JSON parse" in uf,
             "flatten_json fronts the DEEP in-engine flatten")

        ats = inspect.getsource(E.DuckDBManager.add_table_streaming)
        need("pyarrow" in ats and "register" in ats and "executemany" in ats,
             "DuckDB writer uses an Arrow bulk insert with executemany fallback")
        # the Arrow path must build columns via the columnar helper (no per-cell
        # coercion across every column) -- that per-cell call was the wide-table
        # write penalty. Coercion is confined to the executemany fallback.
        need("_columnarize(rows, columns, text_cols)" in ats,
             "wide-table write prepares columns columnarly (no per-cell coerce)")
        # behaviour: numeric/None columns pass straight through; only text
        # columns are stringified.
        out = E._columnarize([(1, "x", 3.0, None), (2, 5, None, "z")],
                             ["a", "b", "c", "d"], {"b", "d"})
        need(out[0] == ([1, 2], False) and out[2] == ([3.0, None], False),
             "columnarize passes numeric/None columns through untouched")
        need(out[1] == (["x", "5"], True) and out[3] == ([None, "z"], True),
             "columnarize stringifies only the text columns")
        need(E._columnarize([], ["a", "b"], {"b"}) == [([], False), ([], True)],
             "columnarize handles an empty batch")
        blank = E._columnarize([("", 1), ("  ", 2), (3, 3)],
                               ["a", "b"], set())
        need(blank[0][0] == [None, None, 3] and blank[0][1] is False,
             "columnarize maps blank strings to NULL on typed columns")

    def t_conversion_errors_fall_back_to_varchar():
        # Blank / mixed cells must never abort CSV or JSON loads with
        # "Could not convert string '' to INT". DuckDB streaming inserts
        # coerce blanks to NULL and widen to VARCHAR on harder mismatches;
        # CSV readers use nullstr='' then all_varchar.
        from samql_core import engines as E
        need(E._is_type_conversion_error(
                RuntimeError("Conversion Error: Could not convert string "
                             "'' to INT64")),
             "classic empty→int is classified as conversion")
        need(E._is_type_conversion_error(
                RuntimeError("ConversionException: could not convert string "
                             "x to INTEGER")),
             "ConversionException phrasing is classified")
        need(not E._is_type_conversion_error(RuntimeError("out of memory")),
             "OOM is not a type conversion")
        eq(E._empty_to_null(""), None, "empty → NULL")
        eq(E._empty_to_null("  "), None, "whitespace → NULL")
        eq(E._empty_to_null("0"), "0", "non-blank kept")

        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        duck = s.get_duckdb()
        need(duck is not None, "DuckDB manager available")
        dd = tempfile.mkdtemp()
        try:
            # Streaming insert: ints in sample, blank later (the reported bug).
            name, n = duck.add_table_streaming(
                "blank_int", ["id", "qty"],
                iter([(1, 10), (2, 20), (3, ""), (4, 40), (5, "x")]),
                chunk=2)
            eq(n, 5, "every row survived blank/mixed qty: %s" % n)
            rows = s.run_query(
                'SELECT id, qty FROM "%s" ORDER BY id' % name,
                target="__duckdb__")["rows"]
            eq(len(rows), 5, "all five rows queryable")
            # Blank became NULL (or '', after varchar widen); 'x' must exist.
            need(any(r[0] == 5 for r in rows), "mixed non-numeric row kept")

            # CSV with blank numeric cells.
            csv_path = os.path.join(dd, "blank.csv")
            with open(csv_path, "w", encoding="utf-8") as f:
                f.write("id,qty,note\n")
                for i in range(200):
                    f.write("%d,%s,n%d\n" % (i, i if i % 17 else "", i))
            out = s.load_file(csv_path, destination="duckdb",
                              base_name="blank_csv")
            need(out and out[0].get("name"), "csv load returned a table")
            cnt = s.run_query(
                'SELECT COUNT(*) FROM "%s"' % out[0]["name"],
                target="__duckdb__")["rows"][0][0]
            eq(cnt, 200, "csv blank cells did not abort the load")

            # Nested JSON array with blank numeric fields → stream/Parquet path.
            js_path = os.path.join(dd, "blank.json")
            payload = [{"id": i, "qty": (i if i % 11 else ""),
                        "meta": {"code": (i if i % 13 else "")}}
                       for i in range(500)]
            with open(js_path, "w", encoding="utf-8") as f:
                json.dump(payload, f)
            jout = s.load_file(js_path, destination="duckdb",
                               base_name="blank_json", flatten=False)
            need(jout and jout[0].get("name"), "json load returned a table")
            jcnt = s.run_query(
                'SELECT COUNT(*) FROM "%s"' % jout[0]["name"],
                target="__duckdb__")["rows"][0][0]
            eq(jcnt, 500, "json blank cells did not abort the load")

            # Stream-flatten path (Python insert) with blanks.
            old = os.environ.get("SAMQL_JSON_STREAM_FLATTEN_MB")
            os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = "0"
            try:
                # Force streamer via giant-object gate: single object + low floor.
                one = os.path.join(dd, "one_blank.json")
                blob = {"code": 1,
                        "items": [{"i": i, "n": ("" if i % 9 == 0 else i)}
                                  for i in range(800)]}
                with open(one, "w", encoding="utf-8") as f:
                    json.dump(blob, f)
                os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = "1"
                fout = s.load_file(one, destination="duckdb",
                                   base_name="one_blank", flatten=True)
                need(fout, "stream-flatten load returned tables")
                need(all(t.get("engine") == "duckdb" for t in fout),
                     "streamer tables in duckdb despite blank numerics")
            finally:
                if old is None:
                    os.environ.pop("SAMQL_JSON_STREAM_FLATTEN_MB", None)
                else:
                    os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = old
        finally:
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_large_csv_json_ondisk_loads_fast():
        # Multi-MB CSV / JSON must take the on-disk Parquet path (bounded RAM)
        # and finish quickly -- no full-file type scan, no in-engine materialize.
        # Size here is large enough to cross soft on-disk floors when lowered.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core import engines as E
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        old_od = os.environ.get("SAMQL_ONDISK_MB")
        old_jod = os.environ.get("SAMQL_JSON_ONDISK_MB")
        old_hard = os.environ.get("SAMQL_ONDISK_HARD_MB")
        os.environ["SAMQL_ONDISK_MB"] = "1"
        os.environ["SAMQL_JSON_ONDISK_MB"] = "1"
        os.environ["SAMQL_ONDISK_HARD_MB"] = "1"
        try:
            # ~2.5 MB CSV
            csv_path = os.path.join(dd, "big.csv")
            with open(csv_path, "w", encoding="utf-8", newline="") as f:
                f.write("id,name,score,tag\n")
                for i in range(80000):
                    f.write("%d,name_%d,%.2f,t%d\n"
                            % (i, i, i * 0.5, i % 9))
            t0 = time.time()
            cout = s.load_file(csv_path, destination="duckdb",
                               base_name="bigcsv")
            csv_s = time.time() - t0
            need(cout and cout[0].get("storage") == "parquet-cache",
                 "large csv uses parquet-cache: %r" % cout)
            ccnt = s.run_query(
                'SELECT COUNT(*) FROM "%s"' % cout[0]["name"],
                target="__duckdb__")["rows"][0][0]
            eq(ccnt, 80000, "large csv row count")
            need(csv_s < 45.0,
                 "large csv load finished quickly (%.1fs)" % csv_s)

            # ~2 MB nested JSON array (NDJSON rewrite + Parquet)
            js_path = os.path.join(dd, "big.json")
            rows = [{"id": i, "sym": "S%d" % (i % 11),
                     "qty": i, "nested": {"a": i % 5, "b": "x"}}
                    for i in range(25000)]
            with open(js_path, "w", encoding="utf-8") as f:
                json.dump(rows, f)
            t1 = time.time()
            jout = s.load_file(js_path, destination="duckdb",
                               base_name="bigjson", flatten=False)
            js_s = time.time() - t1
            need(jout and jout[0].get("storage") == "parquet-cache",
                 "large json uses parquet-cache: %r" % jout)
            jcnt = s.run_query(
                'SELECT COUNT(*) FROM "%s"' % jout[0]["name"],
                target="__duckdb__")["rows"][0][0]
            eq(jcnt, 25000, "large json row count")
            need(js_s < 60.0,
                 "large json load finished quickly (%.1fs)" % js_s)

            # NDJSON rewrite prefers orjson when available (speed contract).
            import inspect
            src = inspect.getsource(E._write_ndjson_from_stream)
            need("orjson" in src,
                 "NDJSON rewrite uses orjson when installed")
        finally:
            for key, old in (("SAMQL_ONDISK_MB", old_od),
                             ("SAMQL_JSON_ONDISK_MB", old_jod),
                             ("SAMQL_ONDISK_HARD_MB", old_hard)):
                if old is None:
                    os.environ.pop(key, None)
                else:
                    os.environ[key] = old
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_json_reader_large_records_linear():
        # Regression: the streaming readers decode by advancing an INDEX and grow
        # their reads to complete a large value, rather than re-slicing the
        # buffer and re-scanning from zero after every value. The old readers did
        # the latter, which is quadratic in record size -- a file of ~MB records
        # crawled (throughput fell from ~47 MB/s at 77 KB records to ~3 MB/s at
        # 4 MB records). Assert (a) large concatenated records read back intact
        # and in order (exercises the grow-to-complete path), and (b) the readers
        # use the index + growing read so the quadratic pattern can't silently
        # return. Pure -> runs everywhere.
        import inspect
        import tempfile
        from samql_core import flatten as F
        # ~2.5 MB per record, concatenated with no separators, so each value
        # spans well past the base read and must be completed by growing reads.
        recs = [{"i": k, "blob": ("v%d " % k) * 500000} for k in range(6)]
        p = tempfile.mktemp(suffix=".json")
        with open(p, "w", encoding="utf-8") as f:
            for r in recs:
                f.write(json.dumps(r))
        try:
            got = list(F.stream_json_records(p))
        finally:
            os.unlink(p)
        need(len(got) == len(recs),
             "all large concatenated records are read (%d of %d)"
             % (len(got), len(recs)))
        need([g.get("i") for g in got] == list(range(len(recs))),
             "large records come back in order")
        need(got[3]["blob"] == recs[3]["blob"],
             "a large record's value survives the growing-read reassembly")
        for fn in (F._iter_concat_values, F._iter_stream_records):
            src = inspect.getsource(fn)
            need("_READ_CAP" in src and "<<= 1" in src,
                 "%s grows its read to complete a large value" % fn.__name__)
            need("scan(" in src,
                 "%s decodes by index (raw_decode at a position)" % fn.__name__)

    def t_deep_flatten_sophis_shape():
        # A real Sophis instrument shape (option on an equity, from the field):
        # deeply nested single objects -- identifier, underlyer, and a 3-level
        # strike -> strikeValue -> strikePrice -- that must FLATTEN INTO the
        # parent row as underscore-joined columns, plus one array (links) that
        # must become a keyed child table. Loads N copies through the real
        # load_json into a real in-memory SQLite engine and checks the tables,
        # the flattened nested columns (including 3-level depth), the row counts,
        # and that every parent joins to exactly its child rows. Runs everywhere.
        import tempfile
        from samql_core.engines import DBManager
        from samql_core import loaders
        rec = {
            "code": 899881807,
            "identifier": {"sophis": 899881807, "optionSymbol": "OPT_CA_BIP",
                           "ticker": "BIP.UN CA 09/18/26 C50 Equity"},
            "currency": "CAD", "name": "OPT_CA_BIP.UN260918C50",
            "underlyer": {"sophis": 136424980, "bbglobalID": "BBG000VC6X81",
                          "longCompName": "Brookfield Infrastructure Partners LP",
                          "netAsset": 31335.47, "dynamicSector": "Utilities"},
            "settlementType": "PhysicalDelivery",
            "strike": {"strikeValue": {"strikePrice": {"currency": "CAD",
                                                       "amount": 50}},
                       "fixingType": "Last"},
            "links": [
                {"rel": "instrumentPosition",
                 "href": "http://echo.tdbfg.com/v1.2/echo/query/globalPositional"
                         "?instrumentCode=899881807"},
                {"rel": "insPositionInstrumentPrice",
                 "href": "http://echo.tdbfg.com/v1.2/echo/query/price"
                         "?instrumentCode=899881807"},
                {"rel": "insUnderlyingInstrumentPrice",
                 "href": "http://echo.tdbfg.com/v1.2/echo/query/price"
                         "?instrumentCode=899881807"},
                {"rel": "basketSettings",
                 "href": "http://echo.tdbfg.com/v1.2/echo/basketSettings/"
                         "899881807"}],
        }
        n = 200
        recs = []
        for i in range(n):
            r = json.loads(json.dumps(rec))
            r["code"] = 899881807 + i
            r["identifier"]["sophis"] = 899881807 + i
            recs.append(r)
        p = tempfile.mktemp(suffix=".json")
        open(p, "w", encoding="utf-8").write(json.dumps(recs))  # top-level array
        db = DBManager(disk_backed=False)
        try:
            out = loaders.load_json(db, p, base_name="sophis", engine="sqlite")
        finally:
            os.unlink(p)
        tabs = {o["name"]: o for o in out}
        need(set(tabs) == {"sophis", "sophis_links"},
             "deep flatten yields root + one keyed child (links): %r"
             % list(tabs))
        eq(tabs["sophis"]["rows"], n, "one root row per instrument")
        eq(tabs["sophis_links"]["rows"], n * 4, "four link rows per instrument")
        conn = db._conn
        cols = set(r[1] for r in conn.execute('PRAGMA table_info("sophis")'))
        for c in ("identifier_sophis", "underlyer_longCompName",
                  "strike_strikeValue_strikePrice_amount", "strike_fixingType"):
            need(c in cols, "nested object flattened into column %r" % c)
        lcols = set(r[1] for r in
                    conn.execute('PRAGMA table_info("sophis_links")'))
        need({"rel", "href", "sophis_id"} <= lcols,
             "child links table has rel/href + a parent FK: %r" % lcols)
        per = conn.execute('SELECT sophis_id, COUNT(*) FROM "sophis_links" '
                           'GROUP BY sophis_id').fetchall()
        need(len(per) == n and all(c == 4 for _, c in per),
             "every parent joins to exactly its 4 links")
        amt = conn.execute('SELECT strike_strikeValue_strikePrice_amount '
                           'FROM "sophis" LIMIT 1').fetchone()[0]
        eq(amt, 50, "a 3-level-deep value (strike amount) flattened intact")

    def t_json_reader_stdlib_override_and_diag():
        # (1) SAMQL_JSON_READER=stdlib forces the stdlib raw_decode reader even
        # for a '[' file -- the lever for boxes where ijson's per-object event
        # building is the slow part. (2) the CLI tool (tools/diag_load.py) is a
        # thin wrapper over the shared samql_core.diagnostics core, so the CLI
        # and the Error log -> Diagnostics tab never drift. Pure -> everywhere.
        import tempfile
        from samql_core import flatten as F
        p = tempfile.mktemp(suffix=".json")
        open(p, "w").write('[{"a":1,"b":{"c":2}},{"a":3,"b":{"c":4}}]')
        prev = os.environ.get("SAMQL_JSON_READER")
        try:
            os.environ["SAMQL_JSON_READER"] = "stdlib"
            recs = list(F.stream_json_records(p))
            need(len(recs) == 2 and recs[0]["a"] == 1,
                 "SAMQL_JSON_READER=stdlib still streams every record")
        finally:
            if prev is None:
                os.environ.pop("SAMQL_JSON_READER", None)
            else:
                os.environ["SAMQL_JSON_READER"] = prev
            os.unlink(p)
        # the CLI delegates to the shared core (imports profile_json_load)
        root = os.path.dirname(BACKEND)
        diag_path = os.path.join(root, "tools", "diag_load.py")
        need(os.path.exists(diag_path), "tools/diag_load.py is present")
        src = open(diag_path, encoding="utf-8").read()
        need("from samql_core.diagnostics import" in src
             and "profile_json_load" in src,
             "diag_load CLI uses the shared samql_core.diagnostics core")

    def t_stream_concatenated_records():
        # The streaming reader must handle a *stream of concatenated* top-level        # values -- one or more arrays and/or bare objects back to back -- not
        # just a single array. Before the fix, a file starting with '[' had
        # everything after the first array's ']' silently dropped. Pure -> runs
        # everywhere (exercises the stdlib concat reader; the ijson path uses
        # multiple_values for the same effect).
        from samql_core import flatten as F
        import tempfile as _tf
        import os as _os

        def _count(text):
            p = _tf.mktemp(suffix=".json")
            open(p, "w").write(text)
            try:
                return list(F.stream_json_records(p))
            finally:
                _os.unlink(p)

        eq(len(_count('[{"id":1},{"id":2},{"id":3}]')), 3, "single array")
        eq(len(_count('[{"id":1},{"id":2}][{"id":3},{"id":4}]')), 4,
           "concatenated arrays yield every element (not just the first array)")
        eq(len(_count('[{"id":1}][{"id":2},{"id":3}]{"id":4}')), 4,
           "mixed concatenated arrays + trailing object")
        eq(len(_count('{"id":1}{"id":2}{"id":3}')), 3, "concatenated objects")
        eq(len(_count('{"a":1}\n{"a":2}\n')), 2, "NDJSON still works")
        eq(len(_count('{"only":1}')), 1, "single object still works")
        # Object-first stream with an EMBEDDED top-level array: the array must be
        # unwrapped element-by-element (streamed), not yielded/buffered as one
        # whole list. This is the fallback path (first char != '['); it now uses
        # the same array-aware reader so an embedded array gets bounded-memory
        # streaming and the fast index + growing-read decode too.
        obj_first = _count('{"id":1}[{"id":2},{"id":3}]{"id":4}')
        eq(len(obj_first), 4,
           "object-first stream with an embedded array yields every record")
        need(all(isinstance(r, dict) for r in obj_first),
             "an embedded top-level array is unwrapped element-by-element, "
             "not buffered/yielded as one whole list")
        # end-to-end: concatenated arrays of trades with nested legs flatten to
        # every trade and every leg, across all arrays.
        p = _tf.mktemp(suffix=".json")
        open(p, "w").write(
            '[{"tradeId":"A","legs":[{"n":1}]}]'
            '[{"tradeId":"B","legs":[{"n":2},{"n":3}]}]')
        fl = F.JSONFlattener(root_name="trades")
        try:
            for rec in F.stream_json_records(p):
                fl.add_record(rec)
        finally:
            _os.unlink(p)
        eq(fl.row_count("trades"), 2, "both concatenated trades flattened")
        eq(fl.row_count("trades_legs"), 3, "all legs across both trades")

    def t_flatten_json_setting():
        # The 'flatten JSON on load' setting defaults OFF (nested Parquet is
        # the fast path), toggles, and persists to the config store. Restores
        # the real config file EXACTLY afterward (removing the key if it was
        # absent) so running the suite never flips the user's default.
        s = _fresh_session()
        had = "flatten_json" in s.config.data
        orig_val = s.config.data.get("flatten_json")
        orig_attr = getattr(s, "flatten_on_load", False)
        try:
            s.config.data.pop("flatten_json", None)
            need(bool(s.config.get("flatten_json", False)) is False,
                 "flatten defaults off when the key is unset")
            # Session attribute follows the same default when re-read from config
            s.flatten_on_load = bool(s.config.get("flatten_json", False))
            need(s.flatten_json_enabled() is False,
                 "session reports flatten off by default")
            need(s.set_flatten_json(True) is True, "set returns new state")
            need(s.flatten_json_enabled() is True, "reads back on")
            need(s.config.get("flatten_json") is True, "persisted to config")
            need(s.set_flatten_json(False) is False and not s.flatten_json_enabled(),
                 "toggled back off")
        finally:
            s.flatten_on_load = orig_attr
            if had:
                s.config.set("flatten_json", orig_val)
            else:
                s.config.data.pop("flatten_json", None)
                s.config.save()

    def t_json_load_shred_only_when_toggled():
        # Relational shred runs only when shred=True / flatten-on-load is on.
        # Default flatten is off so a plain DuckDB JSON load stays one nested
        # table (the fast path for multi-GB files).
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        # Force the session default off regardless of the user's config file.
        s.flatten_on_load = False
        dd = tempfile.mkdtemp()
        try:
            p = os.path.join(dd, "nested.json")
            with open(p, "w", encoding="utf-8") as f:
                json.dump([{"id": i, "legs": [{"n": i}, {"n": i + 1}]}
                           for i in range(20)], f)
            out = s.load_file(p, destination="duckdb", base_name="nest",
                              flatten=False, shred=False)
            names = {t.get("name") for t in out}
            eq(names, {"nest"},
               "no shred without toggle: single table %r" % names)
            need(not any(t.get("shredded") for t in out),
                 "shredded list absent when shred off")

            out2 = s.load_file(p, destination="duckdb", base_name="nest2",
                               flatten=False, shred=True)
            need(any(t.get("shredded") for t in out2),
                 "shred=True produces relational child tables: %r" % out2)
        finally:
            s.shutdown()
            shutil.rmtree(dd, ignore_errors=True)

    def t_flatten_json_load_routing():
        # .423 routing: a JSON load routes by the flatten setting and
        # engine, with the strategy INVERTED from the Python-streamer
        # era:
        #   DuckDB + flatten ON  -> native nested load FIRST (fast, the
        #                           path that always works), THEN the
        #                           in-engine recursive UNNEST flatten
        #                           (session.flatten_json) replacing it.
        #   DuckDB + flatten OFF -> the single nested table, untouched.
        #   SQLite               -> always the Python flattener.
        #   A flatten failure is LOUD and the nested load STANDS.
        from samql_core import loaders as L
        import tempfile as _tf
        calls = []

        class _FD:
            table_columns = {}

        _fd = _FD()

        class _Sess:
            db = object()
            low_memory = False

            def __init__(self, flatten, flat_result="ok"):
                self.flatten_on_load = flatten
                self._flat_result = flat_result

            def get_duckdb(self):
                return _fd

            def default_destination(self):
                return "duckdb"

            def flatten_table(self, table, base=None, **kw):
                # .501 audit: the load path runs the ONE hardened engine
                calls.append(("flatten_table", table, base))
                if self._flat_result == "boom":
                    raise ValueError("bind fail")
                if self._flat_result == "none":
                    return {"ok": True, "created": [], "base": None,
                            "note": "no nested columns to flatten"}
                return {"ok": True, "base": table,
                        "created": [
                            {"name": table, "rows": 925, "kind": "base"},
                            {"name": "json", "rows": 5000, "kind": "list"},
                            {"name": table + "_flattened", "rows": 925,
                             "kind": "joinkeys"},
                        ]}

        def _fake_lj(db, path, base_name=None, **kw):
            calls.append(("load_json", "duckdb" if db is _fd else "sqlite",
                          kw.get("engine")))
            return [{"name": "t", "rows": 1, "columns": [], "engine": "x"}]

        def _fake_nested(session, path, base_name, kind, **kw):
            calls.append(("nested", kind))
            return [{"table": base_name or "nb", "rows": 1, "columns": [],
                     "engine": "duckdb"}]

        o_lj, o_n = L.load_json, L._load_into_duckdb
        L.load_json, L._load_into_duckdb = _fake_lj, _fake_nested
        p = _tf.mktemp(suffix=".json")
        open(p, "w").write('[{"a":1}]')
        try:
            calls.clear()
            out = L.load_file(_Sess(True), p, destination="duckdb")
            need(calls[0] == ("nested", "json")
                 and calls[1][0] == "flatten_table",
                 "flatten-on: nested load FIRST, then flatten_table "
                 "replacing it in place: %r" % calls)
            need(isinstance(out, list)
                 and any(t.get("table", "").endswith("_flattened")
                         for t in out)
                 and all("table" in t for t in out),
                 "the load result reports the flattened tree "
                 "(hub included): %r" % out)
            calls.clear()
            L.load_file(_Sess(False), p, destination="duckdb")
            need(calls[:1] == [("nested", "json")]
                 and not any(c[0] == "flatten_table" for c in calls),
                 "flatten-off: nested table only: %r" % calls)
            calls.clear()
            L.load_file(_Sess(False), p, destination="sqlite")
            need(calls[:1] == [("load_json", "sqlite", None)],
                 "SQLite always flattens regardless of the toggle: "
                 "%r" % calls)
            # a flatten FAILURE is loud and the nested load stands
            calls.clear()
            out = L.load_file(_Sess(True, "boom"), p,
                              destination="duckdb")
            need(calls[0] == ("nested", "json")
                 and isinstance(out, list)
                 and out and out[0].get("table"),
                 "flatten failure: the nested load STANDS: %r" % out)
            # nothing-to-do keeps the nested load too
            calls.clear()
            out = L.load_file(_Sess(True, "none"), p,
                              destination="duckdb")
            need(isinstance(out, list) and out
                 and out[0].get("table"),
                 "flatten nothing-to-do keeps the nested load")
        finally:
            L.load_json, L._load_into_duckdb = o_lj, o_n
            os.unlink(p)

    def t_ram_detection_one_source():
        # RAM detection is now one function; the DuckDB memory cap (GiB) and the
        # session's low-memory heuristic (bytes) both delegate to it, so they
        # can't disagree. Pure -> runs anywhere, and on any real machine it
        # returns a positive byte count.
        from samql_core import engines as E
        from samql_core import Session
        b = E.total_physical_ram_bytes()
        need(isinstance(b, int) and b > 0, "detects some RAM: %r" % b)
        need(abs(E.DuckDBManager._total_ram_gb() - b / (1024 ** 3)) < 1e-6,
             "DuckDB GiB cap reads the same source")
        eq(Session._system_total_bytes(), b,
           "session low-memory heuristic reads the same source")

    def t_ondisk_threshold():
        # The size threshold that routes a load to an on-disk Parquet cache
        # (view) instead of an in-memory table. Pure -> runs everywhere.
        from samql_core import engines as E
        from samql_core import load_thresholds as LT
        old = os.environ.get("SAMQL_ONDISK_MB")
        old_h = os.environ.get("SAMQL_ONDISK_HARD_MB")
        LT.clear_overrides()
        try:
            os.environ.pop("SAMQL_ONDISK_MB", None)
            eq(E._ondisk_min_bytes(), 512 * 1024 * 1024, "default is 512 MB")
            os.environ["SAMQL_ONDISK_MB"] = "128"
            eq(E._ondisk_min_bytes(), 128 * 1024 * 1024, "override honored")
            os.environ["SAMQL_ONDISK_MB"] = "0"
            need(E._ondisk_min_bytes() is None,
                 "0 disables soft threshold")
            os.environ["SAMQL_ONDISK_MB"] = "junk"
            eq(E._ondisk_min_bytes(), 512 * 1024 * 1024, "bad value -> default")
            os.environ.pop("SAMQL_ONDISK_HARD_MB", None)
            eq(E._ondisk_hard_floor_bytes(), 256 * 1024 * 1024,
               "hard floor default 256 MB")
            os.environ["SAMQL_ONDISK_HARD_MB"] = "0"
            need(E._ondisk_hard_floor_bytes() is None,
                 "hard floor can be disabled for tests")
            # UI overrides beat env
            LT.apply_overrides({"ondisk_mb": 64})
            eq(E._ondisk_min_bytes(), 64 * 1024 * 1024,
               "UI override wins over env")
        finally:
            LT.clear_overrides()
            if old is None:
                os.environ.pop("SAMQL_ONDISK_MB", None)
            else:
                os.environ["SAMQL_ONDISK_MB"] = old
            if old_h is None:
                os.environ.pop("SAMQL_ONDISK_HARD_MB", None)
            else:
                os.environ["SAMQL_ONDISK_HARD_MB"] = old_h

    def t_load_thresholds_configure():
        # Session configure_load_thresholds persists and applies live.
        from samql_core import load_thresholds as LT
        from samql_core import engines as E
        LT.clear_overrides()
        s = _fresh_session()
        prev = dict(s.config.get("load_thresholds") or {})
        try:
            info = s.configure_load_thresholds(
                updates={"ondisk_mb": 100, "upload_mb": 2048})
            need(info.get("ok"), "info ok")
            eq(info["thresholds"]["ondisk_mb"]["value"], 100,
               "ondisk applied")
            eq(info["thresholds"]["ondisk_mb"]["source"], "override",
               "marked as override")
            eq(E._ondisk_min_bytes(), 100 * 1024 * 1024,
               "engines see live override")
            snap = s.config.get("load_thresholds") or {}
            eq(snap.get("ondisk_mb"), 100, "persisted in config")
            s.configure_load_thresholds(reset=True)
            need(E._ondisk_min_bytes() == 512 * 1024 * 1024
                 or isinstance(E._ondisk_min_bytes(), (int, type(None))),
                 "reset restores env/default path")
            need(not (s.config.get("load_thresholds") or {}),
                 "config key cleared on reset")
        finally:
            try:
                if prev:
                    s.configure_load_thresholds(updates=prev)
                else:
                    s.configure_load_thresholds(reset=True)
            except Exception:
                LT.clear_overrides()
            s.shutdown()

    def t_load_preflight():
        # Advise before large loads: missing file, Excel guidance, DuckDB gate.
        s = _fresh_session()
        td = tempfile.mkdtemp(prefix="samql_preflight_")
        try:
            miss = s.load_preflight("")
            need(not miss.get("ok") and miss.get("blockers"),
                 "empty path is a blocker")
            miss2 = s.load_preflight(os.path.join(td, "no-such-file-xyz.csv"))
            need(not miss2.get("ok")
                 and any("not found" in b.lower()
                         for b in (miss2.get("blockers") or [])),
                 "missing file blocks: %r" % miss2)
            xlsx = os.path.join(td, "preflight_tiny.xlsx")
            # Touch a fake workbook path (size/ext only — no real Excel bytes).
            with open(xlsx, "wb") as f:
                f.write(b"PK" + b"\0" * 200)
            xl = s.load_preflight(xlsx)
            need(xl.get("exists") and xl.get("ok"),
                 "tiny fake workbook is not a hard block")
            need(any("Excel" in w for w in (xl.get("warnings") or [])),
                 "Excel guidance warning present: %r" % xl)
            # Large CSV without DuckDB -> blocker. Force HAS_DUCKDB off.
            from samql_core import engines as E
            big = os.path.join(td, "preflight_big.csv")
            with open(big, "wb") as f:
                f.write(b"a,b\n" + b"1,2\n" * (70 * 1024))  # ~few hundred KB
            # Inflate reported size via patched getsize for the gate.
            real_getsize = os.path.getsize
            try:
                os.path.getsize = lambda p: (
                    600 * 1024 * 1024 if os.path.abspath(p) == os.path.abspath(big)
                    else real_getsize(p))
                old = E.HAS_DUCKDB
                E.HAS_DUCKDB = False
                try:
                    blocked = s.load_preflight(big)
                    need(not blocked.get("ok"),
                         "large CSV without DuckDB blocks")
                    need(any("DuckDB" in b
                             for b in (blocked.get("blockers") or [])),
                         "DuckDB required message: %r" % blocked)
                finally:
                    E.HAS_DUCKDB = old
            finally:
                os.path.getsize = real_getsize
        finally:
            s.shutdown()
            shutil.rmtree(td, ignore_errors=True)

    def t_copy_parquet_midflight_abort():
        # Mid-flight COPY monitor: byte ceiling and cancel interrupt early.
        from samql_core import engines as E
        import tempfile
        import time

        dest = tempfile.mktemp(suffix=".parquet")
        fwd = dest.replace("\\", "/")

        class _Cur:
            def __init__(self):
                self.interrupted = False
                self.calls = 0

            def execute(self, sql):
                self.calls += 1
                # Simulate a long COPY that grows the dest file.
                with open(dest, "wb") as f:
                    f.write(b"x" * (256 * 1024))
                t0 = time.time()
                while time.time() - t0 < 6.0:
                    if self.interrupted:
                        raise RuntimeError("INTERRUPT")
                    try:
                        with open(dest, "ab") as f:
                            f.write(b"y" * (512 * 1024))
                    except OSError:
                        pass
                    time.sleep(0.2)
                raise RuntimeError("COPY finished without interrupt")

            def interrupt(self):
                self.interrupted = True

        try:
            c = _Cur()
            try:
                E.exec_copy_parquet(
                    c, "SELECT 1", fwd, max_bytes=1024 * 1024)
                need(False, "byte ceiling must abort COPY")
            except RuntimeError as e:
                msg = str(e).lower()
                need("ceiling" in msg or "exceeded" in msg or "gib" in msg,
                     "ceiling error surfaces: %r" % e)
            need(c.interrupted, "interrupt was called")

            c2 = _Cur()
            try:
                E.exec_copy_parquet(
                    c2, "SELECT 1", fwd,
                    should_cancel=lambda: True)
                need(False, "cancel must abort COPY")
            except RuntimeError as e:
                need("cancel" in str(e).lower(),
                     "cancel error surfaces: %r" % e)
        finally:
            try:
                os.unlink(dest)
            except OSError:
                pass

    def t_ondisk_parquet_fail_no_ctas_fallthrough():
        # Large JSON: Parquet-route failure must NOT fall through to in-engine
        # CREATE TABLE AS (OOM risk). It raises a recoverable error so the
        # JSON loader can stream-flatten instead.
        from samql_core import loaders as L

        class _FakeDuck:
            def __init__(self):
                self.table_columns = {}
                self.ctas = 0

            def load_file_to_parquet_view(self, *a, **k):
                raise RuntimeError("simulated parquet COPY failure")

            def create_view_from_file(self, *a, **k):
                raise RuntimeError("simulated view failure")

            def create_table_from_file(self, *a, **k):
                self.ctas += 1
                raise AssertionError("CTAS must not run for large JSON")

            def apply_resource_memory_mb(self, *_a, **_k):
                return False

            def execute(self, _sql):
                return (None, [[0]])

        class _Sess:
            def get_duckdb(self):
                return duck

        duck = _FakeDuck()
        try:
            L._load_into_duckdb(_Sess(), "/tmp/big.json", "big", "json",
                                force_ondisk=True)
            need(False, "expected RuntimeError (no CTAS for large JSON)")
        except RuntimeError as e:
            need("Streaming flatten will be tried" in str(e)
                 or "On-disk Parquet load failed" in str(e),
                 "error signals stream recovery: %s" % e)
            need("simulated parquet" in str(e).lower()
                 or "COPY failure" in str(e),
                 "original failure preserved: %s" % e)
        eq(duck.ctas, 0, "create_table_from_file must not be called")

    def t_json_parquet_fail_stream_flatten_fallback():
        # Flatten-on: any Parquet conversion failure (not only OOM) must
        # stream-flatten so the load succeeds instead of hard-failing.
        from samql_core import loaders as L

        calls = {"stream": 0}

        def _fake_stream(*_a, **_k):
            calls["stream"] += 1
            return [{"name": "t", "rows": 1, "columns": ["a"],
                     "engine": "duckdb", "method": "stream-flatten"}]

        def _fake_native(*_a, **_k):
            raise RuntimeError(
                "On-disk Parquet load failed for large JSON x "
                "(simulated). Streaming flatten will be tried next.")

        o_sf, o_n = L._stream_flatten_into_duckdb, L._load_into_duckdb
        L._stream_flatten_into_duckdb = _fake_stream
        L._load_into_duckdb = _fake_native
        old_mb = os.environ.get("SAMQL_JSON_STREAM_FLATTEN_MB")
        # Keep giant-object short-circuit off so we exercise the Parquet path.
        os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = "0"
        try:
            class _Sess:
                def get_duckdb(self):
                    raise AssertionError("should not open duckdb here")

            dd = tempfile.mkdtemp()
            p = os.path.join(dd, "arr.json")
            with open(p, "w", encoding="utf-8") as f:
                f.write('[{"a":1},{"a":2}]')
            out = L._load_json_duckdb(_Sess(), p, "arr", flatten=True)
            eq(calls["stream"], 1, "stream flatten invoked once")
            eq(out[0]["method"], "stream-flatten", "stream result returned")
        finally:
            L._stream_flatten_into_duckdb = o_sf
            L._load_into_duckdb = o_n
            if old_mb is None:
                os.environ.pop("SAMQL_JSON_STREAM_FLATTEN_MB", None)
            else:
                os.environ["SAMQL_JSON_STREAM_FLATTEN_MB"] = old_mb

    def t_large_csv_sqlite_upgrades_to_duckdb():
        # Multi-hundred-MiB CSV with destination=sqlite must auto-upgrade to
        # DuckDB on-disk Parquet when DuckDB is available (never fail the load).
        if not feats["duckdb"]:
            skip("duckdb not installed")
        from samql_core import loaders as L
        old = os.environ.get("SAMQL_ONDISK_MB")
        old_h = os.environ.get("SAMQL_ONDISK_HARD_MB")
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "wide.csv")
        with open(p, "w", encoding="utf-8") as f:
            f.write("a,b\n")
            for i in range(500):
                f.write("%d,%d\n" % (i, i * 2))
        # Pretend the file is huge via a tiny soft threshold.
        os.environ["SAMQL_ONDISK_MB"] = "0.000001"  # ~1 byte
        os.environ["SAMQL_ONDISK_HARD_MB"] = "0"    # don't also trip floor
        s = _fresh_session()
