    def t_csv_parquet_fail_promotes_via_ctas():
        # When direct COPY→Parquet fails for CSV, CTAS then promote-to-Parquet
        # so the load still ends as an efficient cache (never a hard fail).
        from samql_core import loaders as L

        class _FakeDuck:
            def __init__(self):
                self.table_columns = {"t": ["a", "b"]}
                self.promoted = False
                self.ctas = 0

            def load_file_to_parquet_view(self, *a, **k):
                raise RuntimeError("simulated csv parquet COPY failure")

            def create_table_from_file(self, name, *a, **k):
                self.ctas += 1
                self.table_columns[name] = ["a", "b"]
                return name

            def view_to_parquet(self, table_name, cache, cancel=None):
                with open(cache, "wb") as f:
                    f.write(b"PAR1")  # stub bytes; view path mocked below
                self.promoted = True

            def drop_table(self, _name):
                pass

            def create_view_from_file(self, name, path, kind, delimiter=None):
                self.table_columns[name] = ["a", "b"]
                return name

            def apply_resource_memory_mb(self, *_a, **_k):
                return False

            def execute(self, _sql):
                return (None, [[2]])

        class _Sess:
            def get_duckdb(self):
                return duck

        duck = _FakeDuck()
        out = L._load_into_duckdb(_Sess(), "/tmp/big.csv", "big", "csv",
                                  force_ondisk=True)
        eq(duck.ctas, 1, "CTAS ran as Parquet recovery")
        need(duck.promoted, "table promoted to Parquet")
        eq(out[0].get("storage"), "parquet-cache",
           "final storage is parquet-cache: %s" % out)

    def t_duckdb_large_load_parquet_view():
        # End-to-end: a load at/above the on-disk threshold lands as a Parquet
        # cache exposed as a query-in-place view (bounded memory), not an
        # in-memory table -- and it's queryable with the right rows/columns.
        # Threshold dropped so a small fixture exercises it. Skips without duckdb.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        # The Parquet cache view is the NESTED large-file route; with flattening
        # on (the default) a JSON load normalizes instead, so take the nested
        # path here. Set the attribute DIRECTLY (not set_flatten_json, which
        # would persist to the real config and flip the user's default off).
        s.flatten_on_load = False
        dd = tempfile.mkdtemp()
        p = os.path.join(dd, "trades.json")
        with open(p, "w", encoding="utf-8") as f:
            json.dump([{"id": i, "sym": "X%d" % (i % 5)}
                       for i in range(30000)], f)      # ~0.6 MB single array
        old = os.environ.get("SAMQL_ONDISK_MB")
        old_j = os.environ.get("SAMQL_JSON_STREAM_MB")
        os.environ["SAMQL_ONDISK_MB"] = "0.1"          # ~100 KB -> force on-disk
        os.environ["SAMQL_JSON_STREAM_MB"] = "0.1"
        try:
            out = s.load_file(p, destination="duckdb", base_name="trades")
            eq(out[0].get("storage"), "parquet-cache",
               "a large load is stored as a Parquet cache view")
            cols = [c.lower() for c in out[0]["columns"]]
            need("id" in cols and "sym" in cols,
                 "the array keys became columns: %s" % cols)
            n = s.run_query("SELECT COUNT(*) FROM trades",
                            target="__duckdb__")["rows"][0][0]
            eq(n, 30000, "every row is queryable through the Parquet view")
            # the source points at a .parquet cache, confirming it's not in-memory
            src = s.duckdb.table_sources.get(out[0]["name"], "")
            need(str(src).lower().endswith(".parquet"),
                 "the table is backed by a Parquet file, not an in-memory copy")
        finally:
            for k, v in (("SAMQL_ONDISK_MB", old),
                         ("SAMQL_JSON_STREAM_MB", old_j)):
                if v is None:
                    os.environ.pop(k, None)
                else:
                    os.environ[k] = v
            s.shutdown()

    def t_flatten_no_source_dumps():
        # Flatten a DuckDB table that has NO file on disk (e.g. loaded from
        # the API connector, whose spooled temp file was deleted): flatten_json
        # must dump the table to JSON and flatten that instead of erroring
        # "No source file on disk". We inject a fake DuckDB whose COPY (...) TO
        # writes NDJSON, so the dump+flatten path runs without a real DuckDB.
        import re as _re
        import threading as _th
        s = _fresh_session()

        class _FakeConn:
            def execute(self, sql):
                # emulate DuckDB: COPY (...) TO 'path' (FORMAT JSON) -> NDJSON
                m = _re.search(r"TO '([^']+)'", sql)
                if not m:
                    raise RuntimeError("fake COPY: no path in " + sql)
                with open(m.group(1), "w", encoding="utf-8") as f:
                    for i in range(4):
                        f.write(json.dumps(
                            {"id": i, "name": f"r{i}",
                             "tags": [{"t": "x"}, {"t": "y"}]}) + "\n")
                return self

        class _FakeDuck:
            def native_op_cursor(self):
                import contextlib as _cl

                @_cl.contextmanager
                def _inner():
                    yield self.conn, self.write_lock
                return _inner()

            def __init__(self):
                self.table_sources = {}          # no source -> triggers dump
                self.table_columns = {}
                self.write_lock = _th.RLock()
                self.conn = _FakeConn()
                self._rows = {}                  # tables the flatten writes here

            # the flatten now lands the relational tables back in DuckDB (this
            # engine), so a fake add_table_streaming records what it receives.
            def add_table_streaming(self, raw_name, columns, row_iter,
                                    source="", chunk=50000):
                rows = list(row_iter)
                name, k = raw_name, 2
                while name in self.table_columns:
                    name = "%s_%d" % (raw_name, k)
                    k += 1
                self.table_columns[name] = list(columns)
                self._rows[name] = rows
                return name, len(rows)

            # tables_tree() asks the engine for column types when it lists the
            # newly-created DuckDB tables; return a dict so it doesn't choke.
            def column_types(self, name):
                return {c: "" for c in self.table_columns.get(name, [])}

            # no-op the lifecycle/catalog calls the session makes
            # (sync_catalog, recycle, drop_all, close, checkpoint, ...)
            def __getattr__(self, _name):
                return lambda *a, **k: None

        try:
            # sanity: a non-duckdb engine with no file still reports clearly
            r0 = s.flatten_json("api_data", engine="sqlite")
            need("error" in r0 and "No source file" in r0["error"],
                 "sqlite/no-file flatten should still report no source file")
            # the duckdb dump path -> the flattened tables now land in
            # DuckDB (this engine), NOT SQLite.
            s.duckdb = _FakeDuck()
            res = s.flatten_json("api_data", engine="duckdb")
            need(res.get("ok"),
                 "flatten from dump failed: " + str(res.get("error")))
            tables = res.get("tables") or []
            names = {t["name"] for t in tables}
            need("api_data" in names, "root table missing from dump-flatten")
            child = next((t for t in tables
                          if t["name"].startswith("api_data_tags")), None)
            need(child is not None,
                 "nested child table missing from dump-flatten")
            eq(child["rows"], 8, "flattened child rows (4 rows x 2 tags)")
            need(all(t.get("engine") == "duckdb" for t in tables),
                 "a DuckDB table's flatten must land in DuckDB, not SQLite")
            need(s.duckdb._rows.get(child["name"]) is not None,
                 "the flattened child rows were written to the DuckDB engine")
        finally:
            s.shutdown()

    def t_flatten_source_predicate():
        # _source_is_json_file gates ONLY the read-the-file-directly shortcut:
        # true for a JSON/NDJSON file on disk, false for anything else -- so a
        # DuckDB table with a non-JSON source still routes to the dump path
        # rather than being rejected. Pure -> runs everywhere.
        from samql_core.session import _source_is_json_file
        dd = tempfile.mkdtemp()
        j = os.path.join(dd, "a.json")
        open(j, "w").write("[]")
        nd = os.path.join(dd, "a.ndjson")
        open(nd, "w").write("{}\n")
        t = os.path.join(dd, "a.txt")
        open(t, "w").write("x")
        need(_source_is_json_file(j), "a .json file reads directly")
        need(_source_is_json_file(nd), "a .ndjson file reads directly")
        need(not _source_is_json_file(t), ".txt is not read directly (dump)")
        need(not _source_is_json_file(os.path.join(dd, "nope.json")),
             "a missing file is not read directly")
        need(not _source_is_json_file(None), "no source -> dump path")
        need(not _source_is_json_file(""), "empty source -> dump path")

    def t_flatten_duckdb_nonjson_source_dumps():
        # A DuckDB table whose SOURCE FILE is not JSON (its JSON arrived as a
        # .txt bundle, or it's backed by a Parquet cache from a large load) must
        # still flatten -- by dumping the table to JSON -- instead of erroring
        # "not a JSON-backed table". Uses the same FakeDuck dump path, so it
        # runs without a real DuckDB.
        import re as _re
        import threading as _th
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        src = os.path.join(dd, "sophis_derivs.txt")     # non-JSON extension
        with open(src, "w", encoding="utf-8") as f:
            f.write("(placeholder; flatten must dump the table, not read this)\n")

        class _FakeConn:
            def execute(self, sql):
                m = _re.search(r"TO '([^']+)'", sql)
                if not m:
                    raise RuntimeError("fake COPY: no path in " + sql)
                with open(m.group(1), "w", encoding="utf-8") as f:
                    for i in range(3):
                        f.write(json.dumps(
                            {"id": i, "legs": [{"k": "a"}, {"k": "b"}]}) + "\n")
                return self

        class _FakeDuck:
            def native_op_cursor(self):
                import contextlib as _cl

                @_cl.contextmanager
                def _inner():
                    yield self.conn, self.write_lock
                return _inner()

            def __init__(self):
                self.table_sources = {"derivs": src}    # non-JSON file on disk
                self.table_columns = {}                 # empty: no name collision
                self.write_lock = _th.RLock()
                self.conn = _FakeConn()
                self._rows = {}

            def add_table_streaming(self, raw_name, columns, row_iter,
                                    source="", chunk=50000):
                rows = list(row_iter)
                name, k = raw_name, 2
                while name in self.table_columns:
                    name = "%s_%d" % (raw_name, k)
                    k += 1
                self.table_columns[name] = list(columns)
                self._rows[name] = rows
                return name, len(rows)

            def column_types(self, name):
                return {c: "" for c in self.table_columns.get(name, [])}

            def __getattr__(self, _name):
                return lambda *a, **k: None

        try:
            s.duckdb = _FakeDuck()
            res = s.flatten_json("derivs", engine="duckdb")
            need(res.get("ok"),
                 "non-JSON-source flatten should dump+flatten, got: "
                 + str(res.get("error")))
            names = {t["name"] for t in (res.get("tables") or [])}
            need("derivs" in names, "root table present after dump-flatten")
            need(any(n.startswith("derivs_legs") for n in names),
                 "nested child table produced from the dumped JSON")
        finally:
            s.shutdown()

    def t_load_view_mode():
        # "Query the file in place" load mode: a DuckDB view over read_*,
        # not a materialized copy. Two live checks (the DuckDB view SQL itself
        # needs a real DuckDB, so that part is asserted structurally):
        #   A) with no DuckDB available, view mode safely FALLS BACK to a
        #      normal materialized load (so it never hard-fails);
        #   B) with DuckDB present (faked here), it routes to a view and
        #      returns a view descriptor instead of copying.
        import samql_core.loaders as L
        import threading as _th
        s = _fresh_session()
        dd = tempfile.mkdtemp()
        csv = os.path.join(dd, "rows.csv")
        with open(csv, "w", encoding="utf-8") as f:
            f.write("id,name\n1,a\n2,b\n3,c\n")
        try:
            # A) no DuckDB -> fall back to materialize. Force DuckDB "off" for
            #    this case so the check is hermetic: on a host that actually
            #    has DuckDB installed, get_duckdb() lazily builds a real engine
            #    and view mode would (correctly) return a view, not a fallback.
            _orig_gd = s.get_duckdb
            s.get_duckdb = lambda: None
            try:
                out = L.load_file(s, csv, destination="sqlite",
                                  base_name="fallback", mode="view")
                need(out and not out[0].get("view"),
                     "view mode without DuckDB should fall back to materialize")
                n = s.run_query("SELECT COUNT(*) FROM fallback",
                                target="__local__")["rows"][0][0]
                eq(n, 3, "fallback materialized rows")
            finally:
                s.get_duckdb = _orig_gd

            # B) DuckDB present (faked) -> a view, not a copy
            class _FakeDuck:
                def __init__(self):
                    self.table_columns = {}
                    self.table_sources = {}
                    self.write_lock = _th.RLock()

                def create_view_from_file(self, name, path, kind,
                                          delimiter=None):
                    self.view_call = (name, kind)
                    self.table_columns[name] = ["id", "name"]
                    self.table_sources[name] = path
                    return name

                def __getattr__(self, _n):
                    return lambda *a, **k: None

            s.duckdb = _FakeDuck()
            out2 = L.load_file(s, csv, destination="auto",
                               base_name="inplace", mode="view")
            need(out2 and out2[0].get("view") is True,
                 "view mode with DuckDB should return a view descriptor")
            eq(out2[0]["engine"], "duckdb", "view lives in DuckDB")
            eq(out2[0]["rows"], None, "a view has no eager row count")
            eq(s.duckdb.view_call, ("inplace", "csv"), "view kind = csv")
        finally:
            s.shutdown()

    def t_parquet_materializes_by_default():
        # A .parquet load now reads the file once into a real DuckDB table
        # (fast repeated queries / node re-runs) instead of a zero-copy view
        # that re-parses on every query. Query-in-place is still available via
        # mode="view" (the escape hatch for files too big to copy). DuckDB is
        # faked here so the routing is checked without a real engine.
        import samql_core.loaders as L
        import threading as _th

        class _FakeDuck:
            def __init__(self):
                self.table_columns = {}
                self.table_sources = {}
                self.write_lock = _th.RLock()
                self.table_call = None
                self.view_call = None

            def create_table_from_file(self, name, path, kind, delimiter=None,
                                       **_kw):
                self.table_call = (name, kind)
                self.table_columns[name] = ["a", "b"]
                self.table_sources[name] = path
                return name

            def create_view_from_file(self, name, path, kind, delimiter=None,
                                      **_kw):
                self.view_call = (name, kind)
                self.table_columns[name] = ["a", "b"]
                self.table_sources[name] = path
                return name

            def execute(self, _sql):
                return (None, [[0]])

            def __getattr__(self, _n):
                return lambda *a, **k: None

        s = _fresh_session()
        try:
            # default load -> materialized table, NOT a view
            s.duckdb = _FakeDuck()
            out = L.load_file(s, "/tmp/data.parquet", destination="auto",
                              base_name="pq_mat", mode="materialize")
            need(out and not out[0].get("view"),
                 "default parquet load should materialize, not view")
            eq(out[0]["engine"], "duckdb", "materialized parquet lives in DuckDB")
            eq(s.duckdb.table_call, ("pq_mat", "parquet"),
               "parquet routed to create_table_from_file")
            need(s.duckdb.view_call is None,
                 "default parquet load must not create a view")
            # explicit query-in-place -> a view (escape hatch for huge files)
            s.duckdb = _FakeDuck()
            out2 = L.load_file(s, "/tmp/data.parquet", destination="auto",
                               base_name="pq_view", mode="view")
            need(out2 and out2[0].get("view") is True,
                 "mode=view should still create a parquet view")
            eq(s.duckdb.view_call, ("pq_view", "parquet"),
               "view mode routed to create_view_from_file")
            need(s.duckdb.table_call is None,
                 "view mode must not materialize")
        finally:
            s.shutdown()

    def t_iterator_container_backend():
        # Backend pieces for the container iterator: (a) the iterator's new
        # "out" port reads from its accumulator table by name so downstream
        # nodes can build on it; (b) the driver row -> ${var} binding honors the
        # column->name rename. Both are pure (no engine needed).
        from samql_core import nodeflow as NF
        from samql_core.session import _rename_row_vars
        gi = lambda _p: None
        co = lambda _t: []
        # (a) out compiles to a read of the (sanitized) accumulator table
        sql = NF.node_output_sql(
            {"type": "iterator", "id": "it", "config": {"table": "my acc!"}},
            "out", gi, co, None)
        need('SELECT * FROM "my_acc" AS _iter' in sql,
             "iterator out should read its accumulator table")
        raised = False
        try:
            NF.node_output_sql({"type": "iterator", "id": "it2",
                                "config": {}}, "out", gi, co, None)
        except NF.NodeflowError:
            raised = True
        need(raised, "iterator out without an accumulator name should raise")
        # (b) rename: renamed col -> new var name (original dropped); others kept
        r = _rename_row_vars({"date": "2026-01", "amt": 5, "n": None},
                             {"date": "as_of"})
        eq(r.get("as_of"), "2026-01", "renamed driver column becomes the var")
        need("date" not in r, "original column name dropped once renamed")
        eq(r.get("amt"), "5", "unrenamed column keeps its name (stringified)")
        eq(r.get("n"), "", "None binds as empty string")

    def t_opreg_progress_percent():
        # The op registry computes a true completion percentage when a total is
        # known, and reports None (indeterminate) when it is not.
        from samql_core import progress as opreg
        opreg.reset_for_tests()
        try:
            opreg.begin("query", op_id="p1")
            opreg.advance(3, 12, unit="pass", op_id="p1")
            snap = [o for o in opreg.snapshot() if o["id"] == "p1"][0]
            eq(snap["percent"], 25.0, "3/12 -> 25%")
            eq(snap["unit"], "pass", "unit is recorded")
            eq(snap["done"], 3, "done recorded")
            eq(snap["total"], 12, "total recorded")
            opreg.advance(12, 12, op_id="p1")
            snap = [o for o in opreg.snapshot() if o["id"] == "p1"][0]
            eq(snap["percent"], 100.0, "12/12 -> 100%")
            opreg.begin("query", op_id="p2")
            snap = [o for o in opreg.snapshot() if o["id"] == "p2"][0]
            need(snap["percent"] is None,
                 "no total -> percent None (indeterminate bar)")
            opreg.advance(99, 10, op_id="p2")
            snap = [o for o in opreg.snapshot() if o["id"] == "p2"][0]
            eq(snap["percent"], 100.0, "over-100 clamps to 100")
        finally:
            opreg.reset_for_tests()

    def t_iterator_reports_progress():
        # End to end: a 2-pass container iterator must report determinate
        # progress (pass idx of the known pass count) to the op registry, keyed
        # by its query id, so the Run bar shows a true percentage.
        from samql_core import progress as opreg
        calls = []
        orig = opreg.advance

        def spy(done=None, total=None, unit=None, op_id=None):
            calls.append((done, total, unit, op_id))
            return orig(done=done, total=total, unit=unit, op_id=op_id)

        opreg.advance = spy
        s = Session()
        try:
            vals = {"id": "v", "type": "createtable", "config": {
                "label": "v", "columns": ["col1"],
                "rows": [["a"], ["b"]], "dest": "sqlite"}}
            body = {"id": "b", "type": "createtable", "config": {
                "label": "b", "columns": ["x"],
                "rows": [["z"]], "dest": "sqlite"}}
            it = {"id": "it", "type": "iterator", "config": {
                "table": "res", "accumulate": "append", "reset_first": False,
                "children": [{"id": "fx", "type": "formula", "config": {
                    "label": "formula",
                    "formulas": [{"name": "x2", "expr": "{{col1}}"}]}}]}}
            g = {"nodes": [vals, body, it], "edges": [
                {"from": {"node": "v", "port": "out"},
                 "to": {"node": "it", "port": "vars"}},
                {"from": {"node": "b", "port": "out"},
                 "to": {"node": "it", "port": "in"}}]}
            r = s.run_iterator(g, "it", query_id="QID")
            need(not r.get("error"),
                 "iterator ran: %s" % (r.get("error") or r.get("errors")))
            mine = [c for c in calls if c[3] == "QID"]
            need(mine, "iterator reported progress for its query id")
            dones = sorted(set(c[0] for c in mine))
            need(1 in dones and 2 in dones,
                 "reported pass 1 and pass 2: %r" % dones)
            need(all(c[1] == 2 for c in mine),
                 "total is the 2-row pass count: %r" % mine)
            need(all(c[2] == "pass" for c in mine), "unit is 'pass'")
        finally:
            opreg.advance = orig
            s.shutdown()

    def t_run_loops_report_progress_wiring():
        # Guard the determinate-progress reporting in all three loop bodies
        # (cheaper than building a converging while graph): each reports
        # done/total to opreg so the Run bar can show a real percentage.
        src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        need(re.search(r'opreg\.advance\(idx, len\(var_rows\), unit="pass"',
                       src),
             "container iterator must report opreg.advance(idx, len(var_rows))")
        need(re.search(r'opreg\.advance\(idx, len\(values\), unit="pass"', src),
             "classic iterator must report opreg.advance(idx, len(values))")
        need(re.search(r'opreg\.advance\(i, max_iters, unit="iteration"', src),
             "while loop must report opreg.advance(i, max_iters)")

    def t_retry_loops_unified():
        import samql_core.apiload as A
        src = open(os.path.join(BACKEND, "samql_core", "apiload.py"),
                   encoding="utf-8").read()
        eq(len(re.findall(r"for attempt in range\(", src)), 1,
           "exactly one retry loop should remain (was two)")
        need("_retry_call(" in src, "_retry_call must exist")
        # both tuple shapes give up with an error set after a stuck status
        seen = []
        fr = A._fetch_with_retries(lambda: (503, "j", None, "b", None),
                                   {"retries": 1},
                                   sleep=lambda s: seen.append(s))
        eq(fr[0], 503, "fetch give-up keeps status")
        need(fr[4] and "gave up" in fr[4], "fetch give-up sets error field")
        eq(len(seen), 1, "one backoff sleep between two attempts")
        sr = A._spool_with_retries(lambda: (502, "c", None, 7),
                                   {"retries": 1}, sleep=lambda s: None)
        eq(sr[0], 502, "spool give-up keeps status")
        need(sr[2] and "gave up" in sr[2], "spool give-up sets error msg")
        eq(sr[3], 7, "spool give-up keeps nbytes")
        fr2 = A._fetch_with_retries(lambda: (200, "j", {"x": 1}, "", None),
                                    {"retries": 3}, sleep=lambda s: None)
        eq(fr2[2], {"x": 1}, "non-transient success returns data untouched")

    def t_col_names_shared():
        from samql_core.session import Session

        class _Eng:
            def __init__(self):
                self.q = []

            def execute(self, sql):
                self.q.append(sql)
                return (["a", "b"], [])

        sess = Session.__new__(Session)  # _col_names uses only the engine
        e = _Eng()
        eq(sess._col_names(e, table="my tbl"), ["a", "b"], "table columns")
        need('FROM "my tbl" LIMIT 0' in e.q[-1], "table probe query shape")
        eq(sess._col_names(e, sql="SELECT 1"), ["a", "b"], "subquery columns")
        need("(SELECT 1) AS _z LIMIT 0" in e.q[-1], "subquery probe shape")

        class _Empty:
            def execute(self, sql):
                return (None, [])

        eq(sess._col_names(_Empty(), table="x"), [], "None cols -> []")
        src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        need(src.count("_col_names(") >= 8,
             "the LIMIT-0 introspection sites should use the shared helper")

