    def t_field_tree_heterogeneous_keys_after_early_resolve():
        # CODE was wrong: once head rows resolved array shapes, mid/end probes
        # were skipped — keys that only appear on later records never showed.
        # Phase-2 probes always run for key union when more rows exist.
        if not feats["duckdb"]:
            skip("duckdb not installed")
        s = _fresh_session()
        try:
            # First rows: resolved contacts array. Later rows add unique keys.
            rows = []
            for i in range(40):
                rows.append({
                    "contacts": [{"role": "ops"}],
                    "common": i,
                })
            # Past sequential early-exit: rare keys only at the end.
            rows.append({
                "contacts": [{"role": "rare", "email": "r@x.com"}],
                "common": 99,
                "only_at_end": {"deep_key": 1},
            })
            duck = s.get_duckdb()
            duck.conn.execute(
                "CREATE OR REPLACE TABLE fe_het AS "
                "SELECT unnest(?)::JSON AS payload", [rows])
            duck.sync_catalog()
            tree = s.column_field_tree("duckdb", "fe_het", "payload")
            names = [f.get("name") for f in (tree.get("fields") or [])]
            need("contacts" in names and "role" in names,
                 "resolved array keys present: %r" % names)
            need("only_at_end" in names and "deep_key" in names,
                 "late heterogeneous keys found via mid/end probes: %r"
                 % names)
            need("email" in names,
                 "late contact field unioned: %r" % names)
        finally:
            s.shutdown()

    def t_rest_and_mssql_cancel():
        # Part 3: the IDE REST API fetch (load_api) and the MSSQL import
        # (import_from_connection) register their query id and bail when it's
        # been cancelled; cancel_query interrupts a registered SQL Server
        # connection (which forwards to the active pyodbc cursor's .cancel()).
        s = _loaded_session()
        # REST fetch: a pre-flagged cancel bails before any network request
        s.cancel_query("rest1")
        r = s.load_api("http://example.invalid/x", base_name="apix",
                       query_id="rest1")
        need(r.get("cancelled"), "load_api must bail when pre-cancelled")

        class _StubConn:
            def __init__(self):
                self.interrupted = False

            def execute(self, q):
                raise AssertionError("must not execute a pre-cancelled import")

            def interrupt(self):
                self.interrupted = True

        # MSSQL import: pre-flagged cancel bails before the remote query runs
        s.connections["stub"] = _StubConn()
        s.cancel_query("imp1")
        r2 = s.import_from_connection("stub", "SELECT 1", query_id="imp1")
        need(r2.get("cancelled"),
             "import_from_connection must bail when pre-cancelled")
        # cancel_query interrupts a registered remote connection
        sc2 = _StubConn()
        s._register_run("imp2", sc2, kind="mssql", target="stub")
        s.cancel_query("imp2")
        need(sc2.interrupted,
             "cancel_query must call interrupt() on a registered SQL Server "
             "connection (forwards to cursor.cancel)")
        s._unregister_run("imp2")
        s.shutdown()

    def t_flatten_cancel_not_swallowed():
        # Regression: the JSON flattener wrapped its progress callback in
        # `except Exception: pass`, which SWALLOWED the LoadCancelled the load
        # job raises on Stop -- so a cancelled flatten ran to completion and
        # SQLite finished flattening anyway. The cancel signal must now
        # propagate out of the per-row progress block.
        from samql_core import flatten

        class LoadCancelled(Exception):
            pass

        def boom(_n):
            raise LoadCancelled()

        fl = flatten.JSONFlattener(root_name="r", progress_cb=boom)
        hit = ""
        try:
            for i in range(5000):   # progress_cb fires at emit_total % 5000
                fl.add_record({"a": i})
        except Exception as e:
            hit = type(e).__name__
        finally:
            fl.close()
        eq(hit, "LoadCancelled",
           "flattener must propagate a cancel raised by the progress "
           "callback, not swallow it")

    def t_flatten_json_load_cancellable():
        # End-to-end: a progress callback that signals cancel must abort
        # load_json mid-flatten (the path a JSON file load and the flatten
        # action both take), not run the whole SQLite flatten to completion.
        from samql_core import loaders
        s = _fresh_session()
        d = tempfile.mkdtemp(prefix="fljson_")
        try:
            p = os.path.join(d, "big.json")
            with open(p, "w", encoding="utf-8") as f:
                json.dump([{"a": i, "b": i * 2} for i in range(6000)], f)

            def prog(done, total=0):
                raise loaders.LoadCancelled()

            raised = False
            try:
                loaders.load_json(s.db, p, base_name="big", progress=prog)
            except loaders.LoadCancelled:
                raised = True
            need(raised, "load_json must abort when the progress callback "
                         "signals cancel during the flatten")
        finally:
            s.shutdown()
            shutil.rmtree(d, ignore_errors=True)

    def t_run_query_spark_dialect():
        # The run path can transpile a source dialect (Spark SQL) to the
        # resolved engine's dialect before executing, gated on sqlglot. A
        # construct sqlglot can't translate surfaces as an error -- never
        # silently-mangled SQL. native (and absent) dialect run SQL as-is.
        import importlib.util as _ilu
        has = _ilu.find_spec("sqlglot") is not None
        s = _fresh_session()
        try:
            r = s.run_query("SELECT 1 AS x", target="__local__",
                            dialect="spark")
            if has:
                need(not r.get("error"),
                     "spark dialect should transpile + run when sqlglot is "
                     "present, got: %r" % r)
            else:
                need(bool(r.get("error"))
                     and "sqlglot" in str(r.get("error")).lower(),
                     "spark dialect without sqlglot must surface the "
                     "install-sqlglot error, got: %r" % r)
            r2 = s.run_query("SELECT 1 AS x", target="__local__",
                             dialect="native")
            need(not r2.get("error"),
                 "native dialect must run SQL as-is: %r" % r2)
            r3 = s.run_query("SELECT 1 AS x", target="__local__")
            need(not r3.get("error"),
                 "absent dialect must run SQL as-is: %r" % r3)
        finally:
            s.shutdown()

    def t_flatten_csv_cancel_midrecord():
        # The JSON->CSV flattener (Load Data > Flatten -- the X/Cancel button)
        # checks cancel between top-level records, but a single record that
        # explodes into a huge nested subtree used to spin inside add_record
        # uninterruptibly. A cancel-aware progress_cb now aborts it mid-record
        # too, and the partial output is rolled back. (This path streams to CSV
        # via the pure-Python flattener; it does not touch SQLite.)
        from samql_core import loaders
        s = _fresh_session()
        d = tempfile.mkdtemp(prefix="flcsv_")
        out = tempfile.mkdtemp(prefix="flcsvout_")
        try:
            src = os.path.join(d, "big.json")
            # ONE record -> >5000 emitted child rows, so a cancel that is False
            # at the per-record check but True once inside add_record proves the
            # mid-record path (the flattener's progress_cb), not the outer loop.
            with open(src, "w", encoding="utf-8") as f:
                json.dump({"id": 1, "items": [{"k": i} for i in range(12000)]},
                          f)
            calls = {"n": 0}

            def cancel():
                calls["n"] += 1
                return calls["n"] >= 2

            raised = False
            try:
                s.flatten_json_to_csv_dir(src, out, cancel=cancel)
            except loaders.LoadCancelled:
                raised = True
            need(raised, "flatten_json_to_csv_dir must raise LoadCancelled "
                         "mid-record when cancel flips inside a single huge "
                         "record")
            need(calls["n"] >= 2,
                 "cancel must be polled from inside add_record, not only the "
                 "per-record loop")
            flat = os.path.join(out, "big_flattened")
            need(not os.path.isdir(flat) or not os.listdir(flat),
                 "a cancelled flatten rolls back the CSVs it wrote")
        finally:
            s.shutdown()
            shutil.rmtree(d, ignore_errors=True)
            shutil.rmtree(out, ignore_errors=True)

    def t_load_json_engine_label():
        # load_json labels its output tables with the engine it wrote to, so
        # the flatten action can land DuckDB-sourced tables in DuckDB rather
        # than always SQLite. Default stays sqlite (the file-load path).
        from samql_core import loaders
        s = _fresh_session()
        d = tempfile.mkdtemp(prefix="ljlabel_")
        try:
            p = os.path.join(d, "x.json")
            with open(p, "w", encoding="utf-8") as f:
                json.dump([{"a": 1}, {"a": 2}], f)
            out = loaders.load_json(s.db, p, base_name="x1")
            need(out and all(t.get("engine") == "sqlite" for t in out),
                 "load_json defaults to the sqlite engine label: %r" % out)
            out2 = loaders.load_json(s.db, p, base_name="x2", engine="duckdb")
            need(out2 and all(t.get("engine") == "duckdb" for t in out2),
                 "load_json labels output with the engine passed in: %r" % out2)
        finally:
            s.shutdown()
            shutil.rmtree(d, ignore_errors=True)

    def t_flatten_targets_source_engine():
        # The flatten action loads the flattened tables into the SAME engine
        # the source lives in (DuckDB->DuckDB, SQLite->SQLite), not always
        # SQLite. DuckDB can't run in this sandbox, so guard the routing at the
        # source: flatten_json registers the run on `mgr` and calls
        # load_json(mgr, ..., engine=engine) -- never a hardcoded self.db.
        src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                   encoding="utf-8").read()
        body = src[src.index("def flatten_json(self,"):]
        body = body[:body.index("def _duckdb_table_to_json")]
        need('mgr = self.duckdb if engine == "duckdb" else self.db' in body,
             "flatten_json picks the engine manager from the source engine")
        need("self._register_run(query_id, mgr," in body,
             "flatten_json registers the run on the source engine's manager")
        need("loaders.load_json(mgr," in body and "engine=engine" in body,
             "flatten_json loads the flattened tables into the source engine")
        need("loaders.load_json(self.db" not in body
             and "_register_run(query_id, self.db, kind=\"flatten\"" not in body,
             "flatten_json must not hardcode the SQLite manager as the target")

    def t_iterator_pass_fetch_cancel():
        # The per-pass API fetch inside an iterator / while now shares the run's
        # cancel check (so a mid-fetch Stop is cooperative) WITHOUT clobbering
        # the run's registration: a caller that already owns the run passes
        # should_cancel, and fetch_api_node must NOT _unregister_run that id --
        # doing so would discard the run's cancel flag and end its progress
        # entry. A non-http URL fails fast (no network), so the bookkeeping is
        # all we observe.
        s = _fresh_session()
        try:
            # the iterator owns the run; a cancel flag is live on it
            s._register_run("itq", None)
            s._cancelled_runs.add("itq")
            try:
                s.fetch_api_node(
                    "n1", {"url": "ftp://nowhere/x"}, graph={},
                    should_cancel=lambda: s._run_is_cancelled("itq"))
            except Exception:
                pass
            need("itq" in s._cancelled_runs,
                 "a per-pass fetch must NOT discard the run's cancel flag "
                 "(the iterator still owns 'itq')")
            s._unregister_run("itq")
            # a standalone API node owns + clears its own id (own_run path)
            s._register_run("ownq", None)
            s._cancelled_runs.add("ownq")
            try:
                s.fetch_api_node("n2", {"url": "ftp://nowhere/y"}, graph={},
                                 query_id="ownq")
            except Exception:
                pass
            need("ownq" not in s._cancelled_runs,
                 "a standalone fetch unregisters (and clears) its own id")
            # the iterator / container / while loops thread the run cancel
            # check into their per-pass fetch
            src = open(os.path.join(BACKEND, "samql_core", "session.py"),
                       encoding="utf-8").read()
            need(src.count(
                     "should_cancel=lambda: self._run_is_cancelled(query_id)")
                 >= 1 and src.count("should_cancel=(") >= 2,
                 "iterator / container / while per-pass fetches must pass the "
                 "run cancel check")
        finally:
            s.shutdown()

    def t_materialize():
        # Reconcile compares named tables only, so notebook reconcile cells
        # stage their inputs via Session.materialize. Verify it creates a
        # queryable, catalog-registered table, replaces on re-run, guards bad
        # input, and that two materialised tables reconcile correctly.
        s = _fresh_session()
        try:
            s.db.conn.execute('CREATE TABLE src (id INTEGER, v REAL)')
            s.db.conn.execute(
                "INSERT INTO src VALUES (0,0),(1,10),(2,20),(3,30),(4,40),(5,50)")
            s.db.conn.commit()
            s.db.sync_catalog()
            r = s.materialize("__nb_t", "SELECT id FROM src WHERE id < 5",
                              target="__local__")
            eq(r.get("columns"), ["id"], "materialise returns columns")
            need("__nb_t" in s.db.table_columns,
                 "materialised table not registered in catalog")
            n = s.run_query('SELECT COUNT(*) FROM "__nb_t"',
                            target="__local__")["rows"][0][0]
            eq(n, 5, "materialised row count")
            # re-materialise replaces (shape changes id -> id,v)
            s.materialize("__nb_t", "SELECT id, v FROM src", target="__local__")
            eq(s.db.table_columns.get("__nb_t"), ["id", "v"],
               "re-materialise replaces shape")
            # M1: staging tables are not advertised by tables_tree, but the
            # user's real table is, and reconcile can still resolve the hidden
            # staging tables.
            tnames = [t["name"] for t in s.tables_tree()]
            need(all(not n.startswith("__") for n in tnames),
                 "tables_tree must hide __ staging tables: %r" % tnames)
            need("src" in tnames, "tables_tree must still show real tables")
            # guards
            need(s.materialize('x"; DROP', "SELECT 1",
                               target="__local__").get("error"),
                 "bad name not rejected")
            need(s.materialize("__nb_w", "DROP TABLE src",
                               target="__local__").get("error"),
                 "write statement not rejected")
            # the point of the feature: two materialised tables reconcile
            s.materialize("__nb_l", "SELECT id, v FROM src WHERE id < 4",
                          target="__local__")  # {0,1,2,3}
            s.materialize("__nb_r", "SELECT id, v FROM src WHERE id > 1",
                          target="__local__")  # {2,3,4,5}
            rep = s.reconcile({"left": "__nb_l", "right": "__nb_r",
                               "keys": ["id"], "compare": ["v"]})
            tot = rep.get("totals", {})
            eq([tot.get("a_only"), tot.get("b_only"), tot.get("matching")],
               [2, 2, 2], "reconcile over materialised tables")
        finally:
            s.shutdown()

    def t_mssql_conn_str():
        # The connection-string builder + error classifier are pure and run
        # without pyodbc, so the SQL Server safeguards stay suite-testable even
        # though a live ODBC connection can only be exercised on Windows.
        from samql_core.mssql import build_mssql_conn_str, classify_mssql_error
        cs = build_mssql_conn_str("ODBC Driver 18 for SQL Server", "h", "1433",
                                  "sql", "sa", "p}w", True, True, False, "")
        need("DRIVER={ODBC Driver 18 for SQL Server}" in cs
             and "SERVER=h,1433" in cs and "UID=sa" in cs
             and "PWD={p}}w}" in cs and "Encrypt=yes" in cs
             and "TrustServerCertificate=yes" in cs,
             "sql-login conn str fields: %s" % cs)
        cw = build_mssql_conn_str("D", "h", "", "windows", "", "", False, False,
                                  False, "")
        need("Trusted_Connection=yes" in cw and "UID=" not in cw
             and "Encrypt=no" in cw, "windows-auth conn str: %s" % cw)
        bad = [
            lambda: build_mssql_conn_str("", "h"),                  # no driver
            lambda: build_mssql_conn_str("D", ""),                  # no server
            lambda: build_mssql_conn_str("D", "h", auth="sql",
                                         user="", pwd="p"),         # no user
        ]
        for fn in bad:
            try:
                fn()
                need(False, "expected ValueError from conn-str builder")
            except ValueError:
                pass
        cause, fix = classify_mssql_error("Login timeout expired")
        need(bool(cause and fix), "error classifier returned nothing")

    def t_mssql_alt_auth():
        # The 'Alternate Windows account (runas /netonly)' method and the
        # driver auto-pick are pure and run without pyodbc/pywin32.
        from samql_core.mssql import (build_mssql_conn_str,
                                      split_domain_user, best_odbc_driver)
        # windows_alt -> a Trusted connection string (alternate identity is
        # applied via LogonUser impersonation, never as UID/PWD in the string).
        cs = build_mssql_conn_str("D", "h", "", "windows_alt",
                                  "tdbfg\\laurs72", "pw", True, True, False, "")
        need("Trusted_Connection=yes" in cs and "UID=" not in cs
             and "PWD=" not in cs, "windows_alt conn str: %s" % cs)
        for fn in (
            lambda: build_mssql_conn_str("D", "h", auth="windows_alt",
                                         user="", pwd="pw"),     # no user
            lambda: build_mssql_conn_str("D", "h", auth="windows_alt",
                                         user="d\\u", pwd=""),   # no password
        ):
            try:
                fn()
                need(False, "expected ValueError for windows_alt")
            except ValueError:
                pass
        # domain\\user parsing for the (domain, user, password) LogonUser tuple
        eq(split_domain_user("tdbfg\\laurs72"), ("tdbfg", "laurs72"),
           "split domain\\user")
        eq(split_domain_user("  plainuser "), ("", "plainuser"),
           "split bare user -> empty domain")
        # driver auto-pick prefers the newest installed SQL Server ODBC driver
        eq(best_odbc_driver(["ODBC Driver 13 for SQL Server",
                             "ODBC Driver 18 for SQL Server",
                             "SQL Server Native Client 11.0"]),
           "ODBC Driver 18 for SQL Server", "best driver = newest")
        eq(best_odbc_driver([]), "", "best driver of none -> empty")

    def t_mssql_catalog_routing():
        # The catalog routing is pure (no pyodbc): fake a registered catalog
        # table and assert how queries are steered.
        s = _loaded_session()  # has a local table "data"
        try:
            s.catalog_tables["RemoteTbl"] = {
                "conn": "mssql1", "database": "X", "schema": "dbo",
                "table": "RemoteTbl", "qualified": "[X].[dbo].[RemoteTbl]",
                "columns": [{"name": "a", "type": "int"}]}
            s._catalog_route["remotetbl"] = "mssql1"
            eq(s._catalog_conn_for("SELECT * FROM RemoteTbl"), "mssql1",
               "catalog ref routes to its connection (passthrough)")
            need(s._catalog_conn_for("SELECT * FROM data") is None,
                 "purely-local query stays local")
            need(s._query_mixes_catalog_and_local(
                 "SELECT * FROM RemoteTbl JOIN data ON 1=1"),
                 "remote + local mix is detected")
            # a name present locally wins over a same-named catalog entry
            s.catalog_tables["data"] = {"conn": "mssql1", "table": "data",
                                        "columns": []}
            s._catalog_route["data"] = "mssql1"
            need(s._catalog_conn_for("SELECT * FROM data") is None,
                 "locally-loaded name prefers the local engine")
            tl = s.tables_tree()
            need(any(t["name"] == "RemoteTbl" and t["engine"] == "remote"
                     and t.get("remote") and t["row_count"] is None
                     for t in tl),
                 "catalog table listed as remote with no row count")
            s.forget_catalog("mssql1")
            need(s._catalog_conn_for("SELECT * FROM RemoteTbl") is None,
                 "forget_catalog clears routing")
            need(not any(t.get("remote") for t in s.tables_tree()),
                 "forget_catalog removes catalog tables from the list")
        finally:
            s.shutdown()

    def t_flatten_json_export():
        import json as _json
        import tempfile as _tf
        import csv as _csv2
        import os as _os
        import shutil as _sh
        s = _fresh_session()
        d = _tf.mkdtemp(prefix="t_ft_")
        try:
            jp = _os.path.join(d, "orders.json")
            with open(jp, "w") as f:
                _json.dump([
                    {"id": 1, "customer": {"name": "Acme", "city": "NYC"},
                     "items": [{"sku": "A1", "qty": 2},
                               {"sku": "B2", "qty": 1}]},
                    {"id": 2, "customer": {"name": "Globex", "city": "LA"},
                     "items": [{"sku": "C3", "qty": 5}],
                     "tags": ["urgent", "vip"]},
                ], f)
            res = s.flatten_json_to_csv_dir(jp, d)
            need(res.get("ok"), "flatten export ok")
            eq(res.get("table_count"), 3, "root + items + tags = 3 tables")
            files = {f["file"]: f for f in res["files"]}
            need("orders.csv" in files, "root csv written")
            need(any(f.endswith("_items.csv") for f in files),
                 "nested-array child csv written")
            need(_os.path.basename(res["dir"]) == "orders_flattened",
                 "writes into a <base>_flattened subfolder")
            with open(_os.path.join(res["dir"], "orders.csv"),
                      encoding="utf-8-sig") as fh:
                rows = list(_csv2.reader(fh))
            need(rows and "_id" in rows[0],
                 "csv has a header row with the synthetic _id")
            eq(len(rows) - 1, files["orders.csv"]["rows"],
               "root csv data-row count matches the report")
            # progress callback: reports a reading stage (bytes climbing to the
            # full file size) then a writing stage (tables_done -> tables_total),
            # and the result is unchanged.
            ev = []
            res2 = s.flatten_json_to_csv_dir(
                jp, d, progress=lambda i: ev.append(dict(i)))
            need(res2.get("ok"), "flatten with a progress callback still ok")
            stages = [e["stage"] for e in ev]
            need("reading" in stages and "writing" in stages,
                 "progress reports both the reading and writing stages")
            rd = [e for e in ev if e["stage"] == "reading"]
            need(rd and rd[-1]["bytes_total"] > 0
                 and rd[-1]["bytes_done"] == rd[-1]["bytes_total"],
                 "reading progress reaches the full file size")
            wr = [e for e in ev if e["stage"] == "writing"]
            need(wr and wr[-1]["tables_total"] == 3
                 and wr[-1]["tables_done"] == wr[-1]["tables_total"],
                 "writing progress ends at tables_done == tables_total (3)")
            need(s.flatten_json_to_csv_dir("", d).get("error"),
                 "missing json path -> error")
            need(s.flatten_json_to_csv_dir(
                 jp, _os.path.join(d, "nope")).get("error"),
                 "missing output dir -> error")
        finally:
            _sh.rmtree(d, ignore_errors=True)
            s.shutdown()

    def t_flatten_cancel():
        from samql_core.loaders import LoadCancelled
        import json as _json, tempfile as _tf, os as _os, shutil as _sh
        import server as _server
        s = _fresh_session()
        d = _tf.mkdtemp(prefix="t_ftc_")
        try:
            jp = _os.path.join(d, "data.json")
            with open(jp, "w") as f:
                _json.dump([{"id": i, "n": {"v": i}} for i in range(80)], f)

            # (1) cancel immediately -> LoadCancelled; the _flattened folder we
            # created is removed (a clean rollback, no orphan).
            try:
                s.flatten_json_to_csv_dir(jp, d, "data", cancel=lambda: True)
                need(False, "cancel()=True must raise LoadCancelled")
            except LoadCancelled:
                pass
            flat = _os.path.join(d, "data_flattened")
            need(not _os.path.isdir(flat),
                 "a cancelled flatten removes the folder it created")

            # (2) a pre-existing folder + a prior file survive a cancel -- we
            # only roll back the CSVs THIS run wrote.
            _os.makedirs(flat)
            sentinel = _os.path.join(flat, "keep.txt")
            with open(sentinel, "w") as fh:
                fh.write("prior")
            try:
                s.flatten_json_to_csv_dir(jp, d, "data", cancel=lambda: True)
                need(False, "cancel()=True must raise (pre-existing folder)")
            except LoadCancelled:
                pass
            need(_os.path.isfile(sentinel),
                 "a pre-existing folder + prior file survive a cancelled flatten")
            _sh.rmtree(flat, ignore_errors=True)

            # (3) an uncancelled run still produces the CSVs.
            res = s.flatten_json_to_csv_dir(jp, d, "data", cancel=lambda: False)
            need(res.get("ok") and res.get("files"),
                 "an uncancelled flatten still writes CSV files")

            # (4) the cancel handler + route are wired and flip the job flag.
            need(hasattr(_server.Api, "flatten_cancel"),
                 "flatten_cancel handler exists")
            need(any(p == r"^/api/flatten/cancel/(?P<job>[^/]+)$"
                     for (_mth, p, _fn) in _server.ROUTES),
                 "flatten cancel route registered")
            jid = "ftc_test_job"
            _server.JOBS[jid] = {"id": jid, "kind": "flatten",
                                 "state": "running", "cancel": False}

            class _M:
                def group(self, _k):
                    return jid
            out = _server.Api.flatten_cancel(s, _M(), None, None)
            need(out.get("cancelled") and _server.JOBS[jid]["cancel"] is True,
                 "flatten_cancel sets the job's cancel flag")
            _server.JOBS.pop(jid, None)
        finally:
            _sh.rmtree(d, ignore_errors=True)
            s.shutdown()

    def t_flatten_progress_ijson_path():
        # Guards the ijson fast path's read-progress. The counting wrapper only
        # reports every ~256 KB, so a small array file used to finish without
        # ever emitting a "reading" event; stream_json_records now emits a final
        # read-complete itself. Run with a fake ijson so this holds whether or
        # not the C library is installed in the environment.
        import sys as _sys
        import types as _types
        import json as _json
        import tempfile as _tf
        import os as _os
        import shutil as _sh
        from samql_core import flatten as _F
        recs = [{"id": 1, "items": [{"sku": "A"}]},
                {"id": 2, "items": [{"sku": "B"}]}]
        d = _tf.mkdtemp(prefix="t_ij_")
        p = _os.path.join(d, "a.json")
        with open(p, "w") as f:
            f.write(_json.dumps(recs))
        had = "ijson" in _sys.modules
        saved = _sys.modules.get("ijson")
        fake = _types.ModuleType("ijson")

        def _items(fileobj, prefix):
            data = fileobj.read()
            if isinstance(data, (bytes, bytearray)):
                data = data.decode("utf-8")
            for x in _json.loads(data):
                yield x
        fake.items = _items
        _sys.modules["ijson"] = fake
        try:
            ev = []
            out = list(_F.stream_json_records(
                p, progress=lambda done, total: ev.append((done, total))))
            eq(len(out), 2, "ijson path yields all records")
            need(ev, "ijson path emitted no reading progress at all")
            need(ev[-1][0] == ev[-1][1] == _os.path.getsize(p),
                 "ijson read progress reaches the full file size")
        finally:
            if had:
                _sys.modules["ijson"] = saved
            else:
                _sys.modules.pop("ijson", None)
            _sh.rmtree(d, ignore_errors=True)

    def t_materialize_result():
        s = _loaded_session()  # table "data": 60 rows, 3 categories
        try:
            res = s.run_query("SELECT category, COUNT(*) AS n FROM data "
                              "GROUP BY category ORDER BY category")
            rid = res.get("result_id")
            need(rid, "query produced a result id")
            m = s.materialize_result(rid, "cat_counts", target="sqlite")
            need(m.get("ok"), "result materialized into a table")
            eq(m.get("engine"), "sqlite", "saved into sqlite as requested")
            eq(m.get("rows"), res.get("total_rows"),
               "saved row count matches the result")
            need(any(t["name"] == "cat_counts" for t in s.tables_tree()),
                 "saved table appears in the table list")
            chk = s.run_query("SELECT SUM(n) FROM cat_counts")
            eq(int(chk["rows"][0][0]), 60,
               "saved table holds the aggregated rows")
            m2 = s.materialize_result(rid, "cat_counts", target="sqlite")
            need(m2.get("ok") and m2.get("table") != "cat_counts",
                 "a second save auto-uniquifies the table name")
            need(s.materialize_result(rid, "1bad").get("error"),
                 "an invalid table name is rejected")
            need(s.materialize_result("missing", "x").get("error"),
                 "a missing result id is rejected")
        finally:
            s.shutdown()

    def t_load_folder():
        import csv as _c3
        import json as _j3
        import tempfile as _tf3
        import os as _os3
        import shutil as _sh3
        s = _fresh_session()
        d = _tf3.mkdtemp(prefix="t_bulk_")
        try:
            for nm, n in [("a.csv", 3), ("b.csv", 5)]:
                with open(_os3.path.join(d, nm), "w", newline="") as f:
                    w = _c3.writer(f)
                    w.writerow(["id", "v"])
                    for i in range(n):
                        w.writerow([i, i * 10])
            _j3.dump([{"id": 1}, {"id": 2}],
                     open(_os3.path.join(d, "c.json"), "w"))
            open(_os3.path.join(d, "skip.md"), "w").write("nope")
            ticks = []
            res = s.load_folder(d, destination="sqlite",
                                on_file=lambda i, c, nm: ticks.append(nm))
            need(res.get("ok"), "folder load ok")
            eq(res.get("files"), 3, "found 3 data files, ignoring skip.md")
            eq(len(res.get("loaded", [])), 3, "loaded 3 tables")
            eq(res.get("rows"), 10, "total rows = 3 + 5 + 2")
            eq(len(ticks), 3, "progress callback fired once per file")
            names = {t["name"] for t in s.tables_tree()}
            need({"a", "b", "c"} <= names, "tables a/b/c are registered")
            need(s.load_folder("/no/such/dir").get("error"),
                 "a missing folder is rejected")
            need(s.load_folder(_tf3.mkdtemp()).get("error"),
                 "an empty folder is rejected")
        finally:
            _sh3.rmtree(d, ignore_errors=True)
            s.shutdown()

    def t_build_script_signing():
        with open(_root_script("build.ps1"), encoding="utf-8") as f:
            ps = f.read()
        need("CertThumbprint" in ps and "CertPath" in ps
             and "CertPassword" in ps and "signtool" in ps,
             "build.ps1 exposes an opt-in code-signing step")
        need("/tr" in ps and "SHA256" in ps,
             "the signature is SHA-256 and RFC-3161 timestamped")
        need("-NoSign" in ps and "unsigned" in ps,
             "the build still completes without a certificate")
        need("No signing certificate provided" in ps
             or "leaving BOTH exes unsigned" in ps,
             "unsigned builds print a clear skip message (no cert required)")
        need("param(" in ps.split("$ErrorActionPreference")[0],
             "the param() block precedes the first statement (valid PS)")

    def t_build_clean_rebuild():
        # A changed icon / bundled asset must actually land in the rebuilt exe.
        # PyInstaller reuses its build cache unless told otherwise, so the build
        # scripts force a clean rebuild (--clean) and clear the previous build/
        # and dist/ first.
        ps = open(_root_script("build.ps1"), encoding="utf-8").read()
        sh = open(os.path.join(ROOT, "build.sh"), encoding="utf-8").read()
        for name, txt in (("build.ps1", ps), ("build.sh", sh)):
            need("--clean" in txt,
                 f"{name} runs PyInstaller with --clean (no stale cache)")
        need("Remove-Item" in ps and "build" in ps and "dist" in ps,
             "build.ps1 clears build/ and dist/ before packaging")
        need("rm -rf build dist" in sh,
             "build.sh clears build/ and dist/ before packaging")
        # .498: the build must NOT delete samql.ico. .500: it must also NOT
        # WRITE over the repo-root icon -- that is the USER's input file (the
        # spec reads root\samql.ico and embeds it); the old `Copy-Item ... 
        # samql.ico` clobbered the user's own icon and shipped the default. The
        # scripts now only refresh the shortcut copy in dist/.
        need("Remove-Item -Force backend\\samql.ico" not in ps
             and "samql.ico," not in ps,
             "build.ps1 no longer deletes samql.ico")
        need("rm -f backend/samql.ico" not in sh,
             "build.sh no longer deletes samql.ico")
        need("Copy-Item backend\\samql.ico samql.ico" not in ps
             and "open('samql.ico'" not in ps,
             "build.ps1 does NOT overwrite the user's root samql.ico")
        need("cp -f backend/samql.ico samql.ico" not in sh
             and "open('samql.ico'" not in sh,
             "build.sh does NOT overwrite the user's root samql.ico")
        need(r"dist\SamQL.ico" in ps and "dist/SamQL.ico" in sh,
             "both scripts still drop dist/SamQL.ico for shortcuts")

    def t_build_spec_icon():
        with open(os.path.join(BACKEND, "samql.spec"), encoding="utf-8") as f:
            spec = f.read()
        need("samql.ico" in spec,
             "the PyInstaller spec references samql.ico")
        need("icon=ICON" in spec,
             "the resolved icon is passed to EXE() so it embeds in the .exe")
        # .500: the exe icon prefers a USER file, checked ROOT first
        # (samql.ico / SamQL.ico -- where Sam keeps it), then src/, then
        # frontend/public/; it falls back to the embedded _brand asset. Either
        # way the chosen bytes are written to backend/samql.ico unconditionally
        # (.487: a STALE backend/samql.ico must never be reused), and icon=ICON
        # embeds it. _brand regeneration is the FALLBACK when no user icon exists.
        need("_b.app_ico()" in spec,
             "the spec falls back to the _brand icon source of truth")
        need('os.path.join(REPO, "samql.ico")' in spec
             and 'os.path.join(REPO, "SamQL.ico")' in spec,
             "the build uses the user's icon from the repo ROOT")
        need('os.path.join(REPO, "src", "SamQL.ico")' in spec
             and 'os.path.join(REPO, "frontend", "public", "SamQL.ico")'
             in spec,
             "src/ and frontend/public/ are also accepted icon locations")
        need(spec.index("_user_ico") < spec.index("_b.app_ico()"),
             "a user icon is preferred; _brand is the fallback")
        need("overwrite unconditionally" in spec
             and "if ICON is None:" not in spec,
             "samql.ico is written unconditionally, not only when absent")
        # .498: UPX strips/rewrites the Windows PE icon resource, so a UPX'd exe
        # comes up with the DEFAULT icon even though icon=ICON was set. Both
        # exes must build WITHOUT UPX so the embedded SamQL icon survives.
        need("upx=True" not in spec and spec.count("upx=False") >= 2,
             "every exe disables UPX so the embedded icon isn't stripped")
        # .498: the native-window backend (Edge WebView2 via pythonnet 3.x)
        # loads the CLR through clr_loader; bundle it so the frozen launcher can
        # actually start a native window instead of falling back to a browser.
        need('"clr_loader"' in spec,
             "the launcher bundles clr_loader (pythonnet WebView2 backend)")
        # .500: the launcher exe carries the brand assets so the native window
        # and splash show them with no server round-trip -- SamQL.ico (the exe
        # icon) for the taskbar stamp and frontend/public/logo.png for the
        # splash. Both go into the launcher Analysis's datas.
        need("_la_ico" in spec and "la_datas.append((_la_ico" in spec,
             "the launcher bundles the app icon for the taskbar stamp")
        need("_la_logo" in spec
             and 'os.path.join(REPO, "frontend", "public", "logo.png")' in spec
             and "la_datas.append((_la_logo" in spec
             and "wrote embedded splash logo" in spec,
             "the launcher bundles frontend/public/logo.png for the splash "
             "(seeds embedded mark when the drop-in is absent)")

    def t_launcher_brand_assets_and_onedrive():
        # .500: on-box the exe was run from a OneDrive folder -- first-run _MEI
        # unpack + AV scan blew past the 60 s wait ("server did not come up"),
        # and the icon fetch hit WinError 10061 (server not serving yet). The
        # launcher now (a) waits longer and names OneDrive in the failure, (b)
        # retries the icon fetch, and (c) carries the brand art bundled INTO the
        # exe: samql.ico for the taskbar stamp, logo.png for the splash.
        la = open(os.path.join(BACKEND, "launcher_app.py"),
                  encoding="utf-8").read()
        need('"onedrive"' in la,
             "the boot-timeout failure detects a OneDrive launch")
        need("local folder" in la.lower(),
             "the failure tells the user to run from a LOCAL folder")
        need("after retries" in la and "range(6)" in la,
             "the app-icon fetch retries instead of giving up on one refusal")
        need("def _bundled_asset(" in la,
             "the launcher resolves brand assets bundled into its own exe")
        need('_bundled_asset("logo.png")' in la,
             "the splash shows the bundled logo.png when present")
        # Keep a fixed dark splash chrome so transparent logo corners do not
        # turn the window into a mottled panel (logo doctor strips the matte).
        need('bg, fg = CHROME_BG, "#d7dae0"' in la
             and 'CHROME_BG = "#16181d"' in la
             and "self.root.configure(bg=bg)" in la,
             "the splash uses fixed dark chrome that matches the branded UI")
        need('_b = _bundled_asset("samql.ico")' in la
             and "ico = _b or fetch_app_icon(args.port)" in la,
             "the taskbar stamp prefers the bundled icon, server icon "
             "fallback (.526: split so the log names the art source)")
        # the bundled-asset resolver degrades safely when nothing is bundled
        import importlib.util as _ilu
        _spec = _ilu.spec_from_file_location(
            "samql_launcher_ba", os.path.join(BACKEND, "launcher_app.py"))
        _mod = _ilu.module_from_spec(_spec)
        _spec.loader.exec_module(_mod)
        need(_mod._bundled_asset("does-not-exist-xyz.png") is None,
             "_bundled_asset returns None (never raises) for a missing asset")

    def t_build_ps1_native_window_deps():
        # .498: `pip install pywebview` doesn't always pull pythonnet (its
        # Windows WebView2 backend); when it's missing the app silently opens in
        # a browser. build.ps1 installs it explicitly (best-effort) and WARNS
        # when the pywebview + backend stack isn't importable, so a browser
        # fallback is a known outcome rather than a surprise.
        ps = open(_root_script("build.ps1"), encoding="utf-8").read()
        need("pip install pywebview pythonnet" in ps,
             "build.ps1 installs pythonnet for the WebView2 backend")
        need("import webview, webview.platforms.edgechromium, clr" in ps,
             "build.ps1 verifies the native-window stack is importable")
        need("fall back to a browser" in ps or "browser window" in ps,
             "build.ps1 warns when the native window would fall back")

    def t_native_window_logs_real_error():
        # .498: when the native (pywebview) window can't start, the launcher and
        # server must record the REAL exception (repr), not just its class name
        # or a generic 'not found', so an on-box browser fallback is diagnosable.
        lap = open(os.path.join(BACKEND, "launcher_app.py"),
                   encoding="utf-8").read()
        need("pywebview not importable (%r)" in lap
             and "pywebview window failed (%r)" in lap,
             "launcher_app logs the real pywebview import/start error")
        srv = open(os.path.join(BACKEND, "server.py"), encoding="utf-8").read()
        need("pywebview not importable (%r)" in srv
             and "native window unavailable (%r)" in srv,
             "server.py logs the real error and falls back instead of crashing")
        # the --window start is wrapped so a backend failure AFTER the server is
        # up degrades to a browser rather than taking the process down
        _tail = srv.split("if launched and launched[0] == \"webview\":", 1)[1]
        # .501/.519: the explicit-renderer retry AND the Form-icon callback
        # sit before the fallback now, so the window is wider still.
        # Dark WebView2 background_color comments also sit in this block.
        # .608: that block kept growing (the fallback now lands past offset
        # ~9400), so the slice is widened to keep matching the real code.
        _tail = _tail[:10500]
        need("_launch_browser_window(_url)" in _tail
             and "webbrowser.open(_url)" in _tail,
             "a pywebview start failure falls back to a browser window")

    def t_build_spec_console():
        # The build keeps a console (console=True) so the terminal stays open
        # with the boot/status output and can be stopped with Ctrl+C. There is
        # no bootloader splash, and server.py carries none of the no-console
        # plumbing (stream redirect, fatal dialog) a windowed build needed.
        with open(os.path.join(BACKEND, "samql.spec"), encoding="utf-8") as f:
            spec = f.read()
        need("console=True" in spec,
             "the SERVER exe keeps its console (console=True)")
        # .418: the spec now ALSO builds the app-window launcher, which
        # is windowed BY DESIGN -- its console=False belongs to the
        # SamQL-AppWindow EXE block only, after the server's.
        need(spec.count("console=False") >= 1
             and "console=True" in spec
             and spec.index("console=True")
             < spec.index('name="SamQL-AppWindow"'),
             "the AppWindow exe(s) are console-less; the server keeps "
             "its console (.549: onedir adds a 2nd console-less block)")
        need("Splash(" not in spec and "SPLASH_IMAGE" not in spec,
             "the spec builds no bootloader splash")
        with open(os.path.join(BACKEND, "server.py"), encoding="utf-8") as f:
            srv = f.read()
        need("def _launch_browser_window" in srv,
             "the browser-window launcher is retained")
        need("class _BootBar" in srv,
             "the terminal boot bar still prints startup progress")
        for gone in ("_ensure_std_streams", "_report_fatal", "_excepthook",
                     "MessageBoxW", "pyi_splash", "_splash_text",
                     "_close_splash"):
            need(gone not in srv,
                 "no-console / splash plumbing removed: %s" % gone)

    def t_brand_assets():
        # The app icon doubles as the favicon the browser tab shows. It is
        # embedded as base64 (so it travels as text and is available at
        # runtime), the server serves it ahead of the SPA fallback, and
        # index.html links it.
        import struct
        from samql_core import _brand
        png = _brand.app_icon_png()
        need(png[:8] == b"\x89PNG\r\n\x1a\n", "app icon decodes to a PNG")
        w, h = struct.unpack(">II", png[16:24])
        need((w, h) == (256, 256), f"app icon is 256x256 (got {w}x{h})")
        man = _brand.web_manifest()
        need(man.get("icons") and man["icons"][0]["src"] == "/app-icon.png",
             "manifest references the app icon")
        with open(os.path.join(BACKEND, "server.py"), encoding="utf-8") as f:
            srv = f.read()
        need("def _serve_brand" in srv and "if self._serve_brand(path):" in srv,
             "brand assets are served ahead of the SPA static fallback")
        _sb = srv.split("def _serve_brand")[1].split("\n    def ")[0]
        # .469 repoint: the file lookup moved into _brand_lookup (the
        # exe-adjacent ladder), and no-store became max-age=60 -- the
        # cache starvation was exactly why Edge --app windows never
        # adopted the icon and fell back to the E logo.
        need("_brand_lookup(" in _sb and "_brand_lookup(" in srv
             and "def _brand_lookup" in srv
             and "os.path.isfile" in srv.split("def _brand_lookup")[1]
                                        .split("\n    def ")[0]
                                        if "def _brand_lookup" in srv
                                        else False,
             "a real drop-in image overrides the embedded icon via the "
             "lookup ladder")
        need('"Cache-Control": "max-age=60"' in _sb
             and "X-SamQL-Brand" in _sb,
             "brand assets are cacheable (Edge adopts them) and name "
             "their source")
        for route in ("/favicon.ico", "/app-icon.png", "/manifest.webmanifest"):
            need(route in srv, f"server serves {route}")
        html = open(os.path.join(ROOT, "frontend", "index.html"),
                    encoding="utf-8").read()
        need('href="/app-icon.png"' in html and "manifest.webmanifest" in html,
             "index.html links the app icon + manifest")

    def t_duckdb_by_default():
        # "DuckDB by default" has to hold end to end: the engine is chosen as
        # DuckDB-when-importable, every loader defaults to that, and the build
        # actually bundles DuckDB. This guards all three so none silently
        # regress to SQLite.
        # 1) the recommended-deps file pins a DuckDB that supports the native
        #    folder combine (UNION ALL BY NAME), and the spec bundles it.
        with open(os.path.join(ROOT, "requirements-optional.txt"),
                  encoding="utf-8") as f:
            req = f.read()
        need("duckdb" in req, "requirements-optional.txt recommends duckdb")
        need("duckdb>=0.9" in req or "duckdb >=0.9" in req,
             "duckdb is pinned to a UNION ALL BY NAME-capable version")
        with open(os.path.join(BACKEND, "samql.spec"), encoding="utf-8") as f:
            spec = f.read()
        need('"duckdb"' in spec and "collect_all" in spec,
             "the spec bundles duckdb (and other accel libs) when present")
        # 2) the build installs those deps so the default build isn't SQLite,
        #    and makes a missing DuckDB unmistakable.
        with open(os.path.join(ROOT, "build.sh"), encoding="utf-8") as f:
            sh = f.read()
        need("requirements-optional.txt" in sh and "pip install" in sh,
             "build.sh installs the optional acceleration libraries")
        need("import duckdb" in sh,
             "build.sh checks for duckdb and warns if the build is SQLite-only")
        # 3) the engine default really is DuckDB-when-available.
        import samql_core.session as _sess
        src = open(_sess.__file__, encoding="utf-8").read()
        need('return "duckdb" if HAS_DUCKDB else "sqlite"' in src,
             "default_destination() prefers DuckDB whenever it is installed")
        # no loader may default to SQLite -- they must take 'auto' so the
        # default_destination() decision (DuckDB) is what actually runs.
        need('destination="sqlite"' not in src,
             "no loader hard-defaults to sqlite; loaders use auto -> DuckDB")
        orig = _sess.HAS_DUCKDB
        try:
            _sess.HAS_DUCKDB = True
            s = Session()
            try:
                eq(s.default_destination(), "duckdb",
                   "with DuckDB present the default engine is duckdb")
            finally:
                s.shutdown()
            _sess.HAS_DUCKDB = False
            s = Session()
            try:
                eq(s.default_destination(), "sqlite",
                   "without DuckDB it falls back to sqlite")
            finally:
                s.shutdown()
        finally:
            _sess.HAS_DUCKDB = orig

    def t_history_retention():
        import datetime as _dtt
        from pathlib import Path as _P
        from samql_core.stores import QueryHistoryStore, SavedQueryStore, app_config_dir
        now = _dtt.datetime.now()
        old = (now - _dtt.timedelta(days=40)).isoformat(timespec="seconds")
        recent = (now - _dtt.timedelta(days=5)).isoformat(timespec="seconds")
        hfn, sfn = "test_hist_retention.json", "test_saved_retention.json"
        cfg = app_config_dir()

        eq(QueryHistoryStore.RETENTION_DAYS, 30,
           "history retention window is 30 days")

        h = QueryHistoryStore(filename=hfn); h.clear()
        h.entries = [{"sql": "OLD", "ts": old},
                     {"sql": "RECENT", "ts": recent},
                     {"sql": "NOTS"}]          # missing ts -> must be kept
        h._save()
        reloaded = [e["sql"] for e in QueryHistoryStore(filename=hfn).entries]
        need("OLD" not in reloaded, "history older than 30 days is pruned on load")
        need("RECENT" in reloaded, "history within 30 days is kept")
        need("NOTS" in reloaded, "history without a timestamp is never expired")

        # add() also keeps the window enforced for long-running sessions
        h2 = QueryHistoryStore(filename=hfn)
        h2.entries.append({"sql": "SNEAKY_OLD", "ts": old}); h2._save()
        h2.add("SELECT 4")
        after = [e["sql"] for e in QueryHistoryStore(filename=hfn).entries]
        need("SNEAKY_OLD" not in after and "SELECT 4" in after,
             "add() prunes stale entries while keeping new ones")

        # saved queries are exempt -- a 40-day-old saved query survives
        eq(SavedQueryStore.RETENTION_DAYS, None,
           "saved queries are exempt from expiry")
        sv = SavedQueryStore(filename=sfn); sv.clear()
        sv.entries = [{"name": "q", "sql": "SELECT 9",
                       "created_at": old, "last_used": old}]
        sv._save()
        need(len(SavedQueryStore(filename=sfn).entries) == 1,
             "a 40-day-old saved query is NOT pruned")

        for f in (hfn, sfn):
            try: (cfg / f).unlink()
            except Exception: pass

    def t_api_preview():
        from samql_core.apiload import preview_api, _sample_text, build_url
        # non-http scheme errors WITHOUT a network call
        r = preview_api("ftp://example/x")
        need(r.get("ok") is False and "http" in (r.get("error") or "").lower(),
             "preview rejects non-http(s) URLs with no network call")
        # sample is capped to max_records and flags truncation honestly
        txt, char_trunc = _sample_text([{"a": 1}, {"a": 2}, {"a": 3}],
                                       max_records=2)
        import json as _jp
        eq(len(_jp.loads(txt)), 2, "preview sample capped to max_records")
        need(char_trunc is False, "small sample is not char-truncated")
        _, ct = _sample_text([{"k": "x" * 100} for _ in range(40)],
                             max_records=40, max_chars=200)
        need(ct is True, "oversized sample is char-truncated")
        # query params get appended + encoded onto the URL
        eq(build_url("https://h/p", [("a", "1"), ("b", "2 3")]),
           "https://h/p?a=1&b=2+3", "build_url appends + encodes params")

    def t_api_load_sqlite_flatten():
        # SQLite destination keeps the JSON-flattening logic: a nested array
        # becomes its own child table, all in SQLite.
        from samql_core.apiload import _api_sqlite
        s = _fresh_session()
        records = [{"id": 1, "name": "a", "tags": [{"t": "x"}, {"t": "y"}]},
                   {"id": 2, "name": "b", "tags": []}]
        r = _api_sqlite(s, records, "apitest", "http://x/records", 200)
        need(r.get("ok") is True, "sqlite api load returns ok")
        descs = r["loaded"][0]["tables"]
        need(len(descs) >= 2, "nested array is flattened into a child table")
        need(all(d["engine"] == "sqlite" for d in descs),
             "every flattened table lands in SQLite")
        names = [d["name"] for d in descs]
        need(any(n == "apitest" for n in names), "root table keeps the base name")
        cols, rows = s.db.execute('SELECT COUNT(*) FROM "apitest"')
        eq(rows[0][0], 2, "root table has both records")

    def t_api_sqlite_file_streams_with_spill():
        # The SQLite API path is memory-bounded: it streams records straight
        # from the spooled file into the flattener (with on-disk spill) instead
        # of materializing the whole record list. Driven through load_api with
        # an injected spooler -- no network.
        import inspect
        from samql_core import apiload
        s = _fresh_session()

        def spool_json(text, ctype="application/json"):
            def _s(url, dest, auth_user=None, auth_pass=None, headers=None):
                with open(dest, "w", encoding="utf-8") as fh:
                    fh.write(text)
                return (200, ctype, None, len(text.encode("utf-8")))
            return _s

        # array of records with a nested array -> root + child table, all
        # SQLite, through the streaming path
        body = json.dumps([{"id": i, "name": "n%d" % i,
                            "tags": [{"t": "x"}, {"t": "y"}]}
                           for i in range(40)])
        r = apiload.load_api(s, "http://x.example/recs", base_name="apistream",
                             destination="sqlite", spool=spool_json(body))
        need(r.get("ok") is True, "streamed SQLite api load failed: %r"
             % r.get("error"))
        descs = r["loaded"][0]["tables"]
        need(len(descs) >= 2, "nested array must become a child table")
        need(all(d["engine"] == "sqlite" for d in descs),
             "streamed tables must land in SQLite")
        _c, rows = s.db.execute('SELECT COUNT(*) FROM "apistream"')
        eq(rows[0][0], 40, "root row count after streamed load")
        _c, rows = s.db.execute('SELECT COUNT(*) FROM "apistream_tags"')
        eq(rows[0][0], 80, "child row count after streamed load")

        # json_path: the nested array at .data streams out
        body2 = json.dumps({"meta": 1, "data": [{"id": i} for i in range(10)]})
        r2 = apiload.load_api(s, "http://x.example/wrapped",
                              base_name="apiwrap", destination="sqlite",
                              json_path="data", spool=spool_json(body2))
        need(r2.get("ok") is True, "json_path streamed load failed: %r"
             % r2.get("error"))
        _c, rows = s.db.execute('SELECT COUNT(*) FROM "apiwrap"')
        eq(rows[0][0], 10, "json_path root row count")

        # a JSON body with zero records -> a clean 'no records' error (the
        # _api_sqlite_file None path), not a crash
        r3 = apiload.load_api(s, "http://x.example/none", base_name="apinone",
                              destination="sqlite", spool=spool_json("[]"))
        need(r3.get("ok") is False and "no records" in (r3.get("error") or ""),
             "empty array must give a no-records error: %r" % r3)

        # direct streaming variant returns None on an empty file
        dd = tempfile.mkdtemp()
        empty = os.path.join(dd, "e.json")
        open(empty, "w").close()
        eq(apiload._api_sqlite_file(s, empty, "x", "u", 200), None,
           "_api_sqlite_file must return None for an empty file")
        s.shutdown()

        # source guards: both API SQLite paths use the spill flattener; the
        # streaming variant streams from the file (add_record) rather than
        # building a full list; load_api routes the SQLite stream through it.
        need("_spill_flattener" in inspect.getsource(apiload._api_sqlite),
             "in-memory _api_sqlite must use the spill flattener")
        fsrc = inspect.getsource(apiload._api_sqlite_file)
        need("_spill_flattener" in fsrc and "_records_from_file" in fsrc
             and "add_record" in fsrc,
             "_api_sqlite_file must stream records from the file via the "
             "spill flattener")
        need("_api_sqlite_file(session, tmp" in inspect.getsource(
                apiload.load_api),
             "load_api must route the streaming SQLite path through "
             "_api_sqlite_file")

    def t_api_non_json_error():
        # A non-JSON reply (an HTML login/error page) or an empty body must
        # produce a human error that names the status + content-type + a
        # snippet of what came back -- never a raw JSONDecodeError leaking out
        # (which is what an iterator pass surfaced before). Drives load_api's
        # streaming path with an injected spooler, so no network is needed.
        from samql_core import apiload
        s = _fresh_session()

        def spool_html(url, dest, auth_user=None, auth_pass=None, headers=None):
            with open(dest, "w", encoding="utf-8") as fh:
                fh.write("<!DOCTYPE html><title>Sign in</title>please log in")
            return (200, "text/html; charset=utf-8", None, 50)
        r = apiload.load_api(s, "http://x.example/q", base_name="t_apij",
                             destination="sqlite", spool=spool_html)
        m = r.get("error") or ""
        need(r.get("ok") is False, "an HTML reply must not load as ok")
        need("JSONDecodeError" not in m and "Expecting value" not in m,
             "raw parser error leaked: " + m)
        need("did not return JSON" in m, "no friendly non-JSON note: " + m)
        need("text/html" in m, "content-type missing from message: " + m)
        need("DOCTYPE" in m or "Sign in" in m or "log in" in m,
             "no body snippet in message: " + m)

        def spool_empty(url, dest, auth_user=None, auth_pass=None, headers=None):
            open(dest, "w").close()
            return (200, "application/json", None, 0)
        r2 = apiload.load_api(s, "http://x.example/q", base_name="t_apie",
                              destination="sqlite", spool=spool_empty)
        m2 = r2.get("error") or ""
        need(r2.get("ok") is False, "an empty reply must not load as ok")
        need("JSONDecodeError" not in m2,
             "raw parser error leaked (empty): " + m2)
        need("empty response" in m2, "no empty-response note: " + m2)

    def t_flow_engine_target_apinode_engine():
        # An API node's hidden table lives in whichever engine the fetch loaded
        # it into. The flow must target THAT engine even when the cached catalog
        # doesn't list the freshly-created hidden table yet (as happens inside an
        # iterator pass) -- otherwise the flow runs on the wrong engine and the
        # body fails with "no such table __nbapi_...". _flow_engine_target reads
        # the authoritative engine from the api-node registry.
        from samql_core.session import DUCKDB_TARGET, LOCAL_TARGET
        s = _fresh_session()
        # the fetch recorded the node's data as living in DuckDB, but the table
        # is NOT in either cached catalog -- the exact bug condition.
        s._api_node_tables["api1"] = {"table": "__nbapi_x", "engine": "duckdb",
                                      "err": None, "err_engine": "duckdb"}
        g = {"nodes": [{"id": "api1", "type": "apinode",
                        "config": {"table": "__nbapi_x"}}], "edges": []}
        eq(s._flow_engine_target(g), DUCKDB_TARGET,
           "flow targets the engine the api node loaded into, not the catalog "
           "default (the iterator+apinode 'no such table' fix)")
        # an un-fetched api node (no registry entry) + an unknown table falls
        # back to the catalog/local engine, unchanged.
        g2 = {"nodes": [{"id": "api2", "type": "apinode",
                         "config": {"table": "nope"}}], "edges": []}
        eq(s._flow_engine_target(g2), LOCAL_TARGET,
           "an un-fetched api node falls back to the local engine")

    def t_flow_engine_target_nested_apinode():
        # The container iterator wraps its children in a synthetic "group" node,
        # so an API node nested in that group (or a nested iterator) must still
        # pin the flow's engine. _flow_engine_target descends into group/iterator
        # children and trusts the engine the fetch recorded -- without this the
        # group runs on SQLite while the API data is in DuckDB and the body fails
        # with "no such table __nbapi_..." (the reported iterator+API-node bug).
        from samql_core.session import DUCKDB_TARGET, LOCAL_TARGET
        s = _fresh_session()
        s._api_node_tables["apiC"] = {"table": "__nbapi_c", "engine": "duckdb",
                                      "err": None, "err_engine": "duckdb"}
        # nested one level inside a group (the synthetic __iter_body shape)
        g = {"nodes": [{"id": "g", "type": "group", "config": {"children": [
            {"id": "apiC", "type": "apinode",
             "config": {"table": "__nbapi_c"}}]}}], "edges": []}
        eq(s._flow_engine_target(g), DUCKDB_TARGET,
           "a group's nested api node pins the flow to its engine (duckdb)")
        # nested inside an iterator child as well
        g2 = {"nodes": [{"id": "it", "type": "iterator", "config": {
            "children": [{"id": "apiC", "type": "apinode",
                          "config": {"table": "__nbapi_c"}}]}}], "edges": []}
        eq(s._flow_engine_target(g2), DUCKDB_TARGET,
           "an iterator's nested api node also pins the engine")
        # a group with no engine-pinning child still falls back to local
        g3 = {"nodes": [{"id": "g2", "type": "group", "config": {"children": [
            {"id": "f", "type": "formula", "config": {}}]}}], "edges": []}
        eq(s._flow_engine_target(g3), LOCAL_TARGET,
           "a group with no input/api child falls back to the local engine")

    def t_csv_custom_delimiter():
        # A ~-delimited CSV: DuckDB/SQLite sniffers won't guess ~, so without a
        # delimiter the header collapses to one column; with delimiter="~" the
        # SQLite loader splits it correctly.
        import tempfile as _tfd, os as _osd
        from samql_core import loaders
        data = "id~name~city\n1~Alice~Boston\n2~Bob~Denver\n"
        fd, path = _tfd.mkstemp(suffix=".csv")
        _osd.write(fd, data.encode()); _osd.close(fd)
        try:
            s = _fresh_session()
            loaded = loaders.load_file(s, path, destination="sqlite",
                                       delimiter="~")
            eq(loaded[0]["columns"], ["id", "name", "city"],
               "delimiter '~' splits the CSV into three columns")
            eq(loaded[0]["rows"], 2, "both data rows loaded")
            s2 = _fresh_session()
            cols2 = loaders.load_file(s2, path, destination="sqlite")[0]["columns"]
            need(len(cols2) == 1,
                 "without a delimiter, ~ is not auto-detected (one fat column)")
        finally:
            try:
                _osd.unlink(path)
            except Exception:
                pass
        # delimiter normalization
        eq(loaders._norm_delim(""), None, "empty -> auto")
        eq(loaders._norm_delim("auto"), None, "'auto' -> auto")
        eq(loaders._norm_delim("~"), "~", "single char kept")
        eq(loaders._norm_delim("||"), "|", "multi-char -> first char")
        eq(loaders._norm_delim("\\t"), "\t", "backslash-t -> real tab")
        eq(loaders._norm_delim("tab"), "\t", "'tab' -> real tab")

    def t_secret_store():
        import tempfile as _tfs, os as _oss
        from samql_core.secretstore import SecretStore, dpapi_available
        # Default store on a non-Windows sandbox: encryption unavailable, and
        # set() is a no-op so a plaintext secret is never written.
        if not dpapi_available():
            real = SecretStore(filename="secrets_selftest.json")
            need(real.available is False, "DPAPI store reports unavailable here")
            need(real.set("k", "pw") is False,
                 "set is a no-op without DPAPI (no plaintext written)")
            need(not _oss.path.exists(real.path),
                 "no secrets file is created when encryption is unavailable")
        # Persistence + round-trip with an injected reversible protector.
        d = _tfs.mkdtemp()
        prot = (lambda t: ("E:" + t).encode("utf-8"),
                lambda b: b.decode("utf-8")[2:])
        st = SecretStore(protector=prot)
        st.path = _oss.path.join(d, "secrets.json")
        st._data = {}
        need(st.available is True, "store is available with a protector")
        need(st.set("mssql:Prod", "hunter2") is True, "set succeeds")
        eq(st.get("mssql:Prod"), "hunter2", "get round-trips the secret")
        raw = open(st.path, encoding="utf-8").read()
        need("hunter2" not in raw, "stored file contains no plaintext secret")
        # A failed disk write must not leave memory ahead of disk or return True.
        real_replace = _oss.replace
        def _boom(src, dst):
            raise OSError("disk full")
        _oss.replace = _boom
        try:
            need(st.set("mssql:Prod", "new-secret") is False,
                 "set returns False when persistence fails")
            eq(st.get("mssql:Prod"), "hunter2",
               "in-memory value rolls back after a failed write")
            need("new-secret" not in open(st.path, encoding="utf-8").read(),
                 "failed write leaves the previous on-disk blob untouched")
        finally:
            _oss.replace = real_replace
        need(st.set("api:x", "") is False, "an empty secret is refused")
        # reload from disk -> still decrypts
        st2 = SecretStore(protector=prot)
        st2.path = st.path
        st2._data = st2._load()
        eq(st2.get("mssql:Prod"), "hunter2", "secret survives a reload")
        need(st2.delete("mssql:Prod") is True, "delete removes the secret")
        need(st2.has("mssql:Prod") is False, "deleted secret is gone")

    def t_connection_profiles():
        # Named connection profiles store non-secret fields; passwords stay in
        # SecretStore under mssql:/api: keys. Nodes and Load tabs reuse by key.
        import tempfile as _tfs, os as _oss
        from samql_core.connection_profiles import (
            ConnectionProfileStore, profile_key, parse_profile_key)
        from samql_core.secretstore import SecretStore
        eq(profile_key("mssql", "Prod"), "mssql:Prod", "mssql key form")
        eq(parse_profile_key("api:HR"), ("api", "HR"), "parse key")
        d = _tfs.mkdtemp()
        st = ConnectionProfileStore()
        st.path = _oss.path.join(d, "connection_profiles.json")
        st._data = {"profiles": {}}
        entry = st.upsert("mssql", "Prod", {"server": "db1", "auth": "sql"})
        eq(entry["key"], "mssql:Prod", "upsert returns key")
        eq(st.get("mssql:Prod")["fields"]["server"], "db1", "fields persist")
        prot = (lambda t: ("E:" + t).encode("utf-8"),
                lambda b: b.decode("utf-8")[2:])
        secrets = SecretStore(protector=prot)
        secrets.path = _oss.path.join(d, "secrets.json")
        secrets._data = {}
        secrets.set("mssql:Prod", "hunter2")
        listed = st.list(secrets=secrets)
        need(len(listed) == 1 and listed[0]["has_secret"] is True,
             "list reports has_secret from SecretStore")
        raw = open(st.path, encoding="utf-8").read()
        need("hunter2" not in raw, "profile JSON never holds the password")
        need(st.delete("mssql:Prod") is True, "delete removes the profile")
        need(st.get("mssql:Prod") is None, "deleted profile is gone")

    def t_app_config_dir_migration():
        # Post-656 audit #5: durable config is ~/.samql (not the legacy
        # global ~/.json_csv_sql_explorer name alone). SAMQL_CONFIG_DIR
        # isolates instances; legacy files copy once into the canonical dir.
        import os as _os
        import tempfile as _tf
        from pathlib import Path as _P
        from samql_core.stores import (
            APP_CONFIG_DIRNAME, LEGACY_APP_CONFIG_DIRNAME, app_config_dir,
            ConfigStore, _MIGRATION_MARKER)
        from samql_core.connection_profiles import ConnectionProfileStore

        eq(APP_CONFIG_DIRNAME, ".samql", "canonical config dirname")
        eq(LEGACY_APP_CONFIG_DIRNAME, ".json_csv_sql_explorer",
           "legacy dirname preserved for migration")

        iso = _tf.mkdtemp(prefix="samql_cfg_iso_")
        prev = _os.environ.get("SAMQL_CONFIG_DIR")
        try:
            _os.environ["SAMQL_CONFIG_DIR"] = iso
            root = app_config_dir()
            eq(str(root), iso, "SAMQL_CONFIG_DIR wins")
            cfg = ConfigStore()
            need(str(cfg.path).startswith(iso),
                 "ConfigStore writes under SAMQL_CONFIG_DIR")
            cfg.set("probe", 1)
            need((_P(iso) / "config.json").is_file(), "config file created")
            prof = ConnectionProfileStore()
            need(str(prof.path).startswith(iso),
                 "connection profiles use SAMQL_CONFIG_DIR")
            prof.upsert("api", "Iso", {"url": "https://example.test"})
            need((_P(iso) / "connection_profiles.json").is_file(),
                 "profiles file created under isolated dir")
        finally:
            if prev is None:
                _os.environ.pop("SAMQL_CONFIG_DIR", None)
            else:
                _os.environ["SAMQL_CONFIG_DIR"] = prev

        # Migration: legacy home dir -> empty canonical dir (under a fake home).
        fake_home = _P(_tf.mkdtemp(prefix="samql_home_"))
        legacy = fake_home / LEGACY_APP_CONFIG_DIRNAME
        legacy.mkdir()
        (legacy / "connection_profiles.json").write_text(
            '{"profiles": {"api:Legacy": {"kind": "api", "name": "Legacy",'
            ' "fields": {"url": "https://legacy.test"}}}}',
            encoding="utf-8")
        (legacy / "config.json").write_text('{"migrated_probe": true}',
                                            encoding="utf-8")
        from unittest.mock import patch
        prev2 = _os.environ.pop("SAMQL_CONFIG_DIR", None)
        try:
            with patch.object(_P, "home", return_value=fake_home):
                dest = app_config_dir()
                eq(dest, fake_home / APP_CONFIG_DIRNAME,
                   "canonical dir under fake home")
                need((dest / "connection_profiles.json").is_file(),
                     "profiles copied from legacy")
                need((dest / "config.json").is_file(),
                     "config copied from legacy")
                need((dest / _MIGRATION_MARKER).is_file(),
                     "migration marker written")
                # Second resolve must not wipe / re-copy over existing.
                (dest / "config.json").write_text('{"kept": true}',
                                                  encoding="utf-8")
                dest2 = app_config_dir()
                eq(dest2, dest, "second resolve returns same dir")
                eq((dest / "config.json").read_text(encoding="utf-8"),
                   '{"kept": true}',
                   "existing canonical files are not overwritten")
        finally:
            if prev2 is not None:
                _os.environ["SAMQL_CONFIG_DIR"] = prev2

    def t_chart_multiy():
        s = _loaded_session()
        d = s.chart_data({"table": "data", "engine": "sqlite",
                          "chart_type": "multiy", "x": "category",
                          "y": "score", "y2": "id", "agg": "sum"})
        need(d.get("chart_type") == "multiy", "multiy chart_type echoed")
        need(len(d.get("series") or []) == 2, "multiy returns two series")
        need(d["series"][0].get("yAxisIndex") == 0
             and d["series"][1].get("yAxisIndex") == 1,
             "the two metrics bind to y-axis 0 and 1")
        need(len(d.get("labels") or []) == len(d["series"][0].get("values") or []),
             "series values align with the shared x labels")
        e = s.chart_data({"table": "data", "engine": "sqlite",
                          "chart_type": "multiy", "x": "category", "y": "score"})
        need("y2" in (e.get("error") or "").lower()
             or "two y" in (e.get("error") or "").lower(),
             "multiy without y2 returns a helpful error")

    def t_session_restore():
        import csv as _c4
        import tempfile as _tf4
        import os as _os4
        import time as _t4
        import shutil as _sh4
        import pathlib as _pl4
        d = _tf4.mkdtemp(prefix="t_restore_")
        man = _pl4.Path(_os4.path.join(d, "m.json"))
        try:
            s1 = _fresh_session()
            s1.manifest.path = man
            s1.manifest.clear()
            cp = _os4.path.join(d, "people.csv")
            with open(cp, "w", newline="") as f:
                w = _c4.writer(f)
                w.writerow(["id", "name"])
                for i in range(4):
                    w.writerow([i, "n%d" % i])
            s1.load_file(cp, destination="sqlite", base_name="people")
            s1.record_load("file", cp, "sqlite", "people")
            eq(len(s1.manifest.all()), 1, "the load is recorded in the manifest")
            # Simulate a hard crash: the process dies WITHOUT a graceful
            # shutdown. sync_restore_manifest during record_load already
            # kept the on-disk snapshot equal to the live tables, so the
            # next launch rebuilds that set (not a cumulative older history).
            need(man.exists() and len(s1.manifest.all()) == 1,
                 "the manifest persists on disk for crash recovery")
            s2 = _fresh_session()
            s2.manifest.path = man
            s2.manifest._load()
            need(not any(t["name"] == "people" for t in s2.tables_tree()),
                 "a fresh session starts with no tables")
            s2.restore_session()
            for _ in range(100):
                if not s2.restoring:
                    break
                _t4.sleep(0.03)
            need(any(t["name"] == "people" for t in s2.tables_tree()),
                 "restore rebuilt the previously-loaded table")
            eq(s2._restored_count, 1, "restored count reflects the rebuild")
            s2.clear_all(clear_manifest=True)
            eq(len(s2.manifest.all()), 0,
               "an explicit clear-all empties the manifest")
            s2.shutdown()
        finally:
            _sh4.rmtree(d, ignore_errors=True)

    def t_nodeflow_compile_run():
        s = _loaded_session()  # table "data": 60 rows, score 0..88.5
        try:
            graph = {
                "nodes": [
                    {"id": "n1", "type": "input",
                     "config": {"table": "data", "label": "data"}},
                    {"id": "n2", "type": "filter",
                     "config": {"condition": "score >= 40", "label": "f"}},
                    {"id": "n3", "type": "output", "config": {"label": "out"}},
                ],
                "edges": [
                    {"from": {"node": "n1", "port": "out"},
                     "to": {"node": "n2", "port": "in"}},
                    {"from": {"node": "n2", "port": "true"},
                     "to": {"node": "n3", "port": "in"}},
                ],
            }
            rt = s.run_nodeflow(graph, "n2", "true")
            rf = s.run_nodeflow(graph, "n2", "false")
            need(not rt.get("error") and not rf.get("error"),
                 "both filter outputs run")
            eq(rt["total_rows"] + rf["total_rows"], 60,
               "filter true + false partition every row")
            ro = s.run_nodeflow(graph, "n3", "out")
            eq(ro["total_rows"], rt["total_rows"],
               "an output node passes through its input relation")
            import tempfile as _tfn
            import os as _osn
            import shutil as _shn
            d = _tfn.mkdtemp(prefix="t_nf_")
            try:
                ex = s.export_nodeflow(graph, "n3", d, "csv", base_name="out")
                need(ex.get("ok"), "the output node exports")
                eq(ex.get("rows"), ro["total_rows"],
                   "exported row count matches the preview")
                need(_osn.path.isfile(_osn.path.join(d, ex["file"])),
                     "the CSV is written")
            finally:
                _shn.rmtree(d, ignore_errors=True)
            need(s.run_nodeflow(
                {"nodes": [{"id": "x", "type": "filter",
                            "config": {"condition": "1=1"}}], "edges": []},
                "x", "true").get("error"),
                 "a disconnected input is reported")
            loopg = s.run_nodeflow(
                {"nodes": [{"id": "a", "type": "filter",
                            "config": {"condition": "1=1"}}],
                 "edges": [{"from": {"node": "a", "port": "true"},
                            "to": {"node": "a", "port": "in"}}]},
                "a", "true").get("error") or ""
            need("loop" in loopg.lower(), "a cycle is detected")
        finally:
            s.shutdown()

    def t_flow_fingerprints():
        # Pure fingerprint logic: deterministic, salted by epoch+engine,
        # projection-aware, and changing a node only perturbs it + downstream.
        from samql_core import nodeflow as _nf
        import json as _json
        g = {"nodes": [
            {"id": "a", "type": "input", "config": {"table": "t"}},
            {"id": "b", "type": "filter", "config": {"condition": "x>1"}},
            {"id": "c", "type": "sort", "config": {"by": "x"}}],
             "edges": [
                {"from": {"node": "a", "port": "out"}, "to": {"node": "b", "port": "in"}},
                {"from": {"node": "b", "port": "true"}, "to": {"node": "c", "port": "in"}}]}
        f1 = _nf.flow_fingerprints(g, {}, 0, "sqlite")
        f1b = _nf.flow_fingerprints(g, {}, 0, "sqlite")
        need(f1 == f1b and set(f1) == {"a", "b", "c"},
             "fingerprints are deterministic and cover every node")
        need(len(set(f1.values())) == 3, "distinct nodes get distinct fingerprints")
        f_ep = _nf.flow_fingerprints(g, {}, 1, "sqlite")
        need(all(f_ep[k] != f1[k] for k in f1),
             "bumping the epoch changes every fingerprint")
        f_eng = _nf.flow_fingerprints(g, {}, 0, "duckdb")
        need(all(f_eng[k] != f1[k] for k in f1),
             "switching engine changes every fingerprint")
        g2 = _json.loads(_json.dumps(g))
        g2["nodes"][1]["config"]["condition"] = "x>2"
        fe = _nf.flow_fingerprints(g2, {}, 0, "sqlite")
        eq(fe["a"], f1["a"], "editing a node leaves UPSTREAM fingerprints unchanged")
        need(fe["b"] != f1["b"] and fe["c"] != f1["c"],
             "editing a node changes its own and all DOWNSTREAM fingerprints")
        gs = {"nodes": [
            {"id": "s", "type": "input", "config": {"table": "t"}},
            {"id": "x", "type": "filter", "config": {"condition": "x>1"}},
            {"id": "y", "type": "filter", "config": {"condition": "x>1"}}],
              "edges": [
                {"from": {"node": "s", "port": "out"}, "to": {"node": "x", "port": "in"}},
                {"from": {"node": "s", "port": "out"}, "to": {"node": "y", "port": "in"}}]}
        fps = _nf.flow_fingerprints(gs, {}, 0, "sqlite")
        eq(fps["x"], fps["y"],
           "two identical subgraphs share a fingerprint (one materialised table)")
        pa = _nf.flow_fingerprints(g, {("a", "out"): {"x"}}, 0, "sqlite")
        pb = _nf.flow_fingerprints(g, {("a", "out"): {"x", "g"}}, 0, "sqlite")
        need(pa["a"] != pb["a"],
             "the required-column projection is part of the fingerprint")
        gc = {"nodes": [{"id": "p", "type": "filter", "config": {}},
                        {"id": "q", "type": "filter", "config": {}}],
              "edges": [{"from": {"node": "p", "port": "true"},
                         "to": {"node": "q", "port": "in"}},
                        {"from": {"node": "q", "port": "true"},
                         "to": {"node": "p", "port": "in"}}]}
        try:
            _nf.flow_fingerprints(gc, {}, 0, "sqlite")
        except Exception as e:
            need(False, "a cyclic graph must not crash fingerprinting: %s" % e)

    def t_flow_cache_lru():
        # LRU semantics + eviction actually drops the backing table.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            eng = s.db
            names = ["__nbcache_lru%d" % i for i in range(4)]
            for nm in names:
                eng.execute('CREATE TEMP TABLE "%s" AS SELECT 1 AS x' % nm)
            s.flow_cache_max = 3
            s._flow_cache.clear()
            s._flow_cache_stats["evictions"] = 0
            s._flow_cache_put("A", names[0], LOCAL_TARGET)
            s._flow_cache_put("B", names[1], LOCAL_TARGET)
            s._flow_cache_put("C", names[2], LOCAL_TARGET)
            eq(len(s._flow_cache), 3, "cache holds three entries at the cap")
            eq(s._flow_cache_get("A"), names[0], "get returns the cached table name")
            eq(s._flow_cache_get("zzz"), None, "missing fingerprint returns None")
            s._flow_cache_put("D", names[3], LOCAL_TARGET)
            eq(len(s._flow_cache), 3, "the cap is enforced after inserting a 4th")
            need("B" not in s._flow_cache,
                 "the least-recently-used entry (B) is evicted, not the touched A")
            need("A" in s._flow_cache and "D" in s._flow_cache,
                 "the recently-touched and newest entries survive")
            need(not s._table_exists(eng, names[1]),
                 "the evicted entry's table is physically dropped")
            need(s._table_exists(eng, names[0]),
                 "a surviving entry's table is kept")
            need(s._flow_cache_stats["evictions"] >= 1, "eviction is counted")
            s._flow_cache_clear()
            eq(len(s._flow_cache), 0, "clear empties the registry")
            need(not s._table_exists(eng, names[3]),
                 "clear physically drops the remaining tables")

            # Byte budget is enforced independently of entry count. Use a
            # deterministic estimator so this asserts policy, not SQL sizing.
            b1, b2 = "__nbcache_bytes1", "__nbcache_bytes2"
            eng.execute('CREATE TEMP TABLE "%s" AS SELECT 1 AS x' % b1)
            eng.execute('CREATE TEMP TABLE "%s" AS SELECT 2 AS x' % b2)
            old_est = s._flow_cache_estimate_bytes
            old_sync = s._sync_flow_cache_limits
            old_bytes_cap = s.flow_cache_bytes_max
            try:
                s._flow_cache_estimate_bytes = lambda *_a: 4096
                # This is a byte-policy unit test. Freeze adaptive resampling
                # so the live machine's RAM does not replace the exact 6,000
                # byte fixture ceiling before each insertion.
                s._sync_flow_cache_limits = lambda: {
                    "flow_cache_mb": 0, "persistent_cache_mb": 0,
                    "parallel_workers": 1, "pressure": "test"}
                s.flow_cache_max = 10
                s.flow_cache_bytes_max = 6000
                s._flow_cache_registry.configure(max_entries=10, max_bytes=6000)
                s._flow_cache_put("bytes-A", b1, LOCAL_TARGET)
                s._flow_cache_put("bytes-B", b2, LOCAL_TARGET)
                info = s.flow_cache_info()
                eq(info["size"], 1, "byte cap evicts even below count cap")
                eq(info["bytes"], 4096, "byte accounting follows survivors")
                need(not s._table_exists(eng, b1),
                     "byte-budget eviction drops the oldest table")
                need(s._table_exists(eng, b2),
                     "newest table survives the byte-budget eviction")

                # An individual table larger than the entire budget must not
                # be cached-and-dropped out from under the active flow. It is
                # returned as an ordinary per-run temporary instead.
                b3 = "__nbcache_oversized"
                eng.execute('CREATE TEMP TABLE "%s" AS SELECT 3 AS x' % b3)
                before_oversized = s.flow_cache_info()["oversized"]
                s._flow_cache_estimate_bytes = lambda *_a: 8192
                kept = s._flow_cache_put("bytes-HUGE", b3, LOCAL_TARGET)
                need(not kept, "an entry larger than the total byte cap is refused")
                need("bytes-HUGE" not in s._flow_cache,
                     "oversized entry is absent from the persistent LRU")
                need(s._table_exists(eng, b3),
                     "refusing an oversized cache entry does not drop the live table")
                eq(s.flow_cache_info()["oversized"], before_oversized + 1,
                   "oversized refusal is visible in diagnostics")
                eng.execute('DROP TABLE IF EXISTS "%s"' % b3)
                s._flow_cache_registry.clear()

                # Live reconfiguration trims immediately and telemetry names
                # the largest surviving intermediates without exposing a full
                # content fingerprint.
                c1, c2 = "__nbcache_cfg1", "__nbcache_cfg2"
                eng.execute('CREATE TEMP TABLE "%s" AS SELECT 4 AS x' % c1)
                eng.execute('CREATE TEMP TABLE "%s" AS SELECT 5 AS x' % c2)
                s._flow_cache_registry.configure(max_entries=10, max_bytes=20000)
                s._flow_cache_registry.put("fingerprint-one", c1, LOCAL_TARGET, 2048)
                s._flow_cache_registry.put("fingerprint-two", c2, LOCAL_TARGET, 4096)
                telem = s._flow_cache_registry.info()
                eq(telem["largest"][0]["table"], c2,
                   "largest-entry telemetry is ordered by approximate bytes")
                eq(telem["largest"][0]["fingerprint"], "fingerprint-",
                   "telemetry exposes only a short fingerprint prefix")
                dropped = s._flow_cache_registry.configure(max_entries=1)
                need(dropped >= 1, "lowering the live count cap trims immediately")
                eq(s._flow_cache_registry.info()["size"], 1,
                   "the new live cache cap is enforced")
                need(not s._table_exists(eng, c1),
                     "immediate reconfiguration drops the oldest table")
                cleared = s._flow_cache_registry.clear(reset_stats=True)
                eq(cleared, 1, "clear reports how many cached tables were removed")
                eq(s._flow_cache_registry.info()["evictions"], 0,
                   "reset counters clears cache telemetry")
            finally:
                s._flow_cache_estimate_bytes = old_est
                s._sync_flow_cache_limits = old_sync
                s.flow_cache_bytes_max = old_bytes_cap
                s._flow_cache_clear()
        finally:
            s.shutdown()

    def t_flow_cache_incremental():
        # End-to-end: re-running an unchanged flow hits; editing a node reuses
        # its unchanged upstream; results are identical with the cache off.
        s = _loaded_session()  # table "data"
        try:
            need(s.flow_cache, "the flow cache is on by default")
            g = {"nodes": [
                {"id": "n1", "type": "input", "config": {"table": "data"}},
                {"id": "n2", "type": "pivot", "config": {
                    "rows": ["category"], "cols": ["dt"],
                    "values": [{"field": "score", "agg": "sum"}]}}],
                 "edges": [{"from": {"node": "n1", "port": "out"},
                            "to": {"node": "n2", "port": "in"}}]}
            r1 = s.run_nodeflow(g, "n2", "out")
            need(not r1.get("error"), "first run ok: %s" % r1.get("error"))
            i1 = s.flow_cache_info()
            need(i1["misses"] >= 1 and i1["size"] >= 1, "first run populates the cache")
            rows = r1["total_rows"]
            r2 = s.run_nodeflow(g, "n2", "out")
            i2 = s.flow_cache_info()
            need(i2["hits"] > i1["hits"], "re-running an unchanged flow hits the cache")
            eq(i2["misses"], i1["misses"], "the re-run recomputes nothing")
            eq(r2["total_rows"], rows, "the cached result matches the first run")
            # edit the pivot: its upstream input is unchanged and must be reused
            import copy as _copy
            g2 = _copy.deepcopy(g)
            g2["nodes"][1]["config"]["values"] = [{"field": "score", "agg": "avg"}]
            hbefore = s.flow_cache_info()["hits"]
            r3 = s.run_nodeflow(g2, "n2", "out")
            need(not r3.get("error"), "edited pivot runs")
            need(s.flow_cache_info()["hits"] > hbefore,
                 "editing the pivot reuses its cached upstream input")
            eq(r3["total_rows"], rows, "row count unchanged by the agg edit (3 categories)")
            # parity: identical result with the cache disabled
            s2 = _loaded_session()
            try:
                s2.flow_cache = False
                roff = s2.run_nodeflow(g, "n2", "out")
                eq(roff["total_rows"], rows, "result is identical with the cache OFF")
                eq(s2.flow_cache_info()["size"], 0, "nothing is cached when disabled")
            finally:
                s2.shutdown()
        finally:
            s.shutdown()

    def t_result_expires_after_data_epoch_bump():
        # Latest-data wins: paging a result after a content mutation must expire
        # rather than serve frozen parquet as current.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.run_query(
                "CREATE TABLE ep_src AS SELECT 1 AS g UNION ALL SELECT 2",
                target=LOCAL_TARGET)
            q = s.run_query("SELECT g FROM ep_src", target=LOCAL_TARGET)
            need(not q.get("error"), "seed select: %s" % q.get("error"))
            rid = q["result_id"]
            p1 = s.page(rid, 0, 10)
            need(not p1.get("error"), "fresh page works")
            eq(p1.get("total_rows"), 2, "two rows")
            ep = s._data_epoch
            s.run_query("INSERT INTO ep_src VALUES (3)", target=LOCAL_TARGET)
            need(s._data_epoch > ep, "write bumps data_epoch")
            p2 = s.page(rid, 0, 10)
            eq(p2.get("error"), "result expired",
               "stale snapshot must expire after epoch bump")
            # A new run at the new epoch is pageable again.
            q2 = s.run_query("SELECT g FROM ep_src", target=LOCAL_TARGET)
            need(not q2.get("error"), "re-run after mutation: %s"
                 % q2.get("error"))
            p3 = s.page(q2["result_id"], 0, 10)
            need(not p3.get("error"), "fresh result pages")
            eq(p3.get("total_rows"), 3, "re-run sees inserted row")
        finally:
            s.shutdown()

    def t_flow_cache_skips_nondeterministic():
        # Random sample / unstable SQL must not freeze the first materialisation
        # in the volatile flow cache for the rest of the data epoch.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.flow_cache = True
            s._flow_cache_clear()
            s.run_query(
                "CREATE TABLE rnd_src AS SELECT 1 AS id UNION ALL SELECT 2 "
                "UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 "
                "UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8",
                target=LOCAL_TARGET)
            eng, _ = s._engine_obj(LOCAL_TARGET)
            g = {"nodes": [
                {"id": "n1", "type": "input",
                 "config": {"table": "rnd_src"}},
                {"id": "n2", "type": "sample",
                 "config": {"mode": "random", "n": 3, "label": "s"}},
                {"id": "n3", "type": "output",
                 "config": {"label": "out"}}],
                 "edges": [
                    {"from": {"node": "n1", "port": "out"},
                     "to": {"node": "n2", "port": "in"}},
                    {"from": {"node": "n2", "port": "out"},
                     "to": {"node": "n3", "port": "in"}}]}
            need(s._graph_has_nondeterministic_ops(g, eng),
                 "random sample is non-deterministic")
            r1 = s.run_nodeflow(g, "n3", "out")
            need(not r1.get("error"), "first random sample runs: %s"
                 % r1.get("error"))
            info1 = s.flow_cache_info()
            # Fingerprints must stay empty for this graph (gate disables cache).
            # Hits staying 0 across a second run is the user-visible guarantee.
            hits_before = info1.get("hits") or 0
            size_before = info1.get("size") or 0
            r2 = s.run_nodeflow(g, "n3", "out")
            need(not r2.get("error"), "second random sample runs: %s"
                 % r2.get("error"))
            info2 = s.flow_cache_info()
            eq(info2.get("hits") or 0, hits_before,
               "non-deterministic sample must not hit volatile flow cache")
            # Size should not grow from fingerprint materialisations either.
            need((info2.get("size") or 0) <= size_before + 0,
                 "non-deterministic sample should not populate flow cache")
        finally:
            s.shutdown()

    def t_flow_cache_invalidation():
        # A data write must invalidate the cache so a later run is never stale.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.run_query("CREATE TABLE src AS SELECT 1 AS g, 10 AS v "
                        "UNION ALL SELECT 1, 20", target=LOCAL_TARGET)
            g = {"nodes": [
                {"id": "n1", "type": "input", "config": {"table": "src"}},
                {"id": "n2", "type": "output", "config": {"label": "out"}}],
                 "edges": [{"from": {"node": "n1", "port": "out"},
                            "to": {"node": "n2", "port": "in"}}]}
            r1 = s.run_nodeflow(g, "n2", "out")
            need(not r1.get("error"), "flow runs: %s" % r1.get("error"))
            eq(r1["total_rows"], 2, "two rows before the write")
            need(s.flow_cache_info()["misses"] >= 1, "first run populates the cache")
            ep = s._data_epoch
            s.run_query("INSERT INTO src VALUES (1, 70)", target=LOCAL_TARGET)
            need(s._data_epoch > ep, "a write bumps the data epoch")
            eq(s.flow_cache_info()["size"], 0, "the write clears the flow cache")
            r2 = s.run_nodeflow(g, "n2", "out")
            eq(r2["total_rows"], 3,
               "the re-run reflects the inserted row -- no stale cached table")
        finally:
            s.shutdown()

    def t_flow_cache_eviction():
        # Running more distinct flows than the cap evicts, stays within the cap,
        # and every result is still correct.
        s = _loaded_session()
        try:
            s.flow_cache_max = 2
            s._flow_cache_clear()
            s._flow_cache_stats["evictions"] = 0
            import copy as _copy
            base = {"nodes": [
                {"id": "n1", "type": "input", "config": {"table": "data"}},
                {"id": "n2", "type": "pivot", "config": {
                    "rows": ["category"], "cols": ["dt"],
                    "values": [{"field": "score", "agg": "sum"}]}}],
                    "edges": [{"from": {"node": "n1", "port": "out"},
                               "to": {"node": "n2", "port": "in"}}]}
            counts = []
            for agg in ("sum", "avg", "min", "max", "count"):
                g = _copy.deepcopy(base)
                g["nodes"][1]["config"]["values"] = [{"field": "score", "agg": agg}]
                r = s.run_nodeflow(g, "n2", "out")
                need(not r.get("error"), "pivot(%s) runs: %s" % (agg, r.get("error")))
                counts.append(r["total_rows"])
            info = s.flow_cache_info()
            need(info["size"] <= 2, "cache size never exceeds the cap")
            need(info["evictions"] >= 1,
                 "running more distinct flows than the cap triggers eviction")
            need(all(c == counts[0] for c in counts),
                 "results stay correct despite eviction")
        finally:
            s.shutdown()

    def t_flow_cache_checkpoint():
        # A blocking join feeding a single consumer is materialised + cached, so
        # editing a node downstream of it reuses the join instead of rerunning.
        from samql_core.session import LOCAL_TARGET
        s = _fresh_session()
        try:
            s.run_query("CREATE TABLE jl AS SELECT 1 AS g, 'x' AS a "
                        "UNION ALL SELECT 2, 'y'", target=LOCAL_TARGET)
            s.run_query("CREATE TABLE jr AS SELECT 1 AS g, 100 AS b "
                        "UNION ALL SELECT 2, 200", target=LOCAL_TARGET)
            g = {"nodes": [
                {"id": "L", "type": "input", "config": {"table": "jl"}},
                {"id": "R", "type": "input", "config": {"table": "jr"}},
                {"id": "J", "type": "join", "config": {
                    "keys": [{"left": "g", "right": "g"}], "mode": "inner"}},
                {"id": "F", "type": "filter", "config": {"condition": "b > 50"}}],
                 "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "J", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "J", "port": "right"}},
                    {"from": {"node": "J", "port": "inner"},
                     "to": {"node": "F", "port": "in"}}]}
            r1 = s.run_nodeflow(g, "F", "true")
            need(not r1.get("error"), "join -> filter flow runs: %s" % r1.get("error"))
            eq(r1["total_rows"], 2, "filter b>50 keeps both joined rows")
            need(s.flow_cache_info()["misses"] >= 1,
                 "the join is materialised + cached as a checkpoint")
            hits0 = s.flow_cache_info()["hits"]
            import copy as _copy
            g2 = _copy.deepcopy(g)
            g2["nodes"][3]["config"]["condition"] = "b > 150"
            r2 = s.run_nodeflow(g2, "F", "true")
            need(not r2.get("error"), "edited flow runs")
            need(s.flow_cache_info()["hits"] > hits0,
                 "editing the filter downstream reuses the cached join")
            eq(r2["total_rows"], 1,
               "the edited filter recomputes (one row) -- not stale")
        finally:
            s.shutdown()

    def t_nodeflow_join_union_select():
        import csv as _cj
        import tempfile as _tfj
        import os as _osj
        import shutil as _shj
        s = _fresh_session()
        d = _tfj.mkdtemp(prefix="t_nfj_")
        try:
            lp = _osj.path.join(d, "L.csv")
            rp = _osj.path.join(d, "R.csv")
            with open(lp, "w", newline="") as f:
                w = _cj.writer(f)
                w.writerow(["id", "lname", "score"])
                for i in range(1, 7):
                    w.writerow([i, "L%d" % i, i * 10])
            with open(rp, "w", newline="") as f:
                w = _cj.writer(f)
                w.writerow(["id", "rname", "score"])
                for i in range(4, 10):
                    w.writerow([i, "R%d" % i, i * 100])
            s.load_file(lp, destination="sqlite", base_name="L")
            s.load_file(rp, destination="sqlite", base_name="R")
            J = {
                "nodes": [
                    {"id": "L", "type": "input",
                     "config": {"table": "L", "label": "L"}},
                    {"id": "R", "type": "input",
                     "config": {"table": "R", "label": "R"}},
                    {"id": "J", "type": "join",
                     "config": {"label": "join",
                                "keys": [{"left": "id", "right": "id"}]}},
                    {"id": "U", "type": "union", "config": {"label": "union"}},
                ],
                "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "J", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "J", "port": "right"}},
                    {"from": {"node": "J", "port": "inner"},
                     "to": {"node": "U", "port": "in1"}},
                    {"from": {"node": "J", "port": "left_only"},
                     "to": {"node": "U", "port": "in2"}},
                ],
            }
            inner = s.run_nodeflow(J, "J", "inner")
            lo = s.run_nodeflow(J, "J", "left_only")
            ro = s.run_nodeflow(J, "J", "right_only")
            eq(inner["total_rows"], 3, "inner join matches on the shared key")
            eq(lo["total_rows"], 3, "left_only = rows only in the left input")
            eq(ro["total_rows"], 3, "right_only = rows only in the right input")
            # the canonical join port is now "out" (a plain inner join); the old
            # port names stay for back-compat with saved workflows.
            outp = s.run_nodeflow(J, "J", "out")
            eq(outp["total_rows"], 3, "join 'out' port = inner join")
            eq(sorted(outp["columns"]), sorted(inner["columns"]),
               "join 'out' matches the legacy 'inner' columns")
            need("r_score" in inner["columns"],
                 "a duplicate right column is prefixed to avoid a collision")
            u = s.run_nodeflow(J, "U", "out")
            eq(u["total_rows"], 6,
               "union of inner + left_only reconstructs a left outer join")
            S = {
                "nodes": [
                    {"id": "L", "type": "input",
                     "config": {"table": "L", "label": "L"}},
                    {"id": "S", "type": "select",
                     "config": {"label": "select", "fields": [
                         {"name": "id", "type": "text", "keep": True},
                         {"name": "lname", "rename": "name", "keep": True},
                         {"name": "score", "keep": False},
                     ]}},
                ],
                "edges": [{"from": {"node": "L", "port": "out"},
                           "to": {"node": "S", "port": "in"}}],
            }
            sel = s.run_nodeflow(S, "S", "out")
            eq(sel["columns"], ["id", "name"],
               "select keeps + renames only the ticked fields")
            need(isinstance(sel["rows"][0][0], str),
                 "select casts the id field to text")
            need(s.nodeflow_columns(S, "L", "out").get("columns")
                 == ["id", "lname", "score"],
                 "the columns endpoint returns a node's output fields")
        finally:
            s.shutdown()
            _shj.rmtree(d, ignore_errors=True)

    def t_join_alias_dedup_and_ci_keys():
        # F1: join/crossjoin must never emit two columns with the same name,
        # and a configured key must be excluded case-insensitively (only the
        # alias/exclusion logic changed -- rows and join semantics are the same).
        s = Session()
        try:
            # (i) duplicate-name collision: the left already has `name` AND
            # `r_name`; the right side also has `name`. The right `name`
            # collides with left `name` -> `r_name`, which ALSO already exists
            # -> must become `r_name_2` (no duplicate column names).
            g = {"nodes": [
                {"id": "L", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id, 'L' AS name, 'LR' AS r_name",
                    "label": "L"}},
                {"id": "R", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id, 'R' AS name", "label": "R"}},
                {"id": "J", "type": "join", "config": {
                    "label": "join",
                    "keys": [{"left": "id", "right": "id"}]}}],
                "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "J", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "J", "port": "right"}}]}
            r = s.run_nodeflow(g, "J", "inner")
            need(not r.get("error"), "join runs: %s" % r.get("error"))
            cols = r["columns"]
            eq(len(set(cols)), len(cols),
               "join output column names are all unique: %s" % cols)
            need("r_name_2" in cols,
                 "a right column colliding with an existing r_ alias is "
                 "suffixed (_2), not duplicated: %s" % cols)
            eq(r["total_rows"], 1, "inner join still matches on the key")

            # (ii) case-mismatched configured key: the real column is `id` but
            # the key is stored as `ID`. It must still be excluded from the
            # right projection (never leak as `r_id`), matching case-insensitively.
            g2 = {"nodes": [
                {"id": "L", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id, 'L' AS lval", "label": "L"}},
                {"id": "R", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id, 'R' AS rval", "label": "R"}},
                {"id": "J", "type": "join", "config": {
                    "label": "join",
                    "keys": [{"left": "ID", "right": "ID"}]}}],
                "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "J", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "J", "port": "right"}}]}
            r2 = s.run_nodeflow(g2, "J", "inner")
            need(not r2.get("error"),
                 "case-mismatched key join runs: %s" % r2.get("error"))
            lc = [c.lower() for c in r2["columns"]]
            need("r_id" not in lc,
                 "a case-mismatched key (ID vs id) is excluded, not leaked as "
                 "r_id: %s" % r2["columns"])
            eq(lc.count("id"), 1,
               "only the left key column survives once: %s" % r2["columns"])
            eq(r2["total_rows"], 1, "case-insensitive key still joins the row")

            # crossjoin de-dups too (no keys): right `a` collides with left
            # `a` and the existing `r_a`, so it becomes `r_a_2`.
            g3 = {"nodes": [
                {"id": "L", "type": "sql", "config": {
                    "sql": "SELECT 1 AS a, 2 AS r_a", "label": "L"}},
                {"id": "R", "type": "sql", "config": {
                    "sql": "SELECT 3 AS a", "label": "R"}},
                {"id": "cj", "type": "crossjoin", "config": {}}],
                "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "cj", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "cj", "port": "right"}}]}
            r3 = s.run_nodeflow(g3, "cj", "out")
            need(not r3.get("error"), "crossjoin runs: %s" % r3.get("error"))
            c3 = r3["columns"]
            eq(len(set(c3)), len(c3),
               "crossjoin output column names are all unique: %s" % c3)
            need("r_a_2" in c3,
                 "right `a` colliding with left `a` + `r_a` becomes r_a_2: %s"
                 % c3)
        finally:
            s.shutdown()

    def t_nodeflow_formula_summarize():
        import csv as _cf
        import tempfile as _tff
        import os as _osf
        import shutil as _shf
        s = _fresh_session()
        d = _tff.mkdtemp(prefix="t_nff_")
        try:
            cp = _osf.path.join(d, "t.csv")
            with open(cp, "w", newline="") as f:
                w = _cf.writer(f)
                w.writerow(["id", "grp", "score"])
                for i in range(1, 7):
                    w.writerow([i, "A" if i % 2 else "B", i * 10])
            s.load_file(cp, destination="sqlite", base_name="data")
            F = {
                "nodes": [
                    {"id": "n1", "type": "input",
                     "config": {"table": "data", "label": "data"}},
                    {"id": "f", "type": "formula",
                     "config": {"label": "f", "formulas": [
                         {"name": "bonus", "expr": "score * 1.1"},
                         {"name": "score", "expr": "score + 1"},
                     ]}},
                ],
                "edges": [{"from": {"node": "n1", "port": "out"},
                           "to": {"node": "f", "port": "in"}}],
            }
            rf = s.run_nodeflow(F, "f", "out")
            need("bonus" in rf["columns"], "formula adds a new column")
            need(rf["columns"].count("score") == 1,
                 "a formula re-using an input name replaces it, not duplicates")
            G = {
                "nodes": [
                    {"id": "n1", "type": "input",
                     "config": {"table": "data", "label": "data"}},
                    {"id": "g", "type": "summarize",
                     "config": {"label": "g", "group_by": ["grp"], "aggs": [
                         {"col": "id", "func": "count"},
                         {"col": "score", "func": "sum", "name": "total"},
                     ]}},
                ],
                "edges": [{"from": {"node": "n1", "port": "out"},
                           "to": {"node": "g", "port": "in"}}],
            }
            rg = s.run_nodeflow(G, "g", "out")
            eq(rg["total_rows"], 2, "summarize groups into one row per group")
            need("total" in rg["columns"] and "count_id" in rg["columns"],
                 "aggregations are named (explicit + auto)")
            got = {tuple(r) for r in rg["rows"]}
            need(("A", 3, 90) in got and ("B", 3, 120) in got,
                 "grouped sums/counts are correct")
            GA = {
                "nodes": [
                    {"id": "n1", "type": "input",
                     "config": {"table": "data", "label": "data"}},
                    {"id": "g", "type": "summarize",
                     "config": {"label": "g", "group_by": [], "aggs": [
                         {"col": "score", "func": "max"},
                         {"col": "id", "func": "countd"},
                     ]}},
                ],
                "edges": [{"from": {"node": "n1", "port": "out"},
                           "to": {"node": "g", "port": "in"}}],
            }
            rga = s.run_nodeflow(GA, "g", "out")
            eq(rga["total_rows"], 1,
               "summarize with no group-by aggregates to one row")
            eq(list(rga["rows"][0]), [60, 6], "global max + distinct count")
            need(s.run_nodeflow(
                {"nodes": [{"id": "n1", "type": "input",
                            "config": {"table": "data"}},
                           {"id": "g", "type": "summarize",
                            "config": {"group_by": ["grp"], "aggs": []}}],
                 "edges": [{"from": {"node": "n1", "port": "out"},
                            "to": {"node": "g", "port": "in"}}]},
                "g", "out").get("error"),
                 "a summarize with no aggregations is reported")
        finally:
            s.shutdown()
            _shf.rmtree(d, ignore_errors=True)

    def t_nodeflow_pivot_chart_reconcile():
        import csv as _cp
        import tempfile as _tfp
        import os as _osp
        import shutil as _shp
        s = _fresh_session()
        d = _tfp.mkdtemp(prefix="t_nfp_")
        try:
            cp = _osp.path.join(d, "sales.csv")
            with open(cp, "w", newline="") as f:
                w = _cp.writer(f)
                w.writerow(["region", "quarter", "amount"])
                for r in ["N", "S"]:
                    for q in ["Q1", "Q2", "Q3"]:
                        for _k in range(3):
                            w.writerow([r, q, 10])
            s.load_file(cp, destination="sqlite", base_name="sales")
            P = {
                "nodes": [
                    {"id": "i", "type": "input",
                     "config": {"table": "sales", "label": "sales"}},
                    {"id": "p", "type": "pivot",
                     "config": {"label": "p", "rows": ["region"],
                                "col": "quarter", "value": "amount",
                                "agg": "sum"}},
                    {"id": "o", "type": "output", "config": {"label": "o"}},
                ],
                "edges": [
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "p", "port": "in"}},
                    {"from": {"node": "p", "port": "out"},
                     "to": {"node": "o", "port": "in"}},
                ],
            }
            rp = s.run_nodeflow(P, "p", "out")
            eq(rp["total_rows"], 2, "pivot groups into one row per row-field value")
            need({"region", "Q1", "Q2", "Q3"}.issubset(set(rp["columns"])),
                 "pivot spreads the column field's values into columns")
            eq(s.run_nodeflow(P, "o", "out")["total_rows"], 2,
               "a pivot's output flows downstream like any node")
            need("Q1" in (s.nodeflow_columns(P, "p", "out").get("columns") or []),
                 "the columns endpoint sees a pivot's runtime columns")
            C = {
                "nodes": [
                    {"id": "i", "type": "input",
                     "config": {"table": "sales", "label": "sales"}},
                    {"id": "c", "type": "chart", "config": {"label": "c"}},
                ],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "c", "port": "in"}}],
            }
            rc = s.run_nodeflow_chart(
                C, "c", {"chart_type": "bar", "x": "region", "y": "amount",
                         "agg": "sum"})
            need(not rc.get("error") and rc.get("series"),
                 "chart node returns ChartData")
            eq(rc.get("chart_type"), "bar", "chart type carries through")
            R = {
                "nodes": [
                    {"id": "i", "type": "input",
                     "config": {"table": "sales", "label": "sales"}},
                    {"id": "fa", "type": "filter",
                     "config": {"label": "fa", "condition": "amount > 0"}},
                    {"id": "fb", "type": "filter",
                     "config": {"label": "fb", "condition": "amount > 0"}},
                    {"id": "rc", "type": "reconcile", "config": {"label": "rc"}},
                ],
                "edges": [
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "fa", "port": "in"}},
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "fb", "port": "in"}},
                    {"from": {"node": "fa", "port": "true"},
                     "to": {"node": "rc", "port": "left"}},
                    {"from": {"node": "fb", "port": "true"},
                     "to": {"node": "rc", "port": "right"}},
                ],
            }
            rr = s.run_nodeflow_reconcile(R, "rc", ["region", "quarter"],
                                          ["amount"])
            need(not rr.get("error"), "reconcile runs over the two inputs")
            eq(rr["totals"]["matching"], 6,
               "identical inputs match on every key")
            eq(rr["totals"]["non_matching"], 0, "no differing rows")
            need(s.run_nodeflow_reconcile(R, "rc", [], []).get("error"),
                 "reconcile reports a missing key")
            # the temp tables must not leak into the sidebar
            need(not any(t["name"].startswith("__")
                         for t in s.tables_tree()),
                 "flow temp tables stay hidden from the table list")
        finally:
            s.shutdown()
            _shp.rmtree(d, ignore_errors=True)

    def t_nodeflow_columns_and_temp_cleanup():
        import csv as _cc
        import tempfile as _tfc
        import os as _osc
        import shutil as _shc
        s = _fresh_session()
        # this test counts ALL sqlite temp tables; the flow cache keeps boundary
        # outputs in persistent __nbcache_* tables, so pin it off to assert the
        # per-pass cleanup. Cache lifecycle is covered by the t_flow_cache_* tests.
        s.flow_cache = False
        d = _tfc.mkdtemp(prefix="t_nfc_")
        try:
            cp = _osc.path.join(d, "s.csv")
            with open(cp, "w", newline="") as f:
                w = _cc.writer(f)
                w.writerow(["region", "quarter", "amount"])
                for r in ["N", "S"]:
                    for q in ["Q1", "Q2"]:
                        w.writerow([r, q, 5])
            s.load_file(cp, destination="sqlite", base_name="s")

            def tt():
                return s.db.execute(
                    "SELECT count(*) FROM sqlite_temp_master "
                    "WHERE type='table'")[1][0][0]

            gsel = {
                "nodes": [
                    {"id": "i", "type": "input", "config": {"table": "s"}},
                    {"id": "sel", "type": "select", "config": {"fields": [
                        {"name": "region", "keep": True},
                        {"name": "amount", "keep": True}]}},
                ],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "sel", "port": "in"}}],
            }
            before = tt()
            rc = s.nodeflow_columns(gsel, "sel", "out")
            need(set(rc.get("columns", [])) == {"region", "amount"},
                 "the columns endpoint returns the selected fields")
            eq(tt(), before,
               "a column probe with no pivot upstream creates no temp tables")
            r = s.run_nodeflow(gsel, "sel", "out")
            need(not r.get("error"), "the flow runs")
            eq(tt(), before,
               "run_nodeflow drops its temp tables once the result is cached")
            gp = {
                "nodes": [
                    {"id": "i", "type": "input", "config": {"table": "s"}},
                    {"id": "p", "type": "pivot",
                     "config": {"rows": ["region"], "col": "quarter",
                                "value": "amount", "agg": "sum"}},
                    {"id": "f", "type": "formula",
                     "config": {"formulas": [{"name": "z", "expr": "1"}]}},
                ],
                "edges": [
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "p", "port": "in"}},
                    {"from": {"node": "p", "port": "out"},
                     "to": {"node": "f", "port": "in"}},
                ],
            }
            rcp = s.nodeflow_columns(gp, "f", "out")
            need({"region", "Q1", "Q2", "z"}.issubset(
                set(rcp.get("columns", []))),
                 "columns downstream of a pivot include its runtime columns")
            eq(tt(), before,
               "the pivot column probe also cleans up its temp tables")
        finally:
            s.shutdown()
            _shc.rmtree(d, ignore_errors=True)

    def t_nodeflow_transforms():
        import csv as _ct
        import tempfile as _tft
        import os as _ost
        import shutil as _sht
        s = _fresh_session()
        # counts all sqlite temp tables after each run; pin the flow cache off
        # so persistent __nbcache_* boundary tables don't trip the leak check
        # (cache lifecycle is covered by the t_flow_cache_* tests).
        s.flow_cache = False
        d = _tft.mkdtemp(prefix="t_nft_")
        try:
            cp = _ost.path.join(d, "d.csv")
            with open(cp, "w", newline="") as f:
                w = _ct.writer(f)
                w.writerow(["id", "grp", "q1", "q2", "q3"])
                for i in range(1, 9):
                    w.writerow([i, "A" if i % 2 else "B", i, i * 2, i * 3])
            s.load_file(cp, destination="sqlite", base_name="d")

            def G(nodes, edges):
                return {"nodes": nodes, "edges": [
                    {"from": {"node": a, "port": pp},
                     "to": {"node": b, "port": q}} for (a, pp, b, q) in edges]}
            IN = {"id": "i", "type": "input", "config": {"table": "d"}}

            rs = s.run_nodeflow(G([IN, {"id": "n", "type": "sort", "config": {
                "sorts": [{"col": "id", "dir": "desc"}]}}],
                [("i", "out", "n", "in")]), "n", "out")
            eq(int(rs["rows"][0][0]), 8, "sort desc puts the largest id first")

            rh = s.run_nodeflow(G([IN, {"id": "n", "type": "sample", "config": {
                "mode": "head", "n": 3}}], [("i", "out", "n", "in")]),
                "n", "out")
            eq(rh["total_rows"], 3, "sample head returns n rows")
            rr = s.run_nodeflow(G([IN, {"id": "n", "type": "sample", "config": {
                "mode": "random", "n": 3}}], [("i", "out", "n", "in")]),
                "n", "out")
            eq(rr["total_rows"], 3, "sample random returns n rows")

            ru = s.run_nodeflow(G([IN, {"id": "n", "type": "unique", "config": {
                "by": ["grp"]}}], [("i", "out", "n", "in")]), "n", "out")
            eq(ru["total_rows"], 2, "unique by a key keeps one row per key")
            eq(len(ru["columns"]), 5, "unique keeps all columns")
            ru2 = s.run_nodeflow(G([IN, {"id": "n", "type": "unique",
                "config": {"by": []}}], [("i", "out", "n", "in")]), "n", "out")
            eq(ru2["total_rows"], 8, "unique with no key is full-row distinct")

            rp = s.run_nodeflow(G([IN, {"id": "n", "type": "unpivot", "config": {
                "keep": ["id", "grp"], "unpivot": ["q1", "q2", "q3"]}}],
                [("i", "out", "n", "in")]), "n", "out")
            eq(rp["total_rows"], 24, "unpivot turns 3 columns into 3 rows each")
            need(rp["columns"] == ["id", "grp", "field", "value"],
                 "unpivot yields keep + field + value columns")

            rw = s.run_nodeflow(G([IN, {"id": "n", "type": "window", "config": {
                "windows": [
                    {"func": "running_sum", "col": "q1", "name": "rsum",
                     "partition_by": ["grp"],
                     "order_by": [{"col": "id", "dir": "asc"}]},
                    {"func": "row_number", "name": "rn",
                     "partition_by": ["grp"],
                     "order_by": [{"col": "id", "dir": "asc"}]}]}}],
                [("i", "out", "n", "in")]), "n", "out")
            need("rsum" in rw["columns"] and "rn" in rw["columns"],
                 "window adds its calculated columns")
            ix = {c: k for k, c in enumerate(rw["columns"])}
            arows = sorted([r for r in rw["rows"] if r[ix["grp"]] == "A"],
                           key=lambda r: int(r[ix["id"]]))
            eq([r[ix["rsum"]] for r in arows], [1, 4, 9, 16],
               "running_sum accumulates within a partition in order")

            rb = s.run_nodeflow_browse(G([IN, {"id": "n", "type": "browse",
                "config": {}}], [("i", "out", "n", "in")]), "n")
            eq(rb.get("total_rows"), 8, "browse profiles the row count")
            eq(len(rb.get("columns", [])), 5, "browse profiles every column")
            need(all("distinct" in c and "nulls" in c
                     for c in rb["columns"]),
                 "browse returns per-column stats")

            need(s.db.execute("SELECT count(*) FROM sqlite_temp_master "
                              "WHERE type='table'")[1][0][0] == 0,
                 "transform/browse runs leave no temp tables")
        finally:
            s.shutdown()
            _sht.rmtree(d, ignore_errors=True)

    def t_catalog_qualify_and_grouping():
        # SQL Server catalog tables: a bare name in a query must be expanded to
        # its fully-qualified [db].[schema].[table] before passthrough, and the
        # tables list must carry grouping info so the UI can roll them up.
        s = _fresh_session()
        try:
            s.catalog_tables = {
                "AggCreditCard": {
                    "conn": "TDSQL", "database": "VisionReporting",
                    "schema": "dbo", "table": "AggCreditCard",
                    "qualified": "[VisionReporting].[dbo].[AggCreditCard]",
                    "columns": [{"name": "id", "type": "int"}]},
                "dbo_AggLoan": {
                    "conn": "TDSQL", "database": "VisionReporting",
                    "schema": "risk", "table": "AggLoan",
                    "qualified": "[VisionReporting].[risk].[AggLoan]",
                    "columns": []},
            }
            s._catalog_route = {"aggcreditcard": "TDSQL", "aggloan": "TDSQL"}
            qf = s._qualify_catalog_sql
            eq(qf("SELECT * FROM AggCreditCard", "TDSQL"),
               "SELECT * FROM [VisionReporting].[dbo].[AggCreditCard]",
               "a bare catalog name is fully qualified")
            eq(qf("select * from aggcreditcard", "TDSQL"),
               "select * from [VisionReporting].[dbo].[AggCreditCard]",
               "qualification is case-insensitive")
            eq(qf('SELECT * FROM [AggCreditCard]', "TDSQL"),
               "SELECT * FROM [VisionReporting].[dbo].[AggCreditCard]",
               "a bracketed name is qualified")
            need("[VisionReporting].[dbo].[AggCreditCard] a" in qf(
                "SELECT a.* FROM AggCreditCard a JOIN AggLoan b ON a.id=b.id",
                "TDSQL") and "[VisionReporting].[risk].[AggLoan] b" in qf(
                "SELECT a.* FROM AggCreditCard a JOIN AggLoan b ON a.id=b.id",
                "TDSQL"),
                 "joins qualify every catalog table and keep aliases")
            eq(qf("SELECT * FROM [VisionReporting].[dbo].[AggCreditCard]",
                  "TDSQL"),
               "SELECT * FROM [VisionReporting].[dbo].[AggCreditCard]",
               "an already-qualified name is left unchanged")
            eq(qf("SELECT * FROM LocalThing", "TDSQL"),
               "SELECT * FROM LocalThing",
               "a non-catalog name is left unchanged")
            eq(qf("SELECT * FROM dbo_AggLoan", "TDSQL"),
               "SELECT * FROM [VisionReporting].[risk].[AggLoan]",
               "the display-key form also qualifies")
            eq(s._catalog_conn_for("SELECT * FROM AggCreditCard"), "TDSQL",
               "a catalog query still routes to its connection")
            rem = [t for t in s.tables_tree() if t.get("remote")]
            need(rem and all(t.get("group") == "VisionReporting" for t in rem),
                 "catalog tables are grouped by their database")
            need(all("schema" in t and "conn" in t for t in rem),
                 "catalog tables carry schema + connection for the UI")
        finally:
            s.shutdown()

    def t_workflow_store_crud():
        import tempfile as _tfw
        import shutil as _shw
        from pathlib import Path as _Pw
        from samql_core.stores import WorkflowStore
        d = _tfw.mkdtemp(prefix="t_wf_")
        try:
            st = WorkflowStore()
            # point the store at a temp file (a Path, as the store expects)
            st.path = _Pw(d) / "workflows.json"
            st.entries = []
            g1 = {"nodes": [{"id": "i", "type": "input", "config": {}}],
                  "edges": []}
            need(st.upsert("Flow A", g1) is not None, "a named workflow saves")
            need(st.upsert("", g1) is None, "an unnamed workflow is rejected")
            st.upsert("Flow B", {"nodes": [], "edges": []})
            names = [w["name"] for w in st.all()]
            need("Flow A" in names and "Flow B" in names,
                 "saved workflows are listed")
            need(st.all()[0].get("nodes") == 0 or "nodes" in st.all()[0],
                 "the listing summarises node/edge counts")
            need(st.get("Flow A")["graph"]["nodes"][0]["id"] == "i",
                 "loading a workflow returns its full graph")
            st.upsert("Flow A", {"nodes": [{"id": "x", "type": "input",
                                            "config": {}},
                                           {"id": "y", "type": "output",
                                            "config": {}}], "edges": []})
            eq(len(st.get("Flow A")["graph"]["nodes"]), 2,
               "re-saving a name overwrites it")
            need(st.delete("Flow B"), "a workflow can be deleted")
            need(not st.delete("nope"), "deleting a missing workflow is a no-op")
            # persistence: a fresh store over the same file sees the data
            st2 = WorkflowStore()
            st2.path = _Pw(d) / "workflows.json"
            st2._load()
            need([w["name"] for w in st2.all()] == ["Flow A"],
                 "workflows persist to disk and reload")
        finally:
            _shw.rmtree(d, ignore_errors=True)

    def t_nodeflow_cancel_plumbing():
        # cancel_query interrupts every engine and reports cancelled (Stop
        # cancels everything; harmless when nothing is running), and a flow run
        # accepts a query_id and completes normally when not cancelled.
        import csv as _cx
        import tempfile as _tfx
        import os as _osx
        import shutil as _shx
        s = _fresh_session()
        d = _tfx.mkdtemp(prefix="t_cx_")
        try:
            cp = _osx.path.join(d, "d.csv")
            with open(cp, "w", newline="") as f:
                w = _cx.writer(f)
                w.writerow(["id", "v"])
                for i in range(20):
                    w.writerow([i, i])
            s.load_file(cp, destination="sqlite", base_name="d")
            need(s.cancel_query("never-ran").get("cancelled") is True,
                 "Stop always reports cancelled + interrupts engines "
                 "(harmless when nothing is running)")
            g = {"nodes": [{"id": "i", "type": "input", "config": {"table": "d"}},
                           {"id": "s", "type": "sort", "config": {
                               "sorts": [{"col": "id", "dir": "desc"}]}}],
                 "edges": [{"from": {"node": "i", "port": "out"},
                            "to": {"node": "s", "port": "in"}}]}
            r = s.run_nodeflow(g, "s", "out", query_id="qid-1")
            need(not r.get("error") and not r.get("cancelled"),
                 "a flow with a query_id runs normally when not cancelled")
            need("qid-1" not in s._running,
                 "the run id is unregistered once the flow finishes")
        finally:
            s.shutdown()
            _shx.rmtree(d, ignore_errors=True)

    def t_reclaim_defers_checkpoint_while_running():
        # The background DuckDB checkpoint holds the connection lock, so it must
        # never run while a query/flow is in flight -- otherwise a tiny run can
        # stall on "Running ..." waiting for a slow on-disk checkpoint to give
        # the connection back. _reclaim defers (and reschedules) the checkpoint
        # while a run is registered, and only checkpoints when the engine idles.
        import threading as _th
        s = _fresh_session()
        calls = []

        class _FakeDuck:
            def __init__(self):
                self.write_lock = _th.RLock()
                self.table_columns = {}

            def checkpoint(self):
                calls.append(1)
                return True

        try:
            s.duckdb = _FakeDuck()
            # a run is in flight -> the checkpoint is deferred, not executed
            with s._running_lock:
                s._running["q-busy"] = s.duckdb
            s._reclaim(full=False)
            need(calls == [],
                 "checkpoint must NOT run while a query/flow is in flight")
            # the deferral rescheduled a cleanup timer; cancel it so the test
            # leaves no stray background thread behind
            with s._cleanup_lock:
                if s._cleanup_timer is not None:
                    s._cleanup_timer.cancel()
                    s._cleanup_timer = None
            # engine idle now -> the checkpoint is allowed to run
            with s._running_lock:
                s._running.clear()
            s._reclaim(full=False)
            need(calls == [1], "checkpoint runs once the engine is idle")
        finally:
            s.duckdb = None  # don't let shutdown call engine methods on the fake
            s.shutdown()

    def t_engine_deadline_lock():
        # A foreground op must never wait forever for the engine connection
        # lock: if another thread holds it past the deadline, acquiring raises
        # EngineBusy so the request fails fast (instead of hanging -> a frozen
        # spinner -> "failed to fetch"). The lock stays re-entrant for the
        # owning thread and supports non-blocking acquire (the background
        # checkpoint relies on that).
        import threading as _th
        import time as _t
        from samql_core.engines import _DeadlineRLock, EngineBusy

        lk = _DeadlineRLock(timeout=0.3)

        # re-entrant: the owner re-acquires instantly, no raise / no hang
        with lk:
            with lk:
                pass

        holding = _th.Event()
        release = _th.Event()

        def holder():
            lk.acquire()
            holding.set()
            release.wait(3.0)
            lk.release()

        th = _th.Thread(target=holder, daemon=True)
        th.start()
        try:
            need(holding.wait(1.0), "holder thread acquired the lock")
            # non-blocking acquire fails immediately (returns False, no raise)
            need(lk.acquire(blocking=False) is False,
                 "non-blocking acquire returns False while held elsewhere")
            # blocking acquire raises EngineBusy after ~the deadline
            t0 = _t.time()
            raised = False
            try:
                lk.acquire()
            except EngineBusy:
                raised = True
            dt = _t.time() - t0
            need(raised,
                 "blocking acquire raises EngineBusy when wedged past deadline")
            need(0.2 <= dt <= 2.0,
                 "EngineBusy fires near the deadline, not instantly or never "
                 "(%.2fs)" % dt)
        finally:
            release.set()
            th.join(3.0)
        # once free again a normal `with` works
        with lk:
            pass

    def t_create_table_from_grid():
        # A manually-entered / pasted grid becomes a local table: duplicate
        # column names are disambiguated, empty cells are NULL, numeric-looking
        # cells are stored as numbers, and all-empty rows are dropped.
        s = _fresh_session()
        try:
            r = s.create_table_from_grid(
                "grid59", ["a", "b", "a"],
                [["1", "x", ""], ["2", "y", "7"], ["", "", ""]],
                destination="sqlite")
            need(r.get("ok"), "create_table_from_grid returns ok")
            tname = r["table"]
            eq(r["engine"], "sqlite", "stored in sqlite as requested")
            eq(r["loaded"][0]["tables"][0]["rows"], 2,
               "the all-empty row is dropped")
            eq(r["loaded"][0]["tables"][0]["columns"], ["a", "b", "a_1"],
               "duplicate column names are disambiguated")
            need(any(t["name"] == tname and t["engine"] == "sqlite"
                     for t in s.tables_tree()),
                 "the created table shows in the tables list")
            cols, rows = s.db.execute('SELECT * FROM "%s" ORDER BY a' % tname)
            eq(rows[0], (1, "x", None), "first row coerces 1->int, ''->NULL")
            eq(rows[1], (2, "y", 7), "second row coerces '7'->int")
            bad = s.create_table_from_grid("nope", [], [["1"]],
                                           destination="sqlite")
            need(bad.get("error"), "a table with no columns is rejected")
        finally:
            s.shutdown()

    def t_catalog_columns_lazy():
        # The tables list omits remote columns (so a big catalog is a light
        # payload) but reports a column count; catalog_columns serves the
        # columns on demand.
        s = _fresh_session()
        try:
            s.catalog_tables = {
                "AggCreditCard": {
                    "conn": "TDSQL", "database": "VisionReporting",
                    "schema": "dbo", "table": "AggCreditCard",
                    "qualified": "[VisionReporting].[dbo].[AggCreditCard]",
                    "columns": [{"name": "id", "type": "int"},
                                {"name": "bal", "type": "decimal"}]},
            }
            s._catalog_route = {"aggcreditcard": "TDSQL"}
            rem = [t for t in s.tables_tree() if t.get("remote")]
            need(rem, "the catalog table is listed")
            eq(rem[0]["columns"], [],
               "remote columns are omitted from the tables list")
            eq(rem[0]["col_count"], 2,
               "the column count is reported for display")
            got = s.catalog_columns("AggCreditCard")
            eq(len(got.get("columns", [])), 2,
               "catalog_columns returns the columns on demand")
            need(s.catalog_columns("missing").get("error"),
                 "asking for an unknown catalog table is an error")
        finally:
            s.shutdown()

    def t_free_memory_keeps_tables():
        # The free-memory tool releases cached results and asks the engines to
        # hand memory back, but never drops loaded tables.
        s = _loaded_session()
        try:
            s.run_query("SELECT * FROM data")
            info = s.free_memory()
            need("kept_results" in info and "freed_mb" in info,
                 "free_memory returns a usage summary")
            need(any(t["name"] == "data" for t in s.tables_tree()),
                 "loaded tables survive a free-memory call")
        finally:
            s.shutdown()

    def t_nodeflow_createtable_and_text():
        # The create-table node compiles to a cross-engine VALUES-style query
        # (verified by running it on SQLite); the text note has no runnable
        # output.
        from samql_core import nodeflow
        s = _fresh_session()
        try:
            node = {"id": "ct", "type": "createtable", "config": {
                "columns": ["id", "name", "amount"],
                "rows": [["1", "Alice", "100.5"], ["2", "Bob", ""],
                         ["", "", ""]]}}
            sql = nodeflow.node_output_sql(node, "out",
                                           lambda p: None, lambda rel: [])
            cols, rows = s.db.execute(sql)
            eq(cols, ["id", "name", "amount"], "createtable yields its columns")
            eq(rows, [(1, "Alice", 100.5), (2, "Bob", None)],
               "createtable infers numeric columns and drops the empty row")
            eq(nodeflow.NODE_PORTS["createtable"], {"in": [], "out": ["out"]},
               "createtable has an output port and no inputs")
            eq(nodeflow.NODE_PORTS["text"], {"in": [], "out": []},
               "a text note has no ports")
            raised = False
            try:
                nodeflow.node_output_sql(
                    {"id": "t", "type": "text", "config": {"text": "hi"}},
                    "out", lambda p: None, lambda rel: [])
            except nodeflow.NodeflowError:
                raised = True
            need(raised, "running a text note is refused")
        finally:
            s.shutdown()

    def t_excel_load():
        # Excel workbooks load one table per non-empty sheet (openpyxl).
        if not feats.get("openpyxl"):
            skip("openpyxl not installed")
            return
        import openpyxl
        import tempfile as _tf
        d = _tf.mkdtemp()
        p = os.path.join(d, "book59.xlsx")
        wb = openpyxl.Workbook()
        ws1 = wb.active
        ws1.title = "Sales"
        ws1.append(["id", "region", "amount"])
        ws1.append([1, "East", 100])
        ws1.append([2, "West", 250])
        ws2 = wb.create_sheet("Costs")
        ws2.append(["id", "cost"])
        ws2.append([1, 40])
        wb.save(p)
        s = _fresh_session()
        try:
            s.load_file(p, destination="sqlite")
            names = {t["name"] for t in s.tables_tree()
                     if not t["name"].startswith("__")}
            need("book59_Sales" in names and "book59_Costs" in names,
                 "each sheet becomes its own table")
            _c, rows = s.db.execute('SELECT COUNT(*) FROM "book59_Sales"')
            eq(rows[0][0], 2, "the Sales sheet has 2 data rows")
        finally:
            s.shutdown()
            import shutil as _sh
            _sh.rmtree(d, ignore_errors=True)

    def t_excel_load_cancellable():
        # A big .xlsx read is a plain openpyxl Python loop -- an engine
        # interrupt can't reach it -- so the load must poll progress and unwind
        # on cancel. openpyxl is present here, so this runs (not gated).
        if not feats.get("openpyxl"):
            skip("openpyxl not installed")
            return
        import openpyxl
        from samql_core import loaders
        d = tempfile.mkdtemp()
        p = os.path.join(d, "big.xlsx")
        wb = openpyxl.Workbook()
        ws = wb.active
        ws.append(["id", "name"])
        for i in range(6000):                 # over the 5000-row poll interval
            ws.append([i, "r%d" % i])
        wb.save(p)
        s = _fresh_session()
        calls = [0]

        def prog(done, total=None):
            calls[0] += 1
            raise loaders.LoadCancelled()     # a Stop lands during the read

        raised = False
        try:
            loaders.load_file(s, p, destination="sqlite", progress=prog)
        except loaders.LoadCancelled:
            raised = True
        finally:
            s.shutdown()
            import shutil as _sh
            _sh.rmtree(d, ignore_errors=True)
        need(raised, "a cancel during the .xlsx read unwinds as LoadCancelled")
        need(calls[0] >= 1, "progress is polled during the sheet read")

    def t_split_statements_comments():
        # The statement splitter must not break on a ';' inside a string,
        # a line comment, or a block comment.
        from samql_core.sqlutil import split_statements
        eq(split_statements("SELECT ';' AS x"), ["SELECT ';' AS x"],
           "a semicolon inside a string does not split")
        eq(split_statements("SELECT 1 -- a ; b\n; SELECT 2"),
           ["SELECT 1 -- a ; b", "SELECT 2"],
           "a semicolon inside a line comment does not split")
        eq(split_statements("SELECT 1 /* a ; b */ ; SELECT 2"),
           ["SELECT 1 /* a ; b */", "SELECT 2"],
           "a semicolon inside a block comment does not split")
        eq(split_statements("SELECT 1; SELECT 2"),
           ["SELECT 1", "SELECT 2"],
           "ordinary statements still split on ';'")

    def t_create_table_name_sanitized():
        # A hostile / free-text table name is reduced to a safe identifier so
        # the created table can still be dropped and counted.
        s = _fresh_session()
        try:
            r = s.create_table_from_grid(
                'bad"; DROP TABLE x;--', ["a"], [["1"]],
                destination="sqlite")
            need(r.get("ok"), "table is created from a hostile name")
            tname = r["table"]
            need('"' not in tname and ";" not in tname,
                 "the stored table name is a safe identifier")
            need(any(t["name"] == tname for t in s.tables_tree()),
                 "the sanitized table appears in the tables list")
            # and it must be droppable (the bug this guards against)
            s.drop_table("sqlite", tname)
            need(not any(t["name"] == tname for t in s.tables_tree()),
                 "the created table can be dropped")
            r2 = s.create_table_from_grid("123", ["a"], [["1"]],
                                          destination="sqlite")
            need(not r2["table"][0].isdigit(),
                 "a numeric-leading name is prefixed so it's a valid ident")
        finally:
            s.shutdown()

    def t_drop_table_escapes_identifier():
        # A table whose name contains a double-quote (e.g. created by raw SQL)
        # must still be droppable -- drop_table escapes the identifier.
        s = _fresh_session()
        try:
            name, _n = s.db.add_table_streaming(
                'weird"name', ["a"], iter([(1,)]), source="test")
            need(any(t["name"] == name for t in s.tables_tree()),
                 "the quote-named table is registered")
            s.db.drop_table(name)
            need(name not in s.db.table_columns,
                 "a quote-named table is dropped without a SQL error")
        finally:
            s.shutdown()

    def t_fields_with_spaces_and_quotes():
        # Field data with inline / edge spaces and embedded quotes must survive
        # a round-trip through the CSV loader, the grid, and the create-table
        # node -- byte-for-byte (numeric cells are still trimmed).
        from samql_core import loaders, nodeflow
        import tempfile as _tf
        d = _tf.mkdtemp()
        s = _fresh_session()
        try:
            # CSV (RFC 4180): embedded quotes, embedded comma, edge spaces.
            p = os.path.join(d, "sq.csv")
            open(p, "w", encoding="utf-8", newline="").write(
                'name,note\n'
                'John Smith,"he said ""hi"""\n'
                "O'Brien,\"Boston, MA\"\n"
                '"  padded  ",plain\n')
            res = loaders.load_csv(s.db, p, base_name="sq")
            _c, rows = s.db.execute(
                'SELECT name, note FROM "%s" ORDER BY rowid' % res["name"])
            eq(rows[0], ("John Smith", 'he said "hi"'),
               "CSV keeps inline spaces and de-doubles embedded quotes")
            eq(rows[1], ("O'Brien", "Boston, MA"),
               "CSV keeps a single quote and an embedded comma")
            eq(rows[2], ("  padded  ", "plain"),
               "CSV preserves leading/trailing spaces inside quotes")

            # Grid: text preserved exactly; a spaced numeric is still a number.
            g = s.create_table_from_grid(
                "gsq", ["name", "qty"],
                [["  padded  ", " 42 "], ["O'Brien", "7"],
                 ['say "hi"', "x"]],
                destination="sqlite")
            _c2, gr = s.db.execute(
                'SELECT name, qty FROM "%s" ORDER BY rowid' % g["table"])
            eq(gr[0], ("  padded  ", 42),
               "grid keeps edge spaces in text and trims a numeric cell")
            eq(gr[1], ("O'Brien", 7), "grid keeps a single quote (qty is numeric)")
            eq(gr[2], ('say "hi"', "x"), "grid keeps embedded double quotes")

            # Create-table node literal.
            node = {"id": "ct", "type": "createtable", "config": {
                "columns": ["name", "qty"],
                "rows": [["  padded  ", " 42 "], ["O'Brien", "7"]]}}
            sql = nodeflow.node_output_sql(node, "out",
                                           lambda pt: None, lambda rel: [])
            _c3, nr = s.db.execute(sql)
            eq(nr[0], ("  padded  ", 42),
               "node keeps edge spaces in text and trims a numeric cell")
            eq(nr[1], ("O'Brien", 7), "node escapes a single quote correctly")
        finally:
            s.shutdown()
            import shutil as _sh
            _sh.rmtree(d, ignore_errors=True)

    def t_nodeflow_sql_node():
        # The SQL node runs as a source (reads a loaded table) and as a
        # transform (reads its upstream via the {{in}} token); engine routing
        # follows the tables it references.
        from samql_core import nodeflow
        s = _loaded_session()  # table "data": id,name,score,category,dt; 60 rows
        try:
            g1 = {"nodes": [{"id": "q", "type": "sql", "config": {
                "sql": "SELECT category, COUNT(*) AS n FROM data "
                       "GROUP BY category ORDER BY category"}}],
                  "edges": []}
            r = s.run_nodeflow(g1, "q", "out")
            need(not r.get("error"), "sql source runs: %s" % r.get("error"))
            eq(r["columns"], ["category", "n"], "sql source returns its columns")
            need(sum(row[1] for row in r["rows"]) == 60,
                 "sql source aggregates all rows")
            # engine routing picks the table's engine (sqlite here)
            eq(s._flow_engine_target(g1), "__local__",
               "a sql node referencing a sqlite table routes to sqlite")

            g2 = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "q", "type": "sql", "config": {
                    "sql": "SELECT COUNT(*) AS c FROM {{in}}"}}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "q", "port": "in"}}]}
            r2 = s.run_nodeflow(g2, "q", "out")
            need(not r2.get("error"), "sql transform runs: %s" % r2.get("error"))
            eq(r2["rows"][0][0], 60, "sql transform reads its upstream via {{in}}")

            # a {{in}} token with nothing connected is a clear error
            g3 = {"nodes": [{"id": "q", "type": "sql", "config": {
                "sql": "SELECT * FROM {{in}}"}}], "edges": []}
            need(s.run_nodeflow(g3, "q", "out").get("error"),
                 "{{in}} with no input is rejected")
            # a non-SELECT is refused
            g4 = {"nodes": [{"id": "q", "type": "sql", "config": {
                "sql": "DROP TABLE data"}}], "edges": []}
            need(s.run_nodeflow(g4, "q", "out").get("error"),
                 "a non-read SQL node is refused")
            eq(nodeflow.NODE_PORTS["sql"], {"in": ["in"], "out": ["out"]},
               "sql node has one input and one output")
            eq(nodeflow.NODE_PORTS["python"], {"in": ["in"], "out": ["out"]},
               "python node has one optional input and one output")
            # Python node: standalone (no input)
            g_py = {"nodes": [
                {"id": "p", "type": "python",
                 "config": {"code": 'out = [{"a": 1}, {"a": 2}]'}}],
                "edges": []}
            r_py = s.run_nodeflow(g_py, "p", "out")
            need(not r_py.get("error"), "standalone python node runs: %s"
                 % r_py.get("error"))
            eq(r_py.get("columns"), ["a"], "python out columns")
            need(r_py.get("rows") in ([[1], [2]], [["1"], ["2"]]),
                 "python out rows: %r" % (r_py.get("rows"),))
            # Python node: optional input wired — df/columns available
            g_py2 = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "p", "type": "python",
                 "config": {
                     "code": "out = [{'n': len(df), 'ncols': len(columns)}]"
                 }}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "p", "port": "in"}}]}
            r_py2 = s.run_nodeflow(g_py2, "p", "out")
            need(not r_py2.get("error"), "python with input runs: %s"
                 % r_py2.get("error"))
            need(r_py2.get("rows"), "python with input returns rows")
            need(int((r_py2.get("rows") or [[0]])[0][0]) > 0,
                 "python saw upstream rows")
            # pandas path: df is a DataFrame; filter + assign DataFrame to out
            from samql_core import python_node as _pyn
            need(_pyn.pandas_available(),
                 "distribution builds bundle pandas for Python nodes")
            g_pd = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "p", "type": "python",
                 "config": {
                     "code": (
                         "import pandas as pd\n"
                         "need_df = isinstance(df, pd.DataFrame)\n"
                         "filtered = df[df['score'] > 50]"
                         "[['name', 'score']]\n"
                         "out = filtered if need_df else "
                         "[{'name': 'x', 'score': 1}]\n"
                     )
                 }}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "p", "port": "in"}}]}
            r_pd = s.run_nodeflow(g_pd, "p", "out")
            need(not r_pd.get("error"), "pandas python node runs: %s"
                 % r_pd.get("error"))
            eq(r_pd.get("columns"), ["name", "score"],
               "pandas filter keeps projected columns")
            need(len(r_pd.get("rows") or []) == 26,
                 "score > 50 keeps 26 fixture rows, got %r"
                 % (len(r_pd.get("rows") or []),))
            # unit: bindings expose DataFrame + records; out accepts DataFrame
            cols_u, rows_u = _pyn.run_script(
                "import pandas as pd\n"
                "assert isinstance(df, pd.DataFrame)\n"
                "assert records is not None and len(records) == len(df)\n"
                "out = df.assign(twice=df['score'] * 2)"
                "[['name', 'twice']]\n",
                columns=["name", "score"],
                rows=[("a", 10.0), ("b", 20.0)],
            )
            eq(cols_u, ["name", "twice"], "DataFrame out columns")
            eq(rows_u, [("a", 20.0), ("b", 40.0)], "DataFrame out rows")
        finally:
            s.shutdown()

    def t_python_node_pandas_bindings():
        # Direct python_node coverage: df is a DataFrame after build deps,
        # pandas import is allowed, and DataFrame out normalizes cleanly.
        from samql_core import python_node as pn
        need(pn.pandas_available(), "pandas must be installed for builds/tests")
        cols, rows = pn.run_script(
            "import pandas as pd\n"
            "assert list(df.columns) == columns\n"
            "assert len(rows) == len(df)\n"
            "out = pd.DataFrame({'n': [len(df)], 'ok': [True]})\n",
            columns=["id", "v"],
            rows=[(1, "x"), (2, "y"), (3, "z")],
        )
        eq(cols, ["n", "ok"], "constructed DataFrame columns")
        eq(rows, [(3, True)], "constructed DataFrame rows: %r" % (rows,))
        # Forbidden import stays blocked
        try:
            pn.run_script("import os\nout = [{'a': 1}]")
            raise AssertionError("os import should be blocked")
        except pn.PythonNodeError as exc:
            need("not allowed" in str(exc).lower()
                 or "ImportError" in str(exc),
                 "blocked import surfaces cleanly: %s" % exc)

    def t_nodeflow_write_to_table():
        # The write node materialises its upstream into a real loaded table.
        from samql_core import nodeflow
        s = _loaded_session()
        try:
            g = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "f", "type": "filter",
                 "config": {"condition": "score >= 50"}},
                {"id": "w", "type": "write",
                 "config": {"name": "kept rows!"}}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "f", "port": "in"}},
                          {"from": {"node": "f", "port": "true"},
                           "to": {"node": "w", "port": "in"}}]}
            r = s.run_nodeflow_to_table(g, "w", "kept rows!")
            need(r.get("ok"), "write returns ok: %s" % r.get("error"))
            eq(r["table"], "kept_rows",
               "the table name is sanitised to a safe identifier")
            need(any(t["name"] == "kept_rows" for t in s.tables_tree()),
                 "the written table shows in the tables list")
            res = s.run_query('SELECT COUNT(*) FROM "kept_rows"')
            eq(res["rows"][0][0], r["rows"], "the written row count matches")
            # re-running overwrites (no duplicate / no error)
            r2 = s.run_nodeflow_to_table(g, "w", "kept rows!")
            need(r2.get("ok"), "re-running the write overwrites cleanly")
            need(not [n for n in s.db.table_columns
                      if n.startswith("__nbflow")],
                 "no flow temp tables are left behind")
            eq(nodeflow.NODE_PORTS["write"], {"in": ["in"], "out": ["out"]},
               "write node has an input (sink)")
        finally:
            s.shutdown()

    def t_apiload_scheme_guard():
        # The REST loader only fetches http(s); other schemes (file://, ftp://,
        # a bare path) are refused before any network/file access happens.
        # Both fetch_json AND fetch_to_file (the default single-page spool
        # path) must enforce the private/metadata SSRF policy.
        from samql_core import apiload
        import tempfile, os
        for bad in ("file:///etc/passwd", "ftp://host/x", "/local/path",
                    "gopher://x"):
            st, ct, data, text, err = apiload.fetch_json(bad)
            need(data is None and err and "http" in err.lower(),
                 "rejects non-http(s) URL: %r -> %r" % (bad, err))
        for bad in ("http://127.0.0.1/secret", "http://169.254.169.254/latest",
                    "http://10.0.0.1/x"):
            st, ct, data, text, err = apiload.fetch_json(bad)
            need(data is None and err and "refus" in err.lower(),
                 "rejects private/metadata URL: %r -> %r" % (bad, err))
            fd, path = tempfile.mkstemp(suffix=".json")
            os.close(fd)
            try:
                st2, ct2, err2, nbytes = apiload.fetch_to_file(bad, path)
                need(err2 and "refus" in err2.lower() and nbytes == 0,
                     "fetch_to_file rejects private URL: %r -> %r"
                     % (bad, err2))
            finally:
                try:
                    os.unlink(path)
                except OSError:
                    pass
        # a well-formed https URL is accepted past the scheme check (it will
        # then fail to connect in the sandbox, which is fine -- not a scheme
        # error).
        st, ct, data, text, err = apiload.fetch_json(
            "https://example.invalid/x", timeout=1)
        need(err is None or "http" not in (err or "").lower()
             or "Only http" not in (err or ""),
             "an https URL passes the scheme guard")

    def t_nodeflow_fusion():
        # Fusion inlines SQL-only single-consumer nodes into one nested query
        # (fewer temp tables) and must produce identical results to the
        # node-by-node path; boundaries (shared nodes, pivots) still materialise.
        s = _loaded_session()  # table "data": id,name,score,category,dt; 60 rows
        # this test counts per-pass temp tables; the flow cache (default on)
        # materialises boundary outputs to persistent __nbcache_* tables that
        # aren't on the per-pass drop list, so pin it off here -- the cache
        # layer's own lifecycle is covered by the t_flow_cache_* tests.
        s.flow_cache = False

        def run(graph, node, port="out"):
            created = []
            et = s._flow_engine_target(graph)
            tmp = s._materialize_flow(graph, node, port, et, created)
            eng, _k = s._engine_obj(et)
            cols, rows = eng.execute('SELECT * FROM "%s" ORDER BY 1' % tmp)
            s._drop_flow_temps(et, created)
            return list(cols), [list(r) for r in rows], len(created)

        try:
            # a linear SQL-only chain fuses to a single temp (the target)
            lin = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "f", "type": "filter",
                 "config": {"condition": "score >= 50"}},
                {"id": "se", "type": "select", "config": {"fields": [
                    {"name": "id", "keep": True},
                    {"name": "score", "keep": True}]}},
                {"id": "so", "type": "sort",
                 "config": {"sorts": [{"col": "score", "dir": "desc"}]}}],
                "edges": [
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "f", "port": "in"}},
                    {"from": {"node": "f", "port": "true"},
                     "to": {"node": "se", "port": "in"}},
                    {"from": {"node": "se", "port": "out"},
                     "to": {"node": "so", "port": "in"}}]}
            s.fuse_flows = True
            cF, rF, tF = run(lin, "so")
            s.fuse_flows = False
            cN, rN, tN = run(lin, "so")
            eq((cF, rF), (cN, rN), "fused linear chain == per-node result")
            eq(tF, 1, "a 4-node SQL chain fuses into one temp table")
            need(tN > tF, "fusion creates fewer temps than per-node (%d<%d)"
                 % (tF, tN))

            # a shared (multi-consumer) node is materialised once, not inlined
            dia = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "a", "type": "filter",
                 "config": {"condition": "category = 'A'"}},
                {"id": "b", "type": "filter",
                 "config": {"condition": "category = 'B'"}},
                {"id": "u", "type": "union", "config": {}}],
                "edges": [
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "a", "port": "in"}},
                    {"from": {"node": "i", "port": "out"},
                     "to": {"node": "b", "port": "in"}},
                    {"from": {"node": "a", "port": "true"},
                     "to": {"node": "u", "port": "in1"}},
                    {"from": {"node": "b", "port": "true"},
                     "to": {"node": "u", "port": "in2"}}]}
            s.fuse_flows = True
            _cF, rF, tF = run(dia, "u")
            s.fuse_flows = False
            _cN, rN, _tN = run(dia, "u")
            eq(sorted(rF), sorted(rN), "fused diamond == per-node result")
            eq(tF, 2, "the shared input is materialised once (input + target)")

            # a SQL node whose {{in}} appears twice must not duplicate its input
            sq = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "q", "type": "sql", "config": {"sql":
                    "SELECT a.category, COUNT(*) AS n FROM {{in}} a "
                    "JOIN {{in}} b ON a.id=b.id GROUP BY a.category "
                    "ORDER BY a.category"}}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "q", "port": "in"}}]}
            s.fuse_flows = True
            _cF, rF, _t = run(sq, "q")
            s.fuse_flows = False
            _cN, rN, _t = run(sq, "q")
            eq(rF, rN, "sql {{in}} used twice is consistent fused vs per-node")
        finally:
            s.fuse_flows = True
            s.shutdown()

    def t_write_image():
        # ECharts produces the image client-side; write_image persists the
        # data URL to disk (base64 for png/jpeg, URL-encoded for svg).
        import tempfile, os
        s = Session()
        try:
            d = tempfile.mkdtemp()
            png = ("iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAA"
                   "C0lEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==")
            r = s.write_image(d, "plot", "png", "data:image/png;base64," + png)
            need(r.get("ok"), "png written: %s" % r.get("error"))
            need(os.path.isfile(r["file"]) and r["file"].endswith(".png"),
                 "png file on disk")
            r2 = s.write_image(d, "plot", "svg",
                               "data:image/svg+xml;charset=UTF-8,%3Csvg%2F%3E")
            need(r2.get("ok") and os.path.isfile(r2["file"]),
                 "svg written (url-decoded)")
            need(s.write_image("/no/such/dir/zzz", "x", "png",
                               "data:image/png;base64," + png).get("error"),
                 "a missing folder errors")
            need(s.write_image(d, "x", "gif",
                               "data:image/png;base64," + png).get("error"),
                 "an unsupported format errors")
            # Empty folder → Downloads (SAMQL_DOWNLOADS_DIR in tests).
            old_env = os.environ.get("SAMQL_DOWNLOADS_DIR")
            dl = tempfile.mkdtemp()
            os.environ["SAMQL_DOWNLOADS_DIR"] = dl
            try:
                r3 = s.write_image("", "dlplot", "png",
                                   "data:image/png;base64," + png)
                need(r3.get("ok") and os.path.isfile(r3["file"]),
                     "empty out_dir writes into Downloads: %r" % r3)
                need(r3["file"].startswith(dl),
                     "Downloads path used: %r" % r3.get("file"))
            finally:
                if old_env is None:
                    os.environ.pop("SAMQL_DOWNLOADS_DIR", None)
                else:
                    os.environ["SAMQL_DOWNLOADS_DIR"] = old_env
        finally:
            s.shutdown()

    def t_export_data_formats():
        # Output node writes CSV/TSV/JSON/XLSX; repeated exports must not crash.
        import tempfile, os
        s = _loaded_session()
        try:
            d = tempfile.mkdtemp()
            g = {"nodes": [
                {"id": "i", "type": "input", "config": {"table": "data"}},
                {"id": "o", "type": "output", "config": {}}],
                "edges": [{"from": {"node": "i", "port": "out"},
                           "to": {"node": "o", "port": "in"}}]}
            for fmt, ext in [("csv", "csv"), ("tsv", "tsv"),
                             ("json", "json"), ("xlsx", "xlsx")]:
                r = s.export_nodeflow(g, "o", d, fmt, "out")
                if fmt == "xlsx":
                    try:
                        import openpyxl  # noqa: F401
                    except Exception:
                        need("pip install openpyxl" in (r.get("error")
                                                         or ""),
                             "without openpyxl the xlsx format degrades "
                             "with guidance: %r" % r.get("error"))
                        continue
                need(r.get("ok"), "%s export ok: %s" % (fmt, r.get("error")))
                need(os.path.isfile(os.path.join(d, "out." + ext)),
                     "%s file on disk" % fmt)
            # the missing-openpyxl branch, EXECUTED even where openpyxl
            # exists: block the import and expect guidance, not a raw
            # ModuleNotFoundError (the on-box failure of 2026-07-02)
            import sys as _sys
            _had = _sys.modules.pop("openpyxl", None)
            _sys.modules["openpyxl"] = None
            try:
                r = s.export_nodeflow(g, "o", d, "xlsx", "blocked")
                need(not r.get("ok")
                     and "pip install openpyxl" in (r.get("error") or ""),
                     "a missing openpyxl surfaces as guidance: %r"
                     % r.get("error"))
            finally:
                if _had is not None:
                    _sys.modules["openpyxl"] = _had
                else:
                    _sys.modules.pop("openpyxl", None)
            need(s.export_nodeflow(g, "o", d, "csv", "out").get("ok"),
                 "a repeated export still succeeds (no budget crash)")
            # Empty out_dir → Downloads (SAMQL_DOWNLOADS_DIR in tests).
            old_env = os.environ.get("SAMQL_DOWNLOADS_DIR")
            dl = tempfile.mkdtemp()
            os.environ["SAMQL_DOWNLOADS_DIR"] = dl
            try:
                rdl = s.export_nodeflow(g, "o", "", "csv", "dlout")
                need(rdl.get("ok"),
                     "empty out_dir exports to Downloads: %r" % rdl)
                need(os.path.isfile(os.path.join(dl, "dlout.csv")),
                     "Downloads file on disk")
            finally:
                if old_env is None:
                    os.environ.pop("SAMQL_DOWNLOADS_DIR", None)
                else:
                    os.environ["SAMQL_DOWNLOADS_DIR"] = old_env
        finally:
            s.shutdown()

    def _sql_flow(s, src_sql, node):
        g = {"nodes": [
            {"id": "s", "type": "sql", "config": {"sql": src_sql, "label": "s"}},
            node],
            "edges": [{"from": {"node": "s", "port": "out"},
                       "to": {"node": node["id"], "port": "in"}}]}
        return s.run_nodeflow(g, node["id"], "out")

    def _chain(s, src_sql, node_list, run_port="out"):
        # linear pipeline: sql-source -> node_list[0] -> ... -> last; runs last.
        from samql_core import nodeflow
        gnodes = [{"id": "s", "type": "sql",
                   "config": {"sql": src_sql, "label": "s"}}]
        edges = []
        prev = ("s", "out")
        for nd in node_list:
            gnodes.append(nd)
            inp = (nodeflow.NODE_PORTS.get(nd["type"], {}).get("in")
                   or ["in"])[0]
            edges.append({"from": {"node": prev[0], "port": prev[1]},
                          "to": {"node": nd["id"], "port": inp}})
            outp = (nodeflow.NODE_PORTS.get(nd["type"], {}).get("out")
                    or ["out"])[0]
            prev = (nd["id"], outp)
        g = {"nodes": gnodes, "edges": edges}
        return s.run_nodeflow(g, node_list[-1]["id"], run_port), g

    def t_bin_node():
        s = Session()
        try:
            r = _sql_flow(
                s, "SELECT 5 AS score UNION ALL SELECT 15 UNION ALL SELECT 25",
                {"id": "b", "type": "bin", "config": {
                    "col": "score", "out": "band", "else_label": "high",
                    "cuts": [{"le": 20, "label": "mid"},
                             {"le": 10, "label": "low"}]}})
            need(not r.get("error"), "bin runs: %s" % r.get("error"))
            eq("band" in (r.get("columns") or []), True, "bin adds its column")
            bands = sorted(row[1] for row in r["rows"])
            eq(bands, ["high", "low", "mid"], "bin assigns labels by cut order")
            need(_sql_flow(s, "SELECT 1 AS a",
                           {"id": "b", "type": "bin", "config": {}}).get("error"),
                 "bin needs a column")
        finally:
            s.shutdown()

    def t_rank_node():
        s = Session()
        try:
            r = _sql_flow(
                s, "SELECT 'A' AS cat, 10 AS score UNION ALL "
                   "SELECT 'A', 20 UNION ALL SELECT 'B', 5",
                {"id": "k", "type": "rank", "config": {
                    "partition": ["cat"], "order": "score", "dir": "desc",
                    "method": "row_number", "out": "rnk", "top_n": 1}})
            need(not r.get("error"), "rank runs: %s" % r.get("error"))
            eq(len(r["rows"]), 2, "top-1 per partition keeps two rows")
            need(all(row[2] == 1 for row in r["rows"]),
                 "kept rows are rank 1")
            need(_sql_flow(s, "SELECT 1 AS a",
                           {"id": "k", "type": "rank", "config": {}}).get("error"),
                 "rank needs an order field")
        finally:
            s.shutdown()

    def t_fill_node():
        s = Session()
        try:
            r = _sql_flow(
                s, "SELECT 1 AS id, NULL AS v UNION ALL SELECT 2, 5 "
                   "UNION ALL SELECT 3, NULL",
                {"id": "f", "type": "fill", "config": {
                    "fills": [{"col": "v", "method": "avg"}]}})
            need(not r.get("error"), "fill runs: %s" % r.get("error"))
            vals = [row[1] for row in r["rows"]]
            need(all(v is not None for v in vals), "fill removes nulls")
            need(all(float(v) == 5 for v in vals), "nulls become the average (5)")
            r2 = _sql_flow(
                s, "SELECT 1 AS id, NULL AS label UNION ALL SELECT 2, 'x'",
                {"id": "f", "type": "fill", "config": {
                    "fills": [{"col": "label", "method": "value", "value": "NA"}]}})
            got = sorted(row[1] for row in r2["rows"])
            eq(got, ["NA", "x"], "constant fill replaces the null")
        finally:
            s.shutdown()

    def t_dedupe_node():
        s = Session()
        try:
            src = ("SELECT 1 AS id, 10 AS score UNION ALL SELECT 1, 5 "
                   "UNION ALL SELECT 2, 7")
            r = _sql_flow(s, src, {"id": "d", "type": "dedupe", "config": {
                "keys": ["id"], "sort": "score", "keep": "first"}})
            need(not r.get("error"), "dedupe runs: %s" % r.get("error"))
            eq(len(r["rows"]), 2, "one row per key")
            byid = {row[0]: row[1] for row in r["rows"]}
            eq(byid[1], 5, "keep=first takes the lowest score for id 1")
            r2 = _sql_flow(s, src, {"id": "d", "type": "dedupe", "config": {
                "keys": ["id"], "sort": "score", "keep": "last"}})
            byid2 = {row[0]: row[1] for row in r2["rows"]}
            eq(byid2[1], 10, "keep=last takes the highest score for id 1")
            need(_sql_flow(s, "SELECT 1 AS a",
                           {"id": "d", "type": "dedupe", "config": {}}
                           ).get("error"), "dedupe needs keys")
        finally:
            s.shutdown()

    def t_split_node():
        s = Session()
        try:
            r = _sql_flow(
                s, "SELECT 'a-b-c' AS path UNION ALL SELECT 'x-y'",
                {"id": "sp", "type": "split", "config": {
                    "col": "path", "delim": "-",
                    "names": ["p1", "p2", "p3"]}})
            need(not r.get("error"), "split runs: %s" % r.get("error"))
            for c in ("path", "p1", "p2", "p3"):
                need(c in r["columns"], "split keeps/adds column %s" % c)
            rows = {row[0]: row[1:] for row in r["rows"]}
            eq(list(rows["a-b-c"]), ["a", "b", "c"], "full split")
            eq(list(rows["x-y"]), ["x", "y", ""], "missing parts become empty")
            need(_sql_flow(s, "SELECT 'a' AS x",
                           {"id": "sp", "type": "split",
                            "config": {"col": "x", "names": ["a"]}}
                           ).get("error"), "split needs a delimiter")
        finally:
            s.shutdown()

    def t_node_calc_matrix():
        # Build .209 -- a single fixture (numbers AND strings) pushed through
        # each node, asserting EXACT output: the node is doing the right math /
        # transformation, not merely running. Complements the per-node tests
        # above by exercising both a numeric and a string path over one shared
        # dataset. Runs on SQLite (the in-repo engine); the user re-checks the
        # DuckDB path on the real machine.
        from samql_core.session import LOCAL_TARGET
        s = Session()

        def run(nodes, edges, nid, port="out"):
            g = {"nodes": nodes, "edges": [
                {"from": {"node": a, "port": p}, "to": {"node": b, "port": q}}
                for (a, p, b, q) in edges]}
            return s.run_nodeflow(g, nid, port)

        IN = {"id": "i", "type": "input", "config": {"table": "fx"}}
        try:
            s.run_query(
                "CREATE TABLE fx AS "
                "SELECT 'EMEA' AS region,'Widget' AS product,10 AS qty,2.5 AS price "
                "UNION ALL SELECT 'EMEA','Gadget',5,1.0 "
                "UNION ALL SELECT 'APAC','Widget',20,3.0 "
                "UNION ALL SELECT 'APAC','Widget',4,2.0", target=LOCAL_TARGET)
            s.run_query("CREATE TABLE mgr AS SELECT 'EMEA' AS region,"
                        "'Alice' AS manager UNION ALL SELECT 'APAC','Bob'",
                        target=LOCAL_TARGET)
            s.run_query("CREATE TABLE fx2 AS SELECT 'LATAM' AS region,"
                        "'Widget' AS product,7 AS qty,1.5 AS price",
                        target=LOCAL_TARGET)

            # -- summarize: correct math per group, incl. string min/max ----
            g = run([IN, {"id": "g", "type": "summarize", "config": {
                "group_by": ["region"], "aggs": [
                    {"col": "qty", "func": "sum", "name": "sum_qty"},
                    {"col": "price", "func": "avg", "name": "avg_price"},
                    {"col": "qty", "func": "count", "name": "cnt"},
                    {"col": "qty", "func": "min", "name": "min_qty"},
                    {"col": "qty", "func": "max", "name": "max_qty"},
                    {"col": "product", "func": "countd", "name": "nprod"},
                    {"col": "product", "func": "min", "name": "min_prod"},
                    {"col": "product", "func": "max", "name": "max_prod"}]}}],
                [("i", "out", "g", "in")], "g")
            byreg = {r[0]: r for r in g["rows"]}
            c = g["columns"]
            def cell(reg, name): return byreg[reg][c.index(name)]
            eq([cell("EMEA", "sum_qty"), cell("APAC", "sum_qty")], [15, 24],
               "summarize sum(qty) per region")
            eq([cell("EMEA", "avg_price"), cell("APAC", "avg_price")],
               [1.75, 2.5], "summarize avg(price) per region")
            eq([cell("EMEA", "min_qty"), cell("EMEA", "max_qty")], [5, 10],
               "summarize min/max(qty) for EMEA")
            eq([cell("EMEA", "nprod"), cell("APAC", "nprod")], [2, 1],
               "summarize distinct-count(product) per region")
            eq([cell("EMEA", "min_prod"), cell("EMEA", "max_prod")],
               ["Gadget", "Widget"], "summarize string min/max(product)")

            # -- formula: numeric arithmetic AND string concatenation --------
            g = run([IN, {"id": "f", "type": "formula", "config": {"formulas": [
                {"name": "total", "expr": "[qty] * [price]"},
                {"name": "combo", "expr": "[region] || '-' || [product]"}]}}],
                [("i", "out", "f", "in")], "f")
            c = g["columns"]
            tot = {tuple(r[c.index(x)] for x in ("region", "product")):
                   r[c.index("total")] for r in g["rows"]}
            eq(tot[("EMEA", "Widget")], 25.0, "formula qty*price = 25.0")
            eq(tot[("APAC", "Widget")] in (60.0, 8.0), True,
               "formula computed the APAC Widget totals (60 and 8)")
            combos = sorted(r[c.index("combo")] for r in g["rows"])
            eq(combos, ["APAC-Widget", "APAC-Widget", "EMEA-Gadget",
                        "EMEA-Widget"], "formula string concat region-product")

            # -- sort: multi-key, numeric + string ordering ------------------
            g = run([IN, {"id": "so", "type": "sort", "config": {"sorts": [
                {"col": "region", "dir": "asc"},
                {"col": "qty", "dir": "desc"}]}}],
                [("i", "out", "so", "in")], "so")
            c = g["columns"]
            eq([r[c.index("qty")] for r in g["rows"]], [20, 4, 10, 5],
               "sort region asc then qty desc")
            eq([r[c.index("region")] for r in g["rows"]],
               ["APAC", "APAC", "EMEA", "EMEA"], "string sort key applied first")

            # -- unique: distinct on one and on two keys ---------------------
            eq(run([IN, {"id": "u", "type": "unique",
                "config": {"by": ["region"]}}],
                [("i", "out", "u", "in")], "u")["total_rows"], 2,
                "unique by region -> 2 rows")
            eq(run([IN, {"id": "u", "type": "unique",
                "config": {"by": ["region", "product"]}}],
                [("i", "out", "u", "in")], "u")["total_rows"], 3,
                "unique by region+product -> 3 rows")

            # -- filter: numeric predicate and string equality ---------------
            eq(run([IN, {"id": "fl", "type": "filter",
                "config": {"condition": "[qty] >= 10"}}],
                [("i", "out", "fl", "in")], "fl", "true")["total_rows"], 2,
                "filter qty>=10 keeps 2 rows")
            eq(run([IN, {"id": "fl", "type": "filter",
                "config": {"condition": "[region] = 'EMEA'"}}],
                [("i", "out", "fl", "in")], "fl", "true")["total_rows"], 2,
                "filter region='EMEA' keeps 2 rows")

            # -- select: drop columns + rename -------------------------------
            g = run([IN, {"id": "se", "type": "select", "config": {"fields": [
                {"name": "region", "keep": True},
                {"name": "product", "rename": "item", "keep": True},
                {"name": "qty", "keep": False},
                {"name": "price", "keep": False}]}}],
                [("i", "out", "se", "in")], "se")
            eq(g["columns"], ["region", "item"],
               "select keeps region + renamed item, drops qty/price")
            eq(g["total_rows"], 4, "select keeps every row")

            # -- join: inner join brings the manager string across -----------
            g = run([IN, {"id": "R", "type": "input",
                "config": {"table": "mgr"}}, {"id": "j", "type": "join",
                "config": {"keys": [{"left": "region", "right": "region"}],
                           "mode": "inner"}}],
                [("i", "out", "j", "left"), ("R", "out", "j", "right")],
                "j", "out")
            c = g["columns"]
            eq(g["total_rows"], 4, "inner join on region keeps all 4 rows")
            mgrs = {r[c.index("region")]: r[c.index("manager")]
                    for r in g["rows"]}
            eq([mgrs["EMEA"], mgrs["APAC"]], ["Alice", "Bob"],
               "join attached the right manager per region")

            # -- union: stack two same-shape inputs --------------------------
            g = run([IN, {"id": "i2", "type": "input",
                "config": {"table": "fx2"}}, {"id": "u", "type": "union",
                "config": {}}],
                [("i", "out", "u", "in1"), ("i2", "out", "u", "in2")],
                "u", "out")
            eq(g["total_rows"], 5, "union of 4 + 1 rows -> 5")
            need(any("LATAM" in (r or []) for r in g["rows"]),
                 "union includes the second input's row")

            # -- window: running sum + row number, partitioned ---------------
            g = run([IN, {"id": "w", "type": "window", "config": {"windows": [
                {"func": "running_sum", "col": "qty", "name": "rsum",
                 "partition_by": ["region"],
                 "order_by": [{"col": "qty", "dir": "asc"}]},
                {"func": "row_number", "name": "rn",
                 "partition_by": ["region"],
                 "order_by": [{"col": "qty", "dir": "asc"}]}]}}],
                [("i", "out", "w", "in")], "w")
            c = g["columns"]
            rs = {(r[c.index("region")], r[c.index("qty")]):
                  (r[c.index("rsum")], r[c.index("rn")]) for r in g["rows"]}
            eq(rs[("EMEA", 10)], (15, 2),
               "running_sum reaches 15 at EMEA's 2nd row (5 then 10)")
            eq(rs[("APAC", 20)], (24, 2),
               "running_sum reaches 24 at APAC's 2nd row (4 then 20)")

            # -- rank: top-1 per partition -----------------------------------
            g = run([IN, {"id": "k", "type": "rank", "config": {
                "partition": ["region"], "order": "qty", "dir": "desc",
                "method": "row_number", "out": "rnk", "top_n": 1}}],
                [("i", "out", "k", "in")], "k")
            c = g["columns"]
            eq(g["total_rows"], 2, "rank top-1 keeps one row per region")
            eq(sorted(r[c.index("qty")] for r in g["rows"]), [10, 20],
               "the kept rows are each region's max qty")

            # -- bin: bucket a number by ascending cutoffs -------------------
            g = run([IN, {"id": "b", "type": "bin", "config": {
                "col": "qty", "out": "band", "else_label": "high",
                "cuts": [{"le": 5, "label": "low"},
                         {"le": 15, "label": "mid"}]}}],
                [("i", "out", "b", "in")], "b")
            c = g["columns"]
            eq(sorted((r[c.index("qty")], r[c.index("band")])
                      for r in g["rows"]),
               [(4, "low"), (5, "low"), (10, "mid"), (20, "high")],
               "bin labels qty by cutoff (<=5 low, <=15 mid, else high)")
        finally:
            s.shutdown()

    def t_node_calc_matrix2():
        # Build .210 -- exact-output checks for the remaining transform nodes,
        # numbers and strings, in the same style as the calc matrix. (_sql_flow
        # gives a typed literal source -> node -> its "out" port.)
        s = Session()
        try:
            # fill: nulls -> the column average
            r = _sql_flow(s, "SELECT 1 AS id, NULL AS v UNION ALL SELECT 2,5 "
                          "UNION ALL SELECT 3,NULL",
                          {"id": "f", "type": "fill", "config": {
                              "fills": [{"col": "v", "method": "avg"}]}})
            eq(sorted(float(row[1]) for row in r["rows"]), [5.0, 5.0, 5.0],
               "fill replaces nulls with the average (5)")
            # split: delimiter -> columns, missing parts blank
            r = _sql_flow(s, "SELECT 'a-b-c' AS path UNION ALL SELECT 'x-y'",
                          {"id": "sp", "type": "split", "config": {
                              "col": "path", "delim": "-",
                              "names": ["p1", "p2", "p3"]}})
            rows = {row[0]: list(row[1:]) for row in r["rows"]}
            eq(rows["a-b-c"], ["a", "b", "c"], "split fills three parts")
            eq(rows["x-y"], ["x", "y", ""], "split pads the missing part")
            # unpivot: wide -> long (field/value)
            r = _sql_flow(s, "SELECT 1 AS id, 10 AS q1, 20 AS q2, 30 AS q3",
                          {"id": "up", "type": "unpivot", "config": {
                              "keep": ["id"], "unpivot": ["q1", "q2", "q3"]}})
            eq(r["columns"], ["id", "field", "value"],
               "unpivot yields id + field + value")
            eq(sorted((row[1], row[2]) for row in r["rows"]),
               [("q1", 10), ("q2", 20), ("q3", 30)],
               "unpivot makes one row per source column")
            # dedupe: keep first/last by a sort key
            src = ("SELECT 1 AS id, 10 AS score UNION ALL SELECT 1,5 "
                   "UNION ALL SELECT 2,7")
            r = _sql_flow(s, src, {"id": "d", "type": "dedupe", "config": {
                "keys": ["id"], "sort": "score", "keep": "first"}})
            eq({row[0]: row[1] for row in r["rows"]}[1], 5,
               "dedupe keep=first takes id 1's lowest score")
            r = _sql_flow(s, src, {"id": "d", "type": "dedupe", "config": {
                "keys": ["id"], "sort": "score", "keep": "last"}})
            eq({row[0]: row[1] for row in r["rows"]}[1], 10,
               "dedupe keep=last takes id 1's highest score")
            # jsonextract: pull a number + a string out by path
            r = _sql_flow(s, "SELECT '{\"a\":1,\"b\":\"hi\"}' AS j",
                          {"id": "jx", "type": "jsonextract", "config": {
                              "col": "j", "extracts": [
                                  {"path": "a", "name": "aa"},
                                  {"path": "b", "name": "bb"}]}})
            c = r["columns"]
            eq([r["rows"][0][c.index("aa")], r["rows"][0][c.index("bb")]],
               [1, "hi"], "jsonextract reads a number and a string by path")
            # explode: a JSON array -> one row per element
            r = _sql_flow(s, "SELECT 1 AS id, '[10,20,30]' AS arr",
                          {"id": "ex", "type": "explode", "config": {
                              "col": "arr", "mode": "json", "name": "val"}})
            c = r["columns"]
            eq(sorted(int(row[c.index("val")]) for row in r["rows"]),
               [10, 20, 30], "explode (json) makes a row per array element")
            need(all(row[c.index("id")] == 1 for row in r["rows"]),
                 "explode keeps the other columns on each exploded row")
            # explode: a delimited string -> rows
            r = _sql_flow(s, "SELECT 'a,b,c' AS sname",
                          {"id": "ex", "type": "explode", "config": {
                              "col": "sname", "mode": "delim", "delim": ",",
                              "name": "part"}})
            eq(sorted(row[r["columns"].index("part")] for row in r["rows"]),
               ["a", "b", "c"], "explode (delim) splits into three rows")
            # validate: passes the data through unchanged
            r = _sql_flow(s, "SELECT 7 AS a",
                          {"id": "v", "type": "validate", "config": {}})
            eq([list(row) for row in r["rows"]], [[7]],
               "validate passes the row through unchanged")
        finally:
            s.shutdown()

    def t_window_funcs_full():
        # Build .210 -- the window node's fuller function set (the calc matrix
        # already covers running_sum + row_number). A tie makes rank and
        # dense_rank differ; lag/lead/running_avg are checked by value.
        s = Session()
        try:
            src = ("SELECT 'A' AS g,10 AS v UNION ALL SELECT 'A',10 "
                   "UNION ALL SELECT 'A',20 UNION ALL SELECT 'B',5")
            ob = [{"col": "v", "dir": "asc"}]
            r = _sql_flow(s, src, {"id": "w", "type": "window", "config": {
                "windows": [
                    {"func": "rank", "name": "rk",
                     "partition_by": ["g"], "order_by": ob},
                    {"func": "dense_rank", "name": "dr",
                     "partition_by": ["g"], "order_by": ob},
                    {"func": "lag", "col": "v", "name": "lg",
                     "partition_by": ["g"], "order_by": ob},
                    {"func": "lead", "col": "v", "name": "ld",
                     "partition_by": ["g"], "order_by": ob},
                    {"func": "running_avg", "col": "v", "name": "ra",
                     "partition_by": ["g"], "order_by": ob}]}})
            c = r["columns"]
            inA = [row for row in r["rows"] if row[c.index("g")] == "A"]
            eq(sorted(row[c.index("rk")] for row in inA), [1, 1, 3],
               "rank: the two tied rows share 1, the next is 3")
            eq(sorted(row[c.index("dr")] for row in inA), [1, 1, 2],
               "dense_rank: the two tied rows share 1, the next is 2")
            eq(sorted(int(row[c.index("lg")]) for row in inA
                      if row[c.index("lg")] is not None), [10, 10],
               "lag sees the previous value in the partition")
            eq(sorted(int(row[c.index("ld")]) for row in inA
                      if row[c.index("ld")] is not None), [10, 20],
               "lead sees the next value in the partition")
            ramax = max(float(row[c.index("ra")]) for row in inA)
            need(abs(ramax - (40 / 3.0)) < 1e-6,
                 "running_avg reaches (10+10+20)/3 at A's last row")
        finally:
            s.shutdown()

    def t_node_calc_edge_cases():
        # Build .210 -- behaviour at the edges: NULLs in aggregates, an empty
        # (fully-filtered) input, negative numbers, an embedded quote (must be
        # escaped), and unicode.
        from samql_core.session import LOCAL_TARGET
        s = Session()
        try:
            # NULLs: sum/avg/count all skip the NULL
            r = _sql_flow(s, "SELECT 1 AS v UNION ALL SELECT NULL "
                          "UNION ALL SELECT 3",
                          {"id": "g", "type": "summarize", "config": {
                              "group_by": [], "aggs": [
                                  {"col": "v", "func": "sum", "name": "s"},
                                  {"col": "v", "func": "avg", "name": "a"},
                                  {"col": "v", "func": "count", "name": "c"}]}})
            eq(list(r["rows"][0]), [4, 2.0, 2],
               "sum=4, avg=2.0, count=2 -- the NULL is ignored")
            # empty group: a filter that removes every row -> 0 grouped rows
            base = {"id": "b", "type": "createtable", "config": {
                "label": "b", "columns": ["x"], "rows": [["1"]],
                "dest": "sqlite"}}
            src = {"id": "s", "type": "sql", "config": {
                "sql": "SELECT 1 AS region, 5 AS v UNION ALL SELECT 1,9"}}
            fl = {"id": "fl", "type": "filter",
                  "config": {"condition": "[v] > 1000"}}
            gg = {"id": "g", "type": "summarize", "config": {
                "group_by": ["region"],
                "aggs": [{"col": "v", "func": "sum", "name": "s"}]}}
            G = {"nodes": [base, src, fl, gg], "edges": [
                {"from": {"node": "b", "port": "out"},
                 "to": {"node": "s", "port": "in"}},
                {"from": {"node": "s", "port": "out"},
                 "to": {"node": "fl", "port": "in"}},
                {"from": {"node": "fl", "port": "true"},
                 "to": {"node": "g", "port": "in"}}]}
            eq(s.run_nodeflow(G, "g", "out")["total_rows"], 0,
               "grouping a fully-filtered (empty) input yields 0 rows")
            # negatives: bin with negative cutoffs
            r = _sql_flow(s, "SELECT -5 AS n UNION ALL SELECT 0 "
                          "UNION ALL SELECT 5",
                          {"id": "bn", "type": "bin", "config": {
                              "col": "n", "out": "band", "else_label": "high",
                              "cuts": [{"le": -1, "label": "neg"},
                                       {"le": 4, "label": "low"}]}})
            c = r["columns"]
            eq(sorted((row[c.index("n")], row[c.index("band")])
                      for row in r["rows"]),
               [(-5, "neg"), (0, "low"), (5, "high")],
               "bin handles negative cutoffs")
            # embedded quote: {{nm}} = O'Brien must be escaped to match exactly
            var = {"id": "vn", "type": "variable", "config": {
                "vars": [{"name": "nm", "value": "O'Brien"}]}}
            s.run_query("CREATE TABLE ppl AS SELECT 'O''Brien' AS name "
                        "UNION ALL SELECT 'Smith'", target=LOCAL_TARGET)
            inp = {"id": "i", "type": "input", "config": {"table": "ppl"}}
            flt = {"id": "fl", "type": "filter",
                   "config": {"condition": "[name] = {{nm}}"}}
            G = {"nodes": [var, inp, flt], "edges": [
                {"from": {"node": "i", "port": "out"},
                 "to": {"node": "fl", "port": "in"}}]}
            r = s.run_nodeflow(G, "fl", "true")
            eq(r.get("error"), None, "the embedded-quote filter runs")
            eq(r["total_rows"], 1,
               "{{nm}} with O'Brien is escaped and matches the one row")
            # unicode round-trips through a formula string concat
            s.run_query("CREATE TABLE uu AS SELECT 'caf\u00e9' AS a, "
                        "'na\u00efve' AS b", target=LOCAL_TARGET)
            inp2 = {"id": "i", "type": "input", "config": {"table": "uu"}}
            fx = {"id": "fx", "type": "formula", "config": {"formulas": [
                {"name": "c", "expr": "[a] || '-' || [b]"}]}}
            G = {"nodes": [inp2, fx], "edges": [
                {"from": {"node": "i", "port": "out"},
                 "to": {"node": "fx", "port": "in"}}]}
            r = s.run_nodeflow(G, "fx", "out")
            eq(r["rows"][0][r["columns"].index("c")], "caf\u00e9-na\u00efve",
               "unicode survives a formula string concat")
        finally:
            s.shutdown()

    def t_iterator_accumulate():
        # Build .210 -- an iterator accumulates one body result per pass into
        # its table; a raw ${col1} carries a numeric multiplier each pass. (The
        # while controller's own accumulation is covered by t_while_controller.)
        s = Session()
        try:
            data = {"id": "d", "type": "createtable", "config": {
                "label": "d", "columns": ["x"], "rows": [["10"]],
                "dest": "sqlite"}}
            vals = {"id": "v", "type": "createtable", "config": {
                "label": "v", "columns": ["col1"], "rows": [["2"], ["3"]],
                "dest": "sqlite"}}
            it = {"id": "it", "type": "iterator", "config": {
                "table": "acc", "accumulate": "append", "reset_first": False,
                "var_rename": {"col1": "col1"},
                "children": [{"id": "fx", "type": "formula", "config": {
                    "formulas": [{"name": "r",
                                  "expr": "CAST([x] AS INTEGER) * ${col1}"}]}}]}}
            G = {"nodes": [data, vals, it], "edges": [
                {"from": {"node": "v", "port": "out"},
                 "to": {"node": "it", "port": "vars"}},
                {"from": {"node": "d", "port": "out"},
                 "to": {"node": "it", "port": "in"}}]}
            r = s.run_iterator(G, "it")
            eq(r.get("passes"), 2, "the iterator ran once per values row")
            ro = s.run_nodeflow(G, "it", "out")
            eq(sorted(int(row[ro["columns"].index("r")])
                      for row in ro["rows"]),
               [20, 30], "each pass multiplied x=10 by its ${col1} -> 20, 30")
        finally:
            s.shutdown()

    def t_drop_upload_load_modes():
        # Build .211 -- the drop/upload route honours a load "mode" like the
        # load-data screen: materialize copies into a table (and discards the
        # upload), while view registers a read-only query-in-place DuckDB view
        # (keeping the uploaded file alive). Without DuckDB, view falls back to
        # materialize -- still loads, and cleans the upload up (no leak).
        import server
        from server import Api, _SpooledPart

        import tempfile as _tf

        def _spool(name, data):
            f = _tf.NamedTemporaryFile(suffix=os.path.splitext(name)[1]
                                       or ".dat", delete=False)
            f.write(data)
            f.close()
            return f.name
        from samql_core import tmputil
        from samql_core.session import LOCAL_TARGET

        def part(name, body):
            data = body.encode()
            return _SpooledPart("files", name, "text/csv",
                                _spool(name, data), len(data))

        s = Session()
        try:
            # materialize, forced onto SQLite so the row check is engine-stable
            r = Api.load_files(s, "POST", None, {
                "files": [part("ppl.csv", "name,age\nAda,30\nBo,25\n")],
                "fields": {"destination": "sqlite", "mode": "materialize"}})
            tbls = r["loaded"][0].get("tables", [])
            eq([t.get("name") for t in tbls], ["ppl"],
               "materialize upload creates a table")
            eq(s.run_query("SELECT COUNT(*) FROM ppl",
                           target=LOCAL_TARGET)["rows"][0][0], 2,
               "the materialized table holds the uploaded rows")
            # view: a DuckDB query-in-place view if DuckDB is present, else a
            # clean materialized fallback -- either way it loads with no error
            before = tmputil.instance_size_bytes()
            r = Api.load_files(s, "POST", None, {
                "files": [part("pets.csv", "pet,legs\ncat,4\nspider,8\n")],
                "fields": {"destination": "auto", "mode": "view"}})
            ld = r["loaded"][0]
            eq(ld.get("error"), None, "view-mode upload loads with no error")
            t0 = (ld.get("tables") or [{}])[0]
            eq(t0.get("name"), "pets", "view-mode load is named from the file")
            if t0.get("view"):
                eq(t0.get("engine"), "duckdb",
                   "query-in-place is registered as a DuckDB view")
            else:
                # no DuckDB here: a materialized fallback that holds the rows
                # and leaves no uploaded file lingering in the instance dir
                eq(s.run_query("SELECT COUNT(*) FROM pets",
                               target=LOCAL_TARGET)["rows"][0][0], 2,
                   "the materialized fallback holds the rows")
                eq(tmputil.instance_size_bytes() - before, 0,
                   "the materialized fallback leaves no uploaded file behind")
        finally:
            s.shutdown()

    def t_validate_node():
        s = Session()
        try:
            g = {"nodes": [
                {"id": "s", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id, NULL AS v UNION ALL SELECT 2, 5 "
                           "UNION ALL SELECT 2, 9", "label": "s"}},
                {"id": "v", "type": "validate", "config": {}}],
                "edges": [{"from": {"node": "s", "port": "out"},
                           "to": {"node": "v", "port": "in"}}]}
            res = s.validate_nodeflow(g, "v", [
                {"type": "rows_min", "n": 2},
                {"type": "rows_max", "n": 2},
                {"type": "not_null", "col": "v"},
                {"type": "unique", "col": "id"}])
            eq(res.get("total_rows"), 3, "validate counts rows")
            by = {(r["type"], r["target"]): r["pass"] for r in res["results"]}
            eq(by[("rows_min", "2")], True, "rows_min passes (3 >= 2)")
            eq(by[("rows_max", "2")], False, "rows_max fails (3 > 2)")
            eq(by[("not_null", "v")], False, "not_null fails (a null present)")
            eq(by[("unique", "id")], False, "unique fails (id 2 repeats)")
            eq(res.get("ok"), False, "overall fails when any check fails")
            # data still passes through unchanged
            passthru = s.run_nodeflow(g, "v", "out")
            eq(len(passthru["rows"]), 3, "validate passes all rows through")
        finally:
            s.shutdown()

    def t_appendfolder_node():
        # Reads every file in a folder and stacks them aligned by column name.
        import tempfile, os
        s = Session()
        try:
            d = tempfile.mkdtemp()
            open(os.path.join(d, "jan.csv"), "w", newline="").write(
                "id,region,amt\n1,East,100\n2,West,200\n")
            open(os.path.join(d, "feb.csv"), "w", newline="").write(
                "id,amt,note\n3,50,hi\n")
            open(os.path.join(d, "skip.md"), "w").write("ignore me")
            r = s.load_folder_files(d)
            need(r.get("ok"), "folder read ok: %s" % r.get("error"))
            eq(r.get("files"), 2, "only the two readable files are stacked")
            eq(r.get("rows"), 3, "all rows are stacked")
            tbl = r["table"]
            need(tbl.startswith("__"), "the combined table is hidden")
            need(all(t["name"] != tbl for t in s.tables_tree()),
                 "the combined table isn't listed")
            cset = set(r["columns"])
            eq(cset, {"id", "region", "amt", "note"},
               "columns are the union of all files")
            # behaves like an input
            g = {"nodes": [
                {"id": "af", "type": "appendfolder",
                 "config": {"folder": d, "table": tbl, "label": "f"}},
                {"id": "o", "type": "sort",
                 "config": {"sorts": [{"col": "id", "dir": "asc"}]}}],
                "edges": [{"from": {"node": "af", "port": "out"},
                           "to": {"node": "o", "port": "in"}}]}
            res = s.run_nodeflow(g, "o", "out")
            need(not res.get("error"), "folder flow runs: %s" % res.get("error"))
            eq(len(res["rows"]), 3, "the folder node feeds downstream")
            eq(s.load_folder_files(d).get("table"), tbl,
               "an unchanged folder is cached")
            # same size + preserved mtime rewrite of one folder file must miss
            jan = os.path.join(d, "jan.csv")
            st = os.stat(jan)
            open(jan, "w", newline="").write(
                "id,region,amt\n9,North,1\n8,South,2\n")
            os.utime(jan, (st.st_atime, st.st_mtime))
            r2 = s.load_folder_files(d)
            need(r2.get("ok"), "folder rewrite reload ok: %s" % r2.get("error"))
            eng = s.duckdb if r2.get("engine") == "duckdb" else s.db
            need(eng is not None, "engine available after folder reload")
            _c, got = eng.execute(
                'SELECT COUNT(*) FROM "%s" WHERE id = 9' % r2["table"])
            need(got and int(got[0][0]) == 1,
                 "folder cache served rewritten content, not stale: %r"
                 % (got,))
            # Materialize refreshes folder stacks without a manual Read.
            open(jan, "w", newline="").write(
                "id,region,amt\n1,East,100\n2,West,200\n")
            r0 = s.load_folder_files(d)
            need(r0.get("ok"), "seed folder: %s" % r0.get("error"))
            g2 = {"nodes": [
                {"id": "af", "type": "appendfolder",
                 "config": {"folder": d, "table": r0["table"], "label": "f"}},
                {"id": "o", "type": "sort",
                 "config": {"sorts": [{"col": "id", "dir": "asc"}]}}],
                "edges": [{"from": {"node": "af", "port": "out"},
                           "to": {"node": "o", "port": "in"}}]}
            st2 = os.stat(jan)
            open(jan, "w", newline="").write(
                "id,region,amt\n41,East,9\n42,West,8\n")
            os.utime(jan, (st2.st_atime, st2.st_mtime))
            res2 = s.run_nodeflow(g2, "o", "out")
            need(not res2.get("error"),
                 "folder auto-refresh flow: %s" % res2.get("error"))
            ids = [row[res2["columns"].index("id")] for row in res2["rows"]]
            need(41 in ids and 42 in ids,
                 "materialize saw rewritten folder rows: %r" % ids)
            need(g2["nodes"][0]["config"].get("table"),
                 "appendfolder config.table patched after refresh")
            need(s.load_folder_files("/no/such/folder/zz").get("error"),
                 "a missing folder errors")
        finally:
            s.shutdown()

    def t_group_node():
        # a group is a linear pipeline: group input -> child1 -> child2 -> ...
        s = Session()
        try:
            src = ("SELECT 1 AS id, 50 AS score UNION ALL SELECT 2, 5 "
                   "UNION ALL SELECT 3, 80 UNION ALL SELECT 4, 30")
            group = {"id": "g", "type": "group", "config": {
                "label": "prep", "children": [
                    {"id": "c1", "type": "filter",
                     "config": {"condition": "score >= 30"}},
                    {"id": "c2", "type": "bin",
                     "config": {"col": "score", "out": "band",
                                "else_label": "hi",
                                "cuts": [{"le": 40, "label": "lo"}]}},
                    {"id": "c3", "type": "sort",
                     "config": {"sorts": [{"col": "score", "dir": "asc"}]}}]}}
            g = {"nodes": [
                {"id": "s", "type": "sql", "config": {"sql": src, "label": "s"}},
                group],
                "edges": [{"from": {"node": "s", "port": "out"},
                           "to": {"node": "g", "port": "in"}}]}
            r = s.run_nodeflow(g, "g", "out")
            need(not r.get("error"), "group runs: %s" % r.get("error"))
            need("band" in r["columns"], "the bin step's column flows out")
            eq(len(r["rows"]), 3, "the filter step dropped score 5")
            scores = [row[r["columns"].index("score")] for row in r["rows"]]
            eq(scores, sorted(scores), "the sort step ordered the output")

            # the partial-graph trick the UI uses for per-step columns/preview
            import copy
            from samql_core import nodeflow

            def partial(k):
                gg = copy.deepcopy(g)
                for n in gg["nodes"]:
                    if n["id"] == "g":
                        n["config"]["children"] = n["config"]["children"][:k]
                return gg
            sql2 = nodeflow.compile_port(partial(2), "g", "out",
                                         s.relation_columns)
            need("band" in s.relation_columns(sql2),
                 "columns into step 3 include the bin output")
            sql0 = nodeflow.compile_port(partial(0), "g", "out",
                                         s.relation_columns)
            eq(set(s.relation_columns(sql0)), {"id", "score"},
               "columns into step 1 are the group's input")

            # an empty group passes its input straight through
            g2 = copy.deepcopy(g)
            for n in g2["nodes"]:
                if n["id"] == "g":
                    n["config"]["children"] = []
            eq(len(s.run_nodeflow(g2, "g", "out")["rows"]), 4,
               "an empty group is a passthrough")
        finally:
            s.shutdown()

    def t_multijoin_node():
        # inner join across 3 inputs, with a composite key on one of them
        s = Session()
        try:
            def mk(sql, label):
                return {"id": label, "type": "sql",
                        "config": {"sql": sql, "label": label}}
            o = mk("SELECT 1 AS oid, 'E' AS region, 10 AS cust, 'p1' AS prod "
                   "UNION ALL SELECT 2, 'W', 11, 'p9'", "o")
            c = mk("SELECT 'E' AS reg, 10 AS cid, 'Alice' AS cname", "c")
            p = mk("SELECT 'p1' AS pcode, 'Widget' AS pname", "p")
            mj = {"id": "mj", "type": "multijoin", "config": {
                "base": "in1", "joins": [
                    {"input": "in2", "against": "in1",
                     "on": [{"left": "region", "right": "reg"},
                            {"left": "cust", "right": "cid"}]},
                    {"input": "in3", "against": "in1",
                     "on": [{"left": "prod", "right": "pcode"}]}]}}
            g = {"nodes": [o, c, p, mj], "edges": [
                {"from": {"node": "o", "port": "out"},
                 "to": {"node": "mj", "port": "in1"}},
                {"from": {"node": "c", "port": "out"},
                 "to": {"node": "mj", "port": "in2"}},
                {"from": {"node": "p", "port": "out"},
                 "to": {"node": "mj", "port": "in3"}}]}
            r = s.run_nodeflow(g, "mj", "out")
            need(not r.get("error"), "multijoin runs: %s" % r.get("error"))
            eq(len(r["rows"]), 1, "only the fully-matching row survives")
            cols = set(r["columns"])
            need("cname" in cols and "pname" in cols,
                 "columns from every joined input come through")
            need("reg" not in cols and "pcode" not in cols,
                 "duplicate right-side join keys are dropped")

            # chaining: in3 joins to in2 rather than the base
            mj2 = {"id": "mj", "type": "multijoin", "config": {
                "base": "in1", "joins": [
                    {"input": "in2", "against": "in1",
                     "on": [{"left": "region", "right": "reg"},
                            {"left": "cust", "right": "cid"}]},
                    {"input": "in3", "against": "in2",
                     "on": [{"left": "cname", "right": "pname"}]}]}}
            r2 = s.run_nodeflow({"nodes": [o, c, p, mj2], "edges": g["edges"]},
                                "mj", "out")
            need(not r2.get("error"), "chained multijoin runs")
            eq(len(r2["rows"]), 0, "chained join uses the prior input (no match)")

            mjE = {"id": "mj", "type": "multijoin",
                   "config": {"base": "in1", "joins": []}}
            need(s.run_nodeflow(
                {"nodes": [o, c, mjE], "edges": g["edges"][:2]},
                "mj", "out").get("error"),
                "a multijoin with no joins errors")
        finally:
            s.shutdown()

    def t_jsonextract_node():
        # pull nested fields out of a JSON text column into new columns
        s = Session()
        try:
            src = (
                "SELECT 1 AS id, '{\"user\":{\"name\":\"Alice\",\"age\":30},"
                "\"tags\":[\"x\",\"y\"]}' AS payload "
                "UNION ALL SELECT 2, '{\"user\":{\"name\":\"Bob\",\"age\":25},"
                "\"tags\":[\"z\"]}'")
            node = {"id": "jx", "type": "jsonextract", "config": {
                "col": "payload", "extracts": [
                    {"path": "user.name", "name": "name"},
                    {"path": "$.user.age", "name": "age"},
                    {"path": "tags[0]", "name": "first_tag"}]}}
            r = _sql_flow(s, src, node)
            need(not r.get("error"), "jsonextract runs: %s" % r.get("error"))
            for c in ("id", "payload", "name", "age", "first_tag"):
                need(c in r["columns"], "json output has column %s" % c)
            by = {row[r["columns"].index("id")]:
                  (row[r["columns"].index("name")],
                   row[r["columns"].index("age")],
                   row[r["columns"].index("first_tag")]) for row in r["rows"]}
            eq(by[1], ("Alice", 30, "x"), "nested + array paths extract")
            eq(by[2][0], "Bob", "second row extracts too")
            need(_sql_flow(s, src, {"id": "jx", "type": "jsonextract",
                                    "config": {"col": "payload",
                                               "extracts": []}}).get("error"),
                 "jsonextract needs at least one field")
            # the compiler emits engine-specific SQL
            from samql_core import nodeflow
            g = {"nodes": [{"id": "s", "type": "sql",
                            "config": {"sql": src, "label": "s"}}, node],
                 "edges": [{"from": {"node": "s", "port": "out"},
                            "to": {"node": "jx", "port": "in"}}]}
            sd = nodeflow.compile_port(g, "jx", "out", s.relation_columns,
                                       None, "duckdb")
            need("json_extract_string(" in sd,
                 "DuckDB uses json_extract_string")
            ss = nodeflow.compile_port(g, "jx", "out", s.relation_columns,
                                       None, "sqlite")
            need("json_extract(" in ss and "json_extract_string" not in ss,
                 "SQLite uses json_extract")
        finally:
            s.shutdown()

    def t_flow_filter_summarize_sort():
        # filter -> summarize -> sort, the most common analytic pipeline
        s = Session()
        try:
            src = ("SELECT 'A' AS cat, 10 AS score UNION ALL SELECT 'A', 30 "
                   "UNION ALL SELECT 'B', 50 UNION ALL SELECT 'B', 5 "
                   "UNION ALL SELECT 'C', 80")
            r, _ = _chain(s, src, [
                {"id": "f", "type": "filter",
                 "config": {"condition": "score >= 10"}},
                {"id": "g", "type": "summarize", "config": {
                    "group_by": ["cat"],
                    "aggs": [{"col": "score", "func": "avg",
                              "name": "avg_score"}]}},
                {"id": "o", "type": "sort", "config": {
                    "sorts": [{"col": "avg_score", "dir": "desc"}]}}])
            need(not r.get("error"), "pipeline runs: %s" % r.get("error"))
            eq(set(r["columns"]), {"cat", "avg_score"},
               "summarize shapes the columns")
            eq(len(r["rows"]), 3, "one row per category after the filter")
            avgs = [row[r["columns"].index("avg_score")] for row in r["rows"]]
            eq(avgs, sorted(avgs, reverse=True), "sort ordered the aggregate")
            eq(r["rows"][0][r["columns"].index("cat")], "C",
               "C has the highest average")
        finally:
            s.shutdown()

    def t_flow_join_then_transform():
        # a join's inner output feeding a filter then a select
        s = Session()
        try:
            ls = {"id": "l", "type": "sql", "config": {"sql":
                  "SELECT 1 AS oid, 10 AS cust, 100 AS amt "
                  "UNION ALL SELECT 2, 11, 200 UNION ALL SELECT 3, 99, 9",
                  "label": "l"}}
            rs = {"id": "r", "type": "sql", "config": {"sql":
                  "SELECT 10 AS cust, 'E' AS region "
                  "UNION ALL SELECT 11, 'W'", "label": "r"}}
            jn = {"id": "j", "type": "join", "config": {
                "keys": [{"left": "cust", "right": "cust"}]}}
            fl = {"id": "f", "type": "filter",
                  "config": {"condition": "region = 'E'"}}
            sl = {"id": "sel", "type": "select", "config": {
                "fields": [{"name": "oid", "keep": True},
                           {"name": "amt", "keep": True}]}}
            g = {"nodes": [ls, rs, jn, fl, sl], "edges": [
                {"from": {"node": "l", "port": "out"},
                 "to": {"node": "j", "port": "left"}},
                {"from": {"node": "r", "port": "out"},
                 "to": {"node": "j", "port": "right"}},
                {"from": {"node": "j", "port": "inner"},
                 "to": {"node": "f", "port": "in"}},
                {"from": {"node": "f", "port": "true"},
                 "to": {"node": "sel", "port": "in"}}]}
            r = s.run_nodeflow(g, "sel", "out")
            need(not r.get("error"), "join->filter->select runs: %s"
                 % r.get("error"))
            eq(set(r["columns"]), {"oid", "amt"}, "select narrowed the columns")
            eq(len(r["rows"]), 1, "join matched 2, filter kept the East one")
            eq(r["rows"][0][r["columns"].index("oid")], 1, "the right row won")
        finally:
            s.shutdown()

    def t_connected_node_populates_data():
        # The behaviour the UI leans on when you wire nodes together: a
        # downstream node's field pickers populate from the columns of whatever
        # is connected to it, and previewing a connected node returns the
        # upstream data transformed. Guards columns + rows end to end, plus the
        # unconnected state (offers no columns -> the UI shows "connect an
        # input").
        s = Session()
        try:
            src = ("SELECT 'A' AS cat, 10 AS score UNION ALL SELECT 'B', 5 "
                   "UNION ALL SELECT 'C', 50")
            flt = {"id": "f", "type": "filter",
                   "config": {"condition": "score >= 10"}}
            sel = {"id": "sel", "type": "select",
                   "config": {"fields": [{"name": "cat", "keep": True}]}}
            r, g = _chain(s, src, [flt, sel])
            # (1) downstream pickers see the upstream columns once connected:
            #     the filter offers the source's columns, the select offers the
            #     filter's output columns (this is what fills the inspectors).
            fcols = s.nodeflow_columns(g, "s", "out").get("columns") or []
            eq(set(fcols), {"cat", "score"},
               "filter's input picker shows the source columns")
            scols = s.nodeflow_columns(g, "f", "true").get("columns") or []
            eq(set(scols), {"cat", "score"},
               "select's input picker shows the filter's output columns")
            # (2) the data actually flows through the connection
            need(not r.get("error"),
                 "connected pipeline runs: %s" % r.get("error"))
            eq(set(r["columns"]), {"cat"}, "select narrowed to the kept column")
            cats = sorted(row[0] for row in r["rows"])
            eq(cats, ["A", "C"], "filter dropped B (5); A and C flow through")
            # (3) an unconnected node offers no input columns, and must not
            #     crash -- the inspector reads this as "connect an input".
            lone = {"nodes": [{"id": "x", "type": "filter",
                               "config": {"condition": "1=1"}}], "edges": []}
            lc = s.nodeflow_columns(lone, "x", "out")
            need(not lc.get("columns") and lc.get("error"),
                 "an unconnected node returns no columns")
        finally:
            s.shutdown()

    def t_view_source_parity():
        # A "query in place" source is a database VIEW over a file (DuckDB
        # read_parquet / read_csv_auto, no copy). Every layer references a
        # source by name and emits 'SELECT * FROM <name>', so a view behaves
        # like a table throughout. DuckDB isn't in this sandbox, so we prove the
        # engine-agnostic parity with a SQLite view (the SQL each layer emits is
        # identical): an input node reading a view flows through filter+select
        # into the results viewer, the result exports, and reconcile runs on it.
        import tempfile as _tf, os as _os, shutil as _sh
        s = Session()
        try:
            c = s.db.conn
            c.execute("CREATE TABLE base (id INTEGER, cat TEXT, score INTEGER)")
            c.executemany("INSERT INTO base VALUES (?,?,?)",
                          [(1, "A", 10), (2, "B", 5), (3, "C", 50)])
            c.execute("CREATE VIEW vw AS SELECT id, cat, score FROM base")
            c.commit()
            s.db.sync_catalog()  # register base + vw, like a loaded table
            need("vw" in s.db.table_columns,
                 "the view shows up in the table list like a table")
            g = {"nodes": [
                {"id": "src", "type": "input",
                 "config": {"table": "vw", "label": "vw"}},
                {"id": "f", "type": "filter",
                 "config": {"condition": "score >= 10"}},
                {"id": "sel", "type": "select",
                 "config": {"fields": [{"name": "cat", "keep": True}]}}],
                "edges": [
                {"from": {"node": "src", "port": "out"},
                 "to": {"node": "f", "port": "in"}},
                {"from": {"node": "f", "port": "true"},
                 "to": {"node": "sel", "port": "in"}}]}
            # (1) preview / results-viewer path
            r = s.run_nodeflow(g, "sel", "out")
            need(not r.get("error"),
                 "a view-backed pipeline runs: %s" % r.get("error"))
            eq(set(r["columns"]), {"cat"}, "select narrows the view's columns")
            eq(sorted(row[0] for row in r["rows"]), ["A", "C"],
               "rows flow from the view through filter + select")
            # (2) export
            d = _tf.mkdtemp(prefix="t_vw_")
            try:
                ex = s.export_nodeflow(g, "sel", d, "csv", base_name="out")
                need(ex.get("ok"),
                     "a view-backed flow exports: %s" % ex.get("error"))
                eq(ex.get("rows"), 2, "exported the 2 surviving rows")
                need(_os.path.isfile(_os.path.join(d, ex["file"])),
                     "the export file is written")
            finally:
                _sh.rmtree(d, ignore_errors=True)
            # (3) reconcile (the view vs its identical base table -> all match)
            gr = {"nodes": [
                {"id": "L", "type": "input",
                 "config": {"table": "vw", "label": "vw"}},
                {"id": "R", "type": "input",
                 "config": {"table": "base", "label": "base"}},
                {"id": "rec", "type": "reconcile", "config": {}}],
                "edges": [
                {"from": {"node": "L", "port": "out"},
                 "to": {"node": "rec", "port": "left"}},
                {"from": {"node": "R", "port": "out"},
                 "to": {"node": "rec", "port": "right"}}]}
            rr = s.run_nodeflow_reconcile(gr, "rec", keys=["id"],
                                          compare=["score"])
            need(not rr.get("error"),
                 "reconcile runs over a view-backed input: %s" % rr.get("error"))
        finally:
            s.shutdown()

    def t_query_in_place_view_setup():
        # The query-in-place (no-copy) path: load_file mode="view" registers a
        # DuckDB view over the native read_* readers (read_parquet for parquet
        # -- column/row-group pushdown; read_csv_auto for CSV), marked view:True
        # and not counted at load. Materialize (the default) instead copies into
        # a real DuckDB table via CREATE TABLE so repeated node queries are fast.
        ld = open(os.path.join(BACKEND, "samql_core", "loaders.py"),
                  encoding="utf-8").read()
        en = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                  encoding="utf-8").read()
        checks = [
            ("load_file has a view (query-in-place) branch returning view:True",
             'mode == "view"' in ld and '"view": True' in ld),
            ("view mode routes through create_view_from_file",
             "create_view_from_file" in ld),
            ("the view uses native readers (parquet pushdown / csv) via VIEW",
             "read_parquet(" in en and "read_csv_auto(" in en
             and "CREATE VIEW" in en),
            ("materialize copies into a real table for fast repeated queries",
             "CREATE TABLE" in en and "create_table_from_file" in en),
        ]
        missing = [n for n, ok in checks if not ok]
        need(not missing, "query-in-place setup broken: " + "; ".join(missing))

    def t_flow_group_in_pipeline():
        # a group (filter -> bin) used as a building block, then summarized
        s = Session()
        try:
            src = ("SELECT 5 AS score UNION ALL SELECT 25 UNION ALL SELECT 45 "
                   "UNION ALL SELECT 75 UNION ALL SELECT 95")
            grp = {"id": "grp", "type": "group", "config": {"children": [
                {"id": "c1", "type": "filter",
                 "config": {"condition": "score >= 25"}},
                {"id": "c2", "type": "bin", "config": {
                    "col": "score", "out": "band", "else_label": "high",
                    "cuts": [{"le": 50, "label": "low"}]}}]}}
            r, _ = _chain(s, src, [grp, {
                "id": "sm", "type": "summarize", "config": {
                    "group_by": ["band"],
                    "aggs": [{"col": "score", "func": "count",
                              "name": "n"}]}}])
            need(not r.get("error"), "group-in-pipeline runs: %s"
                 % r.get("error"))
            eq(set(r["columns"]), {"band", "n"},
               "the group's output feeds summarize")
            counts = {row[r["columns"].index("band")]:
                      row[r["columns"].index("n")] for row in r["rows"]}
            eq(counts.get("low"), 2, "25 and 45 land in 'low' after the filter")
            eq(counts.get("high"), 2, "75 and 95 land in 'high'")
        finally:
            s.shutdown()

    def t_flow_group_multi_input():
        # a join INSIDE a group, fed by two of the group's own inputs through
        # config["bindings"] -- the case a single linear input cannot express.
        # Also checks the linear default still applies to an unbound port, and
        # that with no bindings the join's second port is left unfed.
        s = Session()
        try:
            left = {"id": "L", "type": "sql", "config": {"sql":
                    "SELECT 1 AS oid, 10 AS cust UNION ALL SELECT 2, 11 "
                    "UNION ALL SELECT 3, 99", "label": "orders"}}
            right = {"id": "R", "type": "sql", "config": {"sql":
                     "SELECT 10 AS cust, 'E' AS region "
                     "UNION ALL SELECT 11, 'W'", "label": "regions"}}
            # the join's two ports are bound to the group's two inputs; the
            # following select is unbound, so it uses the linear default (the
            # join's output feeds it).
            grp = {"id": "G", "type": "group", "config": {
                "children": [
                    {"id": "j", "type": "join", "config": {
                        "keys": [{"left": "cust", "right": "cust"}]}},
                    {"id": "sel", "type": "select", "config": {
                        "fields": [{"name": "oid", "keep": True},
                                   {"name": "region", "keep": True}]}},
                ],
                "bindings": {"j": {"left": "in", "right": "in2"}}}}
            g = {"nodes": [left, right, grp], "edges": [
                {"from": {"node": "L", "port": "out"},
                 "to": {"node": "G", "port": "in"}},
                {"from": {"node": "R", "port": "out"},
                 "to": {"node": "G", "port": "in2"}}]}
            r = s.run_nodeflow(g, "G", "out")
            need(not r.get("error"),
                 "group with a bound join runs: %s" % r.get("error"))
            eq(set(r["columns"]), {"oid", "region"},
               "the in-group select narrowed the joined columns")
            eq(len(r["rows"]), 2, "the join matched 2 of 3 orders (inner)")
            regions = {row[r["columns"].index("oid")]:
                       row[r["columns"].index("region")] for row in r["rows"]}
            eq(regions.get(1), "E", "order 1 -> cust 10 -> East")
            eq(regions.get(2), "W", "order 2 -> cust 11 -> West")

            # the inspector fetches each bound port's columns from the group
            # input it is wired to -- this is what was empty before the fix:
            # left <- group input "in" (orders), right <- "in2" (regions). The
            # same column endpoint the UI calls must return each side's columns.
            cb = s.nodeflow_columns_batch(g, [
                {"node": "L", "port": "out"}, {"node": "R", "port": "out"}])
            res = cb["results"]
            eq(set(res[0].get("columns") or []), {"oid", "cust"},
               "left port resolves to group input 1 (orders) columns")
            eq(set(res[1].get("columns") or []), {"cust", "region"},
               "right port resolves to group input 2 (regions) columns")

            # with no bindings the join's 'right' is unfed -- the linear default
            # only supplies a child's FIRST input port, so a join can't run.
            grp2 = {"id": "G", "type": "group", "config": {
                "children": [{"id": "j", "type": "join", "config": {
                    "keys": [{"left": "cust", "right": "cust"}]}}]}}
            g2 = {"nodes": [left, right, grp2], "edges": [
                {"from": {"node": "L", "port": "out"},
                 "to": {"node": "G", "port": "in"}},
                {"from": {"node": "R", "port": "out"},
                 "to": {"node": "G", "port": "in2"}}]}
            r2 = s.run_nodeflow(g2, "G", "out")
            need(r2.get("error"),
                 "no bindings -> join's right unfed (linear default only)")
        finally:
            s.shutdown()

    def t_flow_jsonextract_downstream():
        # an extracted JSON field is usable by a downstream filter
        s = Session()
        try:
            src = ("SELECT 1 AS id, '{\"kind\":\"a\",\"v\":1}' AS j "
                   "UNION ALL SELECT 2, '{\"kind\":\"b\",\"v\":2}' "
                   "UNION ALL SELECT 3, '{\"kind\":\"a\",\"v\":3}'")
            r, _ = _chain(s, src, [
                {"id": "jx", "type": "jsonextract", "config": {
                    "col": "j", "extracts": [{"path": "kind", "name": "kind"}]}},
                {"id": "f", "type": "filter",
                 "config": {"condition": "kind = 'a'"}}], run_port="true")
            need(not r.get("error"), "json->filter runs: %s" % r.get("error"))
            eq(len(r["rows"]), 2, "filter keeps the two 'a' rows")
            need("kind" in r["columns"], "the extracted column survives")
        finally:
            s.shutdown()

    def t_flow_dedupe_then_validate():
        # dedupe by key, then validate that the key is now unique
        s = Session()
        try:
            src = ("SELECT 1 AS k, 'x' AS v UNION ALL SELECT 1, 'y' "
                   "UNION ALL SELECT 2, 'z'")
            g = {"nodes": [
                {"id": "s", "type": "sql", "config": {"sql": src, "label": "s"}},
                {"id": "d", "type": "dedupe",
                 "config": {"keys": ["k"], "keep": "first"}},
                {"id": "v", "type": "validate", "config": {}}], "edges": [
                {"from": {"node": "s", "port": "out"},
                 "to": {"node": "d", "port": "in"}},
                {"from": {"node": "d", "port": "out"},
                 "to": {"node": "v", "port": "in"}}]}
            res = s.validate_nodeflow(g, "v", [
                {"type": "unique", "col": "k"},
                {"type": "rows_min", "n": 2}])
            eq(res.get("total_rows"), 2, "dedupe collapsed the duplicate key")
            need(res.get("ok"),
                 "unique + rows_min both pass after dedupe upstream")
        finally:
            s.shutdown()

    def t_memory_budget_bytes():
        # the result cache evicts on a byte ceiling, not just a row count, so a
        # few very wide results can't blow up memory while staying under the
        # row cap. low_memory: row budget 50k, byte budget 128 MiB.
        from samql_core.session import _CachedResult, _estimate_row_bytes
        s = _fresh_session(low_memory=True)
        try:
            # one wide value ~ 2000 chars; a list of 40k references to it is
            # cheap to build but estimates to ~160 MiB (> 128 MiB) while only
            # 40k rows (< 50k row budget) -- so it must be evicted by bytes.
            wide = ("x" * 2000,)
            per = _estimate_row_bytes(wide)
            need(per * 40000 > 128 * 1024 * 1024,
                 "test fixture should exceed the byte budget")
            need(40010 < 50000,
                 "test fixture should stay under the row budget")
            old = _CachedResult("r_old", ["c"], [wide] * 40000, 40000,
                                "sql", None, "sqlite")
            new = _CachedResult("r_new", ["c"], [(1,)] * 10, 10,
                                "sql", None, "sqlite")
            s._results = {"r_old": old, "r_new": new}
            s._results_order = ["r_old", "r_new"]
            s._enforce_memory_budget()
            need("r_old" not in s._results,
                 "wide oldest result evicted by the byte budget")
            need("r_new" in s._results,
                 "newest result is never evicted")
        finally:
            s.shutdown()

    def t_explode_nested_recursive():
        # Explode node's third mode: a native DuckDB LIST/STRUCT column or a
        # nested field path, emitted as UNNEST(..., recursive := true). SQLite
        # rejects it with a clear message.
        from samql_core.nodeflow import node_output_sql, NodeflowError
        mk = lambda cfg: {"id": "ex", "type": "explode", "config": cfg}
        gi = lambda p: "SELECT * FROM t"
        cols = lambda rel: ["id", "json"]
        # plain column: quoted, base column dropped from the kept list
        sql = node_output_sql(mk({"col": "json", "mode": "nested"}),
                              "out", gi, cols, engine="duckdb")
        need("UNNEST(json, recursive := true)" in sql.replace('"', ""),
             "plain column unnests recursively: " + sql)
        keep = sql.split("UNNEST(")[0]
        need('"id", ' in keep and '"json"' not in keep,
             "other columns kept, the exploded column dropped: " + sql)
        # nested field path: passed through, its BASE column dropped
        sql = node_output_sql(
            mk({"col": "json[1].receivingLeg", "mode": "nested"}),
            "out", gi, cols, engine="duckdb")
        need("UNNEST(json[1].receivingLeg, recursive := true)" in sql,
             "field path passes through to UNNEST: " + sql)
        keep = sql.split("UNNEST(")[0]
        need('"json"' not in keep,
             "the path's base column is dropped from the output: " + sql)
        need('"id", ' in keep, "unrelated columns still kept: " + sql)
        # SQLite: clear engine error
        try:
            node_output_sql(mk({"col": "json", "mode": "nested"}),
                            "out", gi, cols, engine="sqlite")
            need(False, "nested mode must reject SQLite")
        except NodeflowError as e:
            need("DuckDB" in str(e), "error names the required engine")

    def t_explode_node():
        s = Session()
        try:
            # JSON-array mode, name omitted -> replaces the array column in place
            r = _sql_flow(
                s,
                "SELECT 1 AS id, '[\"a\",\"b\",\"c\"]' AS tags "
                "UNION ALL SELECT 2, '[\"z\"]'",
                {"id": "ex", "type": "explode",
                 "config": {"col": "tags", "mode": "json"}})
            need(not r.get("error"), "explode json runs: %s" % r.get("error"))
            eq(sorted(r["columns"]), ["id", "tags"],
               "explode replaces the array column in place by default")
            ii, it = r["columns"].index("id"), r["columns"].index("tags")
            vals = sorted((row[ii], row[it]) for row in r["rows"])
            eq(vals, [(1, "a"), (1, "b"), (1, "c"), (2, "z")],
               "json array exploded to one row per element")
            # delimited mode into a new column
            r = _sql_flow(
                s, "SELECT 1 AS id, 'x,y' AS csv UNION ALL SELECT 2, 'p,q,r'",
                {"id": "ex", "type": "explode", "config": {
                    "col": "csv", "mode": "delim", "delim": ",",
                    "name": "part"}})
            need(not r.get("error"), "explode delim runs: %s" % r.get("error"))
            need("part" in r["columns"] and "csv" in r["columns"],
                 "delim explode keeps source + adds the named column")
            ii, ip = r["columns"].index("id"), r["columns"].index("part")
            vals = sorted((row[ii], row[ip]) for row in r["rows"])
            eq(vals, [(1, "x"), (1, "y"), (2, "p"), (2, "q"), (2, "r")],
               "delimited text exploded to one row per piece")
            need(_sql_flow(s, "SELECT 'a' AS x", {
                "id": "ex", "type": "explode",
                "config": {"col": "x", "mode": "delim"}}).get("error"),
                 "delim mode needs a delimiter")
            need(_sql_flow(s, "SELECT 'a' AS x", {
                "id": "ex", "type": "explode", "config": {}}).get("error"),
                 "explode needs a column")
        finally:
            s.shutdown()

    def t_textclean_node():
        s = Session()
        try:
            # multiple columns cleaned in place; ops apply in order
            r = _sql_flow(
                s,
                "SELECT 1 AS id, '  Hello WORLD  ' AS msg, '  Hi ' AS note "
                "UNION ALL SELECT 2, 'Foo', 'Bar'",
                {"id": "tc", "type": "textclean", "config": {
                    "cols": ["msg", "note"], "ops": [
                        {"op": "trim"}, {"op": "lower"},
                        {"op": "replace", "find": "o", "replace": "0"}]}})
            need(not r.get("error"), "textclean runs: %s" % r.get("error"))
            im = r["columns"].index("msg")
            inote = r["columns"].index("note")
            by = {row[r["columns"].index("id")]: (row[im], row[inote])
                  for row in r["rows"]}
            eq(by[1][0], "hell0 w0rld", "msg: trim -> lower -> replace")
            eq(by[1][1], "hi", "note cleaned too (multi-column)")
            eq(by[2][0], "f00", "applies to every row")
            # a column not selected is left untouched
            r2 = _sql_flow(s, "SELECT 'Foo' AS a, 'Bar' AS b", {
                "id": "tc", "type": "textclean", "config": {
                    "cols": ["a"],
                    "ops": [{"op": "padleft", "n": 6, "char": "*"}]}})
            eq(r2["rows"][0][r2["columns"].index("a")], "***Foo",
               "pad left to width 6 with * (in place)")
            eq(r2["rows"][0][r2["columns"].index("b")], "Bar",
               "unselected column is unchanged")
            # legacy single-col config still works
            r3 = _sql_flow(s, "SELECT 'Hello' AS msg", {
                "id": "tc", "type": "textclean", "config": {
                    "col": "msg",
                    "ops": [{"op": "substring", "start": 1, "length": 3}]}})
            eq(r3["rows"][0][r3["columns"].index("msg")], "Hel",
               "legacy single col -> substring(1,3)")
            need(_sql_flow(s, "SELECT 'a' AS x", {
                "id": "tc", "type": "textclean",
                "config": {"ops": [{"op": "trim"}]}}).get("error"),
                 "textclean needs at least one column")
            # fill blanks (folded in from the old Fill-nulls node): literal value
            rf = _sql_flow(
                s,
                "SELECT 1 AS id, 'x' AS name, 10.0 AS amt "
                "UNION ALL SELECT 2, NULL, NULL "
                "UNION ALL SELECT 3, 'z', 30.0",
                {"id": "tc", "type": "textclean", "config": {
                    "cols": ["name"],
                    "ops": [{"op": "fillnull", "method": "value",
                             "value": "Unknown"}]}})
            need(not rf.get("error"), "textclean fillnull runs: %s" % rf.get("error"))
            byf = {row[rf["columns"].index("id")]: row[rf["columns"].index("name")]
                   for row in rf["rows"]}
            eq(byf[2], "Unknown", "fillnull value fills NULL")
            eq(byf[1], "x", "fillnull leaves non-null alone")
            # fill blanks with a column statistic (average over the column)
            ra = _sql_flow(
                s,
                "SELECT 1 AS id, 10.0 AS amt UNION ALL SELECT 2, NULL "
                "UNION ALL SELECT 3, 30.0",
                {"id": "tc", "type": "textclean", "config": {
                    "cols": ["amt"],
                    "ops": [{"op": "fillnull", "method": "avg"}]}})
            need(not ra.get("error"), "textclean fillnull avg runs: %s" % ra.get("error"))
            bya = {row[ra["columns"].index("id")]: row[ra["columns"].index("amt")]
                   for row in ra["rows"]}
            eq(bya[2], 20.0, "fillnull avg fills NULL with the column average")
        finally:
            s.shutdown()

    def t_select_cast():
        s = Session()
        try:
            # cast text -> integer, float -> integer (truncates), rename
            r = _sql_flow(s, "SELECT '42' AS n, 3.9 AS score", {
                "id": "se", "type": "select", "config": {"fields": [
                    {"name": "n", "keep": True, "type": "integer"},
                    {"name": "score", "keep": True, "type": "integer",
                     "rename": "pts"}]}})
            need(not r.get("error"), "select cast runs: %s" % r.get("error"))
            eq(r["columns"], ["n", "pts"], "rename applied to a cast field")
            eq(r["rows"][0][0], 42, "text '42' cast to integer is numeric 42")
            eq(r["rows"][0][1], 3, "3.9 cast to integer truncates to 3")
            # an unticked field is dropped
            r2 = _sql_flow(s, "SELECT 1 AS a, 2 AS b", {
                "id": "se", "type": "select", "config": {"fields": [
                    {"name": "a", "keep": True},
                    {"name": "b", "keep": False}]}})
            eq(r2["columns"], ["a"], "select-none on a field drops it")
            # the ORDER of fields[] is the output column order, so a drag-reorder
            # in the inspector flows straight through (c, a->id, b)
            r3 = _sql_flow(s, "SELECT 1 AS a, 'x' AS b, 9 AS c", {
                "id": "se", "type": "select", "config": {"fields": [
                    {"name": "c", "keep": True},
                    {"name": "a", "keep": True, "rename": "id"},
                    {"name": "b", "keep": True}]}})
            eq(r3["columns"], ["c", "id", "b"],
               "output columns follow the (reordered) fields array")
            # and a downstream node consumes that new order on the next run
            g = {"nodes": [
                {"id": "src", "type": "sql",
                 "config": {"sql": "SELECT 1 AS a, 'x' AS b, 9 AS c"}},
                {"id": "se", "type": "select", "config": {"fields": [
                    {"name": "c", "keep": True},
                    {"name": "a", "keep": True},
                    {"name": "b", "keep": True}]}},
                {"id": "down", "type": "sql",
                 "config": {"sql": "SELECT * FROM input"}}],
                "edges": [
                    {"from": {"node": "src", "port": "out"},
                     "to": {"node": "se", "port": "in"}},
                    {"from": {"node": "se", "port": "out"},
                     "to": {"node": "down", "port": "in"}}]}
            rd = s.run_nodeflow(g, "down", "out")
            eq(rd["columns"], ["c", "a", "b"],
               "a later node sees the reordered columns")
        finally:
            s.shutdown()

    def t_columns_batch():
        # one round-trip returns columns for several (node, port) pairs, and a
        # bad request yields a per-item error rather than failing the batch.
        s = Session()
        try:
            g = {"nodes": [
                {"id": "a", "type": "sql",
                 "config": {"sql": "SELECT 1 AS x, 2 AS y", "label": "a"}},
                {"id": "b", "type": "sql",
                 "config": {"sql": "SELECT 3 AS p, 4 AS q", "label": "b"}}],
                "edges": []}
            res = s.nodeflow_columns_batch(
                g, [{"node": "a", "port": "out"}, {"node": "b", "port": "out"}])
            rs = res["results"]
            eq(len(rs), 2, "batch returns one entry per request, in order")
            byid = {(r["node"], r["port"]): r for r in rs}
            eq(byid[("a", "out")]["columns"], ["x", "y"], "columns for node a")
            eq(byid[("b", "out")]["columns"], ["p", "q"], "columns for node b")
            res2 = s.nodeflow_columns_batch(
                g, [{"node": "a", "port": "out"},
                    {"node": "nope", "port": "out"}])
            m = {(r["node"], r["port"]): r for r in res2["results"]}
            need("columns" in m[("a", "out")],
                 "a good request still resolves alongside a bad one")
            need(m[("nope", "out")].get("error"),
                 "an unknown node yields a per-item error, not a batch failure")
        finally:
            s.shutdown()

    def t_connected_columns_batch():
        # The inspector's real populate-on-connect path: when a node is
        # selected it asks columns-batch for the columns at its wired ports so
        # the field pickers fill in. This covers the cases the simple batch
        # test doesn't -- a multi-input node (join) merging BOTH connected
        # inputs, a schema-adding node (formula) exposing its new column to a
        # downstream picker, and the missing-input state.
        s = Session()
        try:
            L = {"id": "L", "type": "sql",
                 "config": {"sql": "SELECT 1 AS k, 'a' AS name", "label": "L"}}
            R = {"id": "R", "type": "sql",
                 "config": {"sql": "SELECT 1 AS k, 'x' AS city", "label": "R"}}
            J = {"id": "J", "type": "join",
                 "config": {"keys": [{"left": "k", "right": "k"}]}}
            F = {"id": "F", "type": "formula", "config": {"formulas": [
                {"name": "label", "expr": "UPPER(name)"}]}}
            g = {"nodes": [L, R, J, F], "edges": [
                {"from": {"node": "L", "port": "out"},
                 "to": {"node": "J", "port": "left"}},
                {"from": {"node": "R", "port": "out"},
                 "to": {"node": "J", "port": "right"}},
                {"from": {"node": "J", "port": "inner"},
                 "to": {"node": "F", "port": "in"}}]}
            res = s.nodeflow_columns_batch(g, [
                {"node": "J", "port": "inner"},
                {"node": "F", "port": "out"}])
            by = {(r["node"], r["port"]): r for r in res["results"]}
            jcols = by[("J", "inner")].get("columns") or []
            need("name" in jcols and "city" in jcols,
                 "a connected join merges columns from both inputs: %s" % jcols)
            fcols = by[("F", "out")].get("columns") or []
            need("label" in fcols,
                 "a downstream picker sees the formula's new column: %s" % fcols)
            # a required input missing -> the picker can't populate (the UI
            # reads this as "connect both inputs"); reported per-item, no crash.
            g2 = {"nodes": [L, J], "edges": [
                {"from": {"node": "L", "port": "out"},
                 "to": {"node": "J", "port": "left"}}]}
            miss = s.nodeflow_columns_batch(g2, [{"node": "J", "port": "inner"}])
            mr = miss["results"][0]
            need(not mr.get("columns") and mr.get("error"),
                 "a join missing its right input yields a per-item error")
        finally:
            s.shutdown()

    def t_antijoin_node():
        s = Session()
        try:
            g = {"nodes": [
                {"id": "L", "type": "sql", "config": {
                    "sql": "SELECT 1 AS id UNION ALL SELECT 2 UNION ALL SELECT 3",
                    "label": "L"}},
                {"id": "R", "type": "sql", "config": {
                    "sql": "SELECT 1 AS rid UNION ALL SELECT 3", "label": "R"}},
                {"id": "aj", "type": "antijoin", "config": {
                    "mode": "anti",
                    "keys": [{"left": "id", "right": "rid"}]}}],
                "edges": [
                    {"from": {"node": "L", "port": "out"},
                     "to": {"node": "aj", "port": "left"}},
                    {"from": {"node": "R", "port": "out"},
                     "to": {"node": "aj", "port": "right"}}]}
            r = s.run_nodeflow(g, "aj", "out")
            need(not r.get("error"), "antijoin runs: %s" % r.get("error"))
            eq(sorted(row[0] for row in r["rows"]), [2],
               "anti = left rows with no match in right")
            eq(r["columns"], ["id"], "anti keeps only the left columns")
            g["nodes"][2]["config"]["mode"] = "semi"
            r = s.run_nodeflow(g, "aj", "out")
            eq(sorted(row[0] for row in r["rows"]), [1, 3],
               "semi = left rows that have a match (no duplication)")
            g["nodes"][2]["config"] = {"mode": "anti", "keys": []}
            need(s.run_nodeflow(g, "aj", "out").get("error"),
                 "antijoin needs a key pair")
        finally:
            s.shutdown()

    def t_groupconcat_node():
        s = Session()
        try:
            r = _sql_flow(
                s,
                "SELECT 'a' AS g, 1 AS v UNION ALL SELECT 'a', 2 "
                "UNION ALL SELECT 'b', 3",
                {"id": "gc", "type": "groupconcat", "config": {
                    "group": ["g"], "col": "v", "name": "ids", "delim": "|"}})
            need(not r.get("error"), "groupconcat runs: %s" % r.get("error"))
            by = {row[r["columns"].index("g")]: row[r["columns"].index("ids")]
                  for row in r["rows"]}
            eq(sorted(by["a"].split("|")), ["1", "2"],
               "values concatenated per group with the chosen delimiter")
            eq(by["b"], "3", "single-row group")
            r2 = _sql_flow(
                s, "SELECT 1 AS v UNION ALL SELECT 2 UNION ALL SELECT 2",
                {"id": "gc", "type": "groupconcat", "config": {
                    "col": "v", "name": "all", "delim": ","}})
            eq(len(r2["rows"]), 1, "no group => one aggregated row")
            eq(sorted(r2["rows"][0][r2["columns"].index("all")].split(",")),
               ["1", "2", "2"], "every value concatenated")
            r3 = _sql_flow(
                s, "SELECT 2 AS v UNION ALL SELECT 2 UNION ALL SELECT 1",
                {"id": "gc", "type": "groupconcat", "config": {
                    "col": "v", "name": "d", "distinct": True}})
            got = r3["rows"][0][r3["columns"].index("d")]
            eq(sorted(got.split(",")), ["1", "2"], "distinct removes duplicates")
            need(_sql_flow(s, "SELECT 1 AS v", {
                "id": "gc", "type": "groupconcat",
                "config": {}}).get("error"), "groupconcat needs a column")
        finally:
            s.shutdown()

    def t_date_node():
        s = Session()
        try:
            src = ("SELECT 1 AS id, '2024-03-15 09:30:00' AS dt "
                   "UNION ALL SELECT 2, '2023-12-25 00:00:00'")
            r = _sql_flow(s, src, {"id": "d", "type": "date", "config": {
                "col": "dt", "op": "part", "part": "year", "name": "y"}})
            need(not r.get("error"), "date part runs: %s" % r.get("error"))
            by = {row[r["columns"].index("id")]: row[r["columns"].index("y")]
                  for row in r["rows"]}
            eq(by[1], 2024, "year extracted")
            eq(by[2], 2023, "year extracted (row 2)")
            r = _sql_flow(s, src, {"id": "d", "type": "date", "config": {
                "col": "dt", "op": "part", "part": "quarter", "name": "q"}})
            by = {row[r["columns"].index("id")]: row[r["columns"].index("q")]
                  for row in r["rows"]}
            eq(by[1], 1, "Q1 for March")
            eq(by[2], 4, "Q4 for December")
            r = _sql_flow(s, src, {"id": "d", "type": "date", "config": {
                "col": "dt", "op": "trunc", "unit": "month", "name": "m"}})
            by = {row[r["columns"].index("id")]: row[r["columns"].index("m")]
                  for row in r["rows"]}
            eq(by[1], "2024-03-01", "truncated to start of month")
            r = _sql_flow(
                s, "SELECT '2024-01-11' AS a, '2024-01-01' AS b",
                {"id": "d", "type": "date", "config": {
                    "col": "a", "op": "diff", "unit": "day",
                    "other": "b", "name": "gap"}})
            eq(r["rows"][0][r["columns"].index("gap")], 10,
               "10-day difference between two columns")
            need(_sql_flow(s, "SELECT 1 AS x", {
                "id": "d", "type": "date", "config": {}}).get("error"),
                 "date node needs a column")
        finally:
            s.shutdown()

