    def t_db_read_method_sqlite():
        # SQLite read() returns the same as execute() (the locked path -- a
        # single connection can't read concurrently with a write).
        import tempfile
        import os as _os
        s = Session()
        try:
            p = tempfile.mktemp(suffix=".csv")
            open(p, "w").write("a,b\n1,x\n2,y\n3,z\n")
            s.load_file(p, destination="sqlite")
            name = s.tables_tree()[0]["name"]
            sql = 'SELECT COUNT(*) FROM "%s"' % name
            eq(s.db.read(sql)[1][0][0], s.db.execute(sql)[1][0][0],
               "DBManager.read matches execute")
            eq(Session._safe_count(s.db, name), 3, "_safe_count via read")
            try:
                _os.remove(p)
            except Exception:
                pass
        finally:
            s.shutdown()

    def t_safe_count_routing_and_fallback():
        # _safe_count prefers engine.read() and falls back to execute().
        class Reader:
            def __init__(self):
                self.r = 0
                self.e = 0

            def read(self, sql):
                self.r += 1
                return ["c"], [(5,)]

            def execute(self, sql):
                self.e += 1
                return ["c"], [(9,)]
        a = Reader()
        eq(Session._safe_count(a, "t"), 5, "uses read() when present")
        eq((a.r, a.e), (1, 0), "execute untouched when read works")

        class FailRead(Reader):
            def read(self, sql):
                raise RuntimeError("temp not visible on a fresh cursor")
        b = FailRead()
        eq(Session._safe_count(b, "t"), 9, "falls back to execute on read error")
        eq(b.e, 1, "fallback used the serialized execute()")

        class NoRead:
            def __init__(self):
                self.e = 0

            def execute(self, sql):
                self.e += 1
                return ["c"], [(7,)]
        c = NoRead()
        eq(Session._safe_count(c, "t"), 7, "engine without read() uses execute")

        class Broken:
            def read(self, sql):
                raise RuntimeError("x")

            def execute(self, sql):
                raise RuntimeError("y")
        eq(Session._safe_count(Broken(), "t"), None,
           "both paths failing -> None, no crash")

    def t_duck_read_dispatch_unbound():
        # Exercise the REAL DuckDBManager.read() dispatch + fallback without a
        # live DuckDB connection, by binding the method to a stub self.
        from samql_core.engines import DuckDBManager

        class Stub:
            def __init__(self, on):
                self.concurrent_reads = on
                self.calls = []

            def execute_read(self, sql):
                self.calls.append("read")
                return ["c"], [(1,)]

            def execute(self, sql):
                self.calls.append("exec")
                return ["c"], [(2,)]
        on = Stub(True)
        eq(DuckDBManager.read(on, "SELECT 1")[1], [(1,)],
           "flag on -> concurrent cursor (execute_read)")
        eq(on.calls, ["read"], "flag on did not take the locked path")
        off = Stub(False)
        eq(DuckDBManager.read(off, "SELECT 1")[1], [(2,)],
           "flag off -> serialized execute")
        eq(off.calls, ["exec"], "flag off did not open a concurrent cursor")

        class FailReader(Stub):
            def execute_read(self, sql):
                self.calls.append("read")
                raise RuntimeError("temp")
        fr = FailReader(True)
        eq(DuckDBManager.read(fr, "SELECT 1")[1], [(2,)],
           "a failed concurrent read falls back to execute")
        eq(fr.calls, ["read", "exec"], "tried concurrent, then fell back")

    def t_duck_column_types_concurrent_unbound():
        # The concurrent branch of column_types (now in the raw helper) maps
        # DESCRIBE rows from a separate cursor; verify via the REAL method.
        from samql_core.engines import DuckDBManager

        class Stub:
            concurrent_reads = True

            def execute_read(self, sql):
                need('DESCRIBE "t"' in sql, "describes the requested table")
                return (["column_name", "column_type"],
                        [("id", "BIGINT"), ("name", "VARCHAR")])
        st = Stub()
        st._column_types_raw = DuckDBManager._column_types_raw.__get__(
            st, DuckDBManager)
        eq(DuckDBManager.column_types(st, "t"),
           {"id": "BIGINT", "name": "VARCHAR"},
           "column_types maps DESCRIBE rows on the concurrent path")

        class FailStub:
            concurrent_reads = True

            def execute_read(self, sql):
                raise RuntimeError("temp")
        fs = FailStub()
        fs._column_types_raw = DuckDBManager._column_types_raw.__get__(
            fs, DuckDBManager)
        eq(DuckDBManager.column_types(fs, "t"), {},
           "degrades to {} when the schema can't be read (no real conn)")

    def t_duck_sync_catalog_concurrent_unbound():
        # The concurrent reconcile reads information_schema (+ columns) and
        # selective DESCRIBE on separate cursors, then updates under
        # _catalog_lock. Verify the REAL method: live tables added, vanished
        # ones dropped; unchanged tables with warm types skip DESCRIBE.
        import threading as _th
        from samql_core.engines import DuckDBManager

        class Stub:
            concurrent_reads = True

            def __init__(self):
                self.table_columns = {"gone": ["x"], "keep": ["old"]}
                self.table_sources = {"gone": "", "keep": ""}
                self.table_origins = {"gone": "/tmp/gone.json",
                                      "keep": "/tmp/keep.json"}
                self._catalog_lock = _th.Lock()
                self._types_cache = {}
                self.describe_calls = []

            def _types_cache_drop(self, name=None):
                if name is None:
                    self._types_cache.clear()
                else:
                    self._types_cache.pop(name, None)

            def execute_read(self, sql):
                if "information_schema.tables" in sql:
                    return ["table_name"], [("keep",), ("new",)]
                if "information_schema.columns" in sql:
                    return ["table_name", "column_name"], [
                        ("keep", "k1"),
                        ("new", "n1"),
                        ("new", "n2"),
                    ]
                need("DESCRIBE" in sql, "unexpected catalog SQL: %r" % sql)
                tbl = sql.split('"')[1]
                self.describe_calls.append(tbl)
                cols = {"keep": [("k1", "BIGINT")],
                        "new": [("n1", "VARCHAR"), ("n2", "BIGINT")]}[tbl]
                return ["column_name", "column_type"], cols
        st = Stub()
        DuckDBManager.sync_catalog(st)
        eq(sorted(st.table_columns), ["keep", "new"],
           "reconciles to the live set (vanished table dropped)")
        eq(st.table_columns["new"], ["n1", "n2"],
           "new table columns come from DESCRIBE")
        eq(st.table_columns["keep"], ["k1"], "existing columns refreshed")
        need("gone" not in st.table_columns
             and "gone" not in st.table_sources
             and "gone" not in st.table_origins,
             "a table no longer present is removed from columns/sources/origins")
        need("new" in st.table_sources, "the new table gets a source entry")
        need("keep" in st.table_origins,
             "surviving tables keep their origin path")
        eq(sorted(st.describe_calls), ["keep", "new"],
           "first sync DESCRIBEs tables whose shape is new/changed")
        eq(st._types_cache.get("keep"), {"k1": "BIGINT"},
           "sync seeds types cache from DESCRIBE")
        # Second sync: shapes unchanged + warm types -> no DESCRIBE.
        st.describe_calls.clear()
        DuckDBManager.sync_catalog(st)
        eq(st.describe_calls, [],
           "unchanged catalog skips DESCRIBE on refresh")

    def t_concurrent_reads_source_guards():
        # Structural guarantees on the concurrent-read implementation.
        import inspect
        from samql_core.engines import DuckDBManager
        er = inspect.getsource(DuckDBManager.execute_read)
        need(".cursor()" in er, "execute_read uses a separate cursor")
        need("with self.write_lock" not in er,
             "execute_read does NOT acquire write_lock (so it runs "
             "concurrently with a build on the main connection)")
        rd = inspect.getsource(DuckDBManager.read)
        need("concurrent_reads" in rd and "execute_read" in rd
             and "self.execute(" in rd,
             "read() dispatches on the flag and falls back to execute()")
        sc = inspect.getsource(DuckDBManager.sync_catalog)
        # .464 repoint: the flag-off branch was rewritten to the same
        # non-blocking rule as the sqlite twin -- probe the lock, serve
        # the cached catalog when busy, release in finally. Pin THAT.
        need("self.write_lock.acquire(blocking=False)" in sc
             and "self.write_lock.release()" in sc,
             "sync_catalog's flag-off path probes without parking and "
             "releases in finally")
        # Incremental sync (656+): concurrent work lives in _duck_sync_catalog
        # (use_read=True → execute_read), then reconciles under _catalog_lock.
        need("_duck_sync_catalog" in sc and "use_read=True" in sc,
             "sync_catalog concurrent path delegates to _duck_sync_catalog")
        dsc = inspect.getsource(DuckDBManager._duck_sync_catalog)
        need("_catalog_lock" in dsc and "use_read" in dsc,
             "incremental duck sync reconciles under the catalog lock")
        fetch = inspect.getsource(DuckDBManager._duck_fetch_catalog_lists)
        need("execute_read" in fetch,
             "catalog list fetch uses execute_read on the concurrent path")
        ct = inspect.getsource(DuckDBManager._column_types_raw)
        need('hasattr(self, "execute_read")' in ct and "execute_read(" in ct,
             "schema reads try a separate cursor UNCONDITIONALLY (never queue "
             "behind a build), falling back to the locked connection")
        ini = inspect.getsource(DuckDBManager.__init__)
        need("_catalog_lock" in ini and "concurrent_reads" in ini,
             "the manager initializes the catalog lock and the flag")

    def t_tables_tree_correct_with_flag_sqlite():
        # End to end: toggling the flag never changes correctness on SQLite
        # (single connection -> read() is the locked execute()).
        import tempfile
        import os as _os
        s = Session()
        try:
            p = tempfile.mktemp(suffix=".csv")
            open(p, "w").write("id,name\n1,a\n2,b\n3,c\n4,d\n")
            s.load_file(p, destination="sqlite")
            name = s.tables_tree()[0]["name"]
            for flag in (False, True, False):
                s.set_concurrent_reads(flag)
                row = [t for t in s.tables_tree() if t["name"] == name][0]
                eq(row["row_count"], 4, "row count correct (flag=%s)" % flag)
                eq([c["name"] for c in row["columns"]], ["id", "name"],
                   "columns correct (flag=%s)" % flag)
            try:
                _os.remove(p)
            except Exception:
                pass
        finally:
            s.shutdown()

    def t_concurrent_reads_real_duckdb():
        # When DuckDB is present, verify the concurrent read path is
        # functionally correct end to end (count + schema + tables_tree match
        # the serialized path). Dormant in the sandbox (no DuckDB), where the
        # concurrency is reasoned about and validated on the real build.
        from samql_core.engines import HAS_DUCKDB
        if not HAS_DUCKDB:
            return
        import tempfile
        import os as _os
        s = Session()
        try:
            p = tempfile.mktemp(suffix=".csv")
            open(p, "w").write("id,name\n1,a\n2,b\n3,c\n")
            s.load_file(p, destination="duckdb")
            duck = s.get_duckdb()
            name = [n for n in duck.table_columns
                    if not n.startswith("__")][0]
            sql = 'SELECT COUNT(*) FROM "%s"' % name
            base = duck.execute(sql)[1][0][0]
            duck.concurrent_reads = True
            eq(duck.read(sql)[1][0][0], base, "concurrent count matches")
            eq(duck.execute_read(sql)[1][0][0], base,
               "execute_read returns the same count")
            need(set(duck.column_types(name))
                 == set(duck.table_columns[name]),
                 "concurrent column_types matches the columns")
            s.set_concurrent_reads(True)
            row = [t for t in s.tables_tree()
                   if t["name"] == name and t["engine"] == "duckdb"][0]
            eq(row["row_count"], base,
               "tables_tree count matches under the flag")
            try:
                _os.remove(p)
            except Exception:
                pass
        finally:
            s.shutdown()

    def t_concurrent_reads_nonblocking_under_lock():
        # THE async property: with the flag ON a read returns while a build
        # holds write_lock; with it OFF the same read serializes behind the
        # lock. This is decided by the lock, not the engine, so it runs without
        # DuckDB -- it drives the REAL DuckDBManager.read() dispatch against a
        # stub that models the two paths faithfully (execute_read is lock-free,
        # like the real one per the structure guard; execute takes write_lock,
        # like the real one). A generous lock timeout keeps it from raising
        # EngineBusy during the short hold.
        import threading as _th
        from samql_core.engines import DuckDBManager, _DeadlineRLock

        class LockStub:
            def __init__(self, concurrent):
                self.concurrent_reads = concurrent
                self.write_lock = _DeadlineRLock(timeout=30.0)

            def execute_read(self, sql):       # concurrent path: never locks
                return ["c"], [(1,)]

            def execute(self, sql):            # serialized path: takes the lock
                with self.write_lock:
                    return ["c"], [(2,)]

        # ---- flag ON: read comes back while the lock is held ----
        on = LockStub(True)
        on.write_lock.acquire()                 # simulate a build holding it
        try:
            done, box = _th.Event(), {}

            def do_on():
                box["res"] = DuckDBManager.read(on, "SELECT 1")
                done.set()
            t = _th.Thread(target=do_on, daemon=True)
            t.start()
            need(done.wait(3.0),
                 "flag ON: a read must return while a build holds write_lock "
                 "(it never queues behind the lock)")
            eq(box["res"][1], [(1,)], "flag ON used the concurrent cursor")
            t.join(1.0)
        finally:
            on.write_lock.release()

        # ---- flag OFF: the same read blocks until the lock is released ----
        off = LockStub(False)
        off.write_lock.acquire()
        done, box = _th.Event(), {}

        def do_off():
            box["res"] = DuckDBManager.read(off, "SELECT 1")
            done.set()
        t = _th.Thread(target=do_off, daemon=True)
        t.start()
        try:
            need(not done.wait(0.5),
                 "flag OFF: a read must block while write_lock is held "
                 "(it serializes behind the build)")
        finally:
            off.write_lock.release()
        need(done.wait(3.0),
             "flag OFF: the read completes once the lock is released")
        eq(box["res"][1], [(2,)], "flag OFF used the serialized execute path")
        t.join(1.0)

