    def t_duck_sync_catalog_incremental_source():
        # Post-655 audit #4: sync_catalog must not DESCRIBE-all every refresh.
        eng = open(os.path.join(BACKEND, "samql_core", "engines.py"),
                   encoding="utf-8").read()
        need("def _duck_sync_catalog" in eng,
             "incremental duck catalog helper exists")
        # Helpers were split (fetch/describe/sync); assert across that block.
        i = eng.index("def _duck_fetch_catalog_lists")
        j = eng.find("\nclass ", i)
        if j < 0:
            j = len(eng)
        body = eng[i:j]
        need("information_schema.columns" in body,
             "lists columns before selective DESCRIBE")
        need("need_describe" in body, "skips DESCRIBE for unchanged tables")
        need("cache[name]" in body, "seeds types cache from DESCRIBE")
        # Live: second sync + tables_tree pay zero DESCRIBEs when unchanged.
        from samql_core.engines import HAS_DUCKDB
        if not HAS_DUCKDB:
            skip("duckdb is not installed")
        s = _fresh_session()
        try:
            duck = s.get_duckdb()
            duck.conn.execute(
                "CREATE OR REPLACE TABLE inc_a AS SELECT 1 AS x, 2 AS y")
            duck.conn.execute(
                "CREATE OR REPLACE TABLE inc_b AS SELECT 1 AS z")
            duck.sync_catalog()
            n = {"d": 0}
            orig = duck.execute_read

            def wrap(sql):
                if isinstance(sql, str) and sql.strip().upper().startswith(
                        "DESCRIBE"):
                    n["d"] += 1
                return orig(sql)

            duck.execute_read = wrap
            n["d"] = 0
            duck.sync_catalog()
            eq(n["d"], 0, "unchanged sync skips DESCRIBE")
            n["d"] = 0
            # Dirty-skip (659+): force a reconcile so tables_tree is exercised
            # without implying every poll DESCRIBEs.
            s._mark_catalog_dirty()
            names = [t["name"] for t in s.tables_tree()]
            need("inc_a" in names and "inc_b" in names, "tables visible")
            eq(n["d"], 0, "tables_tree does not re-DESCRIBE warm types")
            duck.conn.execute(
                "CREATE OR REPLACE TABLE inc_a AS SELECT 1 AS x, 2 AS y, 3 AS w")
            n["d"] = 0
            duck.sync_catalog()
            eq(n["d"], 1, "column-list change DESCRIBEs only that table")
            eq(duck.table_columns.get("inc_a"), ["x", "y", "w"],
               "columns refreshed after shape change")
        finally:
            s.shutdown()

    def t_scoped_counts_api_hdfs_source():
        # Post-653 audit #2: API/HDFS/iterator/folder loads must not wipe the
        # whole sidebar COUNT cache. HDFS must not re-clear after load_file.
        sess = open(os.path.join(BACKEND, "samql_core", "session.py"),
                    encoding="utf-8").read()
        need("def _refresh_scoped_counts(self, specs):" in sess,
             "scoped count refresh helper exists")
        hdfs_i = sess.index("def hdfs_load_file")
        hdfs_j = sess.index("\n    def ", hdfs_i + 1)
        hdfs = sess[hdfs_i:hdfs_j]
        need("self._invalidate_counts()" not in hdfs,
             "hdfs_load_file must not globally clear counts after load_file")
        need("load_file already scoped" in hdfs,
             "hdfs documents that load_file already scoped counts")
        for name in ("def run_iterator", "def _run_iterator_container",
                     "def run_while", "def load_api", "def fetch_api_node",
                     "def load_directory_file", "def load_folder_files"):
            i = sess.index(name)
            j = sess.index("\n    def ", i + 1)
            body = sess[i:j]
            need("_refresh_scoped_counts" in body
                 or (name == "def hdfs_load_file"),
                 "%s must refresh counts with scope" % name)
            if name != "def load_api":
                # load_api only has the helper call; still no bare clear.
                pass
            need("self._invalidate_counts()" not in body,
                 "%s must not bare-clear the count cache" % name)

